function _getIndCacheKey(){
  if(!curData.length) return '';
  const last = curData[curData.length-1];
  return `${curData.length}_${last.time}_${showSMA?1:0}${showBB?1:0}${showRSI?1:0}${showEMA?1:0}${showVWAP?1:0}${showMACD?1:0}${showStoch?1:0}`;
}
function invalidateIndCache(){ _indCacheKey = ''; _indCache = null; }
function getInds(){
  const key = _getIndCacheKey();
  if(key && key === _indCacheKey && _indCache) return _indCache;
  const data = curCT==='heikin' ? calcHeikin(curData) : curData;
  _indCache = {
    data,
    sma20:    showSMA   ? calcSMA(data,20)    : null,
    sma50:    showSMA   ? calcSMA(data,50)    : null,
    bbs:      showBB    ? calcBB(data)        : null,
    rsiVals:  showRSI   ? calcRSI(data)       : null,
    ema9:     showEMA   ? calcEMA(data,9)      : null,
    ema21:    showEMA   ? calcEMA(data,21)     : null,
    ema200:   showEMA   ? calcEMA(data,200)    : null,
    vwapVals: showVWAP  ? calcVWAP(data)      : null,
    macdVals: showMACD  ? calcMACD(data)      : null,
    stochVals:showStoch ? calcStoch(data)     : null,
  };
  _indCacheKey = key;
  return _indCache;
}
