// ══ SHARED MENTOR TRADE LEVEL CALCULATOR ════════════════════════════════════════════════════════════
// Proper trade construction:
//   1. SL first — placed at the nearest structural swing low/high within 2×ATR,
//      giving a sensible, tight stop that reflects real invalidation.
//   2. TP second — the first future close that achieves at least 1.5:1 R:R.
//      If price never reaches 1.5:1, we try 1:1 as an absolute minimum.
//      If even that can't be reached, return null (setup rejected).
//
// Monitoring (monitorExampleTrade) checks CLOSE prices only — wicks on the chart
// are visual reference only and will never stop out the AI trade.
function computeMentorTradeLevels(direction, entryPrice, barIndex, futureCandles) {
  const atr = calculateATR(barIndex, 14) || (entryPrice * 0.01);
  if (!futureCandles || futureCandles.length < 5) return null;

  // ── Step 1: Structural SL from the last 10 bars of history ───────────────
  // Find the nearest significant swing low (for longs) or swing high (for shorts)
  // within the last 10 bars. Cap at 2.0×ATR — wide enough to respect real structure
  // (the validator's 2.5×ATR upper limit provides the outer bound).
  let structuralStop = null;
  const lookback = Math.min(10, barIndex);
  if (curData && barIndex >= lookback) {
    if (direction === 'long') {
      let swingLow = entryPrice;
      for (let k = barIndex - lookback; k <= barIndex; k++) {
        if (curData[k] && curData[k].low < swingLow) swingLow = curData[k].low;
      }
      // SL just below the swing low — cap at 2.0×ATR to stay practical
      structuralStop = swingLow * 0.999;
      if (entryPrice - structuralStop > atr * 2.0) {
        structuralStop = entryPrice - atr * 2.0;
      }
    } else {
      let swingHigh = entryPrice;
      for (let k = barIndex - lookback; k <= barIndex; k++) {
        if (curData[k] && curData[k].high > swingHigh) swingHigh = curData[k].high;
      }
      structuralStop = swingHigh * 1.001;
      if (structuralStop - entryPrice > atr * 2.0) {
        structuralStop = entryPrice + atr * 2.0;
      }
    }
  }
  // Fallback: 1×ATR stop
  if (!structuralStop) {
    structuralStop = direction === 'long'
      ? entryPrice - atr
      : entryPrice + atr;
  }

  const stopLoss    = structuralStop;
  const riskDistance = Math.abs(entryPrice - stopLoss);
  if (riskDistance < 0.0001) return null;

  // ── Step 2: TP = first future close that hits ≥2.5:1 R:R ─────────────────
  // Walk future candles and find the first close that achieves the target.
  // Aim for 2.5:1, fall back to 2:1, then 1.5:1 as the absolute minimum.
  // Anything below 1.5:1 is rejected — fees + spread make it unprofitable.
  const minRRLevels = [2.5, 2.0, 1.5];
  let takeProfit = null;

  for (const minRR of minRRLevels) {
    const targetDistance = riskDistance * minRR;
    const targetPrice = direction === 'long'
      ? entryPrice + targetDistance
      : entryPrice - targetDistance;

    for (let i = 0; i < futureCandles.length; i++) {
      const c = futureCandles[i];

      // SL check: use the wick (low for longs, high for shorts).
      // Stops are triggered by wicks in real trading — if a wick hits the SL
      // before TP is reached by close, this trade would have been stopped out.
      const slHitByWick = direction === 'long'
        ? c.low  <= stopLoss
        : c.high >= stopLoss;
      if (slHitByWick) break; // SL hit — this R:R level is not achievable

      // TP check: use the close price.
      // We require a close beyond the target so the trade is confirmed.
      const tpHitByClose = direction === 'long'
        ? c.close >= targetPrice
        : c.close <= targetPrice;
      if (tpHitByClose) {
        takeProfit = targetPrice;
        break;
      }
    }
    if (takeProfit !== null) break;
  }

  // If no TP achievable before SL wick is hit, reject the setup
  if (takeProfit === null) return null;

  const rewardAmt = Math.abs(takeProfit - entryPrice);
  const rr        = rewardAmt / riskDistance;

  return { stopLoss, takeProfit, rr, atr, riskDistance };
}

function calculateATR(barIndex, period = 14) {
  if (!curData || barIndex < period) return 0;
  
  let trueRanges = [];
  
  for (let i = barIndex - period + 1; i <= barIndex; i++) {
    const current = curData[i];
    const previous = curData[i - 1];
    
    if (!current || !previous) continue;
    
    const high = current.high;
    const low = current.low;
    const prevClose = previous.close;
    
    const tr = Math.max(
      high - low,
      Math.abs(high - prevClose),
      Math.abs(low - prevClose)
    );
    
    trueRanges.push(tr);
  }
  
  if (trueRanges.length === 0) return 0;
  
  const sum = trueRanges.reduce((a, b) => a + b, 0);
  return sum / trueRanges.length;
}

// ══ REPLAY MODE TRADE DETECTION & AI REVIEW ═══════════════════════════════════════════════════════════

function detectReplayTradePlacement() {
  // Only detect trades in replay mode with mentor enabled
  if (!replayMode || !mentorState.enabled) return;
  
  const currentDrawing = getDrawingTradeData();
  
  // Check if this is a new drawing we haven't processed yet
  if (currentDrawing && currentDrawing !== mentorState.lastDetectedDrawing) {
    mentorState.lastDetectedDrawing = currentDrawing;
    
    console.log('🎯 Replay trade detected:', currentDrawing);
    
    // Handle trade placement based on current lifecycle state
    if (mentorState.lifecycleState === 'setup_wait') {
      // User placed trade during setup wait - switch to trade monitoring
      console.log('🎯 Trade placed during setup wait, switching to trade monitoring');
      mentorState.monitoredTrade = currentDrawing;
      setMentorState('trade_monitoring', 'user trade detected during setup wait');
      
      // Generate initial trade monitoring commentary
      generateTradeMonitoringCommentary(replayCutoff);
      updateMentorUI();
      return;
    }
    
    // Disable normal AI trade analysis for replay trades
    disableNormalTradeAnalysis();
    
    // Trigger AI mentor review (for normal replay mode)
    reviewReplayTrade(currentDrawing);
  }
}

function disableNormalTradeAnalysis() {
  // Flag that we're in replay training mode
  mentorState.replayTrainingMode = true;
  console.log('🚫 Normal trade analysis disabled for replay training');
}

function reviewReplayTrade(tradeData) {
  if (!tradeData || !replayMode) return;
  
  console.log('🤖 AI Mentor reviewing replay trade:', tradeData);
  
  // Get market data up to current replay candle
  const dataForAnalysis = curData.slice(0, replayCutoff + 1);
  const analysis = analyzeMarketData(replayCutoff);
  
  // Generate AI review feedback
  const review = generateTradeReview(tradeData, analysis, dataForAnalysis);
  
  // Store trade for training history
  mentorState.reviewedTrades.push({
    ...tradeData,
    review: review,
    replayBar: replayCutoff,
    timestamp: Date.now()
  });
  
  // Display review to user
  displayTradeReview(review, tradeData);
}

function generateTradeReview(tradeData, marketAnalysis, data) {
  const review = {
    overall: 'NEUTRAL',
    strengths: [],
    weaknesses: [],
    suggestions: [],
    riskReward: null,
    structureAlignment: null
  };
  
  // Analyze entry placement
  const entryAnalysis = analyzeEntryPlacement(tradeData, marketAnalysis);
  if (entryAnalysis.good) {
    review.strengths.push(entryAnalysis.reason);
  } else {
    review.weaknesses.push(entryAnalysis.reason);
  }
  
  // Analyze stop loss placement
  const slAnalysis = analyzeStopLossPlacement(tradeData, marketAnalysis);
  if (slAnalysis.good) {
    review.strengths.push(slAnalysis.reason);
  } else {
    review.weaknesses.push(slAnalysis.reason);
  }
  
  // Analyze take profit placement
  const tpAnalysis = analyzeTakeProfitPlacement(tradeData, marketAnalysis);
  if (tpAnalysis.good) {
    review.strengths.push(tpAnalysis.reason);
  } else {
    review.weaknesses.push(tpAnalysis.reason);
  }
  
  // Calculate risk/reward ratio
  if (tradeData.entry && tradeData.sl && tradeData.tp) {
    const risk = Math.abs(tradeData.entry - tradeData.sl);
    const reward = Math.abs(tradeData.tp - tradeData.entry);
    review.riskReward = (reward / risk).toFixed(2);
    
    if (review.riskReward >= 2) {
      review.strengths.push(`Excellent risk/reward ratio of ${review.riskReward}:1`);
    } else if (review.riskReward >= 1.5) {
      review.strengths.push(`Good risk/reward ratio of ${review.riskReward}:1`);
    } else {
      review.weaknesses.push(`Low risk/reward ratio of ${review.riskReward}:1 (aim for 2:1 or better)`);
    }
  }
  
  // Check structure alignment
  if (tradeData.dir === 'long' && marketAnalysis.trend.includes('up')) {
    review.structureAlignment = 'Trade aligns with uptrend';
    review.strengths.push(review.structureAlignment);
  } else if (tradeData.dir === 'short' && marketAnalysis.trend.includes('down')) {
    review.structureAlignment = 'Trade aligns with downtrend';
    review.strengths.push(review.structureAlignment);
  } else if (marketAnalysis.trend === 'neutral') {
    review.structureAlignment = 'Trade in neutral market structure';
    review.weaknesses.push('Consider waiting for clearer trend direction');
  } else {
    review.structureAlignment = `Trade against ${marketAnalysis.trend.replace(/_/g,' ')} trend`;
    review.weaknesses.push(review.structureAlignment);
  }
  
  // Generate overall assessment
  const strengthScore = review.strengths.length;
  const weaknessScore = review.weaknesses.length;
  
  if (strengthScore > weaknessScore && review.riskReward >= 1.5) {
    review.overall = 'GOOD';
  } else if (strengthScore === weaknessScore && review.riskReward >= 1.5) {
    review.overall = 'ACCEPTABLE';
  } else {
    review.overall = 'NEEDS_IMPROVEMENT';
  }
  
  // Generate training suggestions
  review.suggestions = generateTrainingSuggestions(review, tradeData, marketAnalysis);
  
  return review;
}

function analyzeEntryPlacement(tradeData, analysis) {
  const currentPrice = analysis.current.price;
  const entry = tradeData.entry;
  const resistance = analysis.levels.resistance;
  const support = analysis.levels.support;
  
  if (tradeData.dir === 'long') {
    if (support && entry <= support * 1.02) {
      return { good: true, reason: 'Good entry near support level' };
    } else if (resistance && entry >= resistance * 0.98) {
      return { good: false, reason: 'Entry too close to resistance for long trade' };
    } else if (entry > currentPrice * 1.01) {
      return { good: false, reason: 'Entry above current price (chasing)' };
    }
  } else { // short
    if (resistance && entry >= resistance * 0.98) {
      return { good: true, reason: 'Good entry near resistance level' };
    } else if (support && entry <= support * 1.02) {
      return { good: false, reason: 'Entry too close to support for short trade' };
    } else if (entry < currentPrice * 0.99) {
      return { good: false, reason: 'Entry below current price (chasing)' };
    }
  }
  
  return { good: true, reason: 'Entry at reasonable price level' };
}

function analyzeStopLossPlacement(tradeData, analysis) {
  const entry = tradeData.entry;
  const sl = tradeData.sl;
  const resistance = analysis.levels.resistance;
  const support = analysis.levels.support;
  
  if (tradeData.dir === 'long') {
    const riskPercent = Math.abs((entry - sl) / entry) * 100;
    
    if (support && sl <= support * 1.01) {
      return { good: true, reason: 'Stop loss placed below key support' };
    } else if (riskPercent > 5) {
      return { good: false, reason: 'Stop loss too wide (over 5% risk)' };
    } else if (riskPercent < 1) {
      return { good: false, reason: 'Stop loss too tight (under 1% risk)' };
    }
  } else { // short
    const riskPercent = Math.abs((sl - entry) / entry) * 100;
    
    if (resistance && sl >= resistance * 0.99) {
      return { good: true, reason: 'Stop loss placed above key resistance' };
    } else if (riskPercent > 5) {
      return { good: false, reason: 'Stop loss too wide (over 5% risk)' };
    } else if (riskPercent < 1) {
      return { good: false, reason: 'Stop loss too tight (under 1% risk)' };
    }
  }
  
  return { good: true, reason: 'Stop loss at reasonable distance' };
}

function analyzeTakeProfitPlacement(tradeData, analysis) {
  const entry = tradeData.entry;
  const tp = tradeData.tp;
  const resistance = analysis.levels.resistance;
  const support = analysis.levels.support;
  
  if (tradeData.dir === 'long') {
    const rewardPercent = Math.abs((tp - entry) / entry) * 100;
    
    if (resistance && tp >= resistance * 0.98) {
      return { good: true, reason: 'Take profit at key resistance level' };
    } else if (rewardPercent < 2) {
      return { good: false, reason: 'Take profit too close (under 2% reward)' };
    } else if (rewardPercent > 10) {
      return { good: false, reason: 'Take profit too optimistic (over 10% reward)' };
    }
  } else { // short
    const rewardPercent = Math.abs((entry - tp) / entry) * 100;
    
    if (support && tp <= support * 1.02) {
      return { good: true, reason: 'Take profit at key support level' };
    } else if (rewardPercent < 2) {
      return { good: false, reason: 'Take profit too close (under 2% reward)' };
    } else if (rewardPercent > 10) {
      return { good: false, reason: 'Take profit too optimistic (over 10% reward)' };
    }
  }
  
  return { good: true, reason: 'Take profit at reasonable distance' };
}

function generateTrainingSuggestions(review, tradeData, analysis) {
  const suggestions = [];
  
  // Risk management suggestions
  if (!review.riskReward || review.riskReward < 1.5) {
    suggestions.push('Consider improving your risk/reward ratio to at least 1.5:1');
  }
  
  // Entry suggestions
  if (tradeData.dir === 'long' && analysis.levels.support) {
    suggestions.push('Look for entries closer to key support levels for better risk management');
  } else if (tradeData.dir === 'short' && analysis.levels.resistance) {
    suggestions.push('Consider entries near resistance levels for better risk management');
  }
  
  // Structure suggestions
  if (analysis.trend === 'neutral') {
    suggestions.push('Wait for clearer trend direction before taking trades');
  }
  
  // Confirmation suggestions
  suggestions.push('Always wait for confirmation (candle close, volume spike) before entering');
  suggestions.push('Consider market context and upcoming news/events');
  
  return suggestions;
}

function displayTradeReview(review, tradeData) {
  // Only display during DEBRIEF phase — suppress during live trade to avoid confusing self-contradicting AI review
  if (mentorState.lifecycleState !== 'trade_completed') return;
  let reviewHTML = `
    <div style="background:var(--bg2);border:1px solid var(--b1);border-radius:8px;padding:16px;margin:12px 0;">
      <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px;">
        <span style="font-weight:600;color:var(--purple);">🤖 AI Mentor Review</span>
        <span style="padding:4px 8px;border-radius:4px;font-size:11px;font-weight:600;background:${
          review.overall === 'GOOD' ? 'var(--green)' : 
          review.overall === 'ACCEPTABLE' ? 'var(--amber)' : 'var(--red)'
        };color:white;">
          ${review.overall.replace('_', ' ')}
        </span>
      </div>
      
      <div style="margin-bottom:12px;">
        <strong>Trade Details:</strong> ${tradeData.dir.toUpperCase()} @ $${tradeData.entry.toFixed(2)}
        ${tradeData.sl ? ` | SL: $${tradeData.sl.toFixed(2)}` : ''}
        ${tradeData.tp ? ` | TP: $${tradeData.tp.toFixed(2)}` : ''}
        ${review.riskReward ? ` | R:R ${review.riskReward}:1` : ''}
      </div>
  `;
  
  if (review.strengths.length > 0) {
    reviewHTML += `
      <div style="margin-bottom:12px;">
        <strong style="color:var(--green);">✅ Strengths:</strong>
        <ul style="margin:4px 0;padding-left:16px;color:var(--tx2);">
          ${review.strengths.map(s => `<li>${s}</li>`).join('')}
        </ul>
      </div>
    `;
  }
  
  if (review.weaknesses.length > 0) {
    reviewHTML += `
      <div style="margin-bottom:12px;">
        <strong style="color:var(--red);">⚠️ Areas for Improvement:</strong>
        <ul style="margin:4px 0;padding-left:16px;color:var(--tx2);">
          ${review.weaknesses.map(w => `<li>${w}</li>`).join('')}
        </ul>
      </div>
    `;
  }
  
  if (review.suggestions.length > 0) {
    reviewHTML += `
      <div style="margin-bottom:12px;">
        <strong style="color:var(--purple);">📚 Training Suggestions:</strong>
        <ul style="margin:4px 0;padding-left:16px;color:var(--tx2);">
          ${review.suggestions.map(s => `<li>${s}</li>`).join('')}
        </ul>
      </div>
    `;
  }
  
  reviewHTML += `
      <div style="text-align:right;margin-top:16px;">
        <button onclick="closeTradeReview()" style="padding:6px 12px;background:var(--bg1);color:var(--tx2);border:1px solid var(--b1);border-radius:4px;cursor:pointer;">
          Close Review
        </button>
      </div>
    </div>
  `;
  
  // Show in mentor panel feedback area with proper HTML rendering
  const feedbackEl = document.getElementById('mentor-feedback');
  if (feedbackEl) {
    feedbackEl.innerHTML = reviewHTML;
    feedbackEl.style.display = 'block';
    feedbackEl.style.fontStyle = 'normal';
  }
}

function closeTradeReview() {
  // Clear the review message and return to normal mentor analysis
  const feedbackEl = document.getElementById('mentor-feedback');
  if (feedbackEl) {
    feedbackEl.innerHTML = '';
    feedbackEl.style.display = 'none';
  }
  showMentorMessage('Continue your replay training. AI will alert you to new setups.');
}

// ══ TRADING METHOD FILTERING ═══════════════════════════════════════════════════════════

function changeTradingMethod(newMethod) {
  const methodNames = {
    'breakout': 'Breakout Trading',
    'trend': 'Trend Following',
    'support_resistance': 'Support & Resistance',
    'pullback': 'Pullback Trading',
    'range': 'Range Trading',
    'liquidity': 'Liquidity Sweep'
  };

  if (!newMethod) {
    mentorState.selectedTradingMethod = null;
    mentorState.tradingMethodSelected = false;
    mentorState.currentInsights = ['📚 No strategy selected — pick one to begin.'];
    mentorState.currentQuestion = 'Choose a trading style from the dropdown above.';
    updateMentorUI();
    return;
  }

  const methodDisplayName = methodNames[newMethod] || newMethod;

  // ── Pause replay immediately so we don't scan mid-switch ─────────────────
  const wasPlaying = !!(replayMode && replayTimer);
  if (wasPlaying) {
    clearInterval(replayTimer);
    replayTimer = null;
    updateReplayStatus();
  }

  // ── Show switching state in panel ─────────────────────────────────────────
  mentorState.currentInsights = [
    `🔄 Switching to ${methodDisplayName}...`,
    `⏸ Replay paused while strategy resets.`,
  ];
  mentorState.currentQuestion = 'Clearing old state and rescanning for new setups...';
  updateMentorUI();

  // ── Reset all mentor state for the new method ─────────────────────────────
  mentorState._tradeSetupData    = null;
  mentorState._lastAnnotateBar   = null;
  mentorState._lastAnnStateKey = null; mentorState._annCache = null;
  mentorState.lastTradeSuggestionBar   = -999; // reset cooldown for new strategy
  mentorState._lastMentorUpdateBar     = -99;
  if (typeof _scanCache !== 'undefined') _scanCache = { bar: -1, result: null, method: null };
  clearMentorAnnotations();
  resetMentorStateForStrategyChange();
  mentorState.selectedTradingMethod = newMethod;
  mentorState.tradingMethodSelected = true;
  setMentorState('scanning', 'strategy changed');
  mentorState._proximityHintCache   = null; // clear AI hint cache

  // Sync finder dropdown if open
  const mfSel = document.getElementById('mf-method-select');
  if (mfSel) mfSel.value = newMethod;

  // ── Small delay so UI updates are visible, then rescan ───────────────────
  setTimeout(() => {
    mentorState.currentInsights = [`🎯 ${methodDisplayName} — scanning for setups...`];
    mentorState.currentQuestion = 'Looking for setups that meet the strict criteria for this strategy.';
    updateMentorUI();

    if (replayMode) {
      triggerReplayRescan();
      // Auto-resume if it was playing before the switch
      if (wasPlaying) {
        setTimeout(() => {
          if (replayMode && !replayTimer) {
            replayTimer = setInterval(() => replayStep(1), replaySpeed || 500);
            updateReplayStatus();
          }
        }, 300);
      }
    }
  }, 200);

  toast(`🎯 Strategy → ${methodDisplayName}`);
}

function resetMentorStateForStrategyChange() {
  console.log('🔄 Resetting mentor state for strategy change');
  
  // Clear setup cache to ensure fresh detection (no old losing trades)
  if (mentorState.setupCache) {
    mentorState.setupCache.clear();
    console.log('🗑️ Setup cache cleared');
  }
  
  // Cancel any active setup
  mentorState.setupWaitStart = null;
  mentorState.setupWaitData = null;
  mentorState.monitoredTrade = null;
  mentorState.tradeResultData = null;
  mentorState.resultExplained = false;
  
  // Clear waiting state
  mentorState.waitingStateStart = null;
  mentorState.waitingStateMessage = null;
  
  // Clear message locks
  mentorState.messageLocked = false;
  mentorState.lockedMessage = null;
  mentorState.lockedInsights = [];
  mentorState.lockedQuestion = '';
  mentorState.realtimeUpdates = [];
  
  // Clear example trade
  mentorState.exampleTrade = null;
  mentorState.exampleTradeActive = false;
  mentorState.exampleTradeOutcome = null;
  mentorState.tradeMonitoringUpdates = [];
  
  // Hide any control panels
  const setupControls = document.getElementById('setup-message-controls');
  if (setupControls) {
    setupControls.style.display = 'none';
  }
  
  const completionControls = document.getElementById('trade-completion-controls');
  if (completionControls) {
    completionControls.style.display = 'none';
  }
  
  // Resume replay if it was paused
  if (replayMode && replayPaused && mentorState.setupPausedReplay) {
    replayPaused = false;
    mentorState.setupPausedReplay = false;
    const replayBtn = document.getElementById('replay-play-btn');
    if (replayBtn) {
      replayBtn.innerHTML = '⏸️';
    }
  }
}

function filterSetupByTradingMethod(setupDetection, selectedMethod) {
  // detectStructuredSetups is now method-aware and only returns setups relevant
  // to the selected method, so no post-filtering is needed here.
  return setupDetection;
}

// ══ PASS 1: DETERMINISTIC TRADE VALIDATOR ════════════════════════════════════════════════
// Pipeline: normalize → detect mode → validate → score → verdict
// This layer makes a deterministic decision BEFORE the LLM is involved.
// The LLM in Phase 1/2/3 narrates a verdict that has already been computed here.

function mentorNormalizeTrade(setupDetection, barIndex, fullData) {
  const atr = calculateATR(barIndex, 14) || 0;
  const bar  = fullData && fullData[barIndex];
  const entryPrice = bar ? bar.close : null;
  const futureCandles = fullData
    ? fullData.slice(barIndex + 1, Math.min(barIndex + 51, fullData.length))
    : [];

  let levels = null;
  if (entryPrice && futureCandles.length >= 5) {
    levels = computeMentorTradeLevels(
      setupDetection.direction || 'long',
      entryPrice,
      barIndex,
      futureCandles
    );
  }

  // freshnessScore input: how far price has already run in setup direction over last 5 bars
  let priceRunup = 0;
  if (entryPrice && atr > 0 && fullData && barIndex >= 5) {
    const lookback = fullData.slice(Math.max(0, barIndex - 5), barIndex);
    const dir = setupDetection.direction || 'long';
    if (dir === 'long') {
      const recentLow = Math.min(...lookback.map(b => b.low));
      priceRunup = (entryPrice - recentLow) / atr;
    } else {
      const recentHigh = Math.max(...lookback.map(b => b.high));
      priceRunup = (recentHigh - entryPrice) / atr;
    }
  }

  return {
    direction:     setupDetection.direction || 'long',
    setup:         setupDetection.setup     || 'none',
    quality:       setupDetection.quality   || 'none',
    confluence:    setupDetection.confluence || 0,
    entryPrice,
    barIndex,
    atr,
    futureCandles,
    stopLoss:      levels ? levels.stopLoss     : null,
    takeProfit:    levels ? levels.takeProfit   : null,
    rr:            levels ? levels.rr           : null,
    riskDistance:  levels ? levels.riskDistance : null,
    levels,
    priceRunup,
    method: mentorState.selectedTradingMethod || 'none',
  };
}

function mentorDetectMode(trade) {
  if (!replayMode) return 'live';
  return (trade.futureCandles && trade.futureCandles.length >= 5) ? 'historical' : 'hypothetical';
}

function mentorValidateTrade(trade) {
  const { direction, entryPrice, stopLoss, rr, riskDistance, atr, confluence, levels, futureCandles } = trade;

  if (!entryPrice || entryPrice <= 0) {
    return { valid: false, category: 'invalid_data', reason: 'No valid entry price', details: {} };
  }

  // No future data — pass through, cannot validate
  if (!futureCandles || futureCandles.length < 5) {
    return { valid: true, category: 'insufficient_data', reason: 'Insufficient future data', details: {} };
  }

  // Price action moved against the trade immediately
  if (!levels) {
    return { valid: false, category: 'rejected_by_price_action',
      reason: 'Future price action moves against the trade direction', details: {} };
  }

  // R:R floor — minimum 1.0
  if (rr < 1.0) {
    return { valid: false, category: 'poor_rr',
      reason: `R:R of ${rr.toFixed(2)}:1 is below the 1:1 minimum`, details: { rr } };
  }

  // SL width sanity — too tight (< 0.3×ATR) or too wide (> 2.5×ATR)
  const slWidth = atr > 0 ? riskDistance / atr : 1;
  if (atr > 0 && slWidth < 0.3) {
    return { valid: false, category: 'sl_too_tight',
      reason: `Stop loss is too tight (${slWidth.toFixed(2)}×ATR) — will be wicked out`, details: { slWidth } };
  }
  if (atr > 0 && slWidth > 2.5) {
    return { valid: false, category: 'sl_too_wide',
      reason: `Stop loss is too wide (${slWidth.toFixed(2)}×ATR) — poor capital efficiency`, details: { slWidth } };
  }

  // Confluence floor
  if (confluence < 2) {
    return { valid: false, category: 'low_confluence',
      reason: `Only ${confluence} confluence factor(s) — minimum 2 required`, details: { confluence } };
  }

  // Chased entry: first candle already blasted 1.5×ATR beyond entry in trade direction
  if (futureCandles.length > 0 && atr > 0) {
    const fc = futureCandles[0];
    const chased = direction === 'long'
      ? fc.close > entryPrice + atr * 1.5
      : fc.close < entryPrice - atr * 1.5;
    if (chased) {
      return { valid: false, category: 'chased_entry',
        reason: 'Entry is too late — the initial move has already closed strongly beyond entry', details: {} };
    }
  }

  return { valid: true, category: 'valid',
    reason: `Valid setup — R:R ${rr.toFixed(2)}:1`, details: { rr, slWidth } };
}

function mentorScoreTrade(trade) {
  const { rr, confluence, quality, riskDistance, atr, priceRunup } = trade;

  // rrScore: 0 at <1:1, scales to 100 at 4:1+
  let rrScore = 0;
  if (rr !== null) {
    if      (rr >= 4.0) rrScore = 100;
    else if (rr >= 3.0) rrScore = 80 + (rr - 3.0) * 20;
    else if (rr >= 2.0) rrScore = 50 + (rr - 2.0) * 30;
    else if (rr >= 1.0) rrScore = (rr - 1.0) * 50;
  }

  // confluenceScore
  const confMap = { 0: 0, 1: 10, 2: 40, 3: 65, 4: 85 };
  const confluenceScore = confluence >= 5 ? 100 : (confMap[confluence] ?? 0);

  // structureScore from quality label
  const qualMap = { none: 0, low: 20, medium: 50, high: 80, excellent: 100 };
  const structureScore = qualMap[quality] ?? 50;

  // timingScore: optimal SL = 0.6–1.2×ATR
  let timingScore = 50;
  if (atr > 0 && riskDistance) {
    const w = riskDistance / atr;
    if      (w >= 0.6 && w <= 1.2) timingScore = 100;
    else if (w >= 0.4 && w <= 1.5) timingScore = 75;
    else if (w >= 0.3 && w <= 2.0) timingScore = 50;
    else                            timingScore = 25;
  }

  // freshnessScore: penalises entries where price already ran far before setup bar
  // priceRunup = ATR-normalised move in setup direction over last 5 bars
  let freshnessScore = 75; // neutral default when data unavailable
  if (priceRunup !== undefined && atr > 0) {
    if      (priceRunup <  0.5) freshnessScore = 100; // very fresh entry
    else if (priceRunup <  1.0) freshnessScore = 75;  // acceptable
    else if (priceRunup <  1.5) freshnessScore = 50;  // slightly late
    else                        freshnessScore = 0;   // chased
  }

  const qualityScore = Math.round(
    rrScore         * 0.30 +
    confluenceScore * 0.25 +
    structureScore  * 0.20 +
    timingScore     * 0.20 +
    freshnessScore  * 0.05
  );

  return {
    qualityScore:    Math.max(0, Math.min(100, qualityScore)),
    rrScore:         Math.round(rrScore),
    confluenceScore: Math.round(confluenceScore),
    structureScore:  Math.round(structureScore),
    timingScore:     Math.round(timingScore),
    freshnessScore:  Math.round(freshnessScore),
  };
}

function mentorGenerateVerdict(trade, validation, scores) {
  const { qualityScore, timingScore } = scores;
  const { rr, confluence, quality, direction } = trade;

  // Verdict tier
  let verdict;
  if (!validation.valid)       verdict = 'Reject';
  else if (qualityScore >= 72) verdict = 'Strong';
  else if (qualityScore >= 50) verdict = 'Decent';
  else                         verdict = 'Weak';

  const strengths  = [];
  const weaknesses = [];

  if (rr !== null) {
    if (rr >= 2.5) strengths.push(`Favorable R:R of ${rr.toFixed(1)}:1`);
    else if (rr < 1.5) weaknesses.push(`Low R:R of ${rr.toFixed(1)}:1 — target minimum 2:1`);
  }
  if (confluence >= 3) strengths.push(`${confluence} confluence factors align`);
  else if (confluence < 2) weaknesses.push('Low confluence — wait for more factors');

  if (quality === 'high' || quality === 'excellent') strengths.push('Clean structural setup');
  else if (quality === 'low' || quality === 'none')  weaknesses.push('Weak structural quality');

  if (timingScore >= 75) strengths.push('Well-timed entry with proportionate stop');
  else if (timingScore < 50) weaknesses.push('Entry timing or stop placement needs work');

  if (validation.category === 'sl_too_tight') weaknesses.push('Stop too tight — vulnerable to market noise');
  if (validation.category === 'sl_too_wide')  weaknesses.push('Stop too wide — reduces position sizing efficiency');

  let timing = 'On-time';
  if (validation.category === 'chased_entry')     timing = 'Late/Chased';
  else if (rr >= 2.0 && confluence >= 3)          timing = 'Optimal';

  const adviceMap = {
    Strong:  'High-quality setup. Size according to your risk rules and execute the plan.',
    Decent:  'Acceptable setup — look for one additional confluence factor before entering full size.',
    Weak:    'This setup lacks key characteristics. A cleaner entry point is likely around the corner.',
    Reject:  validation.reason || 'Setup does not meet minimum trade criteria. Pass on this one.',
  };

  return {
    verdict,
    validity:     validation.category,
    timing,
    qualityScore,
    strengths,
    weaknesses,
    advice:       adviceMap[verdict],
    scores,
  };
}

// ── Public entry point that replaces validateSetupWithFutureData ──────────────
// Returns the full Pass 1 result. The `valid` / `reason` / `riskReward` /
// `stopLoss` / `takeProfit` fields are preserved for backward-compat callers.
function runMentorValidatorPass1(setupDetection, barIndex, fullData) {
  const trade      = mentorNormalizeTrade(setupDetection, barIndex, fullData);
  const mode       = mentorDetectMode(trade);
  const validation = mentorValidateTrade(trade);
  const scores     = validation.valid ? mentorScoreTrade(trade) : { qualityScore: 0, rrScore: 0, confluenceScore: 0, structureScore: 0, timingScore: 0, freshnessScore: 0 };
  const verdict    = mentorGenerateVerdict(trade, validation, scores);

  return {
    // Backward-compat fields
    valid:       validation.valid,
    reason:      validation.reason,
    riskReward:  trade.rr,
    stopLoss:    trade.stopLoss,
    takeProfit:  trade.takeProfit,
    // Full Pass 1 payload
    mode,
    trade,
    validation,
    scores,
    verdict,
  };
}

// ══ REPLAY KNOWLEDGE ADVANTAGE ═══════════════════════════════════════════════════════════

function validateSetupWithFutureData(setupDetection, currentBar, fullData) {
  if (!replayMode || !fullData || fullData.length <= currentBar + 5) {
    return { valid: true, reason: 'No future data available' };
  }
  return runMentorValidatorPass1(setupDetection, currentBar, fullData);
}


// ══ CASE HISTORY ENGINE ══════════════════════════════════════════════════════════════════
// Stores past analysis cases in IndexedDB and retrieves similar ones for future analysis.
// This makes the system more grounded over time — not by training the AI, but by
// supplying structured historical context at analysis time.

// ── Storage layer (IndexedDB, abstracted) ────────────────────────────────────────────────
const CaseDB = (() => {
  const DB_NAME    = 'apexfx_cases';
  const DB_VERSION = 1;
  const STORE      = 'cases';
  let _db = null;

  function open() {
    if (_db) return Promise.resolve(_db);
    return new Promise((resolve, reject) => {
      const req = indexedDB.open(DB_NAME, DB_VERSION);
      req.onupgradeneeded = e => {
        const db = e.target.result;
        if (!db.objectStoreNames.contains(STORE)) {
          const store = db.createObjectStore(STORE, { keyPath: 'id' });
          store.createIndex('symbol',    'symbol',    { unique: false });
          store.createIndex('method',    'method',    { unique: false });
          store.createIndex('createdAt', 'createdAt', { unique: false });
        }
      };
      req.onsuccess = e => { _db = e.target.result; resolve(_db); };
      req.onerror   = e => reject(e.target.error);
    });
  }

  async function save(caseObj) {
    const db = await open();
    const tx = db.transaction(STORE, 'readwrite');
    tx.objectStore(STORE).put(caseObj);
    return new Promise((res, rej) => { tx.oncomplete = res; tx.onerror = rej; });
  }

  async function loadAll() {
    const db = await open();
    return new Promise((res, rej) => {
      const tx  = db.transaction(STORE, 'readonly');
      const req = tx.objectStore(STORE).getAll();
      req.onsuccess = () => res(req.result);
      req.onerror   = () => rej(req.error);
    });
  }

  async function updateOutcome(id, outcomeMetrics) {
    const db    = await open();
    const tx    = db.transaction(STORE, 'readwrite');
    const store = tx.objectStore(STORE);
    const req   = store.get(id);
    return new Promise((res, rej) => {
      req.onsuccess = () => {
        const rec = req.result;
        if (!rec) return res();
        rec.outcomeMetrics  = { ...rec.outcomeMetrics, ...outcomeMetrics };
        rec.outcomeStatus   = 'measured';
        store.put(rec);
      };
      tx.oncomplete = res;
      tx.onerror    = rej;
    });
  }

  async function count() {
    const db = await open();
    return new Promise((res, rej) => {
      const req = db.transaction(STORE, 'readonly').objectStore(STORE).count();
      req.onsuccess = () => res(req.result);
      req.onerror   = () => res(0);
    });
  }

  return { save, loadAll, updateOutcome, count };
})();

// ── Supabase ↔ IndexedDB dual-storage helpers ────────────────────────────────
// Supabase is primary (cloud, per-user). IndexedDB is the offline fallback.
// Column names use snake_case to match Postgres conventions.

function _caseToRow(c) {
  return {
    id:                    c.id,
    user_id:               _currentUserId || null,
    symbol:                c.symbol,
    market_type:           c.marketType,
    timeframe:             c.timeframe,
    timestamp:             c.timestamp,
    mode:                  c.mode,
    chart_features:        c.chartFeatures,
    setup_type:            c.setupType,
    direction:             c.direction,
    method:                c.method,
    trend_context:         c.trendContext,
    volatility_context:    c.volatilityContext,
    liquidity_context:     c.liquidityContext,
    invalidation_state:    c.invalidationState,
    ai_analysis:           c.aiAnalysis,
    ai_confidence:         c.aiConfidence,
    final_score:           c.finalScore,
    verdict:               c.verdict,
    entry_zone:            c.entryZone,
    stop_loss:             c.stopLoss,
    take_profit:           c.takeProfit,
    outcome_status:        c.outcomeStatus,
    outcome_measured_after: c.outcomeMeasuredAfter,
    outcome_metrics:       c.outcomeMetrics,
    created_at:            c.createdAt,
  };
}

function _rowToCase(r) {
  return {
    id:                   r.id,
    symbol:               r.symbol,
    marketType:           r.market_type,
    timeframe:            r.timeframe,
    timestamp:            r.timestamp,
    mode:                 r.mode,
    chartFeatures:        r.chart_features   || {},
    setupType:            r.setup_type,
    direction:            r.direction,
    method:               r.method,
    trendContext:         r.trend_context,
    volatilityContext:    r.volatility_context,
    liquidityContext:     r.liquidity_context,
    invalidationState:    r.invalidation_state,
    aiAnalysis:           r.ai_analysis,
    aiConfidence:         r.ai_confidence,
    finalScore:           r.final_score,
    verdict:              r.verdict,
    entryZone:            r.entry_zone,
    stopLoss:             r.stop_loss,
    takeProfit:           r.take_profit,
    outcomeStatus:        r.outcome_status,
    outcomeMeasuredAfter: r.outcome_measured_after,
    outcomeMetrics:       r.outcome_metrics  || {},
    createdAt:            r.created_at,
  };
}

async function saveAnalysisCase(caseObj) {
  // Always write to IndexedDB for offline access
  CaseDB.save(caseObj).catch(() => {});
  // Write to Supabase when available
  if (_supaReady && _supa && _currentUserId) {
    try {
      await _supa.from('mentor_cases').upsert(_caseToRow(caseObj));
    } catch(e) { /* non-fatal */ }
  }
}

async function loadAnalysisCases() {
  // Try Supabase first (has all sessions); fall back to local IndexedDB
  if (_supaReady && _supa && _currentUserId) {
    try {
      const { data, error } = await _supa
        .from('mentor_cases')
        .select('*')
        .eq('user_id', _currentUserId)
        .order('created_at', { ascending: false })
        .limit(500);
      if (!error && data?.length) return data.map(_rowToCase);
    } catch(e) { /* fall through to IndexedDB */ }
  }
  return CaseDB.loadAll().catch(() => []);
}

async function updateCaseOutcome(id, metrics) {
  // Update IndexedDB
  CaseDB.updateOutcome(id, metrics).catch(() => {});
  // Update Supabase
  if (_supaReady && _supa && _currentUserId) {
    try {
      await _supa.from('mentor_cases').update({
        outcome_metrics:  metrics,
        outcome_status:   'measured',
      }).eq('id', id).eq('user_id', _currentUserId);
    } catch(e) { /* non-fatal */ }
  }
}

// ── Feature extraction ───────────────────────────────────────────────────────────────────
// Produces a machine-comparable structured snapshot of current market conditions.
function buildChartFeatures(barIndex, setupDetection, pass1Result) {
  const data = curData ? curData.slice(0, barIndex + 1) : [];
  if (data.length < 10) return {};

  const atr   = calculateATR(barIndex, 14) || 0;
  const bar   = data[barIndex];
  const close = bar?.close || 0;

  // Trend via SMA relationship
  const sma20arr = calcSMA(data, 20);
  const sma50arr = calcSMA(data, 50);
  const sma20    = sma20arr[sma20arr.length - 1];
  const sma50    = sma50arr[sma50arr.length - 1];
  let trendDirection = 'neutral';
  if (sma20 && sma50) {
    if      (close > sma20 && sma20 > sma50) trendDirection = 'bullish';
    else if (close < sma20 && sma20 < sma50) trendDirection = 'bearish';
    else                                      trendDirection = 'mixed';
  }

  // Momentum via RSI
  const rsiArr = calcRSI(data);
  const rsi    = rsiArr[rsiArr.length - 1] || 50;
  let momentumStrength = 'neutral';
  if      (rsi >= 65) momentumStrength = 'strong_bull';
  else if (rsi >= 55) momentumStrength = 'moderate_bull';
  else if (rsi <= 35) momentumStrength = 'strong_bear';
  else if (rsi <= 45) momentumStrength = 'moderate_bear';

  // Volume vs 20-bar average
  const recentVols = data.slice(-20).map(b => b.volume || 0).filter(v => v > 0);
  const avgVol     = recentVols.length ? recentVols.reduce((a, b) => a + b, 0) / recentVols.length : 0;
  const lastVol    = bar?.volume || 0;
  let volumeCondition = 'average';
  if (avgVol > 0) {
    if      (lastVol > avgVol * 1.5) volumeCondition = 'high';
    else if (lastVol < avgVol * 0.6) volumeCondition = 'low';
  }

  // Setup-type boolean flags
  const setup = setupDetection?.setup || '';
  const breakoutDetected = /breakout/.test(setup);
  const retestDetected   = /pullback|retest/.test(setup);
  const sweepDetected    = /liquidity|sweep/.test(setup);

  // Distance from nearest key level (SMA20 as proxy) in ATR units
  const distanceFromKeyLevel = (sma20 && atr > 0) ? Math.abs(close - sma20) / atr : null;

  // Structure quality: numeric (0–4)
  const qualMap = { excellent: 4, high: 3, medium: 2, low: 1, none: 0 };
  const structureQuality = qualMap[setupDetection?.quality] ?? 2;

  // Volatility as ATR % of price
  const volatilityPct = close > 0 ? Math.round((atr / close) * 10000) / 100 : 0;

  // Candle body-to-range ratio for pattern summary
  const body  = bar ? Math.abs(bar.close - bar.open) : 0;
  const range = bar ? (bar.high - bar.low) : 0;
  const bodyRatio = range > 0 ? body / range : 0;
  let candlePatternSummary = 'neutral';
  if      (bodyRatio > 0.7) candlePatternSummary = bar?.close > bar?.open ? 'strong_bull_candle' : 'strong_bear_candle';
  else if (bodyRatio < 0.3) candlePatternSummary = 'doji_indecision';
  else                      candlePatternSummary = bar?.close > bar?.open ? 'moderate_bull_candle' : 'moderate_bear_candle';

  return {
    trendDirection,
    distanceFromKeyLevel,
    breakoutDetected,
    retestDetected,
    sweepDetected,
    structureQuality,
    momentumStrength,
    volumeCondition,
    rrEstimate:          pass1Result?.riskReward || null,
    candlePatternSummary,
    rsi:                 Math.round(rsi),
    atr,
    volatilityPct,
  };
}

// ── Case builder ─────────────────────────────────────────────────────────────────────────
function buildAnalysisCase(setupDetection, barIndex, mode, pass1Result) {
  if (!curData || !curData[barIndex]) return null;

  const bar           = curData[barIndex];
  const chartFeatures = buildChartFeatures(barIndex, setupDetection, pass1Result);
  const structure     = analyzeMarketStructure(curData.slice(0, barIndex + 1));
  const verdict       = pass1Result?.verdict;

  return {
    id:           `case_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`,
    symbol:       curSym?.s   || '?',
    marketType:   curSym?.t   || 'Unknown',
    timeframe:    curTF       || '?',
    timestamp:    bar.time,
    mode:         mode        || (replayMode ? 'replay' : 'live'),
    chartFeatures,
    setupType:    setupDetection?.setup     || 'none',
    direction:    setupDetection?.direction || 'unknown',
    method:       mentorState.selectedTradingMethod || 'none',
    trendContext: structure.trend || 'neutral',
    volatilityContext:
      chartFeatures.volatilityPct < 0.3 ? 'low'
      : chartFeatures.volatilityPct > 1.0 ? 'high' : 'medium',
    liquidityContext:  chartFeatures.volumeCondition,
    invalidationState: 'none',
    aiAnalysis:   null,             // filled after Phase 1 LLM
    aiConfidence: verdict?.qualityScore || null,
    finalScore:   verdict?.qualityScore || null,
    verdict:      verdict?.verdict      || null,
    entryZone:    pass1Result?.stopLoss
      ? { entry: bar.close, sl: pass1Result.stopLoss, tp: pass1Result.takeProfit }
      : null,
    stopLoss:     pass1Result?.stopLoss   || null,
    takeProfit:   pass1Result?.takeProfit || null,
    outcomeStatus:         'pending',
    outcomeMeasuredAfter:  null,
    outcomeMetrics: {
      didPriceMoveAsExpected: null,
      maxFavourableExcursion: null,
      maxAdverseExcursion:    null,
      hitTarget:              null,
      hitStop:                null,
      invalidatedQuickly:     null,
      candlesUntilInvalidation: null,
      confidenceCalibration:  null,
    },
    createdAt: Date.now(),
  };
}

// ── Outcome measurement ──────────────────────────────────────────────────────────────────
function measureReplayOutcome(caseObj, tradeOutcome) {
  const isWin  = tradeOutcome === 'take_profit';
  const entry  = caseObj.entryZone?.entry;
  const sl     = caseObj.stopLoss;
  const tp     = caseObj.takeProfit;
  if (!entry || !sl || !tp) return null;

  const riskDist   = Math.abs(entry - sl);
  const rewardDist = Math.abs(tp - entry);

  return {
    didPriceMoveAsExpected:   isWin,
    maxFavourableExcursion:   isWin  ? rewardDist : riskDist * 0.5,
    maxAdverseExcursion:      !isWin ? riskDist   : rewardDist * 0.2,
    hitTarget:                isWin,
    hitStop:                  !isWin,
    invalidatedQuickly:       false,
    candlesUntilInvalidation: null,
    confidenceCalibration:    caseObj.aiConfidence || null,
  };
}

// ── Similarity engine ────────────────────────────────────────────────────────────────────
function scoreSimilarity(a, b) {
  // Deterministic weighted score 0–100. No ML.
  let score = 0;
  if (a.method     && b.method     && a.method     === b.method)     score += 25;
  if (a.marketType && b.marketType && a.marketType === b.marketType) score += 10;
  if (a.timeframe  && b.timeframe  && a.timeframe  === b.timeframe)  score += 10;
  if (a.setupType  && b.setupType  && a.setupType  === b.setupType)  score += 15;
  if (a.direction  && b.direction  && a.direction  === b.direction)  score += 10;
  if (a.trendContext && b.trendContext && a.trendContext === b.trendContext) score += 10;

  const af = a.chartFeatures || {};
  const bf = b.chartFeatures || {};
  if (af.momentumStrength  === bf.momentumStrength)  score += 7;
  if (af.volumeCondition   === bf.volumeCondition)   score += 4;
  if (af.breakoutDetected  === bf.breakoutDetected)  score += 3;
  if (af.retestDetected    === bf.retestDetected)    score += 3;
  if (af.sweepDetected     === bf.sweepDetected)     score += 3;
  return Math.min(100, score);
}

function findSimilarCases(currentCase, allCases, limit = 5) {
  if (!allCases?.length || !currentCase) return [];
  return allCases
    .filter(c => c.id !== currentCase.id && c.outcomeStatus !== 'pending')
    .map(c    => ({ ...c, _similarity: scoreSimilarity(currentCase, c) }))
    .filter(c => c._similarity >= 30)
    .sort((a, b) => b._similarity - a._similarity)
    .slice(0, limit);
}

// ── Historical AI context ────────────────────────────────────────────────────────────────
function buildHistoricalContext(similarCases) {
  if (!similarCases?.length) return '';
  const total  = similarCases.length;
  const wins   = similarCases.filter(c => c.outcomeMetrics?.hitTarget).length;
  const losses = similarCases.filter(c => c.outcomeMetrics?.hitStop).length;
  const winPct = Math.round((wins / total) * 100);

  const lines = similarCases.slice(0, 3).map(c => {
    const outcome = c.outcomeMetrics?.hitTarget ? 'reached target'
      : c.outcomeMetrics?.hitStop ? 'stopped out' : 'outcome unknown';
    return `  • ${c.symbol} ${c.timeframe} — ${(c.setupType || '').replace(/_/g,' ')} ${c.direction} [${c.verdict || '?'}] — ${outcome} (${c._similarity}% match)`;
  }).join('\n');

  return `HISTORICAL CONTEXT — ${total} similar past setup${total !== 1 ? 's' : ''} on record:
Win rate: ${winPct}% (${wins} wins / ${losses} losses / ${total - wins - losses} unresolved)
${lines}
Consider whether the current setup looks stronger or weaker than these past cases. Do not treat past outcomes as guaranteed — use them as reference only.`;
}

// ── Calibration stats ────────────────────────────────────────────────────────────────────
async function getCalibrationStats() {
  const cases    = await loadAnalysisCases();
  const measured = cases.filter(c => c.outcomeStatus === 'measured');
  if (measured.length < 3) return null;
  const byVerdict = {};
  for (const c of measured) {
    const v = c.verdict || 'Unknown';
    if (!byVerdict[v]) byVerdict[v] = { total: 0, wins: 0 };
    byVerdict[v].total++;
    if (c.outcomeMetrics?.hitTarget) byVerdict[v].wins++;
  }
  return Object.entries(byVerdict).map(([verdict, s]) => ({
    verdict, total: s.total, winRate: Math.round((s.wins / s.total) * 100),
  }));
}

// ── UI renderer ──────────────────────────────────────────────────────────────────────────
function renderHistorySection(similarCases, calibration) {
  const el = document.getElementById('mentor-history-section');
  if (!el) return;
  if (!similarCases?.length) { el.style.display = 'none'; return; }

  el.style.display = 'block';
  const total  = similarCases.length;
  const wins   = similarCases.filter(c => c.outcomeMetrics?.hitTarget).length;
  const losses = similarCases.filter(c => c.outcomeMetrics?.hitStop).length;
  const winPct = total > 0 ? Math.round((wins / total) * 100) : null;
  const winColor = wins > losses ? 'var(--green)' : wins < losses ? 'var(--rd)' : 'var(--amber)';

  const caseRows = similarCases.slice(0, 4).map(c => {
    const outcome = c.outcomeMetrics?.hitTarget
      ? `<span style="color:var(--green);font-weight:600;font-size:10px;">✓ Target</span>`
      : c.outcomeMetrics?.hitStop
      ? `<span style="color:var(--rd);font-weight:600;font-size:10px;">✗ Stopped</span>`
      : `<span style="color:var(--tx3);font-size:10px;">— pending</span>`;
    const vColor = { Strong:'var(--green)', Decent:'var(--amber)', Weak:'var(--amber)', Reject:'var(--rd)' }[c.verdict] || 'var(--tx3)';
    const setup  = (c.setupType || '').replace(/_/g,' ');
    return `<div class="mh-case-row">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:1px;">
        <span style="color:var(--tx2);font-size:10.5px;">${c.symbol} ${c.timeframe} · ${setup}</span>
        <span class="mh-sim-badge">${c._similarity}%</span>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center;">
        <span style="color:${vColor};font-size:10px;">${c.verdict || '—'} · ${c.direction}</span>
        ${outcome}
      </div>
    </div>`;
  }).join('');

  const calibHTML = calibration?.length
    ? `<div class="mh-calibration">${calibration.map(s => `<span>${s.verdict}: <b>${s.winRate}%</b> (${s.total})</span>`).join('')}</div>`
    : '';

  el.innerHTML = `
    <div class="mh-header" onclick="this.closest('.mh-wrap').classList.toggle('mh-collapsed')">
      <span class="mh-label">Similar Past Setups</span>
      <div style="display:flex;align-items:center;gap:6px;">
        ${winPct !== null ? `<span style="color:${winColor};font-size:10.5px;font-weight:600;">${winPct}% win</span>` : ''}
        <span style="color:var(--tx3);font-size:10px;">${total} case${total !== 1 ? 's' : ''}</span>
        <span class="mh-chevron">▾</span>
      </div>
    </div>
    <div class="mh-body">
      ${caseRows}
      ${calibHTML}
    </div>`;
}

// ── Integration hooks ────────────────────────────────────────────────────────────────────
mentorState._currentCase          = null;
mentorState._historySimilarCases  = null;

async function caseHistoryOnSetupDetected(setupDetection, barIndex) {
  const p1      = mentorState._pass1Result;
  const mode    = replayMode ? 'replay' : 'live';
  const caseObj = buildAnalysisCase(setupDetection, barIndex, mode, p1);
  if (!caseObj) return;

  mentorState._currentCase = caseObj;
  saveAnalysisCase(caseObj); // fire-and-forget

  const allCases   = await loadAnalysisCases();
  const similar    = findSimilarCases(caseObj, allCases, 5);
  mentorState._historySimilarCases = similar;

  const calibration = await getCalibrationStats();
  renderHistorySection(similar, calibration);
}

function caseHistoryOnTradeComplete(tradeOutcome) {
  const caseObj = mentorState._currentCase;
  if (!caseObj) return;
  const metrics = measureReplayOutcome(caseObj, tradeOutcome);
  if (metrics) updateCaseOutcome(caseObj.id, metrics);
  mentorState._currentCase         = null;
  mentorState._historySimilarCases = null;
}


// ══ STRUCTURED SETUP DETECTION ═══════════════════════════════════════════════════════════

function detectStructuredSetups(data, barIndex, _methodOverride) {
  // _methodOverride lets callers (like the scanner) specify a method without
  // touching global state, avoiding the cache-key corruption bug.
  const tradingMethod = _methodOverride || mentorState.selectedTradingMethod || 'none';
  const cacheKey = `${barIndex}_${tradingMethod}`;
  if (!_methodOverride && mentorState.cacheEnabled && mentorState.setupCache.has(cacheKey)) {
    return mentorState.setupCache.get(cacheKey);
  }

  const NONE = { setup: 'none', quality: 'none', confluence: 0 };

  if (!data || data.length < 30 || barIndex < 0 || barIndex >= data.length) {
    return NONE;
  }

  const current   = data[barIndex];
  const structure = analyzeMarketStructure(data);

  // ── Run ONLY the detectors relevant to the selected method ───────────────
  // This prevents cross-contamination (e.g. a liquidity sweep being shown
  // when the user selected Pullback) and avoids unnecessary computation.
  let candidates = [];

  switch (tradingMethod) {

    case 'breakout': {
      const consolidation = detectConsolidation(data);
      if (consolidation.isConsolidating && isBreakingOut(current, consolidation)) {
        const direction = current.close > consolidation.upper ? 'long' : 'short';
        candidates.push({ type: 'breakout', direction,
          quality: consolidation.quality,
          confluence: calculateBreakoutConfluence(current, consolidation, structure) });
      }
      // Range breakout is also valid under breakout method
      const rbo = detectRangeBreakout(data, consolidation || { isConsolidating: false });
      if (rbo.detected) {
        candidates.push({ type: 'range_breakout', direction: rbo.direction,
          quality: rbo.quality,
          confluence: calculateRangeBreakoutConfluence(rbo, structure) });
      }
      break;
    }

    case 'trend': {
      const flag = detectFlagPattern(data, structure);
      if (flag.detected) {
        candidates.push({ type: 'flag_continuation', direction: flag.direction,
          quality: flag.quality,
          confluence: calculateFlagConfluence(flag, structure) });
      }
      const str = detectStructureSetup(data, structure);
      if (str.detected) {
        candidates.push({ type: 'structure_continuation', direction: str.direction,
          quality: str.quality,
          confluence: calculateStructureConfluence(str, structure) });
      }
      break;
    }

    case 'support_resistance': {
      const sb = detectSupportBounce(data);
      if (sb.detected) {
        candidates.push({ type: 'support_bounce', direction: 'long',
          quality: sb.quality,
          confluence: calculateSupportConfluence(sb, structure) });
      }
      const rr = detectResistanceRejection(data);
      if (rr.detected) {
        candidates.push({ type: 'resistance_rejection', direction: 'short',
          quality: rr.quality,
          confluence: calculateResistanceConfluence(rr, structure) });
      }
      break;
    }

    case 'pullback': {
      const pb = detectTrendPullback(data, structure);
      if (pb.detected) {
        candidates.push({ type: 'trend_pullback', direction: pb.direction,
          quality: pb.quality,
          confluence: calculatePullbackConfluence(pb, structure) });
      }
      // Flag continuation is also a valid pullback entry
      const flag = detectFlagPattern(data, structure);
      if (flag.detected) {
        candidates.push({ type: 'flag_continuation', direction: flag.direction,
          quality: flag.quality,
          confluence: calculateFlagConfluence(flag, structure) });
      }
      break;
    }

    case 'range': {
      // Range trading: confirm price is IN a range, then look for boundary reactions
      const conso = detectConsolidation(data);
      if (!conso.isConsolidating) break; // not a range environment — skip

      // Range must be wide enough to trade (at least 3×ATR for meaningful R:R)
      const rangeAtr = _atrRaw(data, 14) || 1;
      if ((conso.upper - conso.lower) < rangeAtr * 3) break;

      // Price near lower boundary → long setup
      const current = data[data.length - 1];
      const nearLower = Math.abs(current.close - conso.lower) / (conso.upper - conso.lower) < 0.20;
      const nearUpper = Math.abs(current.close - conso.upper) / (conso.upper - conso.lower) > 0.80;

      if (nearLower) {
        const sb = detectSupportBounce(data);
        if (sb.detected) candidates.push({ type: 'support_bounce', direction: 'long',
          quality: sb.quality, confluence: calculateSupportConfluence(sb, structure) + 1 }); // +1 for range context
      }
      if (nearUpper) {
        const rr = detectResistanceRejection(data);
        if (rr.detected) candidates.push({ type: 'resistance_rejection', direction: 'short',
          quality: rr.quality, confluence: calculateResistanceConfluence(rr, structure) + 1 });
      }
      break;
    }

    case 'liquidity': {
      const sweep = detectLiquiditySweep(data);
      if (sweep.detected) {
        candidates.push({ type: 'liquidity_sweep', direction: sweep.direction,
          quality: sweep.quality,
          confluence: calculateLiquiditySweepConfluence(sweep, structure) });
      }
      break;
    }

    default: {
      // No method selected — run all detectors, pick best
      const consolidation = detectConsolidation(data);
      if (consolidation.isConsolidating && isBreakingOut(current, consolidation)) {
        const dir = current.close > consolidation.upper ? 'long' : 'short';
        candidates.push({ type: 'breakout', direction: dir,
          quality: consolidation.quality,
          confluence: calculateBreakoutConfluence(current, consolidation, structure) });
      }
      const flag = detectFlagPattern(data, structure);
      if (flag.detected) candidates.push({ type: 'flag_continuation', direction: flag.direction, quality: flag.quality, confluence: calculateFlagConfluence(flag, structure) });
      const sb = detectSupportBounce(data);
      if (sb.detected) candidates.push({ type: 'support_bounce', direction: 'long', quality: sb.quality, confluence: calculateSupportConfluence(sb, structure) });
      const rr = detectResistanceRejection(data);
      if (rr.detected) candidates.push({ type: 'resistance_rejection', direction: 'short', quality: rr.quality, confluence: calculateResistanceConfluence(rr, structure) });
      const pb = detectTrendPullback(data, structure);
      if (pb.detected) candidates.push({ type: 'trend_pullback', direction: pb.direction, quality: pb.quality, confluence: calculatePullbackConfluence(pb, structure) });
      const sweep = detectLiquiditySweep(data);
      if (sweep.detected) candidates.push({ type: 'liquidity_sweep', direction: sweep.direction, quality: sweep.quality, confluence: calculateLiquiditySweepConfluence(sweep, structure) });
      const str = detectStructureSetup(data, structure);
      if (str.detected) candidates.push({ type: 'structure_continuation', direction: str.direction, quality: str.quality, confluence: calculateStructureConfluence(str, structure) });
    }
  }

  // ── Quality gate: must meet minimum confluence of 2 ──────────────────────
  // (strict detection already filters most noise; this removes the weakest hits)
  candidates = candidates.filter(s => s.confluence >= 2);

  if (candidates.length === 0) {
    if (!_methodOverride && mentorState.cacheEnabled) mentorState.setupCache.set(cacheKey, NONE);
    return NONE;
  }

  // Pick the highest-confluence candidate
  const best = candidates.reduce((a, b) => b.confluence > a.confluence ? b : a);

  const result = {
    setup: best.type,
    quality: best.quality,
    confluence: best.confluence,
    direction: best.direction,
    details: best,
  };

  if (!_methodOverride && mentorState.cacheEnabled) mentorState.setupCache.set(cacheKey, result);
  return result;
}

// ── Asset-aware price unit helper ────────────────────────────────────────────
// Returns 'pts' for crypto/indices, 'pips' for forex, so debrief text is accurate.
function _mentorPriceUnit() {
  if (_isCrypto()) return 'pts';
  const sym = (curSym || '').toUpperCase();
  // Indices and metals by convention use "points"
  if (/^(SPX|NAS|DOW|DAX|FTSE|NIKKEI|GOLD|SILVER|XAU|XAG)/.test(sym)) return 'pts';
  return 'pips'; // default for forex
}
// ── Crypto-awareness helper ──────────────────────────────────────────────────
// Returns true when the loaded symbol is a crypto asset. Used throughout the
// detection functions to apply crypto-specific adjustments:
//  - Looser breakout body threshold (noisier, higher false-breakout rate)
//  - Higher volume confirmation bar for breakouts (need stronger signal)
//  - More aggressive liquidity sweep detection (thinner books, engineered sweeps)
//  - Shorter pullback tolerance (moves compress timeframes)
//  - 24/7 market → no session bias, so range boundaries checked more strictly
function _isCrypto() {
  return !!(curSym && curSym.t === 'Crypto');
}

// Price-relative round number check.
// Instead of fixed modulo ($1000, $100, $10) which fails at all price scales,
// we compute the nearest "significant round" as a % of price magnitude.
// e.g. BTC $70k → nearest $5k multiple; ETH $3k → nearest $250; DOGE $0.12 → nearest $0.05
function _isPriceRelativeRound(price) {
  if (!price || price <= 0) return false;
  const magnitude = Math.pow(10, Math.floor(Math.log10(price)));
  // Test multiples of 0.5×, 1×, 2×, 5× the magnitude
  const candidates = [magnitude * 0.5, magnitude, magnitude * 2, magnitude * 5];
  // A level is "round" if it's within 0.5% of any candidate round number
  return candidates.some(round => round > 0 && Math.abs(price - Math.round(price / round) * round) / price < 0.005);
}

// ══ METHODOLOGY-STRICT DETECTION FUNCTIONS ══════════════════════════════════════════════════
// Each function enforces the real criteria from the trading methodology document.
// Strict criteria replace the 80-candle cooldown — bad setups are rejected here, not timed out.

// ── Shared helpers ──────────────────────────────────────────────────────────
function _ema(data, period) {
  if (data.length < period) return null;
  const k = 2 / (period + 1);
  let ema = data.slice(0, period).reduce((s,d) => s + d.close, 0) / period;
  for (let i = period; i < data.length; i++) ema = data[i].close * k + ema * (1 - k);
  return ema;
}
function _sma(data, period) {
  if (data.length < period) return null;
  return data.slice(-period).reduce((s,d) => s + d.close, 0) / period;
}
function _avgVol(data, period) {
  if (data.length < period) return 1;
  return data.slice(-period).reduce((s,d) => s + (d.volume||0), 0) / period;
}
function _atrRaw(data, period) {
  if (data.length < period + 1) return null;
  let sum = 0;
  for (let i = data.length - period; i < data.length; i++) {
    const c = data[i], p = data[i-1];
    sum += Math.max(c.high - c.low, Math.abs(c.high - p.close), Math.abs(c.low - p.close));
  }
  return sum / period;
}

// ── 1. BREAKOUT: consolidation zone + decisive close + volume expansion ──────
function detectConsolidation(data) {
  if (data.length < 15) return { isConsolidating: false };
  const crypto = _isCrypto();
  // Exclude the last candle from the consolidation window — it may be the breakout candle
  // and would inflate the range or count as a boundary touch incorrectly.
  // Require at least 8 bars in the zone for a tradeable consolidation.
  const lookback = data.slice(-21, -1); // 20 bars, excluding current
  if (lookback.length < 8) return { isConsolidating: false };
  const highs = lookback.map(d => d.high);
  const lows  = lookback.map(d => d.low);
  const hi = Math.max(...highs), lo = Math.min(...lows);
  const mid = (hi + lo) / 2;
  const rangePercent = (hi - lo) / mid * 100;

  // Crypto: allow wider consolidation (up to 6% — crypto volatility is higher)
  // but require 3 boundary touches (higher false-breakout rate demands tighter zones)
  const maxRange    = crypto ? 6   : 4;
  const minTouches  = crypto ? 3   : 2;
  const touchTol    = crypto ? 0.995 : 0.997; // slightly wider tolerance for touch detection

  const upperTouches = lookback.filter(d => d.high >= hi * touchTol).length;
  const lowerTouches = lookback.filter(d => d.low  <= lo * (2 - touchTol)).length;
  const isConsolidating = rangePercent < maxRange && upperTouches >= minTouches && lowerTouches >= minTouches;

  // Quality thresholds also adjusted for crypto's wider natural ranges
  const quality = rangePercent < (crypto ? 3 : 2) ? 'high'
                : rangePercent < (crypto ? 5 : 3) ? 'medium' : 'low';
  const avgVol = _avgVol(data, 20);
  return { isConsolidating, quality, upper: hi, lower: lo, range: rangePercent,
           avgVolume: avgVol, upperTouches, lowerTouches };
}

function isBreakingOut(current, consolidation) {
  if (!consolidation.isConsolidating) return false;
  const crypto = _isCrypto();
  const bodyTop = Math.max(current.open, current.close);
  const bodyBot = Math.min(current.open, current.close);
  const bodySize = Math.abs(current.close - current.open);
  const candleRange = current.high - current.low;
  // Crypto: require stronger body (60%+ of range) — noisier market, more fakeouts
  const minBodyRatio = crypto ? 0.60 : 0.50;
  if (candleRange > 0 && bodySize / candleRange < minBodyRatio) return false;
  // Close must be clearly outside the zone
  // Crypto: require a slightly larger margin to reduce false signals
  const margin = crypto ? 1.002 : 1.001;
  return current.close > consolidation.upper * margin ||
         current.close < consolidation.lower * (2 - margin);
}

function calculateBreakoutConfluence(current, consolidation, structure) {
  const crypto = _isCrypto();
  let c = 0;
  // 1. Strong body close outside zone
  const bodySize = Math.abs(current.close - current.open);
  const candleRange = current.high - current.low || 1;
  const minBody = crypto ? 0.60 : 0.50;
  if (bodySize / candleRange >= minBody) c++;
  // 2. Volume confirmation — crypto needs higher bar (1.5× avg, not 1.2×)
  //    because crypto retail volume is noisy and a genuine breakout needs real conviction
  const volThreshold = crypto ? 1.5 : 1.2;
  if (current.volume > (consolidation.avgVolume||1) * volThreshold) c++;
  // 3. Zone quality (multiple boundary touches)
  const minTouchesForPoint = crypto ? 4 : 3; // crypto needs more retests to confirm level
  if (consolidation.upperTouches >= minTouchesForPoint || consolidation.lowerTouches >= minTouchesForPoint) c++;
  // 4. Trend alignment
  if (structure && structure.trend && structure.trend !== 'neutral') c++;
  return Math.min(c, 4);
}

// ── 2. FLAG/TREND: strong impulse + low-vol pullback + EMA still fanned ─────
function detectFlagPattern(data, structure) {
  if (data.length < 25 || !structure || structure.trend === 'neutral') return { detected: false };
  const isUp = structure.trend.includes('up');
  const atr = _atrRaw(data, 14);
  if (!atr) return { detected: false };
  const current = data[data.length - 1];

  // Try multiple flag lengths (5–20 bar flags are all valid)
  for (const flagLen of [5, 8, 12, 16, 20]) {
    if (data.length < flagLen + 15) continue;
    const impulse     = data.slice(-(flagLen + 15), -flagLen);
    const flag        = data.slice(-flagLen);
    if (impulse.length < 8) continue;

    // Impulse: strong directional move > 2×ATR
    const impulseMag = Math.abs(impulse[impulse.length-1].close - impulse[0].close);
    if (impulseMag < atr * 2) continue;

    // Impulse direction must match trend
    const impulseUp = impulse[impulse.length-1].close > impulse[0].close;
    if (isUp !== impulseUp) continue;

    // Flag must retrace 10–50% of impulse (real pullback, not sideways drift)
    const flagHigh   = Math.max(...flag.map(d => d.high));
    const flagLow    = Math.min(...flag.map(d => d.low));
    const flagRetrace = isUp
      ? (impulse[impulse.length-1].close - Math.min(...flag.map(d => d.close))) / impulseMag
      : (Math.max(...flag.map(d => d.close)) - impulse[impulse.length-1].close) / impulseMag;
    if (flagRetrace < 0.10 || flagRetrace > 0.55) continue; // need real pullback, not >55%

    // Volume contracting in the flag
    const volImpulse = impulse.reduce((s,d) => s+(d.volume||0), 0) / impulse.length;
    const volFlag    = flag.reduce((s,d) => s+(d.volume||0), 0) / flag.length;
    if (volFlag >= volImpulse) continue;

    // EMA20 still fanned — price above (bull) or below (bear) EMA
    const ema20 = _ema(data, 20);
    if (isUp  && current.close < ema20) continue;
    if (!isUp && current.close > ema20) continue;

    const quality = (impulseMag > atr * 3 && flagRetrace >= 0.20 && flagRetrace <= 0.50) ? 'high' : 'medium';
    return { detected: true, direction: isUp ? 'long' : 'short', quality,
             pattern: 'flag', flagLen, impulse: impulseMag, retrace: flagRetrace };
  }
  return { detected: false };
}

function calculateFlagConfluence(flag, structure) {
  let c = 1; // Base: impulse + consolidation confirmed
  if (structure && structure.trend && structure.trend.includes('strong')) c++;
  if (flag.quality === 'high') c++;
  // EMA alignment already validated in detection, add point
  c++;
  return Math.min(c, 4);
}

// ── 3. SUPPORT BOUNCE: level with 2+ prior touches + confirmation candle ─────
function detectSupportBounce(data) {
  if (data.length < 30) return { detected: false };
  const atr    = _atrRaw(data, 14);
  if (!atr) return { detected: false };
  const crypto = _isCrypto();

  // Crypto: look back further — 24/7 market has more price history to establish levels
  const lookbackSize = crypto ? 50 : 30;
  const lookback = data.slice(-lookbackSize);
  const current  = data[data.length - 1];
  const prev     = data[data.length - 2];

  const swingLows = [];
  // Require 3 bars each side (strength=3) to filter micro-noise
  const swingStrength = 3;
  for (let i = swingStrength; i < lookback.length - swingStrength; i++) {
    let isSwing = true;
    for (let j = 1; j <= swingStrength; j++) {
      if (lookback[i].low >= lookback[i-j].low || lookback[i].low >= lookback[i+j].low) {
        isSwing = false; break;
      }
    }
    // Minimum significance: swing must be at least 1×ATR below surrounding bars
    if (isSwing) {
      const surroundHigh = Math.min(lookback[i-1].low, lookback[i+1].low);
      if (surroundHigh - lookback[i].low >= atr * 0.8) {
        swingLows.push(lookback[i].low);
      }
    }
  }
  if (swingLows.length < 1) return { detected: false };

  const minTouches = crypto ? 3 : 2;

  for (const level of swingLows) {
    const tolerance = atr * (crypto ? 0.7 : 0.5);
    const touches = lookback.filter(d => Math.abs(d.low - level) < tolerance).length;
    if (touches < minTouches) continue;
    if (Math.abs(current.low - level) > tolerance * 1.5) continue;

    const bodyBot   = Math.min(current.open, current.close);
    const bodyTop   = Math.max(current.open, current.close);
    const lowerWick = bodyBot - current.low;
    const bodySize  = bodyTop - bodyBot || atr * 0.1;

    // Crypto: require larger rejection wick relative to body (1.5× for crypto vs 1× standard)
    // — thin books mean stop hunts are common; we need a clear wick for a real bounce
    const minWickRatio = crypto ? 1.5 : 1.0;
    const isRejection  = lowerWick > bodySize * minWickRatio && current.close > prev.close;
    if (!isRejection) continue;

    const quality = touches >= (crypto ? 4 : 3) ? 'high' : 'medium';
    return { detected: true, quality, supportLevel: level, touches };
  }
  return { detected: false };
}

function calculateSupportConfluence(support, structure) {
  const crypto = _isCrypto();
  let c = 1;
  if (support.touches >= 3) c++;
  if (structure && structure.trend && structure.trend.includes('up')) c++;
  // Crypto: extra confluence for round-number proximity.
  // Threshold scales with price so $70k BTC uses the same logic as $0.50 altcoins.
  const level = support.supportLevel || 0;
  const isRoundNumber = level > 0 && _isPriceRelativeRound(level);
  if (crypto && isRoundNumber) c++;
  else if (support.touches >= 4) c++;
  return Math.min(c, 4);
}

// ── 4. RESISTANCE REJECTION: level with 2+ touches + rejection candle ────────
function detectResistanceRejection(data) {
  if (data.length < 30) return { detected: false };
  const atr    = _atrRaw(data, 14);
  if (!atr) return { detected: false };
  const crypto = _isCrypto();

  const lookbackSize = crypto ? 50 : 30;
  const lookback = data.slice(-lookbackSize);
  const current  = data[data.length - 1];
  const prev     = data[data.length - 2];

  const swingHighs = [];
  const swingStrR = 3;
  for (let i = swingStrR; i < lookback.length - swingStrR; i++) {
    let isSwing = true;
    for (let j = 1; j <= swingStrR; j++) {
      if (lookback[i].high <= lookback[i-j].high || lookback[i].high <= lookback[i+j].high) {
        isSwing = false; break;
      }
    }
    if (isSwing) {
      const surroundLow = Math.max(lookback[i-1].high, lookback[i+1].high);
      if (lookback[i].high - surroundLow >= atr * 0.8) {
        swingHighs.push(lookback[i].high);
      }
    }
  }
  if (swingHighs.length < 1) return { detected: false };

  const minTouches = crypto ? 3 : 2;

  for (const level of swingHighs) {
    const tolerance = atr * (crypto ? 0.7 : 0.5);
    const touches = lookback.filter(d => Math.abs(d.high - level) < tolerance).length;
    if (touches < minTouches) continue;
    if (Math.abs(current.high - level) > tolerance * 1.5) continue;

    const bodyBot   = Math.min(current.open, current.close);
    const bodyTop   = Math.max(current.open, current.close);
    const upperWick = current.high - bodyTop;
    const bodySize  = bodyTop - bodyBot || atr * 0.1;

    const minWickRatio = crypto ? 1.5 : 1.0;
    const isRejection  = upperWick > bodySize * minWickRatio && current.close < prev.close;
    if (!isRejection) continue;

    const quality = touches >= (crypto ? 4 : 3) ? 'high' : 'medium';
    return { detected: true, quality, resistanceLevel: level, touches };
  }
  return { detected: false };
}

function calculateResistanceConfluence(resistance, structure) {
  const crypto = _isCrypto();
  let c = 1;
  if (resistance.touches >= 3) c++;
  if (structure && structure.trend && structure.trend.includes('down')) c++;
  const level = resistance.resistanceLevel || 0;
  const isRoundNumber = level > 0 && _isPriceRelativeRound(level);
  if (crypto && isRoundNumber) c++;
  else if (resistance.touches >= 4) c++;
  return Math.min(c, 4);
}

// ── 5. TREND PULLBACK: HTF trend intact + retrace to 38–61.8% Fib + EMA ─────
function detectTrendPullback(data, structure) {
  if (data.length < 30 || !structure || structure.trend === 'neutral') return { detected: false };
  const isUp   = structure.trend.includes('up');
  const crypto = _isCrypto();

  const lookback  = data.slice(-25);
  const swingHigh = Math.max(...lookback.map(d => d.high));
  const swingLow  = Math.min(...lookback.map(d => d.low));
  const swingSize = swingHigh - swingLow;
  if (swingSize === 0) return { detected: false };

  const current = data[data.length - 1];
  const retrace = isUp
    ? (swingHigh - current.close) / swingSize
    : (current.close - swingLow) / swingSize;

  // Crypto: accept 25%–65% retracements — moves are faster and shallower pullbacks
  // are common because momentum traders re-enter quickly. Traditional: 30%–65%.
  const minRetrace = crypto ? 0.25 : 0.30;
  if (retrace < minRetrace || retrace > 0.65) return { detected: false };

  const atr  = _atrRaw(data, 14);
  if (!atr) return { detected: false };
  const ema20 = _ema(data, 20);
  if (!ema20) return { detected: false };

  // EMA zone: ATR-based tolerance adapts to current volatility rather than % of price.
  // When the market is quiet (low ATR), the zone is tighter — catches only real EMA tests.
  // When volatile (high ATR), the zone widens naturally so valid pullbacks aren't missed.
  const emaZoneTol = crypto ? atr * 0.5 : atr * 0.4;
  const emaInZone  = Math.abs(current.close - ema20) < emaZoneTol;
  // Also accept if price wicked through EMA (low < ema20 < close for longs)
  const wickedThroughEMA = isUp
    ? (current.low <= ema20 && current.close >= ema20 * 0.998)
    : (current.high >= ema20 && current.close <= ema20 * 1.002);
  if (!emaInZone && !wickedThroughEMA) return { detected: false };

  const impulseVol  = _avgVol(data.slice(0, -10), 10);
  const pullbackVol = _avgVol(data.slice(-10), 10);
  const volContracting = pullbackVol < impulseVol * 0.85; // require meaningful vol drop

  const ema50 = _ema(data, 50);
  const trendIntact = isUp ? (ema20 > ema50) : (ema20 < ema50);
  if (!trendIntact) return { detected: false };

  // Require a reversal candle at the pullback zone:
  // For longs: current candle must close bullish (close > open) at the EMA
  // For shorts: current candle must close bearish at the EMA
  const prev2 = data[data.length - 2];
  const isReversalCandle = isUp
    ? (current.close > current.open && current.close > prev2.close)
    : (current.close < current.open && current.close < prev2.close);
  if (!isReversalCandle) return { detected: false };

  const quality = (volContracting && retrace >= 0.382 && retrace <= 0.618) ? 'high' : 'medium';
  return { detected: true, quality, direction: isUp ? 'long' : 'short',
           pullbackLevel: current.close, retrace, emaInZone: emaInZone || wickedThroughEMA,
           volContracting };
}

function calculatePullbackConfluence(pullback, structure) {
  let c = 1;
  if (structure.trend.includes('strong')) c++;   // Strong trend
  if (pullback.emaInZone) c++;                    // Price at EMA confluence
  if (pullback.volContracting) c++;               // Volume contracting = healthy pullback
  return Math.min(c, 4);
}

// ── 6. RANGE: 2–3 touches each boundary + range wide enough for 2:1 ─────────
function detectRangeBreakout(data, consolidation) {
  if (!consolidation.isConsolidating) return { detected: false };
  if (data.length < 2) return { detected: false };
  const crypto   = _isCrypto();
  const atr      = _atrRaw(data, 14);
  const current  = data[data.length - 1];
  const avgVol   = _avgVol(data, 20);
  // Crypto needs stronger volume surge to confirm a real breakout (24/7 market has more noise)
  const volMultiplier  = crypto ? 1.5 : 1.3;
  const volExpansion   = current.volume > avgVol * volMultiplier;
  // Require a meaningful body — not just a wick poking out
  const body           = Math.abs(current.close - current.open);
  const bodyRatio      = atr ? body / atr : 0;
  const minBodyRatio   = crypto ? 0.35 : 0.3;
  const hasBody        = bodyRatio >= minBodyRatio;
  // Close margin beyond zone
  const closeMargin    = crypto ? 0.002 : 0.001;

  if (current.close > consolidation.upper * (1 + closeMargin) && volExpansion && hasBody) {
    const quality = volExpansion && bodyRatio >= (crypto ? 0.5 : 0.4) ? 'high' : 'medium';
    return { detected: true, quality, direction: 'long', breakoutLevel: consolidation.upper };
  }
  if (current.close < consolidation.lower * (1 - closeMargin) && volExpansion && hasBody) {
    const quality = volExpansion && bodyRatio >= (crypto ? 0.5 : 0.4) ? 'high' : 'medium';
    return { detected: true, quality, direction: 'short', breakoutLevel: consolidation.lower };
  }
  return { detected: false };
}

function calculateRangeBreakoutConfluence(breakout, structure) {
  let c = 2; // Zone validated (multiple touches confirmed in detectConsolidation)
  if (breakout.quality === 'high') c++;
  if (structure && structure.trend !== 'neutral') c++;
  return Math.min(c, 4);
}

// ── 7. LIQUIDITY SWEEP: wick beyond swing high/low + displacement close ─────
function detectLiquiditySweep(data) {
  if (data.length < 20) return { detected: false };
  const atr = _atrRaw(data, 14);
  if (!atr) return { detected: false };
  const crypto = _isCrypto();

  const lookbackSize = crypto ? 30 : 20;
  // Exclude the sweep candle AND current from lookback — they define the sweep, not the level
  const lookback    = data.slice(-lookbackSize - 2, -2);
  const sweepCandle = data[data.length - 2];
  const current     = data[data.length - 1];

  const priorLow  = Math.min(...lookback.map(d => d.low));
  const priorHigh = Math.max(...lookback.map(d => d.high));

  // The swept level must be a meaningful swing (not just a micro-low)
  // Require it to have at least 2 candles nearby confirming it as a level
  const levelTolerance = atr * 0.5;
  const lowTests  = lookback.filter(d => Math.abs(d.low  - priorLow)  < levelTolerance).length;
  const highTests = lookback.filter(d => Math.abs(d.high - priorHigh) < levelTolerance).length;
  if (lowTests < 2 && highTests < 2) return { detected: false }; // not a significant level

  // Displacement candle needs a real body — 0.6×ATR minimum ensures it's genuine
  // institutional flow, not a small bounce that quickly reverses
  const minDisplacementBody = atr * 0.6;

  // BULL sweep: wick below prior low + displacement up
  const wickBelowLow = sweepCandle.low < priorLow;
  const displacedUp  = current.close > sweepCandle.high &&
                       (current.close - current.open) > minDisplacementBody;

  if (wickBelowLow && displacedUp) {
    const wickDepth = priorLow - sweepCandle.low;
    // Minimum wick depth: 0.3×ATR for crypto (was 0 — too loose), 0.2×ATR for traditional
    const minWickDepth = crypto ? atr * 0.3 : atr * 0.2;
    if (wickDepth >= minWickDepth && lowTests >= 2) {
      return { detected: true, quality: 'high', direction: 'long',
               sweepLevel: priorLow, wickDepth };
    }
  }

  // BEAR sweep: wick above prior high + displacement down
  const wickAboveHigh = sweepCandle.high > priorHigh;
  const displacedDown = current.close < sweepCandle.low &&
                        (current.open - current.close) > minDisplacementBody;

  if (wickAboveHigh && displacedDown) {
    const wickDepth = sweepCandle.high - priorHigh;
    const minWickDepth = crypto ? atr * 0.3 : atr * 0.2;
    if (wickDepth >= minWickDepth && highTests >= 2) {
      return { detected: true, quality: 'high', direction: 'short',
               sweepLevel: priorHigh, wickDepth };
    }
  }

  return { detected: false };
}

function calculateLiquiditySweepConfluence(sweep, structure) {
  const crypto = _isCrypto();
  let c = 1;
  if (sweep.quality === 'high') c++;
  if (sweep.wickDepth && sweep.wickDepth > 0) c++;
  // Crypto: liquidity sweep gets a bonus point — it's the most reliable pattern
  // in crypto due to the frequency of deliberate stop hunts by larger players
  if (crypto) c++;
  else if (structure && structure.trend !== 'neutral') c++;
  return Math.min(c, 4);
}

// ── 8. STRUCTURE (higher low / lower high) ───────────────────────────────────
function detectStructureSetup(data, structure) {
  if (!structure || structure.trend === 'neutral' || data.length < 20) return { detected: false };
  const crypto = _isCrypto();
  const isUp   = structure.trend.includes('up');
  const atr    = _atrRaw(data, 14);
  if (!atr) return { detected: false };
  // Crypto: look back 25 bars — more price history needed to confirm structure on volatile assets
  const lookbackSize = crypto ? 25 : 20;
  const lookback = data.slice(-lookbackSize);
  // Find the last 3 swing lows (for uptrend) or swing highs (for downtrend)
  const pivots = [];
  // Require 2 bars each side for pivot confirmation
  for (let i = 2; i < lookback.length - 2; i++) {
    if (isUp) {
      if (lookback[i].low < lookback[i-1].low && lookback[i].low < lookback[i-2]?.low &&
          lookback[i].low < lookback[i+1].low && lookback[i].low < lookback[i+2]?.low) {
        pivots.push({ idx: i, price: lookback[i].low });
      }
    } else {
      if (lookback[i].high > lookback[i-1].high && lookback[i].high > lookback[i-2]?.high &&
          lookback[i].high > lookback[i+1].high && lookback[i].high > lookback[i+2]?.high) {
        pivots.push({ idx: i, price: lookback[i].high });
      }
    }
  }
  if (pivots.length < 2) return { detected: false };
  const last = pivots[pivots.length - 1];
  const prev = pivots[pivots.length - 2];
  // Structural shift must be meaningful — crypto needs slightly looser minimum
  // because ATR itself is larger, but we don't want to reject real crypto structures
  const minShift = crypto ? atr * 0.4 : atr * 0.5;
  const isValid = isUp
    ? (last.price > prev.price + minShift)
    : (last.price < prev.price - minShift);
  if (!isValid) return { detected: false };
  // Current bar must be close to the pivot — crypto gets wider tolerance (more volatile wicks)
  const nearTolerance = crypto ? atr * 0.7 : atr * 0.5;
  const current   = data[data.length - 1];
  const nearPivot = Math.abs(current.close - last.price) < nearTolerance;
  if (!nearPivot) return { detected: false };
  return { detected: true, quality: pivots.length >= 3 ? 'high' : 'medium',
           direction: isUp ? 'long' : 'short', setupType: isUp ? 'higher_low' : 'lower_high' };
}

function calculateStructureConfluence(setup, structure) {
  let c = 1;
  if (structure.trend.includes('strong')) c++;
  if (setup.quality === 'high') c++; // 3+ pivots confirming structure
  c++; // near-pivot freshness already validated in detection
  return Math.min(c, 4);
}

// Market Analysis Engine (NO future data)
function analyzeMarketData(barIndex) {
  if (!curData || barIndex < 0 || barIndex >= curData.length) {
    return null;
  }

  const data = curData.slice(0, barIndex + 1); // Only current and past data

  const current = data[data.length - 1];
  const previous = data.length > 1 ? data[data.length - 2] : current;
  
  // Enhanced Technical Indicators (matching main AI analysis)
  const sma20 = calculateSMA(data, 20);
  const sma50 = calculateSMA(data, 50);
  const rsi = calcRSI(data);
  const atr = calcATR(data);
  const ema9 = calcEMA(data, 9);
  const ema21 = calcEMA(data, 21);
  const macd = calcMACD(data);
  
  // Trend Analysis
  const trend = analyzeTrend(data, sma20, sma50);
  
  // Support/Resistance Levels
  const levels = findKeyLevels(data);
  const nearestResistance = findNearestLevel(current.high, levels.resistance);
  const nearestSupport = findNearestLevel(current.low, levels.support);
  
  // Volume Analysis
  const avgVol20 = data.slice(-20).reduce((s, b) => s + b.volume, 0) / 20;
  const volumeStatus = current.volume > avgVol20 ? 'Above average (strong conviction)' : 'Below average (weak conviction)';
  const volumeAnalysis = {
    current: current.volume,
    average: avgVol20,
    status: volumeStatus
  };
  
  // Pattern Recognition
  const patterns = detectPatterns(data);
  
  // Market Structure
  const structure = analyzeMarketStructure(data);
  
  // Enhanced indicator analysis
  const lastRSI = rsi[rsi.length - 1];
  const lastMACD = macd[macd.length - 1];
  const lastEMA9 = ema9[ema9.length - 1];
  const lastEMA21 = ema21[ema21.length - 1];
  const lastATR = atr[atr.length - 1];
  
  const result = {
    trend,
    structure,
    current: {
      price: current.close,
      high: current.high,
      low: current.low,
      volume: current.volume,
      change: ((current.close - previous.close) / previous.close * 100).toFixed(2)
    },
    levels: {
      resistance: nearestResistance,
      support: nearestSupport
    },
    volume: volumeAnalysis,
    patterns,
    indicators: {
      sma20: sma20[sma20.length - 1],
      sma50: sma50[sma50.length - 1],
      rsi: lastRSI,
      atr: lastATR,
      ema9: lastEMA9,
      ema21: lastEMA21,
      macd: lastMACD
    },
    // Enhanced analysis data
    analysis: {
      shortTrend: current.close > sma20[sma20.length - 1] ? 'Bullish (price above SMA20)' : 'Bearish (price below SMA20)',
      htfTrend: current.close > sma50[sma50.length - 1] ? 'Bullish (price above SMA50)' : 'Bearish (price below SMA50)',
      rsiStatus: lastRSI > 70 ? 'Overbought' : lastRSI < 30 ? 'Oversold' : 'Neutral',
      macdStatus: `MACD: ${lastMACD?.macd?.toFixed(5) || 'N/A'} | Signal: ${lastMACD?.signal?.toFixed(5) || 'N/A'} | Histogram: ${lastMACD?.hist?.toFixed(5) || 'N/A'} (${lastMACD?.hist > 0 ? 'Bullish' : 'Bearish'} momentum)`,
      maStatus: `EMA9: ${lastEMA9?.toFixed(5) || 'N/A'} | EMA21: ${lastEMA21?.toFixed(5) || 'N/A'} | SMA50: ${sma50[sma50.length - 1]?.toFixed(5) || 'N/A'}`,
      recentAction: data.slice(-3).map(b => `${b.close > b.open ? 'Bullish' : 'Bearish'} candle (O:${fP(b.open)} H:${fP(b.high)} L:${fP(b.low)} C:${fP(b.close)})`).join(' -> ')
    }
  };
  
  return result;
}

// Helper Functions for Analysis
function calculateSMA(data, period) {
  const sma = [];
  for (let i = period - 1; i < data.length; i++) {
    const sum = data.slice(i - period + 1, i + 1).reduce((acc, bar) => acc + bar.close, 0);
    sma.push(sum / period);
  }
  return sma;
}

function analyzeTrend(data, sma20, sma50) {
  if (sma20.length < 2 || sma50.length < 2) return 'neutral';
  
  const currentSMA20 = sma20[sma20.length - 1];
  const currentSMA50 = sma50[sma50.length - 1];
  const prevSMA20 = sma20[sma20.length - 2];
  const prevSMA50 = sma50[sma50.length - 2];
  
  const price = data[data.length - 1].close;
  
  if (currentSMA20 > currentSMA50 && price > currentSMA20) {
    return currentSMA20 > prevSMA20 ? 'strong_uptrend' : 'uptrend';
  } else if (currentSMA20 < currentSMA50 && price < currentSMA20) {
    return currentSMA20 < prevSMA20 ? 'strong_downtrend' : 'downtrend';
  }
  
  return 'neutral';
}

function findKeyLevels(data) {
  const resistance = [];
  const support = [];
  const lookback = Math.min(20, data.length);
  
  for (let i = lookback; i < data.length - lookback; i++) {
    const bar = data[i];
    
    // Check if this is a resistance level
    let isResistance = true;
    for (let j = i - lookback; j < i; j++) {
      if (data[j].high >= bar.high) isResistance = false;
    }
    for (let j = i + 1; j <= i + lookback; j++) {
      if (data[j].high >= bar.high) isResistance = false;
    }
    if (isResistance) resistance.push(bar.high);
    
    // Check if this is a support level
    let isSupport = true;
    for (let j = i - lookback; j < i; j++) {
      if (data[j].low <= bar.low) isSupport = false;
    }
    for (let j = i + 1; j <= i + lookback; j++) {
      if (data[j].low <= bar.low) isSupport = false;
    }
    if (isSupport) support.push(bar.low);
  }
  
  return { resistance, support };
}

function findNearestLevel(price, levels) {
  if (!levels.length) return null;
  return levels.reduce((nearest, level) => {
    const currentDistance = Math.abs(price - level);
    const nearestDistance = Math.abs(price - nearest);
    return currentDistance < nearestDistance ? level : nearest;
  }, levels[0]);
}

function analyzeVolume(data) {
  if (data.length < 2) return 'normal';
  
  const current = data[data.length - 1].volume;
  const avgVolume = data.slice(-20).reduce((sum, bar) => sum + bar.volume, 0) / Math.min(20, data.length);
  
  if (current > avgVolume * 2) return 'very_high';
  if (current > avgVolume * 1.5) return 'high';
  if (current < avgVolume * 0.5) return 'low';
  return 'normal';
}

function analyzeMarketStructure(data) {
  if (data.length < 10) return { trend: 'neutral' };
  
  const recentHighs = data.slice(-10).map(bar => bar.high);
  const recentLows = data.slice(-10).map(bar => bar.low);
  
  const higherHighs = recentHighs.filter((high, i) => i > 0 && high > recentHighs[i - 1]).length;
  const higherLows = recentLows.filter((low, i) => i > 0 && low > recentLows[i - 1]).length;
  
  let trend = 'neutral';
  if (higherHighs >= 3 && higherLows >= 2) trend = 'uptrend_structure';
  else if (higherHighs <= 1 && higherLows <= 1) trend = 'downtrend_structure';
  else trend = 'range_structure';
  
  console.log('🔍 Market structure analysis:', { trend, higherHighs, higherLows });
  
  return { trend };
}

