// Popup functions
function showMentorPopup() {
  const popup = document.getElementById('mentor-popup');
  if (popup) {
    if (!localStorage.getItem('mentor-popup-seen')) {
      popup.style.display = 'block';
    } else {
      // Skip popup for returning users — go straight to enabling
      enableMentorFromPopup();
      return;
    }
    popup.style.opacity = '0';
    popup.style.transform = 'translate(-50%, -50%) scale(0.9)';
    
    // Fade in animation
    setTimeout(() => {
      popup.style.transition = 'all 0.3s ease';
      popup.style.opacity = '1';
      popup.style.transform = 'translate(-50%, -50%) scale(1)';
    }, 50);
    
    // Auto-hide after 8 seconds if no action
    setTimeout(() => {
      if (popup.style.display === 'block') {
        closeMentorPopup();
      }
    }, 8000);
  }
}

function closeMentorPopup() {
  const popup = document.getElementById('mentor-popup');
  if (popup) {
    popup.style.transition = 'all 0.2s ease';
    popup.style.opacity = '0';
    popup.style.transform = 'translate(-50%, -50%) scale(0.95)';
    setTimeout(() => {
      popup.style.display = 'none';
      // Reset to base state so next open animates correctly
      popup.style.transition = '';
      popup.style.opacity = '1';
      popup.style.transform = 'translate(-50%, -50%) scale(1)';
    }, 200);
  }
}

function enableMentorFromPopup() {
  closeMentorPopup();
  localStorage.setItem('mentor-popup-seen', '1');
  // Defer activation until after the popup close animation (200ms) has fully completed.
  // Without this delay, Vercel's CDN-served JS can race the setTimeout inside
  // closeMentorPopup and the panel.style.display = 'none' fires AFTER we show the panel.
  setTimeout(() => {
    mentorState.enabled = true;
    mentorState.currentBar = -1; // Reset to force re-analysis
    mentorState.lastTradeSuggestionBar = -1000; // Reset cooldown
    setMentorState('method_selection', 'mentor enabled'); // Start with method selection
    mentorState.setupWaitStart = null;
    mentorState.setupWaitData = null;
    mentorState.monitoredTrade = null;
    mentorState.exampleTrade = null;
    mentorState.exampleTradeActive = false;
    mentorState.exampleTradeOutcome = null;
    mentorState.tradeMonitoringUpdates = [];
    mentorState.tradeResultData = null;
    mentorState.selectedTradingMethod = null;
    mentorState.tradingMethodSelected = false;
    mentorState.currentInsights = ['🤖 AI Trading Mentor is now active'];
    mentorState.currentQuestion = 'Please select your preferred trading style to begin...';

    const panel = document.getElementById('ai-mentor-panel');
    if (panel) {
      panel.style.display = 'block';
      // Always reset to a visible position so the panel is never off-screen
      panel.style.left = '80px';
      panel.style.top  = '60px';
      panel.style.right  = 'auto';
      panel.style.bottom = 'auto';
    }

    // Show trading method selection
    const methodSelection = document.getElementById('trading-method-selection');
    if (methodSelection) {
      methodSelection.style.display = 'block';
    }

    updateMentorUI();
  }, 250);
}

function selectTradingMethod(method) {
  if (mentorState.exampleTradeActive) {
    showToast('Strategy locked — finish this lesson first, then change strategy.', 'info');
    return;
  }
  mentorState.selectedTradingMethod = method;
  mentorState.tradingMethodSelected = true;
  setMentorState('scanning', 'strategy selected');

  // Test annotation: place a visible marker at the current bar so user knows
  // the annotation system is working. Clears when setup is found.
  if (replayMode && curData && replayCutoff > 0) {
    const bar   = replayCutoff;
    const price = curData[bar]?.close;
    if (price) {
      _clearMentorAnnotationsSilent();
      _addMentorArrow(bar, price, `🎯 ${method} strategy active`, 'down', false);
      _addMentorLabel(bar, price, [`Strategy: ${method}`, 'Scanning for setups...']);
      if (typeof draw === 'function') draw();
    }
  }

  // Hide method selection panel
  const methodSelection = document.getElementById('trading-method-selection');
  if (methodSelection) {
    methodSelection.style.display = 'none';
  }

  // Update welcome message based on selected method
  const methodNames = {
    'breakout': 'Breakout Trading',
    'trend': 'Trend Following',
    'support_resistance': 'Support & Resistance',
    'pullback': 'Pullback Trading',
    'range': 'Range Trading',
    'liquidity': 'Liquidity Sweep'
  };

  mentorState.currentInsights = [`📚 Now teaching: ${methodNames[method]}`];
  mentorState.currentQuestion = 'Analyzing market data for ' + methodNames[method].toLowerCase() + ' opportunities...';

  // Always trigger a fresh scan in replay mode — previously this was gated on
  // lifecycleState being 'no_setup_found' or 'waiting', but by this point it had
  // already been set to 'scanning', so the condition was always false and neither
  // triggerReplayRescan() nor updateMentor() ever ran on first click.
  if (replayMode) {
    triggerReplayRescan();
  } else {
    updateMentorUI();
  }

  toast(`📚 Teaching ${methodNames[method]} strategy`);
}

