// Integration with Replay System
function integrateMentorWithReplay() {
  // Show mentor when replay starts
  const originalStartReplay = startReplay;
  startReplay = function() {
    originalStartReplay();
    
    // Show popup notification when replay starts
    setTimeout(() => {
      showMentorPopup();
    }, 1000); // Show after 1 second to let replay initialize
    
    if (mentorState.enabled) {
      document.getElementById('ai-mentor-panel').style.display = 'block';
    }
  };
  
  // Hide mentor when replay ends
  const originalStopReplay = stopReplay;
  stopReplay = function() {
    originalStopReplay();
    // Only hide mentor panel if we're fully exiting replay (not symbol change)
    // replayMode will have been set to false by originalStopReplay if truly exiting
    if (!replayMode) {
      closeMentorPopup();
      const panel = document.getElementById('ai-mentor-panel');
      if (panel) panel.style.display = 'none';
    }
  };
  
  // replayStep already calls updateMentor via its bar-based throttle.
  // No monkey-patch needed — avoids double-firing and setTimeout accumulation.
}

// Initialize mentor integration and draggable functionality
function initializeMentor() {
  integrateMentorWithReplay();
  makeMentorDraggable();
}

// Initialize mentor when page loads.
// Use requestIdleCallback if available (fires when browser is idle, not just after 1s),
// falling back to 1000ms timeout. Either way, initializeMentor is safe to call multiple
// times since integrateMentorWithReplay guards against double monkey-patching.
if (typeof requestIdleCallback !== 'undefined') {
  requestIdleCallback(() => initializeMentor(), { timeout: 2000 });
} else {
  setTimeout(initializeMentor, 1000);
}

// Make mentor functions globally accessible
window.toggleMentor = toggleMentor;
window.mentorDecision = mentorDecision;
window.mentorHint = mentorHint;
window.updateMentor = updateMentor;
window.showMentorPopup = showMentorPopup;
window.closeMentorPopup = closeMentorPopup;
window.enableMentorFromPopup = enableMentorFromPopup;

// ══ AI TRADE FINDER (embedded in mentor panel) ══════════════════════════════
// The finder lives inside the mentor panel — toggled with the 🔍 Find button.
// Scans the whole chart, lists setups as cards, and launches replay to each one.

let _mfSetups    = [];    // last scan results
let _mfScanKey   = null;  // sym+method+length key so we know when to re-scan
let _mfViewOpen  = false; // whether finder view is showing

function toggleMentorFinder() {
  _mfViewOpen = !_mfViewOpen;
  const view = document.getElementById('mentor-finder-view');
  const btn  = document.getElementById('mentor-finder-toggle');
  if (!view) return;
  view.style.display = _mfViewOpen ? 'flex' : 'none';
  if (btn) {
    btn.style.background   = _mfViewOpen ? 'rgba(61,127,255,.35)' : 'rgba(61,127,255,.15)';
    btn.style.borderColor  = _mfViewOpen ? 'rgba(61,127,255,.8)'  : 'rgba(61,127,255,.4)';
  }
  // Pre-select current strategy in the finder dropdown
  if (_mfViewOpen) {
    const sel = document.getElementById('mf-method-select');
    if (sel && mentorState.selectedTradingMethod) sel.value = mentorState.selectedTradingMethod;
  }
}

function runMentorFinderScan() {
  const methodSel = document.getElementById('mf-method-select');
  const method    = methodSel ? methodSel.value : (mentorState.selectedTradingMethod || '');

  if (!curData || curData.length < 50) {
    _mfRenderResults([], method);
    return;
  }

  const key = (curSym?.s||'') + '_' + method + '_' + curData.length;
  if (key === _mfScanKey && _mfSetups.length > 0) {
    _mfRenderResults(_mfSetups, method);
    return;
  }
  _mfScanKey = key;
  _mfSetups  = [];
  // Clear setup cache — stale cached results from a different method would cause
  // "no setups found" since the cache key includes the old method name.
  if (mentorState.setupCache) mentorState.setupCache.clear();

  // Show progress
  const idle     = document.getElementById('mf-idle');
  const list     = document.getElementById('mf-list');
  const empty    = document.getElementById('mf-empty');
  const progWrap = document.getElementById('mf-progress-wrap');
  const progBar  = document.getElementById('mf-progress-bar');
  const progTxt  = document.getElementById('mf-progress-txt');
  const subtitle = document.getElementById('mf-subtitle');
  const scanBtn  = document.getElementById('mf-scan-btn');

  if (idle)     idle.style.display    = 'none';
  if (list)     list.style.display    = 'none';
  if (empty)    empty.style.display   = 'none';
  if (progWrap) progWrap.style.display = 'block';
  if (scanBtn)  { scanBtn.disabled = true; scanBtn.textContent = 'Scanning...'; }

  const total  = curData.length;
  const step   = 4;    // check every 4th bar (was 3 — reduces noise)
  const minGap = 40;   // minimum 40 bars between reported setups (was 20 — prevents clusters)
  let   i      = 50;
  let   lastFoundBar = -999;

  function barLabel(idx) {
    if (!curData[idx]) return 'Bar ' + idx;
    const d = new Date(curData[idx].time * 1000);
    const intra = ['1m','5m','15m','30m','1h','4h'].includes(curTF);
    return intra
      ? d.toLocaleDateString([],{month:'short',day:'numeric'}) + ' ' +
        d.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit',hour12:false})
      : d.toLocaleDateString([],{month:'short',day:'numeric',year:'2-digit'});
  }

  function chunk() {
    const end = Math.min(i + 100, total);
    for (; i < end; i += step) {
      try {
        // Pass method directly as override — avoids global state mutation and
        // cache-key corruption that caused the "no setups found" bug.
        const scanMethod = method || mentorState.selectedTradingMethod || 'breakout';
        const sd = detectStructuredSetups(curData.slice(0, i + 1), i, scanMethod);

        // Only surface HIGH-quality setups — confluence >= 3 means at least 3 of 4
        // methodology criteria are met. This prevents the scanner from finding a trade
        // every few bars and only shows genuinely valid setups.
        if (sd.setup === 'none' || sd.confluence < 3) continue;
        if (sd.quality === 'low') continue; // reject low-quality even if confluence passes
        if (i - lastFoundBar < minGap) continue;

        const futureC = curData.slice(i + 1, Math.min(i + 51, curData.length));
        if (futureC.length < 5) continue;

        const entryPrice = curData[i].close;
        const dir   = sd.direction || 'long';

        // Use entryBar (next bar open) for level computation, same as the live mentor
        const entryBar = Math.min(i + 1, curData.length - 1);
        const futureFromEntry = curData.slice(entryBar + 1, Math.min(entryBar + 51, curData.length));
        if (futureFromEntry.length < 5) continue;
        const entryPriceActual = curData[entryBar].open;
        const levels = computeMentorTradeLevels(dir, entryPriceActual, entryBar, futureFromEntry);
        if (!levels) continue;

        lastFoundBar = i;
        _mfSetups.push({ bar: i, setup: sd.setup, direction: dir,
          quality: sd.quality, confluence: sd.confluence,
          label: barLabel(i), levels, price: entryPriceActual });
      } catch(e) {}
    }

    const pct = Math.round(i / total * 100);
    if (progBar) progBar.style.width = pct + '%';
    if (progTxt) progTxt.textContent = 'Scanning bar ' + Math.min(i, total) + ' / ' + total + ' — ' + _mfSetups.length + ' found so far';
    if (subtitle) subtitle.textContent = 'Scanning... ' + pct + '%';

    if (i < total) {
      setTimeout(chunk, 0);
    } else {
      if (progWrap) progWrap.style.display = 'none';
      if (scanBtn)  { scanBtn.disabled = false; scanBtn.textContent = 'Scan Chart'; }
      _mfRenderResults(_mfSetups, method);
    }
  }
  setTimeout(chunk, 0);
}

function _mfRenderResults(setups, method) {
  const idle    = document.getElementById('mf-idle');
  const list    = document.getElementById('mf-list');
  const empty   = document.getElementById('mf-empty');
  const count   = document.getElementById('mf-count');
  const subtitle = document.getElementById('mf-subtitle');

  if (idle) idle.style.display = 'none';

  if (!setups || setups.length === 0) {
    if (empty)   empty.style.display = 'block';
    if (list)    list.style.display  = 'none';
    if (count)   count.textContent   = 'No setups found';
    if (subtitle) subtitle.textContent = 'No setups found';
    return;
  }

  if (empty)   empty.style.display   = 'none';
  if (list)    list.style.display    = 'block';
  if (count)   count.textContent     = setups.length + ' setup' + (setups.length === 1 ? '' : 's') + ' found';
  if (subtitle) subtitle.textContent = setups.length + ' valid trade' + (setups.length === 1 ? '' : 's') + ' detected';

  const labels = {
    breakout:'Breakout', range_breakout:'Range Breakout', flag_continuation:'Flag',
    structure_continuation:'Structure', support_bounce:'Support Bounce',
    resistance_rejection:'Resistance Rej.', trend_pullback:'Pullback',
    liquidity_sweep:'Liq. Sweep',
  };

  list.innerHTML = setups.map((s, idx) => {
    const dirIcon = s.direction === 'long' ? '📈' : '📉';
    const dirCol  = s.direction === 'long' ? 'var(--tl)' : 'var(--rd)';
    const qCol    = s.quality === 'high' ? 'var(--tl)' : s.quality === 'medium' ? 'var(--am)' : 'var(--tx3)';
    const stars   = '★'.repeat(s.confluence) + '☆'.repeat(Math.max(0, 4 - s.confluence));
    const lbl     = labels[s.setup] || s.setup.replace(/_/g,' ');
    const rrTxt   = s.levels ? 'R:R ~' + s.levels.rr.toFixed(1) : '';
    const price   = s.price ? ' @ ' + s.price.toFixed(s.price < 10 ? 4 : 2) : '';

    return `<div style="background:var(--bg3);border:1px solid var(--b1);border-radius:6px;padding:9px 10px;margin-bottom:6px;cursor:pointer;transition:all 0.15s;"
      onmouseover="this.style.borderColor='rgba(138,43,226,.7)';this.style.background='var(--bg1)'"
      onmouseout="this.style.borderColor='var(--b1)';this.style.background='var(--bg3)'"
      onclick="_mfLaunch(${idx})">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:4px;">
        <div style="display:flex;align-items:center;gap:6px;">
          <span style="font-size:14px;">${dirIcon}</span>
          <span style="color:${dirCol};font-weight:700;font-size:11px;">${s.direction.toUpperCase()}</span>
          <span style="color:var(--tx1);font-size:11px;font-weight:600;">${lbl}</span>
        </div>
        <span style="color:var(--tx3);font-size:10px;font-family:monospace;">${s.label}</span>
      </div>
      <div style="display:flex;align-items:center;gap:10px;font-size:10px;">
        <span style="color:${qCol};">${(s.quality||'').toUpperCase()}</span>
        <span style="color:var(--am);letter-spacing:1px;">${stars}</span>
        <span style="color:var(--tx3);">${rrTxt}</span>
        <span style="color:var(--tx3);">${price}</span>
        <span style="margin-left:auto;color:var(--purple);font-weight:700;">▶ Go</span>
      </div>
    </div>`;
  }).join('');
}

// Launch replay to a found setup — scroll chart, set method, start replay 25 bars before.
function _mfLaunch(idx) {
  const setup = _mfSetups[idx];
  if (!setup || !curData) return;

  toggleMentorFinder();

  // Start replay 30 bars before the setup bar — enough context to read the
  // chart and understand why the setup is forming, and to see the question
  // appear naturally as the candles approach.
  const PRE_BARS = 40;
  const startBar = Math.max(1, setup.bar - PRE_BARS);

  if (replayMode) stopReplay();

  // Map setup type → trading method
  const methodMap = {
    breakout:'breakout', range_breakout:'breakout',
    flag_continuation:'trend', structure_continuation:'trend',
    support_bounce:'support_resistance', resistance_rejection:'support_resistance',
    trend_pullback:'pullback',
    liquidity_sweep:'liquidity',
  };
  const m = methodMap[setup.setup] || mentorState.selectedTradingMethod || 'breakout';
  mentorState.selectedTradingMethod = m;
  mentorState.tradingMethodSelected = true;
  const sel1 = document.getElementById('trading-method-select');
  if (sel1) sel1.value = m;

  // ── Reset mentor state completely ─────────────────────────────────────────
  mentorState.enabled                = true;
  mentorState.currentBar             = -1;
  mentorState.lastTradeSuggestionBar = -1000;
  mentorState.setupWaitStart         = null;
  mentorState.setupWaitData          = null;
  mentorState.exampleTrade           = null;
  mentorState.exampleTradeActive     = false;
  mentorState.messageLocked          = false;
  mentorState.lockedMessage          = null;
  mentorState.lockedInsights         = [];
  mentorState.lockedQuestion         = '';
  mentorState.realtimeUpdates        = [];
  mentorState.pendingSetupDetection  = null;
  mentorState.pendingSetupBar        = null;
  mentorState.earlyWarningShown      = false;
  mentorState.resultExplained        = false;
  if (mentorState.setupCache) mentorState.setupCache.clear();

  // ── Pre-inject the known setup as upcomingSetup so the mentor skips ────────
  // scanning entirely. When replayCutoff reaches within 15 bars of setup.bar,
  // handleSetupDetectedState fires the early question automatically.
  // Build a minimal setup detection object from what the scanner found.
  // Do NOT pre-cache levels from the scanner — they may have been computed with
  // old logic. handleSetupDetectedState will always recompute fresh at question time.
  const injectedSetup = {
    setup:     setup.setup,
    direction: setup.direction,
    quality:   setup.quality,
    confluence: setup.confluence,
    _entryBar: Math.min(setup.bar + 1, curData.length - 1),
  };

  setMentorState('setup_detected', 'finder launched preview');
  mentorState.upcomingSetup  = {
    setup:      injectedSetup,
    bar:        setup.bar,
    windowSize: PRE_BARS,
  };

  // Brief scanning message while user reads the chart context
  const setupLabel = setup.setup.replace(/_/g, ' ');
  const dirEmoji   = setup.direction === 'long' ? '📈' : '📉';
  mentorState.currentInsights = [
    `${dirEmoji} Navigating to a ${setupLabel} setup`,
    `Watch the price action develop — the mentor will pause and ask you what to do as the setup approaches.`,
  ];
  mentorState.currentQuestion = 'Use this time to study the chart structure leading up to the setup.';

  // Show mentor panel
  const mentorPanel = document.getElementById('ai-mentor-panel');
  if (mentorPanel) mentorPanel.style.display = 'block';
  const methodSel = document.getElementById('trading-method-selection');
  if (methodSel) methodSel.style.display = 'none';

  // Position chart so startBar is on the left and setup.bar is visible.
  // Don't call _replayScrollToBar — it uses barWidth which may not be ready yet.
  // Instead set rightBarIndex so startBar lands at ~20% from the left edge.
  // We use a generous estimate of ~80 visible bars; actual barWidth is set on first draw.
  const estVisibleBars = 80;
  rightBarIndex = Math.min(curData.length - 1 + 10, startBar + estVisibleBars);
  mentorState._freezeScrollForPreview = false; // not frozen yet — will freeze at pause

  // Start replay at startBar (no picking phase needed)
  replayMode        = true;
  replayPicking     = false;
  replayCutoff      = startBar;
  replayJustStarted = true;
  // Reset mentor throttle counters so the very first bar gets a full scan
  mentorState._lastMentorUpdateBar = -99;
  mentorState._lastAnnStateKey = null; mentorState._annCache = null;
  if (typeof _scanCache !== 'undefined')
    _scanCache = { bar: -1, result: null, method: null };
  setTimeout(() => { replayJustStarted = false; }, 500);

  const rbtn = document.getElementById('btn-replay');
  if (rbtn) rbtn.classList.add('on');
  _syncAllDockedBtns && _syncAllDockedBtns();
  updateReplayStatus();
  draw();

  // Give the DOM a tick then sync the mentor UI
  setTimeout(() => {
    _buildSetupDetectedMessage(replayCutoff);
    updateMentorUI();
  }, 150);

  toast('▶ Replay started — play the candles and watch for the setup');
}

