// ══ NEWS PANEL ════════════════════════════════════════════════════════════════
// ══ NEWS PANEL ════════════════════════════════════════════════════════════════
let newsCache = {};

// ── Groq key rotation ─────────────────────────────────────────────────────────
// ── AI provider keys ─────────────────────────────────────────────────────────
// Order: all Groq keys first (fastest), then Gemini Flash as fallback.
// Add more Groq keys by creating additional free accounts at console.groq.com.
// Get a Gemini key free at aistudio.google.com (15 RPM, 1M tokens/day).
function getLocalApiBase(){
  try{
    const { protocol, hostname, port } = window.location;
    if((hostname === 'localhost' || hostname === '127.0.0.1') && port && port !== '3001'){
      return `${protocol}//${hostname}:3001`;
    }
  }catch(e){}
  return '';
}
async function aiComplete(prompt, {
  model = 'llama-3.1-8b-instant',
  max_tokens = 1000,
  temperature = 0,
  timeoutMs = 30000,
} = {}){
  let res;
  const apiBase = getLocalApiBase();
  try {
    res = await fetch(`${apiBase}/api/ai`, {
      method: 'POST',
      signal: AbortSignal.timeout(timeoutMs),
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ prompt, model, max_tokens, temperature, timeoutMs })
    });
  } catch(networkErr) {
    res = null;
  }

  if (!res) {
    throw new Error('AI service unavailable. Please check your connection and try again.');
  }

  let data = null;
  try {
    data = await res.json();
  } catch(parseErr) {
    let rawText = '';
    try { rawText = await res.text(); } catch(e) {}
    const snippet = rawText.replace(/\s+/g, ' ').trim().slice(0, 180);
    if (res.status === 404) {
      throw new Error(`AI HTTP 404 from ${apiBase || window.location.origin}/api/ai${snippet ? ` — ${snippet}` : ''}`);
    }
    if (res.status === 401 || res.status === 403) {
      throw new Error(`AI HTTP ${res.status}${snippet ? ` — ${snippet}` : ''}`);
    }
    throw new Error(`AI HTTP ${res.status} - invalid response${snippet ? ` — ${snippet}` : ''}`);
  }

  if(!res.ok){
    const msg = data?.error || `HTTP ${res.status}`;
    const err = new Error(`AI: ${msg}`);
    if(res.status === 429){
      const rl = res.headers?.get?.('x-ratelimit-reset-requests') || res.headers?.get?.('retry-after');
      if(rl) err._rateLimitResetMs = _tapParseResetHeader(rl);
      err._is429 = true;
    }
    throw err;
  }

  const text = data?.text?.trim() || data?.choices?.[0]?.message?.content?.trim() || '';
  if(!text) throw new Error('AI returned empty response');
  return text;
}

// Parse Groq/Vercel rate-limit reset header ("1s", "1m30s", or numeric seconds)
function _tapParseResetHeader(val){
  if(!val) return 2000;
  const n = parseFloat(val);
  if(!isNaN(n)) return Math.ceil(n * 1000);
  let ms = 0;
  const m = val.match(/(\d+)m/); if(m) ms += parseInt(m[1]) * 60000;
  const s = val.match(/(\d+)s/); if(s) ms += parseInt(s[1]) * 1000;
  return ms || 2000;
}

async function groqFetch(prompt, options = {}){
  return await aiComplete(prompt, {
    model: options.model || 'llama-3.1-8b-instant',
    max_tokens: options.max_tokens ?? 1000,
    temperature: options.temperature ?? 0,
    timeoutMs: options.timeoutMs ?? 30000,
  });
}
function buildInfo(){
  if(!curData.length) return;
  const last=curData[curData.length-1], prev=curData[curData.length-2]||last;
  const pct=((last.close-prev.close)/prev.close*100).toFixed(2);
  // Use current bar's high/low (matches the topbar OHLC readout)
  const hi=fP(last.high);
  const lo=fP(last.low);
  const avgVol=fV(Math.round(curData.slice(-20).reduce((s,d)=>s+d.volume,0)/20));
  document.getElementById('rp-stats').innerHTML=`
    <div class="cell"><div class="clbl">LAST</div><div class="cval">${fP(last.close)}</div></div>
    <div class="cell"><div class="clbl">CHG%</div><div class="cval ${pct>=0?'up':'dn'}">${pct>=0?'+':''}${pct}%</div></div>
    <div class="cell"><div class="clbl">HIGH</div><div class="cval up">${hi}</div></div>
    <div class="cell"><div class="clbl">LOW</div><div class="cval dn">${lo}</div></div>
    <div class="cell"><div class="clbl">AVG VOL</div><div class="cval">${avgVol}</div></div>
    <div class="cell"><div class="clbl">TYPE</div><div class="cval">${curSym.t}</div></div>`;
  fetchNews(curSym.s, curSym.n || curSym.s);
}

function timeAgo(dateStr){
  if(!dateStr) return '';
  const diff = (Date.now() - new Date(dateStr).getTime()) / 1000;
  if(isNaN(diff)||diff<0) return '';
  if(diff < 3600) return `${Math.round(diff/60)}m ago`;
  if(diff < 86400) return `${Math.round(diff/3600)}h ago`;
  return `${Math.round(diff/86400)}d ago`;
}

// Map symbol to best RSS search query
function symToRSSQuery(sym){
  const map = {
    'BTC/USD':'Bitcoin','ETH/USD':'Ethereum','XRP/USD':'XRP',
    'EUR/USD':'EUR/USD','GBP/USD':'GBP/USD',
    'USD/JPY':'USD/JPY','AUD/USD':'AUD/USD',
    'XAU/USD':'Gold price','XAG/USD':'Silver price',
    'OIL':'Crude Oil','NDX':'Nasdaq 100','SPX':'S&P 500',
    'DJI':'Dow Jones','VIX':'VIX volatility index',
  };
  return map[sym] || sym.replace(/\.(NYSE|NASDAQ|LSE)$/i,'');
}

function symType(sym){
  if(curSym && curSym.s === sym) return curSym.t;
  const s = SYMS.find(x=>x.s===sym);
  return s ? s.t : 'Stock';
}

function parseRSSXML(xmlText){
  try {
    const doc = new DOMParser().parseFromString(xmlText, 'text/xml');
    if(doc.querySelector('parsererror')) return [];
    return [...doc.querySelectorAll('item')].map(item => {
      const g = tag => item.querySelector(tag)?.textContent?.trim()||'';
      const pairEl = item.getElementsByTagNameNS('*','pair')[0];
      return { title:g('title'), link:g('link')||g('guid'), date:g('pubDate'), pair:(pairEl?.textContent||'').trim().toUpperCase(), desc:g('description') };
    }).filter(i=>i.title);
  } catch(e){ return []; }
}

// Fetch news via our secure /api/news Vercel serverless function
async function fetchNewsFromAPI(sym, type) {
  const url = `/api/news?sym=${encodeURIComponent(sym)}&type=${encodeURIComponent(type)}`;
  try {
    const r = await fetch(url, { signal: AbortSignal.timeout(10000) });
    if (!r.ok) return null;
    const data = await r.json();
    if (!Array.isArray(data) || !data.length) return null;
    // Normalise to the shape renderNews expects
    return data.map(i => ({
      title:   i.title   || i.headline || '',
      link:    i.link    || i.url      || '',
      date:    i.date    || '',
      source:  i.source  || 'Finnhub',
      summary: i.summary || '',
    })).filter(i => i.title);
  } catch(e) { return null; }
}

function scoreWithGroq(headlines, sym, name){
  // Client-side keyword sentiment scoring — no API call.
  // Covers the vast majority of financial headline sentiment accurately.
  const BULLISH_RE = /\b(surge|surged|surging|rally|rallied|rallying|soar|soared|soaring|beat|beats|beats? expectations?|gain|gained|gaining|gains|rise|risen|rising|rose|high|higher|record|upgrade|upgraded|outperform|strong|stronger|strength|bull|bullish|growth|grew|grow|profit|profits|revenue|revenues|beat estimates|above estimates|above expectations|positive|boost|boosted|buy|buyback|dividend|approval|approved|launch|launched|partnership|deal|expansion|expansion|recovery|recover|recovered|rebound|rebounded|momentum|breakout|breakthrough|contract|contracts|win|wins|winning|award|awarded|milestone)\b/i;
  const BEARISH_RE = /\b(crash|crashed|crashing|drop|dropped|dropping|fall|fell|falling|decline|declined|declining|plunge|plunged|plunging|miss|missed|misses|below estimates|below expectations|loss|losses|losing|warn|warning|warned|downgrade|downgraded|underperform|weak|weaker|weakness|bear|bearish|cut|cuts|layoff|layoffs|fired|bankrupt|bankruptcy|debt|default|recall|investigation|probe|fine|fined|penalty|lawsuit|sue|sued|fraud|scandal|concern|concerns|risk|risks|sell|selloff|sell-off|pressure|pressured|headwind|headwinds|deficit|downside|disappoints|disappointed|disappointing|halt|halted|suspended|suspension|violation|regulatory|charges|charged|cost|costs|missed estimates)\b/i;

  return Promise.resolve(headlines.map(h => {
    const text = `${h.title} ${h.summary || ''}`;
    const bullScore = (text.match(BULLISH_RE) || []).length;
    const bearScore = (text.match(BEARISH_RE) || []).length;
    const sentiment = bullScore > bearScore ? 'BULLISH' : bearScore > bullScore ? 'BEARISH' : 'NEUTRAL';
    return { ...h, sentiment };
  }));
}

async function fetchNews(sym, name){
  const el = document.getElementById('rp-news');
  if(!el) return;
  // 5-minute cache
  if(newsCache[sym] && Date.now()-newsCache[sym].ts < 300000){
    renderNews(newsCache[sym].items, sym); return;
  }
  el.innerHTML='<div style="padding:16px 8px;font-size:10px;color:var(--tx3);text-align:center;">⟳ Fetching latest news...</div>';

  const type = symType(sym);
  const headlines = await fetchNewsFromAPI(sym, type);

  if(!headlines || !headlines.length){
    el.innerHTML=`<div style="padding:16px 10px;font-size:10px;color:var(--tx3);text-align:center;line-height:1.7;">
      <div style="font-size:18px;margin-bottom:6px;">📡</div>
      <div style="color:var(--tx2);">No news found for ${sym}</div>
      <div style="font-size:11px;margin-top:4px;color:var(--tx3);">News is temporarily unavailable — check back shortly</div>
      <div style="margin-top:8px;"><button onclick="delete newsCache[curSym.s]; buildInfo();" style="background:var(--bg3);border:1px solid var(--b2);color:var(--tx2);font-size:11px;padding:3px 10px;border-radius:3px;cursor:pointer;">↻ Retry</button></div>
    </div>`;
    return;
  }

  // Score sentiment immediately with client-side keyword matching (no API call),
  // then render once with real sentiments already applied.
  try {
    const scored = await scoreWithGroq(headlines, sym, name || sym);
    newsCache[sym] = {ts: Date.now(), items: scored};
    if(curSym.s === sym) renderNews(scored, sym);
  } catch(e){
    // Fallback to neutral if scoring somehow fails
    const provisional = headlines.map(h => ({...h, sentiment:'NEUTRAL'}));
    newsCache[sym] = {ts: Date.now(), items: provisional};
    renderNews(provisional, sym);
  }
}

function renderNews(items, sym){
  const el = document.getElementById('rp-news');
  if(!items?.length){ el.innerHTML='<div style="padding:12px 8px;font-size:10px;color:var(--tx3);">No news found.</div>'; return; }

  const colMap = {BULLISH:'#00c9a0', BEARISH:'#f03060', NEUTRAL:'#778899'};
  const iconMap = {BULLISH:'▲', BEARISH:'▼', NEUTRAL:'—'};
  const bullCount = items.filter(i=>i.sentiment==='BULLISH').length;
  const bearCount = items.filter(i=>i.sentiment==='BEARISH').length;
  const allNeutral = bullCount===0 && bearCount===0;
  const overallCol = allNeutral ? '#778899' : bullCount>bearCount ? '#00c9a0' : bearCount>bullCount ? '#f03060' : '#f0a500';
  const overallLabel = allNeutral ? 'FETCHING SENTIMENT…' : bullCount>bearCount ? 'BULLISH' : bearCount>bullCount ? 'BEARISH' : 'MIXED';
  const cached = newsCache[sym];
  const fetchedAt = cached ? new Date(cached.ts).toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'}) : '';

  let html = '<div style="margin:4px 6px 6px;padding:7px 10px;background:var(--bg3);border-radius:4px;border-left:3px solid '+overallCol+';font-size:10px;">'
    + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:2px;">'
    + '<div style="font-weight:700;color:'+overallCol+';">'+overallLabel+'</div>'
    + '<button onclick="delete newsCache[\''+sym+'\'];buildInfo();" title="Refresh" style="background:none;border:none;color:var(--tx3);cursor:pointer;font-size:13px;padding:0;line-height:1;">↻</button>'
    + '</div>'
    + '<div style="color:var(--tx3);">'+items.length+' articles'+(allNeutral ? '' : ' · '+bullCount+'▲ '+bearCount+'▼')+'</div>'
    + (fetchedAt ? '<div style="color:var(--tx3);font-size:11px;margin-top:2px;">Updated '+fetchedAt+'</div>' : '')
    + '</div>';

  items.forEach(item => {
    const col = colMap[item.sentiment] || colMap.NEUTRAL;
    const icon = iconMap[item.sentiment] || '—';
    const ago = timeAgo(item.date);
    const title = (item.title||'').replace(/</g,'&lt;').replace(/>/g,'&gt;');
    const isLink = !!item.link;
    html += isLink ? '<a href="'+item.link+'" target="_blank" rel="noopener" style="text-decoration:none;">' : '<div>';
    html += '<div class="ni" style="border-left:2px solid '+col+'55;padding-left:6px;margin:0 4px;padding-top:5px;padding-bottom:5px;transition:background .15s;" onmouseover="this.style.background=\'var(--bg3)\'" onmouseout="this.style.background=\'\'">'
      + '<div style="display:flex;align-items:flex-start;gap:5px;">'
      + '<span style="color:'+col+';font-size:10px;font-weight:700;margin-top:1px;flex-shrink:0;">'+icon+'</span>'
      + '<div class="nh" style="color:var(--tx);line-height:1.4;">'+title+'</div>'
      + '</div>'
      + '<div class="nm" style="margin-top:3px;display:flex;gap:8px;flex-wrap:wrap;">'
      + (item.sentiment!=='NEUTRAL' ? '<span style="color:'+col+';font-weight:700;font-size:11px;letter-spacing:.3px;">'+item.sentiment+'</span>' : '')
      + '<span style="color:var(--tx3);font-size:11px;">'+(item.source||'')+'</span>'
      + (ago ? '<span style="color:var(--tx3);font-size:11px;">'+ago+'</span>' : '')
      + '</div></div>';
    html += isLink ? '</a>' : '</div>';
  });

  el.innerHTML = html;
}



// ══ CANVAS CHART ══════════════════════════════════════════════════════════════
function sizeCanvases(){
  const area=_el('chart-area');
  const W=area.clientWidth, totalH=area.clientHeight;
  const volH=showVol?68:0, rsiH=showRSI?74:0;
  const macdH=showMACD?74:0, stochH=showStoch?74:0;
  const mainH=Math.max(100,totalH-volH-rsiH-macdH-stochH);

  const mc=_el('main-canvas');
  mc.width=W; mc.height=mainH; mc.style.height=mainH+'px';

  const panels=[
    {show:showVol,  id:'vol-panel',   cid:'vol-canvas',   h:volH},
    {show:showRSI,  id:'rsi-panel',   cid:'rsi-canvas',   h:rsiH},
    {show:showMACD, id:'macd-panel',  cid:'macd-canvas',  h:macdH},
    {show:showStoch,id:'stoch-panel', cid:'stoch-canvas', h:stochH},
  ];
  panels.forEach(({show,id,cid,h})=>{
    const p=document.getElementById(id); if(!p)return;
    p.style.display=show?'':'none';
    if(show){
      const cv=document.getElementById(cid);
      cv.width=W; cv.height=h-1; cv.style.height=(h-1)+'px';
      p.style.height=h+'px';
    }
  });

  // Custom indicator sub-panels
  const CUSTOM_PANEL_H = 74;
  customIndicators.filter(i=>i.visible&&i.type==='panel').forEach(ind=>{
    let p=document.getElementById('ci-panel-'+ind.id);
    if(!p){
      p=document.createElement('div'); p.className='panel'; p.id='ci-panel-'+ind.id;
      const lbl=document.createElement('div'); lbl.className='plbl'; lbl.textContent=ind.name;
      const btn=document.createElement('button'); btn.className='px-btn'; btn.textContent='✕';
      btn.onclick=()=>indToggle(ind.id);
      const cv=document.createElement('canvas'); cv.id='ci-canvas-'+ind.id;
      p.append(lbl,btn,cv);
      _el('chart-area').appendChild(p);
    }
    p.style.display=''; p.style.height=CUSTOM_PANEL_H+'px';
    const cv=document.getElementById('ci-canvas-'+ind.id);
    cv.width=W; cv.height=CUSTOM_PANEL_H-1; cv.style.height=(CUSTOM_PANEL_H-1)+'px';
  });
  // Hide panels for hidden/overlay indicators
  customIndicators.filter(i=>!i.visible||i.type!=='panel').forEach(ind=>{
    const p=document.getElementById('ci-panel-'+ind.id);
    if(p) p.style.display='none';
  });
  // Keep _mcRect fresh so mouse events are accurate after resize/tab switch
  if(typeof _mcRect !== 'undefined'){
    const _mc2 = _el('main-canvas');
    if(_mc2) try{ _mcRect = _mc2.getBoundingClientRect(); }catch(e){}
  }
}

// CSS var cache — avoids getComputedStyle on every draw call
let _cssVarCache = {};
let _cssVarCacheDirty = true;
function getCSSVar(v){
  if(_cssVarCacheDirty || !_cssVarCache[v]){
    _cssVarCache[v] = getComputedStyle(document.documentElement).getPropertyValue(v).trim();
  }
  return _cssVarCache[v];
}
function invalidateCSSVarCache(){ _cssVarCache = {}; _cssVarCacheDirty = true; }
// Cached DOM element references (only looked up once)
function _el(id){ return _elCache[id] || (_elCache[id] = document.getElementById(id)); }
function invalidateElCache(){ _elCache = {}; }

// Pre-warm all vars used in draw() once per frame
function _warmCSSVars(){
  const style = getComputedStyle(document.documentElement);
  ['--bg','--bg2','--bg3','--bg4','--b1','--b2','--tx2','--tx3','--am','--tl','--rd','--bl'].forEach(v=>{
    _cssVarCache[v] = style.getPropertyValue(v).trim();
  });
  _cssVarCacheDirty = false;
}

let _drawRaf = null;
function draw(){
  if(_drawRaf) return; // already scheduled this frame
  _drawRaf = requestAnimationFrame(() => {
    _drawRaf = null;
    _drawImmediate();
  });
}
function _drawImmediate(){
  if(!curData || !curData.length) return;
  const mc=_el('main-canvas');
  if(!mc) return;
  const W=mc.width, H=mc.height;
  if(!W||!H) return;
  
  // Additional safety checks for replay mode
  if(replayMode && !replayPicking && (replayCutoff < 0 || replayCutoff >= curData.length)) {
    // Reset replay state if it becomes invalid (but not during picking phase)
    console.log('Replay state invalid - stopping replay. replayCutoff:', replayCutoff, 'replayPicking:', replayPicking);
    stopReplay();
    return;
  }

  // Pre-warm CSS var cache once per draw
  _warmCSSVars();

  // ── Live CSS-variable colours ────────────────────────────────────────────
  const C = {
    bg:   getCSSVar('--bg')  || '#07090e',
    bg2:  getCSSVar('--bg2') || '#0c0e16',
    bg3:  getCSSVar('--bg3') || '#10131c',
    b1:   getCSSVar('--b1')  || '#1a2030',
    b2:   getCSSVar('--b2')  || '#232d42',
    tx2:  getCSSVar('--tx2') || '#8fa0bf',
    tx3:  getCSSVar('--tx3') || '#556070',
    am:   getCSSVar('--am')  || '#f0a500',
    tl:   getCSSVar('--tl')  || '#00c9a0',
    rd:   getCSSVar('--rd')  || '#f03060',
    bl:   getCSSVar('--bl')  || '#3d7fff',
  };
  // Derived with alpha
  const hex2rgb = h => { h=h.replace('#',''); const n=parseInt(h.length===3?h.split('').map(x=>x+x).join(''):h,16); return [(n>>16)&255,(n>>8)&255,n&255]; };
  const ca = (col,a) => { try{ const [r,g,b]=hex2rgb(col); return `rgba(${r},${g},${b},${a})`; } catch(e){ return col; } };

  // Use cached indicators — only recalculated when data or indicator flags change
  const {data,sma20,sma50,bbs,rsiVals,ema9,ema21,ema200,vwapVals,macdVals,stochVals} = getInds();

  // ── Coordinate helpers ────────────────────────────────────────────────────
  // barX(i): pixel x of bar i's centre
  const barX = i => W - (rightBarIndex - i) * barWidth;
  // Visible bar range
  const firstBarOnScreen = Math.max(0, Math.ceil(rightBarIndex - W / barWidth));
  // In replay mode (committed), hard-clamp so future bars are never rendered
  const _rawLast = Math.min(data.length - 1, Math.floor(rightBarIndex));
  const lastBarOnScreen  = (replayMode && !replayPicking && replayCutoff >= 0)
    ? Math.min(_rawLast, replayCutoff)
    : _rawLast;
  const visible = data.slice(firstBarOnScreen, lastBarOnScreen + 1);
  if(!visible.length) return;

  // ── Price range ───────────────────────────────────────────────────────────
  let hi, lo;
  if(priceHi !== null){ hi = priceHi; lo = priceLo; }
  else {
    hi = -Infinity; lo = Infinity;
    visible.forEach(d=>{ hi=Math.max(hi,d.high); lo=Math.min(lo,d.low); });
    if(bbs){ const vbb=bbs.slice(firstBarOnScreen,lastBarOnScreen+1).filter(Boolean); if(vbb.length){ hi=Math.max(hi,...vbb.map(b=>b.upper)); lo=Math.min(lo,...vbb.map(b=>b.lower)); }}
    const pad=(hi-lo)*.08||hi*.01; hi+=pad; lo-=pad;
  }
  const py = p => H - (p - lo) / (hi - lo) * H;
  const yToPrice = y => lo + (H - y) / H * (hi - lo);

  const ctx=mc.getContext('2d');
  ctx.clearRect(0,0,W,H);
  ctx.fillStyle=C.bg3; ctx.fillRect(0,0,W,H);

  const bw2 = Math.max(1, barWidth * 0.8); // body width
  const axisFontPx = uiInvariantPx(12, 10);
  const axisBoldFontPx = uiInvariantPx(11, 9);
  const axisPadPx = uiInvariantPx(14, 10);

  // Grid (horizontal)
  for(let i=0;i<=6;i++){
    const y=Math.floor(H/6*i)+.5;
    if(isSettingEnabled('scGrid', true)){ ctx.strokeStyle=C.b1; ctx.lineWidth=1; ctx.setLineDash([]); ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke(); }
    if(isSettingEnabled('scPriceScale', true)){ ctx.fillStyle=C.tx2; ctx.font=`${axisFontPx}px monospace`; ctx.textAlign='right'; ctx.fillText(fP(hi-(hi-lo)/6*i),W-R_PANEL_OFFSET-uiInvariantPx(3,2),y-uiInvariantPx(2,1)); }
  }

  // ── TradingView-style x-axis ───────────────────────────────────────────────
  const isSubDay = ['1m','5m','15m','30m','1h','4h'].includes(curTF);

  // Min pixel gap before placing the next label (based on a typical label width)
  ctx.font = `bold ${axisBoldFontPx}px monospace`;
  const _minGap = ctx.measureText('00:00').width + axisPadPx;

  // Pre-compute crosshair label bounds to suppress any static label underneath it
  let xhLabelL = -1, xhLabelR = -1;
  if(mouseX >= 0 && mouseX < W){
    const hb2 = Math.max(0, Math.min(data.length-1, Math.round(firstBarOnScreen + (mouseX - barX(firstBarOnScreen)) / barWidth)));
    if(data[hb2]){
      const dh = new Date(data[hb2].time * 1000);
      const ts = isSubDay
        ? dh.toLocaleDateString([],{month:'short',day:'numeric'}) + ' ' + dh.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit',hour12:false})
        : dh.toLocaleDateString([],{day:'numeric',month:'short',year:'numeric'});
      ctx.font = `bold ${axisBoldFontPx}px monospace`;
      const lw = ctx.measureText(ts).width + axisPadPx;
      const lx = Math.max(lw/2 + 2, Math.min(W - R_PANEL_OFFSET - lw/2 - 2, mouseX));
      xhLabelL = lx - lw/2 - 4;
      xhLabelR = lx + lw/2 + 4;
    }
  }

  ctx.textAlign = 'center';

  // ── Pass 1: collect ticks (spacing enforced here, crosshair-independent) ───
  const xTicks = [];
  let lastTickX = -9999;
  for(let i = firstBarOnScreen; i <= lastBarOnScreen; i++){
    const d    = new Date(data[i].time * 1000);
    const x    = barX(i);
    const prev = i > 0 ? new Date(data[i-1].time * 1000) : null;
    const tick = getXAxisTick(d, prev, curTF);
    if(!tick) continue;
    if(x - lastTickX < _minGap) continue;
    if(x > W - R_PANEL_OFFSET - _minGap/2) continue;
    xTicks.push({x, tick});
    lastTickX = x;
  }

  // ── Pass 2: draw grid lines (never suppressed by crosshair) ─────────────
  if(isSettingEnabled('scGrid', true)){
    const showDayBoundaries = isSettingEnabled('scDayBnd', true);
    for(const {x, tick} of xTicks){
      if(!showDayBoundaries && tick.tier <= 1) continue;
      const lineAlpha = tick.tier <= 1 ? 0.18 : tick.tier === 2 ? 0.12 : 0.07;
      ctx.strokeStyle = tick.tier <= 1 ? ca(C.am, lineAlpha) : C.b1;
      ctx.lineWidth   = tick.tier <= 1 ? 1.5 : 1;
      ctx.setLineDash([]);
      ctx.beginPath();
      ctx.moveTo(Math.floor(x)+.5, 0);
      ctx.lineTo(Math.floor(x)+.5, H);
      ctx.stroke();
    }
  }

  // ── Pass 3: draw labels (suppressed under crosshair only) ───────────────
  for(const {x, tick} of xTicks){
    if(!isSettingEnabled('scDayBnd', true) && tick.tier <= 1) continue;
    if(x >= xhLabelL && x <= xhLabelR) continue;
    ctx.font      = tick.bold ? `bold ${axisBoldFontPx}px monospace` : `${axisBoldFontPx}px monospace`;
    ctx.fillStyle = tick.tier === 0 ? C.tx
                  : tick.tier === 1 ? C.am
                  : tick.tier === 2 ? C.tx2
                  : 'rgba(107,128,153,0.85)';
    ctx.fillText(tick.label, x, H - uiInvariantPx(3, 2));
  }

  // Session highlight bands (behind everything)
  drawSessions(ctx, data, firstBarOnScreen, lastBarOnScreen, barX, H);

  // BB
  if(bbs){
    ['upper','lower'].forEach(k=>{
      ctx.beginPath(); ctx.strokeStyle='rgba(0,212,160,.3)'; ctx.lineWidth=1; let f=true;
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const b=bbs[i];if(!b)continue;const x=barX(i);const y=py(b[k]);f?(ctx.moveTo(x,y),f=false):ctx.lineTo(x,y);}
      ctx.stroke();
    });
    ctx.beginPath(); let f2=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const b=bbs[i];if(!b)continue;const x=barX(i);f2?(ctx.moveTo(x,py(b.upper)),f2=false):ctx.lineTo(x,py(b.upper));}
    for(let i=lastBarOnScreen;i>=firstBarOnScreen;i--){const b=bbs[i];if(!b)continue;ctx.lineTo(barX(i),py(b.lower));}
    ctx.fillStyle='rgba(0,212,160,.03)'; ctx.fill();
  }

  // SMA
  if(sma20){
    [[sma20,smaCols[0]],[sma50,smaCols[1]]].forEach(([arr,col])=>{
      ctx.beginPath(); ctx.strokeStyle=col; ctx.lineWidth=1.5; let f=true;
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=arr[i];if(!v)continue;const x=barX(i);const y=py(v);f?(ctx.moveTo(x,y),f=false):ctx.lineTo(x,y);}
      ctx.stroke();
    });
  }

  // EMA 9 / 21
  if(ema9){
    [[ema9,'#ff9800'],[ema21,'#e040fb']].forEach(([arr,col])=>{
      ctx.beginPath(); ctx.strokeStyle=col; ctx.lineWidth=1.5; ctx.setLineDash([]); let f=true;
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=arr[i];if(!v)continue;const x=barX(i);f?(ctx.moveTo(x,py(v)),f=false):ctx.lineTo(x,py(v));}
      ctx.stroke();
    });
  }

  // EMA 200
  if(ema200){
    ctx.beginPath(); ctx.strokeStyle='#888888'; ctx.lineWidth=1.5; ctx.setLineDash([]); let f200=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=ema200[i];if(!v)continue;const x=barX(i);f200?(ctx.moveTo(x,py(v)),f200=false):ctx.lineTo(x,py(v));}
    ctx.stroke();
  }

  // VWAP
  if(vwapVals){
    ctx.beginPath(); ctx.strokeStyle='#00bcd4'; ctx.lineWidth=1.5; ctx.setLineDash([4,3]); let fv=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=vwapVals[i];if(!v)continue;const x=barX(i);fv?(ctx.moveTo(x,py(v)),fv=false):ctx.lineTo(x,py(v));}
    ctx.stroke(); ctx.setLineDash([]);
  }

  // Candles / Line / Area
  if(curCT==='line'||curCT==='area'){
    if(curCT==='area'){
      ctx.beginPath(); let f=true;
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const x=barX(i);const y=py(data[i].close);f?(ctx.moveTo(x,y),f=false):ctx.lineTo(x,y);}
      ctx.lineTo(barX(lastBarOnScreen),H); ctx.lineTo(barX(firstBarOnScreen),H);
      ctx.fillStyle=ca(C.am,.1); ctx.fill();
    }
    ctx.beginPath(); ctx.strokeStyle=C.am; ctx.lineWidth=2; let f2=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const x=barX(i);const y=py(data[i].close);f2?(ctx.moveTo(x,y),f2=false):ctx.lineTo(x,y);}
    ctx.stroke();
  } else {
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){
      const d=data[i]; const x=barX(i);
      const up=d.close>=d.open;
      const col=up?candleBullColor:candleBearColor;
      const yO=py(Math.max(d.open,d.close)), yC=py(Math.min(d.open,d.close));
      const bh=Math.max(1,yC-yO);
      if(isSettingEnabled('scWicks', true)){ ctx.strokeStyle=col; ctx.lineWidth=1; ctx.setLineDash([]); ctx.beginPath(); ctx.moveTo(x,py(d.high)); ctx.lineTo(x,yO); ctx.moveTo(x,yC); ctx.lineTo(x,py(d.low)); ctx.stroke(); }
      if(bw2>=1){ if(isSettingEnabled('scHollow', false)){ ctx.strokeStyle=col; ctx.lineWidth=1; ctx.strokeRect(x-bw2/2,yO,bw2,bh); } else { ctx.fillStyle=col; ctx.fillRect(x-bw2/2, yO, bw2, bh); } }
    }
  }

  // Visible high / low labels (live — based on what's currently on screen)
  if(isSettingEnabled('scHiLo', true)){
    // Find the actual highest high and lowest low bar in the visible range
    let hiPrice = -Infinity, loPrice = Infinity;
    let hiBarX = 0, loBarX = 0;
    for(let i=firstBarOnScreen; i<=lastBarOnScreen; i++){
      const d = data[i]; if(!d) continue;
      if(d.high > hiPrice){ hiPrice = d.high; hiBarX = barX(i); }
      if(d.low  < loPrice){ loPrice = d.low;  loBarX = barX(i); }
    }
    const hiY = py(hiPrice);
    const loY = py(loPrice);

    // High label — above the candle, teal
    ctx.font = 'bold 9px monospace'; ctx.textAlign = 'left';
    const hiTxt = '▲ ' + fP(hiPrice);
    const loTxt = '▼ ' + fP(loPrice);
    // Position label to left or right of the bar so it stays on screen
    const hiLabelX = hiBarX + 6 > W - R_PANEL_OFFSET - 70 ? hiBarX - ctx.measureText(hiTxt).width - 8 : hiBarX + 6;
    const loLabelX = loBarX + 6 > W - R_PANEL_OFFSET - 70 ? loBarX - ctx.measureText(loTxt).width - 8 : loBarX + 6;
    ctx.fillStyle = C.tl;
    ctx.fillText(hiTxt, hiLabelX, hiY - 5);
    ctx.fillStyle = C.rd;
    ctx.fillText(loTxt, loLabelX, loY + 13);
  }

  // ── Drawings ──────────────────────────────────────────────────────────────
  renderDrawings(ctx, W, H, barX, py, yToPrice);

  // ── AI Chart Overlay ──────────────────────────────────────────────────────
  renderAIOverlay(ctx, W, H, py, barX, C);

  // Crosshair
  // ── Replay overlay: cutoff line + hover line when picking ────────────────
  if(replayMode){
    const hoverIdx = replayHoverBar(); // -1 when not picking

    // --- PICKING PHASE: amber line tracks mouse ---
    if(replayPicking && hoverIdx >= 0){
      const hoverX = W - (rightBarIndex - hoverIdx) * barWidth;
      ctx.save();
      ctx.strokeStyle = 'rgba(240,165,0,0.85)';
      ctx.lineWidth   = 1.5;
      ctx.setLineDash([4, 3]);
      ctx.beginPath();
      ctx.moveTo(Math.floor(hoverX)+0.5, 0);
      ctx.lineTo(Math.floor(hoverX)+0.5, H);
      ctx.stroke();
      ctx.setLineDash([]);
      // Label
      ctx.font = 'bold 9px monospace'; ctx.textAlign='center';
      const ltxt = '▶ CLICK TO START';
      const lw2  = ctx.measureText(ltxt).width + 12;
      const lx2  = Math.max(lw2/2+2, Math.min(W-lw2/2-2, hoverX));
      ctx.fillStyle='rgba(240,165,0,0.9)'; ctx.fillRect(lx2-lw2/2,4,lw2,15);
      ctx.fillStyle='#07090e'; ctx.fillText(ltxt, lx2, 15);
      ctx.restore();
    }

    // --- COMMITTED PHASE: teal cutoff line + drag handle + play button ---
    if(!replayPicking && replayCutoff >= 0){
      const cutoffX = W - (rightBarIndex - replayCutoff) * barWidth;
      const isHoveringLine = Math.abs(mouseX - cutoffX) <= 8;
      ctx.save();
      // Line — brighter and solid when hovered/dragging
      ctx.strokeStyle = (_replayLineDragging || isHoveringLine)
        ? 'rgba(0,201,160,1.0)' : 'rgba(0,201,160,0.65)';
      ctx.lineWidth   = (_replayLineDragging || isHoveringLine) ? 2.5 : 1.5;
      ctx.setLineDash([4, 3]);
      ctx.beginPath();
      ctx.moveTo(Math.floor(cutoffX)+0.5, 0);
      ctx.lineTo(Math.floor(cutoffX)+0.5, H);
      ctx.stroke();
      ctx.setLineDash([]);
      // Drag handle — two small horizontal grip bars near the top
      if(isHoveringLine || _replayLineDragging){
        const hx = Math.floor(cutoffX) + 0.5;
        const hy = 40;
        ctx.fillStyle = 'rgba(0,201,160,0.9)';
        ctx.beginPath(); ctx.roundRect(hx - 10, hy - 12, 20, 24, 4); ctx.fill();
        ctx.strokeStyle = 'rgba(0,201,160,0.4)';
        ctx.lineWidth = 1;
        for(let g = -4; g <= 4; g += 4){
          ctx.beginPath(); ctx.moveTo(hx - 5, hy + g); ctx.lineTo(hx + 5, hy + g); ctx.stroke();
        }
      }

      // Canvas play/pause button — centred on the cutoff line, vertically centred
      const isPlaying = !!replayTimer;
      const btnR  = 18;  // radius
      const btnX  = Math.min(W - btnR - 6, Math.max(btnR + 6, cutoffX + 2));
      const btnY  = H / 2;
      // Shadow
      ctx.shadowColor='rgba(0,0,0,0.6)'; ctx.shadowBlur=8;
      ctx.fillStyle = isPlaying ? 'rgba(240,48,96,0.88)' : 'rgba(0,201,160,0.88)';
      ctx.beginPath(); ctx.arc(btnX, btnY, btnR, 0, Math.PI*2); ctx.fill();
      ctx.shadowBlur=0;
      // Icon
      ctx.fillStyle = '#07090e';
      ctx.font = 'bold 15px monospace'; ctx.textAlign='center';
      ctx.fillText(isPlaying ? '⏸' : '▶', btnX, btnY+5);

      // Store button position for click detection
      window._replayBtnX = btnX; window._replayBtnY = btnY; window._replayBtnR = btnR;
      ctx.restore();
    } else {
      window._replayBtnX = -1;
    }
  }

  if(mouseX>=0&&mouseX<W&&mouseY>=0&&mouseY<H&&isSettingEnabled('scCross', true)){
    ctx.strokeStyle='rgba(255,255,255,.12)'; ctx.lineWidth=1; ctx.setLineDash([4,4]);
    ctx.beginPath(); ctx.moveTo(mouseX,0); ctx.lineTo(mouseX,H); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(0,mouseY); ctx.lineTo(W-R_PANEL_OFFSET,mouseY); ctx.stroke();
    ctx.setLineDash([]);
    // Price label on right Y-axis
    const price = yToPrice(mouseY);
    const priceTagW = uiInvariantPx(62, 50);
    const priceTagH = uiInvariantPx(22, 18);
    ctx.fillStyle=C.am; ctx.fillRect(W-R_PANEL_OFFSET-priceTagW,mouseY-priceTagH/2,priceTagW,priceTagH);
    ctx.fillStyle=C.bg; ctx.font=`bold ${axisFontPx}px monospace`; ctx.textAlign='right';
    ctx.fillText(fP(price),W-R_PANEL_OFFSET-uiInvariantPx(3,2),mouseY+uiInvariantPx(5,4));
    // OHLC tooltip
    const hoverBar = Math.round(firstBarOnScreen + (mouseX - barX(firstBarOnScreen)) / barWidth);
    const hb = Math.max(0,Math.min(data.length-1,hoverBar));
    // Timestamp label on X-axis at crosshair position
    if(data[hb]&&isSettingEnabled('scXAxisLbl', true)){
      const d  = new Date(data[hb].time * 1000);
      const isSubDay = ['1m','5m','15m','30m','1h','4h'].includes(curTF);
      const timeStr = isSubDay
        ? d.toLocaleDateString([],{weekday:'short',month:'short',day:'numeric'}) + '  ' + d.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit',hour12:false})
        : d.toLocaleDateString([],{weekday:'short',month:'short',day:'numeric',year:'numeric'});
      ctx.font = `bold ${axisFontPx}px monospace`;
      const lw = ctx.measureText(timeStr).width + uiInvariantPx(18, 12);
      const lh = uiInvariantPx(20, 16);
      const lx = Math.max(lw/2 + 2, Math.min(W - lw/2 - 2, mouseX));
      // Erase strip behind label — tall enough to cover the axis text at H-3
      ctx.fillStyle = C.bg3;
      ctx.fillRect(lx - lw/2 - 2, H - lh - 2, lw + 4, lh + 2);
      ctx.fillStyle = C.am;
      ctx.fillRect(lx - lw/2, H - lh, lw, lh);
      ctx.fillStyle = C.bg3;
      ctx.textAlign = 'center';
      ctx.fillText(timeStr, lx, H - lh/2 + uiInvariantPx(3,2));
    }
    const d=data[hb];
    _el('tt-o').textContent=fP(d.open);
    _el('tt-h').textContent=fP(d.high);
    _el('tt-l').textContent=fP(d.low);
    _el('tt-c').textContent=fP(d.close);
    _el('tooltip').style.display=isSettingEnabled('scOhlc', true)?'flex':'none';
  } else {
    _el('tooltip').style.display='none';
  }

  // VOLUME panel
  const vc=_el('vol-canvas');
  if(showVol&&vc.width&&vc.height){
    const vctx=vc.getContext('2d'); const VW=vc.width,VH=vc.height;
    vctx.fillStyle=C.bg3; vctx.fillRect(0,0,VW,VH);
    const maxVol=Math.max(...visible.map(d=>d.volume))||1;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){
      const d=data[i]; const x=barX(i);
      const bh=Math.max(1,(d.volume/maxVol)*(VH-10));
      vctx.fillStyle=d.close>=d.open?ca(C.tl,.4):ca(C.rd,.4);
      vctx.fillRect(x-bw2/2,VH-bh,bw2,bh);
    }
    vctx.fillStyle=C.tx2; vctx.font='11px monospace'; vctx.textAlign='right';
    vctx.fillText(fV(maxVol),VW-3,10);
  }

  // RSI panel
  const rc=_el('rsi-canvas');
  if(showRSI&&rsiVals&&rc.width&&rc.height){
    const rctx=rc.getContext('2d'); const RW=rc.width,RH=rc.height;
    rctx.fillStyle=C.bg3; rctx.fillRect(0,0,RW,RH);
    const ry=v=>RH-(v/100)*(RH-14)-4;
    rctx.fillStyle=ca(C.rd,.05); rctx.fillRect(0,ry(100),RW,ry(70)-ry(100));
    rctx.fillStyle=ca(C.tl,.05); rctx.fillRect(0,ry(30),RW,RH-ry(30));
    [70,50,30].forEach(v=>{
      rctx.strokeStyle=v===50?C.b1:ca(C.tx3,.35); rctx.lineWidth=1;
      rctx.beginPath(); rctx.moveTo(0,ry(v)); rctx.lineTo(RW,ry(v)); rctx.stroke();
      rctx.fillStyle=C.tx2; rctx.font='11px monospace'; rctx.textAlign='right';
      rctx.fillText(v,RW-2,ry(v)-1);
    });
    rctx.beginPath(); rctx.strokeStyle=C.am; rctx.lineWidth=1.5; let rf=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){
      const rv=rsiVals[i]; if(rv==null)continue;
      const x=barX(i); const y=ry(rv);
      rf?(rctx.moveTo(x,y),rf=false):rctx.lineTo(x,y);
    }
    rctx.stroke();
    const lastRSI=rsiVals[lastBarOnScreen];
    if(lastRSI!=null){
      const col=lastRSI>70?C.rd:lastRSI<30?C.tl:C.am;
      rctx.fillStyle=col; rctx.font='bold 9px monospace'; rctx.textAlign='left';
      rctx.fillText(lastRSI.toFixed(1),3,11);
    }
  }

  // MACD panel
  const mc2=_el('macd-canvas');
  if(showMACD&&macdVals&&mc2&&mc2.width&&mc2.height){
    const mctx=mc2.getContext('2d'); const MW=mc2.width,MH=mc2.height;
    mctx.fillStyle=C.bg3; mctx.fillRect(0,0,MW,MH);
    const visM=macdVals.slice(firstBarOnScreen,lastBarOnScreen+1).filter(Boolean);
    if(visM.length){
      const maxA=Math.max(...visM.map(v=>Math.max(Math.abs(v.macd),Math.abs(v.signal),Math.abs(v.hist))))||1;
      const my=v=>MH/2-(v/maxA)*(MH/2-8);
      // Zero line
      mctx.strokeStyle=C.b2; mctx.lineWidth=1; mctx.setLineDash([]);
      mctx.beginPath(); mctx.moveTo(0,MH/2); mctx.lineTo(MW,MH/2); mctx.stroke();
      // Histogram bars
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){
        const v=macdVals[i]; if(!v)continue;
        const x=barX(i); const y0=MH/2; const y1=my(v.hist);
        mctx.fillStyle=v.hist>=0?ca(C.tl,.55):ca(C.rd,.55);
        mctx.fillRect(x-Math.max(1,bw2/2),Math.min(y0,y1),Math.max(1,bw2),Math.abs(y0-y1));
      }
      // MACD line
      mctx.beginPath(); mctx.strokeStyle='#ff9800'; mctx.lineWidth=1.5; let mf=true;
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=macdVals[i];if(!v)continue;const x=barX(i);mf?(mctx.moveTo(x,my(v.macd)),mf=false):mctx.lineTo(x,my(v.macd));}
      mctx.stroke();
      // Signal line
      mctx.beginPath(); mctx.strokeStyle='#e040fb'; mctx.lineWidth=1.5; let sf=true;
      for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=macdVals[i];if(!v)continue;const x=barX(i);sf?(mctx.moveTo(x,my(v.signal)),sf=false):mctx.lineTo(x,my(v.signal));}
      mctx.stroke();
      // Labels
      const lv=macdVals[lastBarOnScreen];
      if(lv){
        mctx.font='bold 11px monospace'; mctx.textAlign='left';
        mctx.fillStyle='#ff9800'; mctx.fillText('M:'+lv.macd.toFixed(4),3,10);
        mctx.fillStyle='#e040fb'; mctx.fillText('S:'+lv.signal.toFixed(4),3,20);
        mctx.fillStyle=lv.hist>=0?C.tl:C.rd; mctx.fillText('H:'+lv.hist.toFixed(4),3,30);
      }
    }
  }

  // Stochastic panel
  const sc2=_el('stoch-canvas');
  if(showStoch&&stochVals&&sc2&&sc2.width&&sc2.height){
    const sctx=sc2.getContext('2d'); const SW=sc2.width,SH=sc2.height;
    sctx.fillStyle=C.bg3; sctx.fillRect(0,0,SW,SH);
    const sy=v=>SH-(v/100)*(SH-14)-4;
    // OB/OS zones
    sctx.fillStyle=ca(C.rd,.05); sctx.fillRect(0,sy(100),SW,sy(80)-sy(100));
    sctx.fillStyle=ca(C.tl,.05); sctx.fillRect(0,sy(20),SW,SH-sy(20));
    [80,50,20].forEach(v=>{
      sctx.strokeStyle=v===50?C.b1:ca(C.tx3,.35); sctx.lineWidth=1;
      sctx.beginPath(); sctx.moveTo(0,sy(v)); sctx.lineTo(SW,sy(v)); sctx.stroke();
      sctx.fillStyle=C.tx2; sctx.font='11px monospace'; sctx.textAlign='right';
      sctx.fillText(v,SW-2,sy(v)-1);
    });
    // %K line
    sctx.beginPath(); sctx.strokeStyle=C.bl; sctx.lineWidth=1.5; let kf=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=stochVals[i];if(!v)continue;const x=barX(i);kf?(sctx.moveTo(x,sy(v.k)),kf=false):sctx.lineTo(x,sy(v.k));}
    sctx.stroke();
    // %D line
    sctx.beginPath(); sctx.strokeStyle='#ff9800'; sctx.lineWidth=1.5; let df=true;
    for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){const v=stochVals[i];if(!v)continue;const x=barX(i);df?(sctx.moveTo(x,sy(v.d)),df=false):sctx.lineTo(x,sy(v.d));}
    sctx.stroke();
    const lv=stochVals[lastBarOnScreen];
    if(lv){
      sctx.font='bold 8px monospace'; sctx.textAlign='left';
      sctx.fillStyle=C.bl; sctx.fillText('%K '+lv.k.toFixed(1),3,11);
      sctx.fillStyle='#ff9800'; sctx.fillText('%D '+lv.d.toFixed(1),3,21);
    }
  }

  // ── Custom Indicators ──────────────────────────────────────────────────────
  customIndicators.filter(i=>i.visible).forEach(ind=>{
    try{
      const vals = evalIndFormula(ind.formula, data);
      if(!vals) return;
      const dash = ind.linestyle==='dashed'?[6,4]:ind.linestyle==='dotted'?[2,4]:[];
      if(ind.type==='overlay'){
        ctx.beginPath(); ctx.strokeStyle=ind.color; ctx.lineWidth=ind.linewidth||1.5;
        ctx.setLineDash(dash); let first=true;
        for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){
          const v=vals[i]; if(v==null||!isFinite(v))continue;
          const x=barX(i), y=py(v);
          first?(ctx.moveTo(x,y),first=false):ctx.lineTo(x,y);
        }
        ctx.stroke(); ctx.setLineDash([]);
        // Label last value
        const lv=vals[lastBarOnScreen];
        if(lv!=null&&isFinite(lv)){
          ctx.fillStyle=ind.color; ctx.font='bold 9px monospace'; ctx.textAlign='right';
          ctx.fillText(ind.name+' '+fP(lv), W-R_PANEL_OFFSET-4, py(lv)-4);
        }
      } else {
        // Sub-panel
        const cv2 = document.getElementById('ci-canvas-'+ind.id);
        if(!cv2||!cv2.width||!cv2.height) return;
        const cx2=cv2.getContext('2d'); const PW=cv2.width,PH=cv2.height;
        cx2.fillStyle=C.bg3; cx2.fillRect(0,0,PW,PH);
        // Auto-scale to visible range
        const visVals=vals.slice(firstBarOnScreen,lastBarOnScreen+1).filter(v=>v!=null&&isFinite(v));
        if(!visVals.length) return;
        const pMin=Math.min(...visVals), pMax=Math.max(...visVals);
        const pRange=pMax-pMin||1;
        const py2=v=>PH-((v-pMin)/pRange)*(PH-16)-4;
        // Zero line if range spans zero
        if(pMin<0&&pMax>0){
          cx2.strokeStyle=C.b2; cx2.lineWidth=1; cx2.setLineDash([]);
          cx2.beginPath(); cx2.moveTo(0,py2(0)); cx2.lineTo(PW,py2(0)); cx2.stroke();
        }
        // Grid labels
        [pMax, (pMax+pMin)/2, pMin].forEach(v=>{
          cx2.fillStyle=C.tx2; cx2.font='8px monospace'; cx2.textAlign='right';
          cx2.fillText(fP(v),PW-2,py2(v)+3);
        });
        cx2.beginPath(); cx2.strokeStyle=ind.color; cx2.lineWidth=ind.linewidth||1.5;
        cx2.setLineDash(dash); let cf=true;
        for(let i=firstBarOnScreen;i<=lastBarOnScreen;i++){
          const v=vals[i]; if(v==null||!isFinite(v))continue;
          const x=barX(i),y=py2(v);
          cf?(cx2.moveTo(x,y),cf=false):cx2.lineTo(x,y);
        }
        cx2.stroke(); cx2.setLineDash([]);
        // Last value label
        const lv2=vals[lastBarOnScreen];
        if(lv2!=null&&isFinite(lv2)){
          cx2.fillStyle=ind.color; cx2.font='bold 8px monospace'; cx2.textAlign='left';
          cx2.fillText(fP(lv2),3,11);
        }
      }
    }catch(e){ /* silent — bad formula on symbol change */ }
  });

  updateChartScrubber();
}

// ══ DRAWING TOOLS ══════════════════════════════════════════════════════════════
let activeTool = 'cursor';
let drawingColor = '#f0a500';
let drawingLineStyle = 'solid';
let drawingLineWidth = 1;

// ── Per-symbol drawing persistence ───────────────────────────────────────────
// ── Drawing coordinate helpers ──────────────────────────────────────────────
// Drawings are stored with Unix timestamps so they transfer across timeframes.
// bar → time: look up curData[Math.round(bar)].time (clamp to valid range)
function barToTime(bar) {
  if(!curData.length) return 0;
  const i = Math.max(0, Math.min(curData.length-1, Math.round(bar)));
  return curData[i].time;
}
// time → bar: binary search in curData for closest bar
function timeToBar(time) {
  if(!curData.length) return 0;
  let lo=0, hi=curData.length-1;
  while(lo<hi){ const mid=(lo+hi)>>1; if(curData[mid].time<time) lo=mid+1; else hi=mid; }
  // pick closest neighbour
  if(lo>0 && Math.abs(curData[lo-1].time-time) < Math.abs(curData[lo].time-time)) lo--;
  return lo;
}
// Convert all bar fields in a drawing to time fields (for storage)
function drawingToTime(d) {
  const s = JSON.parse(JSON.stringify(d));
  if(s.bar    !== undefined) { s.time  = barToTime(s.bar);  }
  if(s.bar1   !== undefined) { s.time1 = barToTime(s.bar1); }
  if(s.bar2   !== undefined) { s.time2 = barToTime(s.bar2); }
  if(s.pts) s.pts = s.pts.map(p => ({...p, time: barToTime(p.bar)}));
  return s;
}
// Convert all time fields in a drawing back to bar indices for current TF
function drawingFromTime(d) {
  const s = JSON.parse(JSON.stringify(d));
  if(s.time  !== undefined) s.bar  = timeToBar(s.time);
  if(s.time1 !== undefined) s.bar1 = timeToBar(s.time1);
  if(s.time2 !== undefined) s.bar2 = timeToBar(s.time2);
  if(s.pts) s.pts = s.pts.map(p => ({...p, bar: p.time !== undefined ? timeToBar(p.time) : p.bar}));
  return s;
}
// Drawings are shared per symbol (not per TF) since timestamps are universal
function _drawKey(sym,tf){ return `drawings-${sym}`; }
function saveDrawings(sym,tf){
  try{
    // Exclude temporary refinement/overlay annotations (_noSave) from persistence
    const portable = drawings.filter(d => !d._noSave).map(drawingToTime);
    _lsSet(_drawKey(sym,tf), JSON.stringify(portable));
  }catch(e){}
  // Use cached AI panel data — force=false prevents Groq re-calls on drawing move/save
  if(curSym?.s === sym && curTF === tf) buildAIPanel(false);
}
function loadDrawings(sym,tf){
  try{
    const raw=_lsGet(_drawKey(sym,tf));
    const stored = raw ? JSON.parse(raw) : [];
    drawings = stored.map(drawingFromTime);
  }catch(e){ drawings=[]; }
}
let drawingWIP = null;       // in-progress drawing
let selectedDrawing = null;  // currently selected drawing
let pitchforkStage = 0;      // pitchfork needs 3 clicks
let channelStage = 0;        // channel needs 3 clicks

// Effective half-width in bars — uses stored duration if available for TF-independence
function effectiveHalfBars(d){ 
  if(d.halfDuration) return secsToHalfBars(d.halfDuration, curTF);
  return d.halfBars || 8;
}
function defaultTradeToolHalfBars(tf){
  return ({
    '1m': 18,
    '5m': 16,
    '15m': 14,
    '1h': 12,
    '4h': 10,
    '1d': 8,
    '1w': 6,
    '1M': 5,
  })[tf] || 8;
}
function defaultTradeToolMinRiskPct(tf){
  return ({
    '1m': 0.0035,
    '5m': 0.005,
    '15m': 0.0075,
    '1h': 0.01,
    '4h': 0.015,
    '1d': 0.02,
    '1w': 0.035,
    '1M': 0.05,
  })[tf] || 0.01;
}
function buildTimeframeAwareTradeTool(direction, entryPrice, barIndex, tf){
  const safeTf = tf || curTF || '1d';
  const atr = calculateATR(Math.min(curData.length - 1, Math.max(14, barIndex)), 14) || 0;
  const minRisk = entryPrice * defaultTradeToolMinRiskPct(safeTf);
  const riskDist = Math.max(atr * 1.15, minRisk);
  const rewardDist = riskDist * 2;
  const isLong = direction === 'long';
  const halfBars = defaultTradeToolHalfBars(safeTf);
  return {
    sl: isLong ? entryPrice - riskDist : entryPrice + riskDist,
    tp: isLong ? entryPrice + rewardDist : entryPrice - rewardDist,
    halfBars,
    halfDuration: halfBarsToSecs(halfBars, safeTf),
    atr,
  };
}

// ── Drag / resize state ──────────────────────────────────────────────────────
let isDraggingDrawing  = false;  // moving whole drawing
let isResizingDrawing  = false;  // dragging a handle
let resizeHandle       = null;   // which handle ('p1','p2','sl','tp','price','bar', etc.)
let dragStartBar       = 0;      // bar coord at drag start
let dragStartPrice     = 0;      // price coord at drag start
let dragStartX         = 0;      // screen x at drag start
let dragStartY         = 0;      // screen y at drag start
let dragSnapshot       = null;   // deep copy of drawing at drag start

let isMarquee = false;
let marqueeX0=0, marqueeY0=0, marqueeX1=0, marqueeY1=0;
let selectedDrawings = [];

const TOOL_BTNS = ['cursor','long','short','line','extline','channel','hline','hray','vline','ray','rect','pricerange','fib','fibext','pitchfork','text','arrow','measure','eraser'];

function _btApplyLineStyle(ctx, style){
  if(style==='dashed') ctx.setLineDash([6,4]);
  else if(style==='dotted') ctx.setLineDash([2,3]);
  else ctx.setLineDash([]);
}
function _dtSetColor(btn){
  document.querySelectorAll('.dt-color').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  draw();
}
function _dtSetStyle(btn, style){
  document.querySelectorAll('.dt-style-btn').forEach(b=>b.classList.remove('active'));
  btn.classList.add('active');
  drawingLineStyle = style;
}
function setTool(t){
  activeTool = t;
  drawingWIP = null; pitchforkStage = 0; channelStage = 0;
  TOOL_BTNS.forEach(id=>{
    const b = document.getElementById('dt-'+id);
    if(b) b.classList.toggle('on', id===t);
  });
  const mc = _el('main-canvas');
  mc.style.cursor = t==='cursor'?'crosshair': t==='eraser'?'cell':'crosshair';
  // Reflect drawing tool active state on docked button
  const drawBtn = document.getElementById('tbdock-draw');
  if(drawBtn) drawBtn.classList.toggle('active', t !== 'cursor');
  draw();
}

// Keyboard shortcuts for tools
document.addEventListener('keydown', e=>{
  if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA') return;
  const map = {v:'cursor',l:'long',s:'short',t:'line',h:'hline',r:'rect',f:'fib',e:'eraser',x:'text',a:'arrow',c:'channel',p:'pricerange'};
  if(map[e.key.toLowerCase()]) setTool(map[e.key.toLowerCase()]);
  if(e.key==='Escape'){ setTool('cursor'); drawingWIP=null; pitchforkStage=0; channelStage=0; draw(); }
  if((e.key==='Delete'||e.key==='Backspace') && (selectedDrawing||selectedDrawings.length)){
    const toDelete = selectedDrawings.length ? new Set(selectedDrawings) : new Set([selectedDrawing]);
    drawings = drawings.filter(d=>!toDelete.has(d));
    saveDrawings(curSym.s,curTF);
    selectedDrawing=null; selectedDrawings=[]; draw();
  }
});

function clearDrawings(){
  if(!drawings.length) return;
  if(!appPrefs.confirmClearDrawings){
    drawings=[]; drawingWIP=null; selectedDrawing=null; saveDrawings(curSym.s,curTF); draw();
    return;
  }
  showConfirm('Clear all drawings?','All lines, shapes and annotations will be removed.',()=>{
    drawings=[]; drawingWIP=null; selectedDrawing=null; saveDrawings(curSym.s,curTF); draw();
  });
}

// ── Coordinate converters (need barX/py from draw scope, so we use closures stored each frame)
let _barX=null, _py=null, _yToPrice=null, _xToBar=null;
let _drawW=0, _drawH=0;

function screenToDraw(sx, sy){
  // sx,sy = canvas pixel coords
  const price = _yToPrice ? _yToPrice(sy) : 0;
  const bar   = _xToBar   ? _xToBar(sx)   : 0;
  return { bar, price, x: sx, y: sy };
}

function _mentorGetBubbleRect(d){
  if (!d || !d._bubbleRect) return null;
  const r = d._bubbleRect;
  if (!Number.isFinite(r.x) || !Number.isFinite(r.y) || !Number.isFinite(r.w) || !Number.isFinite(r.h)) return null;
  return r;
}

function _mentorBubbleHit(d, sx, sy, pad = 6){
  const r = _mentorGetBubbleRect(d);
  if (!r) return false;
  return sx >= r.x - pad && sx <= r.x + r.w + pad && sy >= r.y - pad && sy <= r.y + r.h + pad;
}

function _mentorConfluenceExplanation(label, method = '', direction = 'long') {
  const base = (label || '').split(' + ')[0].trim();
  const isLong = direction !== 'short';

  if (base.startsWith('Support zone')) {
    return `This is marked as support because price has already reacted here multiple times and held instead of closing cleanly through it. Each successful defense shows buyers are willing to step in around this same price area, so the level becomes more meaningful with every hold. What matters next is whether price rejects this zone again with a wick or strong bullish close rather than drifting through it.`;
  }
  if (base.startsWith('Resistance zone')) {
    return `This is marked as resistance because price has already failed here before and sellers kept capping the move. Repeated failures at nearly the same price tell us supply is sitting in this area. The confirmation is another rejection, bearish response, or failed attempt to break through with conviction.`;
  }
  if (base.startsWith('Breakout line') || base.startsWith('Breakdown line')) {
    return `This line matters because it is the edge of the consolidation that price has been respecting. While price stays inside that box, the market is still balanced. Once a candle closes decisively outside it, that balance breaks and one side has likely taken control. The quality of the break depends on body strength, follow-through, and whether price avoids snapping straight back inside the range.`;
  }
  if (base.startsWith('Consolidation')) {
    return `This is called consolidation because price is compressing into a relatively tight box instead of trending cleanly. That tells us the market is pausing, orders are building, and energy is being stored. The longer this compression holds without breaking, the more important the eventual escape from the box becomes.`;
  }
  if (base.startsWith('Pullback zone')) {
    return `This is the pullback zone because the current retracement sits inside the Fibonacci area where healthy trends often resume. A good pullback is not random weakness; it is price temporarily retracing into value without fully breaking structure. The mentor is watching this area because it offers a better risk-to-reward entry than chasing after the move has already expanded.`;
  }
  if (base.startsWith('Liquidity pool')) {
    return `This is treated as liquidity because traders naturally place stop losses around obvious equal highs, equal lows, prior swing extremes, and clean breakout points. When price pokes into that pocket and quickly reverses, it suggests those stops were harvested first and then the real move began. The clue is not just the level itself, but the sweep and rejection behavior around it.`;
  }
  if (base.startsWith('Range bottom') || base.startsWith('Range support')) {
    return `This is the lower edge of the range because price has repeatedly found demand here instead of breaking down. In a true range, the boundaries matter more than the middle because that is where the market keeps rejecting price. The lesson is to wait for evidence that buyers are defending the edge again rather than entering in the middle of the chop.`;
  }
  if (base.startsWith('Range top') || base.startsWith('Range resistance')) {
    return `This is the upper edge of the range because price has repeatedly stalled here instead of continuing upward. That repeated rejection shows supply is concentrated near this boundary. The better short is not just because price is high, but because it is reacting at a known ceiling where sellers have already proven themselves.`;
  }
  if (base.startsWith('Range')) {
    return `This is classified as a range because price is rotating between a clear ceiling and floor rather than trending in one direction. In a ranging market the edge comes from trading the boundaries, not from assuming continuation in the middle. The mentor highlights this so the user learns where location matters most.`;
  }
  if (base.startsWith('Higher low') || base.startsWith('Prior higher low')) {
    return `This matters because an uptrend is built on higher lows: buyers step in sooner on each pullback and do not allow price to revisit the previous low. That tells us demand is getting more aggressive. The mentor marks these points to show that the bullish idea is supported by real structure, not just by a single candle.`;
  }
  if (base.startsWith('Lower high') || base.startsWith('Prior lower high')) {
    return `This matters because a downtrend is built on lower highs: sellers step in earlier and prevent price from reclaiming the previous swing high. That tells us supply is controlling the market. The mentor marks these points so the user can see that the bearish bias is structural, not random.`;
  }
  if (base.startsWith('Rejection wick')) {
    return `This is called a rejection wick because price traded through the level intrabar but could not stay there by the close. The long wick shows one side tried to continue, then got absorbed and pushed back. That matters because it is evidence of real defense at the level, not just a touch.`;
  }
  if (base.startsWith('Reaction candle') || base.startsWith('Level test')) {
    return `This candle matters because it is the market's immediate response at the level. Even if the rejection is not dramatic yet, the fact that price is pausing and reacting where it should is useful context. The next candle tells us whether this is genuine defense or only a temporary stall.`;
  }
  if (base.startsWith('Breakout')) {
    return `This is labeled a breakout candle because price has not only touched the boundary, it has pushed away from it with a meaningful body. The larger the body relative to the full candle range, the more conviction there is behind the move. What the mentor wants the user to notice is whether this is true expansion or just a weak poke beyond the level.`;
  }
  if (base.includes('pullback') || base.startsWith('Trend resuming')) {
    return `This is the continuation trigger because the retracement appears to be ending and price is trying to rotate back with the trend. A good pullback entry happens after structure stays intact, the retracement reaches a sensible value area, and momentum starts to return in the trend direction. The mentor is teaching patience here: wait for the pullback to prove it is finished.`;
  }
  if (base.startsWith('Stop hunt wick')) {
    return `This wick is important because it shows the sweep itself, not just the reversal after it. Price ran into an obvious stop area, triggered those clustered orders, and then quickly rejected the move. That sequence is what makes it a liquidity event rather than a normal breakout.`;
  }
  if (base.startsWith('Displacement')) {
    return `This is the confirmation candle after the sweep. Displacement matters because it shows price did not simply bounce a little; it left the swept area with urgency and direction. That shift from sweep to expansion is what gives the entry real context.`;
  }
  if (base.startsWith('Boundary bounce') || base.startsWith('Boundary rejection')) {
    return `This is the range trigger because price has reached the edge of the range and visibly reacted away from it. In a range, the strongest trades usually come from seeing the market reject a boundary that has already proven itself. The move becomes more trustworthy when the candle closes back inside the range instead of hovering on the edge.`;
  }

  if (method === 'liquidity') {
    return `This confluence matters in the liquidity method because the setup depends on price interacting with an obvious stop area, sweeping it, and then reclaiming the level with intent. The mentor is highlighting the specific clue that makes this a trap-and-reverse pattern rather than a normal continuation.`;
  }
  if (method === 'pullback' || method === 'trend' || method === 'flag_continuation' || method === 'structure_continuation') {
    return `This confluence matters because continuation setups need two things at the same time: trend structure must stay intact, and the pullback must show signs of ending in a sensible value area. The mentor is calling out the feature that helps confirm both.`;
  }
  if (method === 'support_resistance') {
    return `This confluence matters because support and resistance are only useful when the market actually respects them. The mentor is highlighting the clue that shows participants are defending the level rather than letting price drift straight through it.`;
  }
  if (method === 'breakout' || method === 'range_breakout') {
    return `This confluence matters because breakout trades only work well when the market has first compressed, then expanded with real intent. The mentor is showing the feature that suggests the move is escaping balance instead of faking out.`;
  }
  if (method === 'range') {
    return `This confluence matters because range trading is about reacting at proven edges, not guessing in the middle. The mentor is showing the evidence that the current edge is still being respected.`;
  }

  return `This is a meaningful confluence because it adds evidence to the idea already forming on the chart. The mentor is highlighting it so the user can learn not just where price is, but why that location matters to the trade thesis.`;
}

function _mentorResolveBubblePlacement(ctx, d, opts){
  const {
    anchorX, anchorY, bubbleW, bubbleH, chartLeft, chartRight, chartTop, chartBottom,
    preferBottom, tryBandFn
  } = opts;

  if (_mentorGetBubbleRect(d) && Number.isFinite(d.bubbleOffsetX) && Number.isFinite(d.bubbleOffsetY)) {
    const bubbleX = Math.max(chartLeft, Math.min(chartRight - bubbleW, anchorX + d.bubbleOffsetX));
    const bubbleY = Math.max(chartTop, Math.min(chartBottom - bubbleH, anchorY + d.bubbleOffsetY));
    return { bubbleX, bubbleY, useBottom: bubbleY >= anchorY };
  }

  let pl = tryBandFn(preferBottom) || tryBandFn(!preferBottom);
  if (!pl) {
    const col = (ctx._placedBubbles?.length || 0) % 3;
    const row = Math.floor((ctx._placedBubbles?.length || 0) / 3);
    const fallbackX = Math.max(chartLeft, Math.min(chartRight - bubbleW, anchorX - bubbleW / 2 + (col - 1) * (bubbleW + 10)));
    const fallbackY = Math.min(chartBottom - bubbleH, Math.max(chartTop, chartBottom - Math.max(bubbleH + 12, (chartBottom - chartTop) * 0.22) + row * (bubbleH + 5)));
    pl = { bubbleX: fallbackX, bubbleY: fallbackY, useBottom: true };
  }

  const bubbleX = pl.bubbleX ?? pl.bX ?? pl.bXb;
  const bubbleY = pl.bubbleY ?? pl.bY;
  return { bubbleX, bubbleY, useBottom: !!pl.useBottom };
}

// ── Drawing hit test ──────────────────────────────────────────────────────────
function hitTest(d, sx, sy){
  if(!_barX||!_py) return false;
  const TOL = 8;
  switch(d.type){
    case 'hline': case 'hray':{
      return Math.abs(sy - _py(d.price)) < TOL;
    }
    case 'vline':{
      return Math.abs(sx - _barX(d.bar)) < TOL;
    }
    case 'line':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      return ptSegDist(sx,sy,x1,y1,x2,y2) < TOL;
    }
    case 'ray':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      const angle=Math.atan2(y2-y1,x2-x1);
      const ex=x1+Math.cos(angle)*_drawW*4, ey=y1+Math.sin(angle)*_drawW*4;
      return ptSegDist(sx,sy,x1,y1,ex,ey) < TOL;
    }
    case 'rect':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      const minX=Math.min(x1,x2)-TOL,maxX=Math.max(x1,x2)+TOL;
      const minY=Math.min(y1,y2)-TOL,maxY=Math.max(y1,y2)+TOL;
      // hit border or interior
      return sx>minX&&sx<maxX&&sy>minY&&sy<maxY;
    }
    case 'fib':{
      const x1=_barX(d.bar1),x2=_barX(d.bar2);
      const range=d.price1-d.price2;
      const inX = sx>=Math.min(x1,x2)-TOL && sx<=Math.max(x1,x2)+TOL;
      return inX && [0,0.236,0.382,0.5,0.618,0.786,1].some(lv=>
        Math.abs(sy-_py(d.price2+range*lv))<TOL
      );
    }
    case 'text':{
      const x=_barX(d.bar),y=_py(d.price);
      const w = (d.text||'').length*7+16;
      return sx>x-4&&sx<x+w&&sy>y-16&&sy<y+4;
    }
    case 'mentor_arrow':{
      if (_mentorBubbleHit(d, sx, sy)) return true;
      const ax=_barX(d.bar), ay=_py(d.price);
      const arrLen=40, isDown=d.pointing!=='up';
      const tipY=ay+(isDown?-8:8), tailY=tipY+(isDown?-arrLen:arrLen);
      return Math.abs(sx-ax)<12 && sy>=Math.min(tipY,tailY)-5 && sy<=Math.max(tipY,tailY)+5;
    }
    case 'mentor_box':{
      if (_mentorBubbleHit(d, sx, sy)) return true;
      const bx1=_barX(d.bar1),bx2=_barX(d.bar2);
      const by1=_py(d.priceHigh),by2=_py(d.priceLow);
      return sx>=Math.min(bx1,bx2)-barWidth && sx<=Math.max(bx1,bx2)+barWidth &&
             sy>=Math.min(by1,by2)-10 && sy<=Math.max(by1,by2)+10;
    }
    case 'mentor_label':{
      const lax=_barX(d.bar),lay=_py(d.price);
      return Math.abs(sx-lax)<barWidth*3 && Math.abs(sy-lay)<30;
    }
    case 'long': case 'short':{
      const ex=_barX(d.bar), ey=_py(d.price);
      const hb=effectiveHalfBars(d);
      const bx=d.isMentorExample?ex:ex-hb*barWidth, w=d.isMentorExample?hb*barWidth:hb*2*barWidth;
      const sly=_py(d.sl), tpy=_py(d.tp);
      const minY=Math.min(ey,sly,tpy)-TOL, maxY=Math.max(ey,sly,tpy)+TOL;
      return sx>bx-TOL&&sx<bx+w+TOL&&sy>minY&&sy<maxY;
    }
    case 'pitchfork':{
      if(!d.pts||d.pts.length<3) return false;
      const pts=d.pts;
      const p0x=_barX(pts[0].bar),p0y=_py(pts[0].price);
      const p1x=_barX(pts[1].bar),p1y=_py(pts[1].price);
      const p2x=_barX(pts[2].bar),p2y=_py(pts[2].price);
      const midX=(p1x+p2x)/2, midY=(p1y+p2y)/2;
      return ptSegDist(sx,sy,p0x,p0y,midX,midY)<TOL ||
             ptSegDist(sx,sy,p0x,p0y,p1x,p1y)<TOL ||
             ptSegDist(sx,sy,p0x,p0y,p2x,p2y)<TOL;
    }
    case 'measure':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      const minX=Math.min(x1,x2)-TOL,maxX=Math.max(x1,x2)+TOL;
      const minY=Math.min(y1,y2)-TOL,maxY=Math.max(y1,y2)+TOL;
      return sx>minX&&sx<maxX&&sy>minY&&sy<maxY;
    }
    case 'extline':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      return ptSegDist(sx,sy,x1,y1,x2,y2) < TOL;
    }
    case 'channel':{
      if(!d.bar2||!d.price3) return false;
      const x1=_barX(d.bar1),y1=_py(d.price1);
      const x2=_barX(d.bar2),y2=_py(d.price2);
      const y3=_py(d.price3);
      const offsetY=y3-y1;
      // hit top line, parallel line, or inside fill
      const onLine1=ptSegDist(sx,sy,x1,y1,x2,y2)<TOL;
      const onLine2=ptSegDist(sx,sy,x1,y1+offsetY,x2,y2+offsetY)<TOL;
      const minY=Math.min(y1,y1+offsetY)-TOL, maxY=Math.max(y1,y1+offsetY)+TOL;
      const inFill=sx>=Math.min(x1,x2)-TOL&&sx<=Math.max(x1,x2)+TOL&&sy>=minY&&sy<=maxY;
      return onLine1||onLine2||inFill;
    }
    case 'pricerange':{
      const y1=_py(d.price1), y2=_py(d.price2);
      return sy>=Math.min(y1,y2)-TOL && sy<=Math.max(y1,y2)+TOL;
    }
    case 'fibext':{
      const x1=_barX(d.bar1),x2=_barX(d.bar2);
      const range=d.price1-d.price2;
      const inX = sx>=Math.min(x1,x2)-TOL && sx<=Math.max(x1,x2)+TOL;
      return inX && [0,0.236,0.382,0.5,0.618,0.786,1,1.272,1.414,1.618,2,2.618].some(lv=>
        Math.abs(sy-_py(d.price2+range*lv))<TOL
      );
    }
    case 'arrow':{
      const ax=_barX(d.bar), ay=_py(d.price);
      return Math.hypot(sx-ax, sy-ay) < 20;
    }
  }
  return false;
}

// ── Get resize handles for a drawing ─────────────────────────────────────────
function getHandles(d){
  if(!_barX||!_py) return [];
  switch(d.type){
    case 'line': case 'ray': case 'measure':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      return [
        {id:'p1',  x:x1, y:y1, cur:'crosshair'},
        {id:'mid', x:(x1+x2)/2, y:(y1+y2)/2, cur:'move'},
        {id:'p2',  x:x2, y:y2, cur:'crosshair'},
      ];
    }
    case 'fib':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      return [
        {id:'p1',  x:x1, y:y1, cur:'crosshair'},
        {id:'mid', x:(x1+x2)/2, y:(y1+y2)/2, cur:'move'},
        {id:'p2',  x:x2, y:y2, cur:'crosshair'},
      ];
    }
    case 'rect':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      const minX=Math.min(x1,x2),maxX=Math.max(x1,x2);
      const minY=Math.min(y1,y2),maxY=Math.max(y1,y2);
      return [
        {id:'tl',  x:minX, y:minY, cur:'nwse-resize'},
        {id:'tr',  x:maxX, y:minY, cur:'nesw-resize'},
        {id:'br',  x:maxX, y:maxY, cur:'nwse-resize'},
        {id:'bl',  x:minX, y:maxY, cur:'nesw-resize'},
        {id:'mid', x:(minX+maxX)/2, y:(minY+maxY)/2, cur:'move'},
      ];
    }
    case 'hline': case 'hray':{
      const y=_py(d.price);
      return [{id:'price', x:_drawW/2, y:y, cur:'ns-resize'}];
    }
    case 'vline':{
      const x=_barX(d.bar);
      return [{id:'bar', x:x, y:_drawH/2, cur:'ew-resize'}];
    }
    case 'text':
      return [{id:'p1', x:_barX(d.bar), y:_py(d.price), cur:'move'}];
    case 'mentor_arrow': {
      const bubble = _mentorGetBubbleRect(d);
      if (bubble) return [{ id:'bubble', x:bubble.x + bubble.w / 2, y:bubble.y + bubble.h / 2, cur:'move' }];
      return [{ id:'p1', x:_barX(d.bar), y:_py(d.price), cur:'move' }];
    }
    case 'mentor_box': {
      const bubble = _mentorGetBubbleRect(d);
      if (bubble) return [{ id:'bubble', x:bubble.x + bubble.w / 2, y:bubble.y + bubble.h / 2, cur:'move' }];
      return [{ id:'mid', x:(_barX(d.bar1)+_barX(d.bar2))/2, y:(_py(d.priceHigh)+_py(d.priceLow))/2, cur:'move' }];
    }
    case 'long': case 'short':{
      const ex=_barX(d.bar), ey=_py(d.price);
      const hb=effectiveHalfBars(d);
      const bx=d.isMentorExample?ex:ex-hb*barWidth, w=d.isMentorExample?hb*barWidth:hb*2*barWidth;
      const sly=_py(d.sl), tpy=_py(d.tp);
      const boxTop=Math.min(ey,sly,tpy), boxBot=Math.max(ey,sly,tpy);
      const midY=(boxTop+boxBot)/2;
      return [
        {id:'entry', x:bx+w/2,    y:ey,   cur:'move'},
        {id:'sl',    x:bx+w*0.75, y:sly,  cur:'ns-resize'},
        {id:'tp',    x:bx+w*0.75, y:tpy,  cur:'ns-resize'},
        {id:'left',  x:bx,        y:midY, cur:'ew-resize'},
        {id:'right', x:bx+w,      y:midY, cur:'ew-resize'},
      ];
    }
    case 'pitchfork':{
      if(!d.pts||d.pts.length<3) return [];
      return d.pts.map((p,i)=>({id:'pt'+i, x:_barX(p.bar), y:_py(p.price), cur:'crosshair'}));
    }
    case 'extline': case 'fibext':{
      const x1=_barX(d.bar1),y1=_py(d.price1),x2=_barX(d.bar2),y2=_py(d.price2);
      return [
        {id:'p1',  x:x1, y:y1, cur:'crosshair'},
        {id:'mid', x:(x1+x2)/2, y:(y1+y2)/2, cur:'move'},
        {id:'p2',  x:x2, y:y2, cur:'crosshair'},
      ];
    }
    case 'channel':{
      if(!d.bar2||d.price3===undefined) return [];
      return [
        {id:'p1',     x:_barX(d.bar1), y:_py(d.price1), cur:'crosshair'},
        {id:'p2',     x:_barX(d.bar2), y:_py(d.price2), cur:'crosshair'},
        {id:'offset', x:_barX(d.bar1), y:_py(d.price3), cur:'ns-resize'},
      ];
    }
    case 'pricerange':{
      return [
        {id:'price1', x:_drawW/2, y:_py(d.price1), cur:'ns-resize'},
        {id:'price2', x:_drawW/2, y:_py(d.price2), cur:'ns-resize'},
      ];
    }
    case 'arrow':
      return [{id:'p1', x:_barX(d.bar), y:_py(d.price), cur:'move'}];
    default: return [];
  }
}

// ── Hit test a specific handle ────────────────────────────────────────────────
function hitTestHandle(d, sx, sy){
  const TOL = 11;
  for(const h of getHandles(d)){
    if(Math.hypot(sx-h.x, sy-h.y) < TOL) return h.id;
  }
  return null;
}

function ptSegDist(px,py,ax,ay,bx,by){
  const dx=bx-ax,dy=by-ay;
  if(dx===0&&dy===0) return Math.hypot(px-ax,py-ay);
  const t=Math.max(0,Math.min(1,((px-ax)*dx+(py-ay)*dy)/(dx*dx+dy*dy)));
  return Math.hypot(px-ax-t*dx,py-ay-t*dy);
}

// Returns true if drawing d is entirely or partially within screen rect
function drawingInRect(d, minX, maxX, minY, maxY){
  if(!_barX||!_py) return false;
  function inRect(x,y){ return x>=minX&&x<=maxX&&y>=minY&&y<=maxY; }
  switch(d.type){
    case 'hline': case 'hray': return _py(d.price)>=minY && _py(d.price)<=maxY;
    case 'vline': return _barX(d.bar)>=minX && _barX(d.bar)<=maxX;
    case 'line': case 'ray': case 'fib': case 'measure':
      return inRect(_barX(d.bar1),_py(d.price1)) || inRect(_barX(d.bar2),_py(d.price2));
    case 'rect':
      return inRect(_barX(d.bar1),_py(d.price1)) || inRect(_barX(d.bar2),_py(d.price2));
    case 'text':
      return inRect(_barX(d.bar),_py(d.price));
    case 'long': case 'short':{
      const ex=_barX(d.bar), ey=_py(d.price);
      return inRect(ex,ey) || inRect(ex,_py(d.sl)) || inRect(ex,_py(d.tp));
    }
    case 'pitchfork':
      return d.pts && d.pts.some(p=>inRect(_barX(p.bar),_py(p.price)));
    case 'extline': case 'fibext':
      return inRect(_barX(d.bar1),_py(d.price1)) || inRect(_barX(d.bar2),_py(d.price2));
    case 'channel':
      return inRect(_barX(d.bar1),_py(d.price1)) || inRect(_barX(d.bar2),_py(d.price2));
    case 'pricerange':
      return (_py(d.price1)>=minY&&_py(d.price1)<=maxY) || (_py(d.price2)>=minY&&_py(d.price2)<=maxY);
    case 'arrow':
      return inRect(_barX(d.bar),_py(d.price));
    default: return false;
  }
}

// ── Drawing canvas handler (called from setupEvents mousedown/move/up) ────────
function handleDrawMousedown(sx, sy, e){
  // ── CTRL+DRAG: marquee selection ───────────────────────────────────────────
  if(e.ctrlKey || e.metaKey){
    isMarquee = true;
    marqueeX0 = marqueeX1 = sx;
    marqueeY0 = marqueeY1 = sy;
    selectedDrawing  = null;
    selectedDrawings = [];
    e.preventDefault(); e.stopPropagation();
    draw(); return true;
  }

  // ── CURSOR MODE: select, drag, resize ──────────────────────────────────────
  if(activeTool === 'cursor'){
    // First check: are we clicking a handle on the selected drawing?
    if(selectedDrawing){
      const hid = hitTestHandle(selectedDrawing, sx, sy);
      if(hid){
        isResizingDrawing = true;
        resizeHandle      = hid;
        dragStartBar      = _xToBar ? _xToBar(sx) : 0;
        dragStartPrice    = _yToPrice ? _yToPrice(sy) : 0;
        dragStartX        = sx;
        dragStartY        = sy;
        dragSnapshot      = JSON.parse(JSON.stringify(selectedDrawing));
        e.preventDefault(); e.stopPropagation();
        return true;
      }
    }
    // Check: clicking any drawing body to select + start drag
    for(let i=drawings.length-1; i>=0; i--){
      if(hitTest(drawings[i], sx, sy)){
        selectedDrawing   = drawings[i];
        const bubbleDrag = (drawings[i].type==='mentor_arrow' || drawings[i].type==='mentor_box') && _mentorBubbleHit(drawings[i], sx, sy);
        isDraggingDrawing = !bubbleDrag;
        isResizingDrawing = bubbleDrag;
        resizeHandle      = bubbleDrag ? 'bubble' : null;
        dragStartBar      = _xToBar ? _xToBar(sx) : 0;
        dragStartPrice    = _yToPrice ? _yToPrice(sy) : 0;
        dragStartX        = sx;
        dragStartY        = sy;
        dragSnapshot      = JSON.parse(JSON.stringify(selectedDrawing));
        // If user clicks a long/short drawing, make it the active analysis target
        // Skip the popup for AI mentor examples and temporary refinement suggestions
        if((drawings[i].type==='long'||drawings[i].type==='short') && drawings[i]!==_tapDrawing && !drawings[i].isMentorExample && !drawings[i]._tapRefinement){
          _tapDrawing = drawings[i];
          showTradeAnalysisPopup(drawings[i], false); // re-open with this drawing's lock
        }
        e.preventDefault(); e.stopPropagation();
        draw(); return true;
      }
    }
    // Click on empty area: deselect
    selectedDrawing = null;
    draw();
    return false;
  }

  const mc = _el('main-canvas');
  e.preventDefault(); e.stopPropagation();

  if(activeTool==='eraser'){
    const hit = drawings.find(d=>hitTest(d,sx,sy));
    if(hit){ drawings=drawings.filter(d=>d!==hit); saveDrawings(curSym.s,curTF); draw(); }
    return true;
  }

  if(activeTool==='text'){
    const { bar, price } = screenToDraw(sx, sy);
    const txt = prompt('Enter label text:','');
    if(txt){ drawings.push({type:'text',bar,price,text:txt}); saveDrawings(curSym.s,curTF); draw(); }
    setTool('cursor');
    return true;
  }

  if(activeTool==='arrow'){
    const bar=Math.round(pxToBar(sx));
    const price=pxToPrice(sy);
    const label=prompt('Arrow label (optional):','');
    drawings.push({type:'arrow',bar,price,pointing:sy<H/2?'down':'up',label:label||'',color:drawingColor});
    saveDrawings(curSym.s,curTF);
    draw(); return true;
  }

  if(activeTool==='hline'){
    const { price } = screenToDraw(sx, sy);
    drawings.push({type:'hline',price,color:drawingColor,ls:drawingLineStyle,lw:drawingLineWidth}); saveDrawings(curSym.s,curTF); draw(); return true;
  }
  if(activeTool==='vline'){
    const { bar } = screenToDraw(sx, sy);
    drawings.push({type:'vline',bar,color:drawingColor,ls:drawingLineStyle,lw:drawingLineWidth}); saveDrawings(curSym.s,curTF); draw(); return true;
  }

  if(activeTool==='pitchfork'){
    const {bar,price}=screenToDraw(sx,sy);
    if(pitchforkStage===0){
      drawingWIP = {type:'pitchfork', pts:[{bar,price}]};
      pitchforkStage=1;
    } else if(pitchforkStage===1){
      drawingWIP.pts.push({bar,price});
      pitchforkStage=2;
    } else if(pitchforkStage===2){
      drawingWIP.pts.push({bar,price});
      drawings.push(JSON.parse(JSON.stringify(drawingWIP))); saveDrawings(curSym.s,curTF);
      drawingWIP=null; pitchforkStage=0; setTool('cursor');
    }
    draw(); return true;
  }

  if(activeTool==='channel'){
    const bar=Math.round(pxToBar(sx));
    const price=pxToPrice(sy);
    if(channelStage===0){
      drawingWIP={type:'channel',bar1:bar,price1:price,bar2:bar,price2:price,price3:price,color:drawingColor,ls:drawingLineStyle,lw:drawingLineWidth};
      channelStage=1;
    } else if(channelStage===1){
      drawingWIP.bar2=bar; drawingWIP.price2=price;
      channelStage=2;
    } else {
      drawingWIP.price3=price;
      drawings.push(drawingWIP);
      saveDrawings(curSym.s,curTF);
      drawingWIP=null; channelStage=0;
      draw(); return true;
    }
    draw(); return true;
  }

  if(activeTool==='long'||activeTool==='short'){
    const { bar, price } = screenToDraw(sx, sy);
    
    // Check if we're in mentor mode with future data available
    let sl, tp, halfBars, halfDuration;
    const isMentorMode = typeof mentorState !== 'undefined' && mentorState.enabled && mentorState.waitingForUserTrade;
    const hasFutureData = curData && bar < curData.length - 20;
    
    if (isMentorMode && hasFutureData) {
      // AI MENTOR MODE: Use future data to calculate PERFECT winning trade levels
      console.log('🔮 AI Mentor: Using future data for perfect trade placement');
      
      const futureCandles = curData.slice(bar + 1, Math.min(bar + 31, curData.length));
      let highestHigh = price;
      let lowestLow = price;
      
      for (let i = 0; i < futureCandles.length; i++) {
        const candle = futureCandles[i];
        if (candle.high > highestHigh) highestHigh = candle.high;
        if (candle.low < lowestLow) lowestLow = candle.low;
      }
      
      if (activeTool === 'long') {
        // For LONG: SL below lowest wick, TP at peak
        sl = Math.min(lowestLow * 0.998, price * 0.995);
        tp = highestHigh * 0.998;
      } else {
        // For SHORT: SL above highest wick, TP at valley
        sl = Math.max(highestHigh * 1.002, price * 1.005);
        tp = lowestLow * 1.002;
      }
      
      console.log('🔮 AI-calculated perfect levels:', { 
        entry: price.toFixed(2), 
        sl: sl.toFixed(2), 
        tp: tp.toFixed(2),
        direction: activeTool 
      });
    } else {
      // NORMAL MODE: Use timeframe-aware width and ATR-based levels
      const defaultTrade = buildTimeframeAwareTradeTool(activeTool, price, Math.round(bar), curTF);
      sl = defaultTrade.sl;
      tp = defaultTrade.tp;
      halfBars = defaultTrade.halfBars;
      halfDuration = defaultTrade.halfDuration;
    }
    if(!halfBars || !halfDuration){
      const defaultTrade = buildTimeframeAwareTradeTool(activeTool, price, Math.round(bar), curTF);
      halfBars = defaultTrade.halfBars;
      halfDuration = defaultTrade.halfDuration;
    }
    // Give each drawing a unique ID so locks are per-drawing not per-symbol
    const drawingId = 'draw_' + Date.now() + '_' + Math.random().toString(36).slice(2,6);
    const drawing = {type:activeTool,bar,price,sl,tp,halfBars,halfDuration,tf:curTF,id:drawingId};
    drawings.push(drawing);
    saveDrawings(curSym.s, curTF);
    draw(); setTool('cursor');
    
    // Intercept drawing if we are in "Let Me Try It" mode
    if (typeof mentorState !== 'undefined' && mentorState.waitingForUserTrade) {
      mentorState.waitingForUserTrade = false;
      mentorState.exampleTrade = {
        type: 'user_placement',
        direction: activeTool,
        entry: price,
        stopLoss: sl,
        takeProfit: tp,
        riskReward: Math.abs(tp - price) / Math.abs(price - sl),
        timestamp: bar,
        isUserGuided: true
      };
      mentorState.exampleTradeActive = true;
      mentorState.tradeMonitoringUpdates = [];
      
      mentorState.lockedQuestion = "Monitoring your trade. Watching position...";
      updateLockedMentorUI();
      
      console.log('🎯 User guided trade activated:', mentorState.exampleTrade);
      return true;
    }
    
    showTradeAnalysisPopup(drawing, true); // freshPlacement=true — don't restore old lock
    return true;
  }

  // two-click tools
  const { bar, price } = screenToDraw(sx, sy);
  drawingWIP = {type:activeTool, bar1:bar, price1:price, bar2:bar, price2:price, color:drawingColor, ls:drawingLineStyle, lw:drawingLineWidth};
  return true;
}

function handleDrawMousemove(sx, sy){
  // ── Marquee selection drag ──────────────────────────────────────────────────
  if(isMarquee){
    marqueeX1 = sx;
    marqueeY1 = sy;
    draw(); return;
  }

  // ── Resizing a handle ───────────────────────────────────────────────────────
  if(isResizingDrawing && selectedDrawing && dragSnapshot){
    const bar   = _xToBar   ? _xToBar(sx)   : 0;
    const price = _yToPrice ? _yToPrice(sy)  : 0;
    const d = selectedDrawing;
    const s = dragSnapshot;
    const dBar=bar-dragStartBar, dPrice=price-dragStartPrice;
    const dX = sx - dragStartX, dY = sy - dragStartY;
    switch(d.type){
      case 'line': case 'ray': case 'fib': case 'measure':
        if(resizeHandle==='p1'){ d.bar1=bar; d.price1=price; }
        else if(resizeHandle==='p2'){ d.bar2=bar; d.price2=price; }
        else{ d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar; d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; }
        break;
      case 'rect':{
        const x1=_barX(s.bar1),y1=_py(s.price1),x2=_barX(s.bar2),y2=_py(s.price2);
        const minX=Math.min(x1,x2),maxX=Math.max(x1,x2),minY=Math.min(y1,y2),maxY=Math.max(y1,y2);
        if(resizeHandle==='tl'){ d.bar1=bar; d.price1=price; }
        else if(resizeHandle==='tr'){ d.bar2=bar; d.price1=price; }
        else if(resizeHandle==='br'){ d.bar2=bar; d.price2=price; }
        else if(resizeHandle==='bl'){ d.bar1=bar; d.price2=price; }
        else{ d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar; d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; }
        break;
      }
      case 'hline': case 'hray': d.price=price; break;
      case 'vline': d.bar=bar; break;
      case 'text': d.bar=bar; d.price=price; break;
      case 'mentor_arrow':
        if(resizeHandle==='bubble'){
          d.bubbleOffsetX = (s.bubbleOffsetX || 0) + dX;
          d.bubbleOffsetY = (s.bubbleOffsetY || 0) + dY;
        } else {
          d.bar=s.bar+dBar; d.price=s.price+dPrice;
        }
        break;
      case 'mentor_label': d.bar=s.bar+dBar; d.price=s.price+dPrice; break;
      case 'mentor_box':
        if(resizeHandle==='bubble'){
          d.bubbleOffsetX = (s.bubbleOffsetX || 0) + dX;
          d.bubbleOffsetY = (s.bubbleOffsetY || 0) + dY;
        } else {
          d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar;
          d.priceHigh=s.priceHigh+dPrice; d.priceLow=s.priceLow+dPrice;
        }
        break;
      case 'long': case 'short':
        if(resizeHandle==='entry'){
          d.bar=s.bar+dBar;
          d.price=s.price+dPrice;
          d.sl=s.sl+dPrice;
          d.tp=s.tp+dPrice;
        }
        else if(resizeHandle==='sl'){ d.sl=price; }
        else if(resizeHandle==='tp'){ d.tp=price; }
        else if(resizeHandle==='left'){
          // dragging left edge: right edge stays fixed, left moves
          // dBar is negative when dragging left (making wider), positive when dragging right (making narrower)
          const newHB = Math.max(2, effectiveHalfBars(s) - dBar);
          d.halfBars = newHB;
          d.halfDuration = halfBarsToSecs(newHB, curTF);
          // keep right edge fixed: rightEdge = s.bar + s.halfBars, center = rightEdge - newHB
          d.bar = s.bar + effectiveHalfBars(s) - newHB;
        }
        else if(resizeHandle==='right'){
          // dragging right edge: left edge stays fixed, right moves
          const newHB = Math.max(2, effectiveHalfBars(s) + dBar);
          d.halfBars = newHB;
          d.halfDuration = halfBarsToSecs(newHB, curTF);
          // keep left edge fixed: leftEdge = s.bar - s.halfBars, center = leftEdge + newHB
          d.bar = s.bar - effectiveHalfBars(s) + newHB;
        }
        break;
      case 'pitchfork':{
        const idx=parseInt(resizeHandle.replace('pt',''));
        if(!isNaN(idx)&&d.pts[idx]){ d.pts[idx].bar=bar; d.pts[idx].price=price; }
        break;
      }
      case 'extline': case 'fibext':{
        if(resizeHandle==='p1'){ d.bar1=bar; d.price1=price; }
        else if(resizeHandle==='p2'){ d.bar2=bar; d.price2=price; }
        else{ d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar; d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; }
        break;
      }
      case 'channel':{
        if(resizeHandle==='p1'){ d.bar1=bar; d.price1=price; }
        else if(resizeHandle==='p2'){ d.bar2=bar; d.price2=price; }
        else if(resizeHandle==='offset'){ d.price3=price; }
        else{ d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar; d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; d.price3=s.price3+dPrice; }
        break;
      }
      case 'pricerange':{
        if(resizeHandle==='price1') d.price1=price;
        else if(resizeHandle==='price2') d.price2=price;
        else{ d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; }
        break;
      }
      case 'arrow':{ d.bar=s.bar+dBar; d.price=s.price+dPrice; break; }
    }
    draw();
    if((d.type==='long'||d.type==='short') && !d._tapRefinement) tapSyncDrawingToPopup(d);
    return;
  }

  // ── Dragging whole drawing ──────────────────────────────────────────────────
  if(isDraggingDrawing && selectedDrawing && dragSnapshot){
    const bar   = _xToBar   ? _xToBar(sx)   : 0;
    const price = _yToPrice ? _yToPrice(sy)  : 0;
    const dBar   = bar   - dragStartBar;
    const dPrice = price - dragStartPrice;
    const d = selectedDrawing;
    const s = dragSnapshot;
    switch(d.type){
      case 'hline': case 'hray': d.price=s.price+dPrice; break;
      case 'vline': d.bar=s.bar+dBar; break;
      case 'line': case 'ray': case 'fib': case 'rect': case 'measure':
      case 'extline': case 'fibext':
        d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar;
        d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; break;
      case 'channel':
        d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar;
        d.price1=s.price1+dPrice; d.price2=s.price2+dPrice;
        d.price3=s.price3+dPrice; break;
      case 'pricerange': d.price1=s.price1+dPrice; d.price2=s.price2+dPrice; break;
      case 'arrow': d.bar=s.bar+dBar; d.price=s.price+dPrice; break;
      case 'text': d.bar=s.bar+dBar; d.price=s.price+dPrice; break;
      case 'mentor_arrow':
        if (_mentorBubbleHit(d, sx, sy)) {
          d.bubbleOffsetX = (s.bubbleOffsetX || 0) + (sx - dragStartX);
          d.bubbleOffsetY = (s.bubbleOffsetY || 0) + (sy - dragStartY);
        } else {
          d.bar=s.bar+dBar; d.price=s.price+dPrice;
        }
        break;
      case 'mentor_box':
        if (_mentorBubbleHit(d, sx, sy)) {
          d.bubbleOffsetX = (s.bubbleOffsetX || 0) + (sx - dragStartX);
          d.bubbleOffsetY = (s.bubbleOffsetY || 0) + (sy - dragStartY);
        } else {
          d.bar1=s.bar1+dBar; d.bar2=s.bar2+dBar;
          d.priceHigh=s.priceHigh+dPrice; d.priceLow=s.priceLow+dPrice;
        }
        break;
      case 'long': case 'short':
        d.bar=s.bar+dBar; d.price=s.price+dPrice;
        d.sl=s.sl+dPrice; d.tp=s.tp+dPrice; break;
      case 'pitchfork':
        d.pts=s.pts.map(p=>({bar:p.bar+dBar,price:p.price+dPrice})); break;
    }
    draw();
    if((d.type==='long'||d.type==='short') && !d._tapRefinement) tapSyncDrawingToPopup(d);
    return;
  }

  if(drawingWIP?.type==='channel'){
    const bar=Math.round(pxToBar(sx));
    const price=pxToPrice(sy);
    if(channelStage===1){ drawingWIP.bar2=bar; drawingWIP.price2=price; }
    else if(channelStage===2){ drawingWIP.price3=price; }
    draw(); return;
  }

  if(!drawingWIP) return;
  const { bar, price } = screenToDraw(sx, sy);
  if(drawingWIP.type==='pitchfork'){
    // update preview: last pt tracks mouse
    const stage = drawingWIP.pts.length;
    if(stage===1) drawingWIP.pts[1]={bar,price};
    else if(stage>=2) drawingWIP.pts[2]={bar,price};
  } else {
    drawingWIP.bar2  = bar;
    drawingWIP.price2 = price;
  }
  draw();
}

function handleDrawMouseup(sx, sy){
  // ── Marquee: commit selection ───────────────────────────────────────────────
  if(isMarquee){
    isMarquee = false;
    const minX=Math.min(marqueeX0,marqueeX1), maxX=Math.max(marqueeX0,marqueeX1);
    const minY=Math.min(marqueeY0,marqueeY1), maxY=Math.max(marqueeY0,marqueeY1);
    // only select if rect is meaningful
    if(maxX-minX > 4 || maxY-minY > 4){
      selectedDrawings = drawings.filter(d => drawingInRect(d, minX, maxX, minY, maxY));
      // highlight first as primary selection too
      selectedDrawing = selectedDrawings.length===1 ? selectedDrawings[0] : null;
    }
    draw(); return;
  }

  // End drag or resize
  if(isDraggingDrawing || isResizingDrawing){
    try { saveDrawings(curSym.s, curTF); } catch(e) {}
    isDraggingDrawing = false;
    isResizingDrawing = false;
    resizeHandle = null;
    dragSnapshot = null;
    dragStartX = 0;
    dragStartY = 0;
    draw();
    return;
  }

  if(!drawingWIP) return;
  const { bar, price } = screenToDraw(sx, sy);
  drawingWIP.bar2  = bar;
  drawingWIP.price2 = price;
  // Only commit if mouse actually moved (not a click in place)
  const dist = Math.hypot(
    (_barX?_barX(drawingWIP.bar2)-_barX(drawingWIP.bar1):0),
    (_py?_py(drawingWIP.price2)-_py(drawingWIP.price1):0)
  );
  if(dist > 4){
    drawings.push({...drawingWIP});
    if(activeTool!=='measure') setTool('cursor');
  }
  drawingWIP = null;
  draw();
}

// ── Render all drawings onto the chart ───────────────────────────────────────
// ── roundRect helper (polyfill for older browsers) ───────────────────────
function roundRect(ctx, x, y, w, h, r) {
  r = Math.min(r, w / 2, h / 2);
  ctx.beginPath();
  ctx.moveTo(x + r, y);
  ctx.arcTo(x + w, y,     x + w, y + h, r);
  ctx.arcTo(x + w, y + h, x,     y + h, r);
  ctx.arcTo(x,     y + h, x,     y,     r);
  ctx.arcTo(x,     y,     x + w, y,     r);
  ctx.closePath();
}

// ── Mentor Annotation System ─────────────────────────────────────────────
// Draws arrows, highlight boxes, and label callouts on the chart at key
// setup moments. All annotations are full drawings — selectable and deletable
// by the user. Cleared per-session via clearMentorAnnotations().

let _mentorAnnotationIds = []; // track IDs so we can clear them

function clearMentorAnnotations() {
  drawings = drawings.filter(d => !d.isMentorAnnotation);
  _mentorAnnotationIds = [];
  try { saveDrawings(curSym.s, curTF); } catch(e) {}
  // Don't call draw() here — caller is responsible for redrawing
  // (avoids premature draw when called mid-annotation inside _mentorAnnotateSetup)
  if (typeof draw === 'function') draw();
}

// Silent clear — no redraw. Used internally before adding new annotations.
function _clearMentorAnnotationsSilent() {
  drawings = drawings.filter(d => !d.isMentorAnnotation);
  _mentorAnnotationIds = [];
}

// Add an arrow pointing at a specific bar/price.
// direction: 'down' (arrow points down toward candle from above) or 'up'
function _addMentorArrow(bar, price, label, direction = 'down', highlight = false, explanation = '') {
  const id = 'mentor_ann_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);
  // Anchor at the actual structural price — no ATR offset so dots sit ON the structure
  const drawing = {
    type: 'mentor_arrow',
    bar, price: price,
    pointing: direction === 'up' ? 'up' : 'down',
    label: label || '',
    explanation: explanation || '',
    highlight,
    tier: highlight ? 'primary' : 'secondary',
    id,
    isMentorAnnotation: true,
  };
  drawings.push(drawing);
  _mentorAnnotationIds.push(id);
  return id;
}

// Add a highlight box around a range of bars and price levels.
function _addMentorBox(bar1, bar2, priceLow, priceHigh, label, color) {
  const id = 'mentor_ann_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);
  // returns id so callers can attach extra data (e.g. explanation) to the drawing
  const drawing = {
    type: 'mentor_box',
    bar1, bar2,
    priceLow, priceHigh,
    label: label || '',
    color: color || '#8a2be2',
    id,
    isMentorAnnotation: true,
  };
  drawings.push(drawing);
  _mentorAnnotationIds.push(id);
  return id;
}

// Add a floating label callout next to a bar.
// lines: array of strings, joined with | for rendering
function _addMentorLabel(bar, price, lines) {
  const id = 'mentor_ann_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6);
  const drawing = {
    type: 'mentor_label',
    bar, price,
    label: Array.isArray(lines) ? lines.join(' | ') : lines,
    id,
    isMentorAnnotation: true,
  };
  drawings.push(drawing);
  _mentorAnnotationIds.push(id);
  return id;
}

// ══ MENTOR ANNOTATION ENGINE ═════════════════════════════════════════════════
// Universal, clean annotation system.
// Rules:
//   • Max 5 annotations per setup (1 context + 1 key level + 1 confluence + 1 entry + 1 objective)
//   • All anchored to real price structures (no floating)
//   • All within visible candle range (no off-screen labels)
//   • Overlap prevention via label stagger
//   • Progressive: Step1(context) → Step2(+levels) → Step3(+confluences)

// ── Confluence factor label builder ──────────────────────────────────────────
// Returns an array of {name, explanation} objects for each confluence factor
// that was counted when the setup was scored. Used to annotate each factor
// on the chart so the user can see WHY the setup qualified.
function _buildConfluenceFactors(setupDetection, data, structure, atr, dir, method) {
  const factors = [];
  const type = setupDetection.setup || setupDetection.type || method;
  const crypto = _isCrypto();
  const trend = structure?.trend || '';

  if (type === 'breakout' || type === 'range_breakout') {
    const current = data[data.length - 1];
    const bodySize = Math.abs(current.close - current.open);
    const candleRange = (current.high - current.low) || 1;
    const minBody = crypto ? 0.60 : 0.50;
    if (bodySize / candleRange >= minBody)
      factors.push({ name: 'Strong body close', explanation: `The breakout candle closed with ${Math.round(bodySize/candleRange*100)}% of its range as body — showing conviction that buyers/sellers committed to the new level, not just a temporary spike.` });
    const conso = detectConsolidation(data);
    if (current.volume > (conso?.avgVolume || 1) * (crypto ? 1.5 : 1.2))
      factors.push({ name: 'Volume spike', explanation: `Volume on the breakout candle was ${Math.round(current.volume/(conso?.avgVolume||1)*10)/10}× the consolidation average — confirming real participation, not a low-conviction false breakout.` });
    if (conso?.upperTouches >= (crypto?4:3) || conso?.lowerTouches >= (crypto?4:3))
      factors.push({ name: 'Well-tested zone', explanation: `The breakout level had ${Math.max(conso?.upperTouches||0,conso?.lowerTouches||0)} prior touches — the more times a level is tested and holds, the stronger the eventual breakout when it finally gives way.` });
    if (trend && trend !== 'neutral')
      factors.push({ name: 'Trend aligned', explanation: `The breakout is in the direction of the ${trend.replace(/_/g,' ')} — trading with the trend increases the probability that the breakout will follow through rather than snap back.` });

  } else if (type === 'flag_continuation' || type === 'structure_continuation') {
    factors.push({ name: 'Impulse + pullback', explanation: `A strong directional impulse followed by a low-volume pullback — the classic flag pattern. The impulse shows institutional conviction; the pullback is retail taking profits, creating the entry opportunity.` });
    if (trend.includes('strong'))
      factors.push({ name: 'Strong trend', explanation: `The higher-timeframe trend is ${trend.replace(/_/g,' ')} — strong trends produce the cleanest flag patterns because momentum is high and counter-moves are corrective, not reversal.` });
    const flag = detectFlagPattern(data, structure);
    if (flag?.quality === 'high')
      factors.push({ name: 'High-quality flag', explanation: `The pullback retraced ${Math.round((flag.retrace||0)*100)}% of the impulse — in the ideal 38–62% zone. A shallower pullback means weak follow-through; deeper means potential reversal. This depth is optimal.` });
    factors.push({ name: 'EMA alignment', explanation: `Price is on the correct side of the 20 EMA — a basic filter that removes counter-trend setups. When price is above EMA20 in an uptrend, the path of least resistance is up.` });

  } else if (type === 'support_bounce') {
    factors.push({ name: 'Support bounce', explanation: `Price reached an established support level and showed rejection — the foundation of S&R trading. This level has proven it attracts buyers.` });
    const sb = detectSupportBounce(data);
    if (sb?.touches >= 3)
      factors.push({ name: `${sb.touches}× tested support`, explanation: `This support level has been tested ${sb.touches} times without breaking. Each successful test strengthens the level — sellers keep trying and failing, which brings more buyers to defend it.` });
    if (trend.includes('up'))
      factors.push({ name: 'Uptrend confluence', explanation: `The larger trend is up, so bouncing from support aligns with the trend direction. Trading with the trend + from support = double confluence for a long entry.` });
    const level = sb?.supportLevel || 0;
    if (crypto && level > 0 && _isPriceRelativeRound(level))
      factors.push({ name: 'Round-number level', explanation: `Support sits near a round-number price ($${Math.round(level/1000)*1000 || level.toFixed(0)}). Round numbers attract cluster stops and pending orders from retail traders — this concentrates liquidity and reinforces the support zone.` });
    else if (sb?.touches >= 4)
      factors.push({ name: 'Highly tested level', explanation: `Four or more distinct tests that held — this is an unusually strong level. When a level holds this many times, large orders are likely protecting it.` });

  } else if (type === 'resistance_rejection') {
    factors.push({ name: 'Resistance rejection', explanation: `Price reached an established resistance level and showed clear rejection — the hallmark of an S&R short setup. This level has proven sellers defend it.` });
    const rr = detectResistanceRejection(data);
    if (rr?.touches >= 3)
      factors.push({ name: `${rr.touches}× tested resistance`, explanation: `This resistance level has held ${rr.touches} separate times. Each failed breakout attempt adds to the evidence that supply is heavy at this level.` });
    if (trend.includes('down'))
      factors.push({ name: 'Downtrend confluence', explanation: `The larger trend is down, so fading resistance aligns with the dominant direction. Selling into resistance in a downtrend is the highest-probability S&R setup.` });
    if (rr?.touches >= 4)
      factors.push({ name: 'Highly tested level', explanation: `Four or more tests of this resistance that held — an unusually strong ceiling. This many failures to break higher signals significant sell-side pressure.` });

  } else if (type === 'trend_pullback') {
    const pb = detectTrendPullback(data, structure);
    factors.push({ name: 'Trend resuming', explanation: `Price pulled back against the ${trend.replace(/_/g,' ')} trend and is now showing signs of resuming. Pullbacks in trends are buy/sell opportunities because the underlying momentum hasn't changed.` });
    if (pb?.retrace) {
      const pct = Math.round(pb.retrace * 100);
      factors.push({ name: `${pct}% Fibonacci retracement`, explanation: `The pullback retraced ${pct}% of the prior impulse. Fibonacci levels at 38%, 50%, and 62% are where trend pullbacks most often end — this hit the optimal zone, increasing the probability the trend resumes from here.` });
    }
    if (pb?.volContracting)
      factors.push({ name: 'Volume contracting', explanation: `Volume dried up during the pullback — a healthy sign. Low-volume pullbacks mean sellers aren't committed; they're just profit-taking. When volume contracts on the counter-move, the dominant buyers/sellers are still in control.` });
    if (trend.includes('strong'))
      factors.push({ name: 'Strong trend', explanation: `The underlying trend is ${trend.replace(/_/g,' ')} — strong trends produce shallower pullbacks and faster resumptions. More momentum = higher probability that the pullback is corrective, not reversal.` });

  } else if (type === 'liquidity_sweep') {
    const sw = detectLiquiditySweep(data);
    factors.push({ name: 'Stop hunt detected', explanation: `Price swept below/above a cluster of stops before reversing sharply — a liquidity sweep. Smart money engineers these moves to fill large orders at retail traders' expense.` });
    if (sw?.wickToBodyRatio > 2)
      factors.push({ name: `${Math.round(sw.wickToBodyRatio)}× rejection wick`, explanation: `The sweep candle has a wick ${Math.round(sw.wickToBodyRatio)}× its body — a textbook liquidity grab fingerprint. The larger the wick, the more stops were triggered and the more decisively price reversed.` });
    if (sw?.volumeSpike)
      factors.push({ name: 'Volume spike on sweep', explanation: `Volume spiked when the sweep wick formed — confirming real institutional order flow, not just a thin-book spike. Volume on the sweep + immediate reversal = strong evidence of smart money activity.` });
    if (trend && trend !== 'neutral')
      factors.push({ name: 'Trend aligned reversal', explanation: `The sweep reversal points back in the direction of the ${trend.replace(/_/g,' ')} — sweeps that reverse WITH the trend have the highest follow-through rate.` });
  }

  return factors.slice(0, 4); // cap at 4 factors to avoid annotation clutter
}

function _mentorAnnotateSetup(setupDetection, anchorBar, setupBar) {
  if (!curData || mentorState.annotationsEnabled === false) return;

  const method  = mentorState.selectedTradingMethod || 'breakout';
  const detBar  = Math.min(setupBar, curData.length - 1);
  const liveBar = replayMode
    ? Math.max(0, Math.min(replayCutoff, curData.length - 1))
    : Math.max(0, Math.min(anchorBar ?? detBar, curData.length - 1));

  // ── Determine current stage based on proximity to setup ──────────────────
  // Stage 1 (>25 bars away): structural context only
  // Stage 2 (≤25 bars away): + key level / zone
  // Stage 3 (≤12 bars away): + entry signal
  const barsAway    = Math.max(0, setupBar - liveBar);
  const curStage    = barsAway > 25 ? 1 : barsAway > 12 ? 2 : 3;

  // ── Cache check: serve cached drawings if stage hasn't advanced ──────────
  // This ensures annotations NEVER disappear when scrolling back.
  // We only recompute when curStage advances beyond what's cached.
  const cache = mentorState._annCache;
  if (cache && cache.setupBar === setupBar && cache.method === method) {
    if (curStage <= cache.stage) {
      // Stage hasn't advanced — restore cached drawings and return
      const existingIds = new Set(drawings.filter(d => d.isMentorAnnotation).map(d => d.id));
      let restored = false;
      for (const cd of cache.drawings) {
        if (!existingIds.has(cd.id)) {
          drawings.push(cd);
          _mentorAnnotationIds.push(cd.id);
          restored = true;
        }
      }
      if (restored) draw();
      return;
    }
    // Stage advanced — fall through to recompute with the new stage
  }

  // ── Compute fresh annotations for the current stage ───────────────────────
  _clearMentorAnnotationsSilent();
  mentorState._lastAnnStateKey = `${setupBar}_${method}`;

  const dir          = setupDetection.direction || 'long';
  const detectionBar = detBar;
  // visibleUpTo anchored to detectionBar so price ranges are stable
  const visibleUpTo  = Math.min(detectionBar, liveBar);

  if (visibleUpTo < 10) return;

  const data      = curData.slice(0, visibleUpTo + 1);
  const structure = analyzeMarketStructure(data);
  const atr       = calculateATR(visibleUpTo, 14) || (curData[visibleUpTo]?.close * 0.005) || 1;

  // Price range bounds for annotation placement
  const visSlice  = curData.slice(Math.max(0, visibleUpTo - 60), visibleUpTo + 1);
  const rangeHigh = Math.max(...visSlice.map(b => b.high));
  const rangeLow  = Math.min(...visSlice.map(b => b.low));
  const histFrom  = Math.max(0, visibleUpTo - 60);

  function inRange(p) { return Number.isFinite(p) && p >= rangeLow - atr && p <= rangeHigh + atr; }
  function isVis(b)   { return Number.isFinite(b) && b >= 0 && b <= visibleUpTo; }

  // Progressive reveal — unlocks as user steps closer to the setup
  const showLevels = curStage >= 2; // key level/zone appears at ≤25 bars away
  const showConf   = curStage >= 3; // entry signal appears at ≤12 bars away

  // max annotations: 2 at stage 1, 3 at stage 2, 4 at stage 3
  const ann = [];
  // stageCandle must be <= replayCutoff so _commit doesn't filter annotations out
  const stageCandle = visibleUpTo;

  function addZone(f, t, price, label, pri, explanation) {
    const max = showConf ? 4 : 3;
    if (ann.filter(a=>a.type!=='context').length >= max || !inRange(price)) return;
    const fb = Math.max(0,f), tb = Math.min(visibleUpTo+5,t);
    if (!isVis(fb) || fb >= tb) return;
    ann.push({ type:'zone', f:fb, t:tb, price, label, pri:pri||2, candleIndex:stageCandle, explanation:explanation||'' });
  }
  function addBox(f, t, lo, hi, label, pri, explanation) {
    const max = showConf ? 4 : 3;
    if (ann.filter(a=>a.type!=='context').length >= max) return;
    const fb = Math.max(0,f), tb = Math.min(visibleUpTo+5,t);
    const cl = Math.max(lo, rangeLow - atr*0.3);
    const ch = Math.min(hi, rangeHigh + atr*0.3);
    if (!isVis(fb) || fb >= tb || cl >= ch) return;
    ann.push({ type:'box', f:fb, t:tb, lo:cl, hi:ch, label, pri:pri||2, candleIndex:stageCandle, explanation:explanation||'' });
  }
  // historical=true: uses bar as its own candleIndex (appears when replay reaches that bar)
  // and doesn't count against the structural annotation limit.
  function addArrow(bar, price, label, pointing, highlight, pri, explanation, historical = false) {
    if (!isVis(bar) || !inRange(price)) return;
    if (!historical) {
      const max = showConf ? 4 : 3;
      if (ann.filter(a=>a.type!=='context').length >= max) return;
    }
    const ci = historical ? bar : stageCandle;
    ann.push({ type:'arrow', bar, price, label, pointing, highlight:!!highlight, pri:pri||2, candleIndex:ci, explanation:explanation||'' });
  }

  // ── Find significant swing points ─────────────────────────────────────────
  function findMajorSwings(type) {
    const strength = 3, minSize = atr * 1.5;
    const raw = [];
    for (let i = histFrom+strength; i <= visibleUpTo-strength; i++) {
      const c = curData[i]; if (!c) continue;
      let ok = true;
      for (let j=1; j<=strength; j++) {
        const p=curData[i-j], n=curData[i+j]; if (!p||!n){ok=false;break;}
        if (type==='high'?(p.high>=c.high||n.high>=c.high):(p.low<=c.low||n.low<=c.low)){ok=false;break;}
      }
      if (!ok) continue;
      const price = type==='high' ? c.high : c.low;
      if (!inRange(price)) continue;
      const adj1 = type==='high' ? Math.max(...[1,2,3].map(j=>curData[i-j]?.low||0))
                                 : Math.min(...[1,2,3].map(j=>curData[i-j]?.high||Infinity));
      const adj2 = type==='high' ? Math.max(...[1,2,3].map(j=>curData[i+j]?.low||0))
                                 : Math.min(...[1,2,3].map(j=>curData[i+j]?.high||Infinity));
      const prom = type==='high' ? price - Math.max(adj1,adj2) : Math.min(adj1,adj2) - price;
      if (prom < minSize) continue;
      raw.push({ bar:i, price, prominence:prom });
    }
    const out = [];
    for (const sw of raw) {
      const last = out[out.length-1];
      if (last && sw.bar - last.bar < 6) { if (sw.prominence > last.prominence) out[out.length-1] = sw; }
      else out.push(sw);
    }
    return out;
  }
  const swingH = findMajorSwings('high');
  const swingL = findMajorSwings('low');


  // ══════════════════════════════════════════════════════════════════════════
  // STAGE 1 — MARKET CONTEXT
  // Structural swing annotations. Only shown for trend/pullback methods where
  // the swing sequence IS the primary confluence. Breakout, liquidity, range,
  // and S&R methods show their own structural context in Stage 2.
  // ══════════════════════════════════════════════════════════════════════════
  const _methodNeedsSwingContext = method === 'trend' || method === 'pullback' ||
    method === 'flag_continuation' || method === 'structure_continuation';
    // Note: support_resistance intentionally excluded — S&R is about price levels,
    // not swing sequences. Level touches are shown in Stage 2 instead.
  if (_methodNeedsSwingContext) {
    const tUp = structure.trend?.includes('up');
    const tDn = structure.trend?.includes('down');
    const ctxSwings = (dir==='long' ? swingL : swingH);

    // Show the two most recent structural swings — together they prove the trend
    const sw1 = ctxSwings.slice(-1)[0];
    const sw2 = ctxSwings.slice(-2)[0];

    if (sw1) {
      const lbl = tUp && dir==='long'  ? 'Higher low'
                : tDn && dir==='short' ? 'Lower high'
                : dir==='long'  ? 'Swing low' : 'Swing high';
      addArrow(sw1.bar, sw1.price, lbl,
        dir==='long'?'up':'down', false, 3,
        tUp&&dir==='long'  ? `Higher low at ${fP(sw1.price)} — price made a higher low here, confirming the uptrend. Buyers stepped in before the previous low, showing increasing demand.`
        : tDn&&dir==='short' ? `Lower high at ${fP(sw1.price)} — price failed to reach the previous high, confirming the downtrend. Sellers stepped in earlier, showing increasing supply.`
        : dir==='long'  ? `Swing low at ${fP(sw1.price)} — buyers defended this level and pushed price higher.`
        :                   `Swing high at ${fP(sw1.price)} — sellers defended this level and pushed price lower.`);
    }

    if (sw2 && sw1 && Math.abs(sw2.bar - sw1.bar) > 8 && isVis(sw2.bar)) {
      const lbl2 = tUp && dir==='long'  ? 'Prior higher low'
                 : tDn && dir==='short' ? 'Prior lower high'
                 : dir==='long'  ? 'Prior swing low' : 'Prior swing high';
      addArrow(sw2.bar, sw2.price, lbl2,
        dir==='long'?'up':'down', false, 3,
        tUp&&dir==='long'  ? `Prior higher low at ${fP(sw2.price)} — with the more recent higher low, this confirms a series of higher lows. This is the structure of an uptrend.`
        : tDn&&dir==='short' ? `Prior lower high at ${fP(sw2.price)} — with the more recent lower high, confirms a series of lower highs — the structure of a downtrend.`
        : dir==='long'  ? `Prior swing low — provides additional context for the support area.`
        :                   `Prior swing high — provides additional context for the resistance area.`);
    }
  } // end _methodNeedsSwingContext


  // ══════════════════════════════════════════════════════════════════════════
  // STAGE 2 — KEY LEVEL / ZONE + WHY IT WAS PICKED
  // The specific price area the trade is based on.
  // For each method: show the level AND mark the prior touches that validate it.
  // ══════════════════════════════════════════════════════════════════════════
  if (showLevels) {
    switch (method) {

      case 'support_resistance': {
        const det   = dir==='long' ? detectSupportBounce(data) : detectResistanceRejection(data);
        const level = det.detected ? (det.supportLevel || det.resistanceLevel) : null;
        if (!level || !inRange(level)) break;

        // Find all historical touches of this level
        const touchBars = [];
        for (let i = histFrom; i <= visibleUpTo; i++) {
          const cd = curData[i]; if (!cd) continue;
          const dist = dir==='long' ? Math.abs(cd.low - level) : Math.abs(cd.high - level);
          if (dist < atr * 0.8) touchBars.push(i);
        }
        // Cluster touches (5-bar window) so nearby bars count as one test
        const touchClusters = [];
        for (const tb of touchBars) {
          if (!touchClusters.length || tb - touchClusters[touchClusters.length-1] > 5)
            touchClusters.push(tb);
        }

        // Draw level zone anchored from FIRST touch
        const firstTouch = touchClusters[0] ?? histFrom;
        if (firstTouch < visibleUpTo) {
          addZone(firstTouch, visibleUpTo + 5, level,
            dir==='long' ? `Support zone — ${fP(level)}` : `Resistance zone — ${fP(level)}`,
            1,
            dir==='long'
              ? `This level was picked because price bounced here ${touchClusters.length} time${touchClusters.length>1?'s':''} without breaking down. That tells us buyers repeatedly accepted value around ${fP(level)} and were strong enough to push price away each time. In other words, this is support because the market has already proven demand lives here, not because the mentor guessed a number. The more separate tests that hold, the stronger that support story becomes.`
              : `This level was picked because price reversed here ${touchClusters.length} time${touchClusters.length>1?'s':''} instead of continuing higher. That tells us sellers repeatedly defended this area near ${fP(level)} and capped the move. In other words, this is resistance because supply has already shown itself here, not because the mentor guessed a number. The more separate rejections we see, the more trustworthy that ceiling becomes.`);
        }

        // Mark each prior touch as it happened — revealed progressively as replay reaches each bar.
        const labels = ['1st test', '2nd test', '3rd test'];
        touchClusters.slice(0, -1).forEach((tb, idx) => {
          if (!isVis(tb)) return;
          const cd = curData[tb]; if (!cd) return;
          const px = dir==='long' ? cd.low : cd.high;
          if (!inRange(px)) return;
          addArrow(tb, px,
            labels[idx] || `Test ${idx+1}`,
            dir==='long'?'up':'down', false, 2,
            idx === 0
              ? `First time price reached ${fP(level)} — and held. This established the level as significant.`
              : `Test ${idx+1} — level held again. Repeated tests that hold confirm strong interest at this price.`,
            true); // historical=true: appears when replay reaches this bar, not counted in structural limit
        });
        break;
      }

      case 'breakout': case 'range_breakout': {
        const conso = detectConsolidation(data);
        if (!conso.isConsolidating || (conso.upper-conso.lower) >= atr*5) break;
        if (!inRange(conso.lower) || !inRange(conso.upper)) break;
        const cf = Math.max(histFrom, detectionBar-15);
        if (!isVis(cf) || cf >= visibleUpTo) break;

        addBox(cf, visibleUpTo, conso.lower, conso.upper, `Consolidation — ${fP(conso.lower)} to ${fP(conso.upper)}`, 1,
          `Price has been coiling in this ${Math.round((conso.upper-conso.lower)/atr*10)/10}×ATR range. The longer price compresses, the stronger the eventual breakout. Watch for a close outside this box with volume.`);

        const bl = dir==='long' ? conso.upper : conso.lower;
        if (inRange(bl))
          addZone(cf, visibleUpTo+6, bl,
            dir==='long' ? `Breakout line — ${fP(bl)}` : `Breakdown line — ${fP(bl)}`,
            1,
            dir==='long' ? `Upper boundary of the range. A strong close above ${fP(bl)} confirms buyers have overwhelmed sellers — this is the entry trigger.`
                         : `Lower boundary of the range. A strong close below ${fP(bl)} confirms sellers are in control — this is the entry trigger.`);
        break;
      }

      case 'pullback': case 'trend':
      case 'flag_continuation': case 'structure_continuation': {
        const look25 = data.slice(-25);
        const swHi   = Math.max(...look25.map(b=>b.high));
        const swLo   = Math.min(...look25.map(b=>b.low));
        const rng    = swHi - swLo;
        if (rng <= atr*2) break;

        const f382 = dir==='long' ? swHi-rng*0.382 : swLo+rng*0.382;
        const f618 = dir==='long' ? swHi-rng*0.618 : swLo+rng*0.618;
        const hiI  = detectionBar-24 + look25.findIndex(b=>b.high===swHi);
        const loI  = detectionBar-24 + look25.findIndex(b=>b.low===swLo);
        const anch = Math.max(0, dir==='long' ? hiI : loI);

        if (isVis(anch) && anch<visibleUpTo && inRange(f382) && inRange(f618)) {
          addBox(anch, visibleUpTo+6, Math.min(f382,f618), Math.max(f382,f618),
            `Pullback zone — 38–62% Fib`,
            1,
            `Measured from the swing ${dir==='long'?'high at '+fP(swHi):'low at '+fP(swLo)}. The 38–62% zone (${fP(Math.min(f382,f618))}–${fP(Math.max(f382,f618))}) is where healthy pullbacks typically end and the trend resumes. This is the optimal entry area.`);
        }

        const fibAnchorBar   = dir==='long' ? hiI : loI;
        const fibAnchorPrice = dir==='long' ? swHi : swLo;
        if (isVis(fibAnchorBar) && inRange(fibAnchorPrice))
          addArrow(fibAnchorBar, fibAnchorPrice,
            dir==='long' ? `Swing high — ${fP(swHi)}` : `Swing low — ${fP(swLo)}`,
            dir==='long'?'down':'up', false, 2,
            `The Fibonacci retracement is measured FROM this ${dir==='long'?'high':'low'}. The 38–62% zone below/above it is where the trend is most likely to resume.`);
        break;
      }

      case 'liquidity': {
        const sw = detectLiquiditySweep(data);
        if (!sw.detected || !inRange(sw.sweepLevel)) break;
        const anch = Math.max(histFrom, detectionBar-25);
        if (!isVis(anch) || anch >= visibleUpTo) break;

        addZone(anch, visibleUpTo+4, sw.sweepLevel,
          `Liquidity pool — ${fP(sw.sweepLevel)}`,
          1,
          `Stop losses from retail traders sat clustered ${dir==='long'?'below':'above'} this level. This was the target — price swept through to trigger those stops before reversing. The wick depth of ${fP(sw.wickDepth||atr*0.5)} confirms real stops were hit.`);
        break;
      }

      case 'range': {
        const conso = detectConsolidation(data);
        if (!conso.isConsolidating || !inRange(conso.lower) || !inRange(conso.upper)) break;
        const anch = Math.max(histFrom, detectionBar-18);
        if (!isVis(anch) || anch >= visibleUpTo) break;

        addBox(anch, visibleUpTo+4, conso.lower, conso.upper,
          `Range — ${fP(conso.lower)} to ${fP(conso.upper)}`,
          1,
          `Price has been bouncing between these two levels. The range is ${Math.round((conso.upper-conso.lower)/atr*10)/10}×ATR wide. Strategy: enter at the boundaries, target the opposite side, exit before the middle.`);

        const boundary = dir==='long' ? conso.lower : conso.upper;
        if (inRange(boundary))
          addZone(anch, visibleUpTo+4, boundary,
            dir==='long' ? `Range bottom — ${fP(boundary)}` : `Range top — ${fP(boundary)}`,
            1,
            dir==='long' ? `The lower boundary where buyers have stepped in each time. A rejection wick here confirms the bounce.`
                         : `The upper boundary where sellers have stepped in each time. A rejection wick here confirms the fade.`);
        break;
      }
    }
  }


  // ══════════════════════════════════════════════════════════════════════════
  // STAGE 3 — ENTRY SIGNAL
  // The specific candle behaviour that triggers the trade.
  // Anchored to real OHLC. Explains exactly what to look for.
  // ══════════════════════════════════════════════════════════════════════════
  if (showConf) {
    // For stage-3 entry annotations during setup_detected phase,
    // the setup bar may still be in the future so detectionBar fails isVis().
    // Use liveBar as the anchor so the annotation renders at the current bar.
    const entryAnchorBar = isVis(detectionBar) ? detectionBar : liveBar;
    const dc = curData[entryAnchorBar] || null;

    if (dc) {
      switch (method) {

        case 'support_resistance': {
          const px   = dir==='long' ? dc.low : dc.high;
          const wick = dir==='long'
            ? Math.max(0, Math.min(dc.open,dc.close)-dc.low)
            : Math.max(0, dc.high-Math.max(dc.open,dc.close));
          const body = Math.abs(dc.close-dc.open)||0.001;
          const ratio = wick/body;
          if (inRange(px))
            addArrow(entryAnchorBar, px,
              ratio >= 1.5 ? `Rejection wick (${ratio.toFixed(1)}×)`
              : ratio >= 0.7 ? `Reaction candle`
              : `Level test`,
              dir==='long'?'up':'down', true, 1,
              ratio >= 1.5
                ? `The wick is ${ratio.toFixed(1)}× the candle body — a strong rejection signal. Price was forcefully pushed back from ${fP(dir==='long'?dc.low:dc.high)}, confirming buyers${dir==='long'?'':'/sellers'} are defending this level aggressively.`
                : `Price is reacting at the level. The candle body shows ${dir==='long'?'buying':'selling'} pressure. Watch for the next candle to close ${dir==='long'?'above':'below'} the level to confirm the move.`);
          break;
        }

        case 'breakout': case 'range_breakout': {
          const px = dir==='long' ? dc.high : dc.low;
          const pct = Math.round(Math.abs(dc.close-dc.open)/Math.max(dc.high-dc.low,0.001)*100);
          if (inRange(px))
            addArrow(entryAnchorBar, px,
              `Breakout (${pct}% body)`,
              dir==='long'?'down':'up', true, 1,
              pct >= 60
                ? `Strong breakout candle — ${pct}% of the candle range is body, showing conviction. Price has closed ${dir==='long'?'above resistance':'below support'} decisively.`
                : `Breakout candle with ${pct}% body. Moderate conviction — watch for follow-through on the next candle to confirm the breakout is real.`);
          break;
        }

        case 'pullback': case 'trend':
        case 'flag_continuation': case 'structure_continuation': {
          const pb  = detectTrendPullback(data, structure);
          const px  = dir==='long' ? dc.low : dc.high;
          const pct = pb.detected && pb.retrace ? Math.round(pb.retrace*100) : null;
          if (inRange(px))
            addArrow(entryAnchorBar, px,
              pct ? `${pct}% pullback — entry` : `Trend resuming`,
              dir==='long'?'up':'down', true, 1,
              pct
                ? `Price pulled back ${pct}% into the Fibonacci zone${pb.volContracting?' with volume contracting (healthy pullback — sellers losing momentum)':' — watch for volume to contract before entering'}. The trend is expected to resume ${dir==='long'?'upward':'downward'} from here.`
                : `Price is resuming the ${dir==='long'?'up':'down'}trend. Entry here follows the path of least resistance.`);
          break;
        }

        case 'liquidity': {
          const sw  = detectLiquiditySweep(data);
          const swB = entryAnchorBar-1;
          const swC = isVis(swB) ? curData[swB] : null;
          if (sw.detected && swC) {
            const sp = dir==='long' ? swC.low : swC.high;
            if (inRange(sp))
              addArrow(swB, sp, `Stop hunt wick`,
                dir==='long'?'up':'down', false, 2,
                `This wick swept the stops sitting ${dir==='long'?'below':'above'} ${fP(sw.sweepLevel)}. The long wick + immediate reversal is the signature of a liquidity sweep — smart money filled orders and reversed.`);
          }
          const dp = dir==='long' ? dc.high : dc.low;
          if (inRange(dp))
            addArrow(entryAnchorBar, dp, `Displacement — enter next`,
              dir==='long'?'down':'up', true, 1,
              `The displacement candle closed strongly ${dir==='long'?'up':'down'} after the sweep — this is institutional money entering. Enter on the open of the next candle.`);
          break;
        }

        case 'range': {
          const px = dir==='long' ? dc.low : dc.high;
          if (inRange(px))
            addArrow(entryAnchorBar, px,
              dir==='long' ? `Boundary bounce` : `Boundary rejection`,
              dir==='long'?'up':'down', true, 1,
              dir==='long'
                ? `Price reached the range bottom and bounced. The rejection wick confirms buyers are defending the boundary. Enter long, target the range top.`
                : `Price reached the range top and reversed. The rejection wick confirms sellers are defending the boundary. Enter short, target the range bottom.`);
          break;
        }
      }

      // One prior structural reference for pullback/trend methods
      if (ann.filter(a=>a.pri<=2).length < 4 &&
          (method==='pullback'||method==='trend'||method==='flag_continuation'||method==='structure_continuation')) {
        const peak = (dir==='long' ? swingH : swingL).slice(-1)[0];
        if (peak && peak.bar < visibleUpTo-3 && inRange(peak.price))
          addArrow(peak.bar, peak.price,
            dir==='long' ? `Peak — pullback started` : `Trough — pullback started`,
            dir==='long'?'down':'up', false, 2,
            `The trend ${dir==='long'?'peaked':'bottomed'} here before the current pullback. The Fibonacci retracement zone is measured from this point.`);
      }
    }
  }

  // ══════════════════════════════════════════════════════════════════════════
  // CONFLUENCE FACTOR ANNOTATIONS
  // Show each confluence factor as a named label so the user can see WHY
  // this setup qualified. Appears in all stages so context is always visible.
  // ══════════════════════════════════════════════════════════════════════════
  {
    const cfFactors = _buildConfluenceFactors(setupDetection, data, structure, atr, dir, method);
    if (cfFactors.length) {
      // Draw a stacked label at the setup bar listing all confluence factors
      const labelBar = Math.min(detectionBar, visibleUpTo);
      const labelPrice = dir === 'long'
        ? Math.max(...(curData.slice(Math.max(0,labelBar-5), labelBar+1).map(b=>b.high||0))) + atr * 0.5
        : Math.min(...(curData.slice(Math.max(0,labelBar-5), labelBar+1).map(b=>b.low||Infinity))) - atr * 0.5;
      if (isVis(labelBar) && inRange(labelPrice + (dir==='long'?0:atr))) {
        // One arrow per factor so each has its own explanation bubble on hover
        cfFactors.forEach((f, i) => {
          ann.push({
            type: 'arrow',
            bar: labelBar,
            price: dir === 'long' ? labelPrice + atr * i * 0.35 : labelPrice - atr * i * 0.35,
            label: `✦ ${f.name}`,
            pointing: dir === 'long' ? 'down' : 'up',
            highlight: false,
            pri: 4,   // lowest priority — doesn't block structural annotations
            candleIndex: stageCandle,
            explanation: f.explanation,
            isConfluenceFactor: true,
          });
        });
      }
    }
  }

  mentorState._annCurStage = curStage;
  _commit(ann);
}

// ── Post-trade debrief annotation ────────────────────────────────────────────
// Called when user clicks "Show Annotations" on the trade_completed screen.
// Step 1: runs the full _mentorAnnotateSetup at stage-3 to draw all confluence
//         factors and structural context that led to the trade.
// Step 2: layers entry arrow, SL zone, TP zone, and R:R label on top.
function _mentorAnnotateDebrief() {
  const trade = mentorState.exampleTrade;
  if (!trade || !curData) return;

  const tsd      = mentorState._tradeSetupData;
  const entryBar = Math.min(trade.timestamp ?? 0, replayCutoff, curData.length - 1);
  const tradeEnd = Math.min(replayCutoff, curData.length - 1);
  const dir      = trade.direction || 'long';
  const isLong   = dir === 'long';
  const atr      = calculateATR(tradeEnd, 14) || (curData[tradeEnd]?.close * 0.005) || 1;

  // ── Step 1: Full confluence / structural context via _mentorAnnotateSetup ──
  // Since the setup bar is well in the past (barsAway = 0), the function always
  // runs at stage 3 — all 3 layers of annotations are revealed at once.
  if (tsd?.setup && typeof tsd.setupBar === 'number') {
    const _prev = mentorState.annotationsEnabled;
    mentorState.annotationsEnabled = true;   // temporarily allow annotations
    mentorState._annCache = null;            // force a fresh full-stage-3 draw
    mentorState._lastAnnStateKey = null;
    _mentorAnnotateSetup(tsd.setup, replayCutoff, tsd.setupBar);
    mentorState.annotationsEnabled = _prev;  // restore (false)
    // _mentorAnnotateSetup called _clearMentorAnnotationsSilent + _commit internally,
    // so confluence / structure drawings are now in the drawings array.
  } else {
    // No stored setup data — just clear and start fresh
    _clearMentorAnnotationsSilent();
  }

  // ── Step 2: Layer trade levels on top (entry, SL, TP, R:R) ────────────────
  // Extract explanations from the AI debrief text stored in lockedInsights
  const insights  = mentorState.lockedInsights || [];
  const entryLine = insights.find(l => l && /ENTRY REASONING/i.test(l)) || '';
  const slLine    = insights.find(l => l && /STOP LOSS/i.test(l) && !/TAKE PROFIT/i.test(l)) || '';
  const tpLine    = insights.find(l => l && /TAKE PROFIT TARGET/i.test(l)) || '';

  const extractText = (str) => {
    if (!str) return '';
    const idx = str.indexOf(':');
    return idx >= 0 ? str.slice(idx + 1).trim().slice(0, 140) : str.trim().slice(0, 140);
  };
  const fP = (p) => typeof p === 'number' ? p.toFixed(2) : '?';

  // Entry arrow — gold highlight, points in trade direction
  _addMentorArrow(
    entryBar,
    trade.entry,
    isLong ? '▲ ENTRY' : '▼ ENTRY',
    isLong ? 'up' : 'down',
    true,  // highlight = gold tier
    extractText(entryLine) || `${isLong ? 'Long' : 'Short'} entry at ${fP(trade.entry)}`
  );

  // Stop Loss zone line — dashed red, spans entry to trade end
  const slId = _addMentorBox(entryBar, tradeEnd, trade.stopLoss - atr * 0.07, trade.stopLoss + atr * 0.07, 'STOP LOSS');
  if (slId) {
    const slD = drawings.find(d => d.id === slId);
    if (slD) {
      slD.isLine      = true;
      slD.explanation = extractText(slLine) || `Stop placed at ${fP(trade.stopLoss)} — above/below key structure.`;
      slD.lineColor   = 'rgba(255,77,106,0.85)';
    }
  }

  // Take Profit zone line — dashed green, spans entry to trade end
  const tpId = _addMentorBox(entryBar, tradeEnd, trade.takeProfit - atr * 0.07, trade.takeProfit + atr * 0.07, 'TAKE PROFIT');
  if (tpId) {
    const tpD = drawings.find(d => d.id === tpId);
    if (tpD) {
      tpD.isLine      = true;
      tpD.explanation = extractText(tpLine) || `Target at ${fP(trade.takeProfit)} — next key level / support-resistance zone.`;
      tpD.lineColor   = 'rgba(0,212,160,0.85)';
    }
  }

  // R:R label — secondary arrow near trade midpoint
  const midPrice = (trade.stopLoss + trade.takeProfit) / 2;
  const rrLabel  = `R:R ${typeof trade.riskReward === 'number' ? trade.riskReward.toFixed(1) : '?'}`;
  _addMentorArrow(
    Math.max(entryBar + 3, tradeEnd - 10),
    midPrice,
    rrLabel,
    isLong ? 'up' : 'down',
    false,
    `Risk-to-reward ratio of ${typeof trade.riskReward === 'number' ? trade.riskReward.toFixed(2) : '?'}:1 on this trade.`
  );

  try { saveDrawings(curSym.s, curTF); } catch(e) {}
  if (typeof draw === 'function') draw();
}

// Toggle debrief annotations on/off via the Show/Hide button
function toggleMentorDebriefAnnotations() {
  const btn = document.getElementById('btn-show-annotations');
  if (mentorState._debriefAnnotationsVisible) {
    clearMentorAnnotations();
    mentorState._debriefAnnotationsVisible = false;
    if (btn) {
      btn.textContent = '📍 Show Annotations';
      btn.style.opacity = '1';
      btn.style.background = 'linear-gradient(135deg,rgba(139,92,246,0.2),rgba(139,92,246,0.08))';
      btn.style.borderColor = 'rgba(139,92,246,0.35)';
      btn.style.color = '#a78bfa';
    }
  } else {
    _mentorAnnotateDebrief();
    mentorState._debriefAnnotationsVisible = true;
    if (btn) {
      btn.textContent = '🙈 Hide Annotations';
      btn.style.opacity = '0.8';
      btn.style.background = 'linear-gradient(135deg,rgba(139,92,246,0.35),rgba(139,92,246,0.15))';
      btn.style.borderColor = 'rgba(139,92,246,0.7)';
      btn.style.color = '#c4b5fd';
    }
  }
}

function _commit(ann) {
  if (!ann?.length) return;

  const atr = calculateATR(Math.min(replayCutoff, curData.length-1), 14) || 1;
  const now  = replayCutoff;
  const methodCtx = mentorState.selectedTradingMethod || 'general';
  const dirCtx = mentorState.upcomingSetup?.setup?.direction || mentorState.exampleTrade?.direction || 'long';

  ann.sort((a,b) => (a.pri||2)-(b.pri||2));

  const usedAt = {};
  const usedPY = {};

  // Track whether this call produces a NEW primary annotation that warrants a pause
  let firstPrimaryLabel = null;
  let firstPrimaryBar   = -1;
  let firstPrimaryPrice = null;
  let firstPrimaryDir   = 'up';

  ann.forEach(a => {
    const ci = a.candleIndex ?? now;
    if (ci > now) return;

    if (a.type==='zone') {
      const enrichedExplanation = [a.explanation, _mentorConfluenceExplanation(a.label, methodCtx, dirCtx)].filter(Boolean).join(' ');
      const existing = drawings.find(d =>
        d.isMentorAnnotation && d.type==='mentor_box' &&
        d.priceHigh && d.priceLow &&
        Math.abs(((d.priceHigh+d.priceLow)/2) - a.price) < atr*1.5);
      if (existing) {
        if (!existing.label.includes(a.label)) existing.label += ' + ' + a.label;
        return;
      }
      // Store explanation on the box itself — rendered as tooltip on hover, NOT as a
      // separate floating arrow (which caused duplicate bubbles on top of each other).
      const zoneDrawingId = _addMentorBox(a.f, a.t, a.price-atr*0.08, a.price+atr*0.08, a.label);
      if (zoneDrawingId) {
        const zd = drawings.find(d => d.id === zoneDrawingId);
        if (zd) {
          if (enrichedExplanation) zd.explanation = enrichedExplanation;
          zd.isLine = true; // render as a single dashed line, not a filled zone box
        }
      }
      if ((a.pri||2) === 1 && !firstPrimaryLabel) {
        firstPrimaryLabel = a.label;
        firstPrimaryBar   = Math.min(a.t, now);
        firstPrimaryPrice = a.price;
        firstPrimaryDir   = 'up';
      }

    } else if (a.type==='box') {
      const enrichedExplanation = [a.explanation, _mentorConfluenceExplanation(a.label, methodCtx, dirCtx)].filter(Boolean).join(' ');
      const existing = drawings.find(d =>
        d.isMentorAnnotation && d.type==='mentor_box' &&
        d.priceLow && d.priceHigh &&
        d.priceLow < a.hi + atr && d.priceHigh > a.lo - atr);
      if (existing) {
        if (!existing.label.includes(a.label)) existing.label += ' + ' + a.label;
        return;
      }
      const boxDrawingId = _addMentorBox(a.f, a.t, a.lo, a.hi, a.label);
      if (enrichedExplanation && boxDrawingId) {
        const bd = drawings.find(d => d.id === boxDrawingId);
        if (bd) bd.explanation = enrichedExplanation;
      }
      if ((a.pri||2) === 1 && !firstPrimaryLabel) {
        firstPrimaryLabel = a.label;
        firstPrimaryBar   = Math.min(a.t, now);
        firstPrimaryPrice = (a.lo + a.hi) / 2;
        firstPrimaryDir   = 'up';
      }

    } else if (a.type==='arrow') {
      const enrichedExplanation = [a.explanation, _mentorConfluenceExplanation(a.label, methodCtx, dirCtx)].filter(Boolean).join(' ');
      // Anchor arrows at their actual structural price — bubble placement handles visual spacing.
      // Only apply a tiny nudge when two annotations land on exactly the same bar+direction.
      let price = a.price;
      const key   = `${a.bar}_${a.pointing}`;
      const used  = usedAt[key]||0;
      const off   = used * atr * 0.3 * (a.pointing==='down'?1:-1);
      usedAt[key] = used+1;
      price += off;
      _addMentorArrow(a.bar, price, a.label, a.pointing, a.highlight, enrichedExplanation || '');
      if ((a.pri||2) === 1 && a.highlight && !firstPrimaryLabel) {
        firstPrimaryLabel = a.label;
        firstPrimaryBar   = a.bar;
        firstPrimaryPrice = price;
        firstPrimaryDir   = a.pointing === 'up' ? 'up' : 'down';
      }
    }
  });

  // ── Cache the computed drawings so scroll-back can restore them ───────────
  if (mentorState._lastAnnStateKey) {
    // stateKey format: "<setupBar>_<method>" — method may contain underscores
    const sepIdx = mentorState._lastAnnStateKey.indexOf('_');
    const setupBarNum = Number(mentorState._lastAnnStateKey.slice(0, sepIdx));
    const methodStr   = mentorState._lastAnnStateKey.slice(sepIdx + 1);
    mentorState._annCache = {
      setupBar: setupBarNum,
      method: methodStr,
      stage: mentorState._annCurStage || 1,
      drawings: drawings.filter(d => d.isMentorAnnotation).map(d => ({ ...d })),
    };
  }

  try { saveDrawings(curSym.s, curTF); } catch(e) {}
  if (typeof draw==='function') draw();

  // ── Confluence pause: when a new primary annotation appears during setup_detected,
  //    pause replay and draw an explanation dialogue at the current bar ──────────
  _maybePauseForConfluence(firstPrimaryLabel, firstPrimaryBar, firstPrimaryPrice, firstPrimaryDir, atr);
}

// Pause and show a dialogue when a major confluence is first spotted
function _maybePauseForConfluence(label, bar, price, dir, atr) {
  if (!label || !replayMode || !replayTimer) return;
  if (mentorState.lifecycleState !== 'setup_detected') return;
  if (!mentorState.upcomingSetup) return;

  // Only fire once per unique label — avoid re-pausing on every redraw
  if (!mentorState._confluencePauses) mentorState._confluencePauses = new Set();
  // Normalise label: strip merged suffixes like " + EMA confluence" so the
  // base level name is stable across redraws
  const baseLabel = label.split(' + ')[0].trim();
  if (mentorState._confluencePauses.has(baseLabel)) return;
  mentorState._confluencePauses.add(baseLabel);

  // Build the explanation for this confluence type
  const explanations = {
    'Support zone':        'Price has previously bounced from this level. Buyers are defending it — watch for a rejection wick to confirm.',
    'Resistance zone':     'Price has previously reversed here. Sellers stepped in at this level — watch for a wick rejection before entering short.',
    'Consolidation range': 'Price is coiling in a tight range. This compression builds energy. A breakout from this range often leads to a strong directional move.',
    'Breakout level':      'This is the key level to break. A candle closing convincingly above/below this line is the trigger to enter.',
    'Breakdown level':     'This is the support line to break. A close below confirms the breakdown and is the entry trigger.',
    'Fib 38–62% pullback zone': 'Price has pulled back into the Fibonacci golden zone — the most common reversal area in trending markets. Watch for the trend to resume here.',
    'Pullback zone (38–62%)':   'Price has pulled back into the Fibonacci golden zone — the most common reversal area in trending markets. Watch for the trend to resume here.',
    'Liquidity pool':      'Stop losses are clustered here. A wick into this zone sweeps those stops before reversing — the sweep is the entry signal.',
    'Trading range':       'Price is bouncing between two levels. The strategy is to enter at the boundaries. Avoid trading near the middle of the range.',
    'Range support':       'The lower boundary of the range — where buyers have repeatedly defended. Look for a reaction here.',
    'Range resistance':    'The upper boundary of the range — where sellers have repeatedly stepped in. Look for a rejection here.',
  };
  const explanation = _mentorConfluenceExplanation(
    baseLabel,
    mentorState.selectedTradingMethod || 'general',
    mentorState.upcomingSetup?.setup?.direction || 'long'
  );

  // Pause replay
  clearInterval(replayTimer);
  replayTimer = null;
  mentorState.setupPausedReplay = true;
  updateReplayStatus();

  // Draw an explanation arrow at the current bar pointing at the confluence
  const c = curData[Math.min(bar, replayCutoff)];
  if (c) {
    const arrowPrice = dir === 'up' ? c.low - atr * 0.5 : c.high + atr * 0.5;
    _addMentorArrow(replayCutoff, arrowPrice,
      `📍 ${label}`, dir === 'up' ? 'up' : 'down', false);
  }

  // Show explanation in the mentor panel
  mentorState.currentInsights = [
    `⏸ Mentor spotted a confluence — replay paused`,
    `📌 ${label}`,
    explanation,
    `Press Space or ▶ to continue when ready.`,
  ];
  mentorState.currentQuestion = 'Study this level before the trade forms.';
  updateMentorUI();
  scheduleDraw();

  toast(`⏸ Confluence: ${label}`);
}


// ── Mentor annotation helpers — defined at module scope (not inside render loop) ──
function _mentorWrapText(ctx, text, font, maxW) {
  ctx.font = font;
  const words = text.split(' ');
  const lines = []; let line = '';
  for (const w of words) {
    const test = line ? line + ' ' + w : w;
    if (ctx.measureText(test).width > maxW && line) { lines.push(line); line = w; }
    else line = test;
  }
  if (line) lines.push(line);
  return lines;
}

function _mentorBubbleOverlaps(r1x, r1y, r1w, r1h, r2x, r2y, r2w, r2h) {
  return r1x < r2x+r2w+4 && r1x+r1w+4 > r2x && r1y < r2y+r2h+4 && r1y+r1h+4 > r2y;
}

function _mentorTryBand(ctx, ax, bubbleW, bubbleH, inBottom, H, W) {
  const marginH = Math.max(bubbleH + 10, H * 0.18);
  const bandTop = inBottom ? H - marginH : 4;
  const bandBot = inBottom ? H - 4 : marginH;
  for (let attempt = 0; attempt < 8; attempt++) {
    const bY = bandTop + attempt * (bubbleH + 6);
    if (bY + bubbleH > bandBot) break;
    const bX = Math.max(4, Math.min(W - bubbleW - 4, ax - bubbleW / 2));
    if (!ctx._placedBubbles.some(b => _mentorBubbleOverlaps(bX, bY, bubbleW, bubbleH, b.x, b.y, b.w, b.h)))
      return { bX, bY, inBottom };
  }
  return null;
}

// Batched draw — coalesces multiple draw() calls in the same JS task into one rAF
let _pendingDraw = false;
function scheduleDraw() {
  if (_pendingDraw) return;
  _pendingDraw = true;
  requestAnimationFrame(() => {
    _pendingDraw = false;
    if (typeof draw === 'function') draw();
  });
}

function renderDrawings(ctx, W, H, barXfn, pyfn, yToPricefn){
  ctx._mentorBubbleCount = 0;   // reset per-frame bubble count
  ctx._placedBubbles    = [];  // collision registry reset each frame
  const C = {
    bg:   getCSSVar('--bg')  || '#07090e',
    bg2:  getCSSVar('--bg2') || '#0c0e16',
    bg3:  getCSSVar('--bg3') || '#10131c',
    b1:   getCSSVar('--b1')  || '#1a2030',
    b2:   getCSSVar('--b2')  || '#232d42',
    tx:   getCSSVar('--tx')  || '#dde4f5',
    tx2:  getCSSVar('--tx2') || '#8fa0bf',
    am:   getCSSVar('--am')  || '#f0a500',
    tl:   getCSSVar('--tl')  || '#00c9a0',
    rd:   getCSSVar('--rd')  || '#f03060',
  };
  const hex2rgb = h => { h=h.replace('#',''); const n=parseInt(h.length===3?h.split('').map(x=>x+x).join(''):h,16); return [(n>>16)&255,(n>>8)&255,n&255]; };
  const ca = (col,a) => { try{ const [r,g,b]=hex2rgb(col); return `rgba(${r},${g},${b},${a})`; } catch(e){ return col; } };
  _barX=barXfn; _py=pyfn; _yToPrice=yToPricefn; _drawW=W; _drawH=H;
  _xToBar = sx => rightBarIndex - (W-sx)/barWidth;

  const all = drawingWIP ? [...drawings, drawingWIP] : drawings;

  // Eraser hover highlight
  if(activeTool==='eraser' && mouseX>=0){
    const hovered = drawings.find(d=>hitTest(d,mouseX,mouseY));
    if(hovered){
      ctx.save();
      ctx.globalAlpha=0.25;
      ctx.strokeStyle='#f03060'; ctx.lineWidth=8; ctx.setLineDash([]);
      // draw a wide stroke over the drawing center
      ctx.beginPath();
      if(hovered.bar1!==undefined){
        ctx.moveTo(barXfn(hovered.bar1),pyfn(hovered.price1));
        ctx.lineTo(barXfn(hovered.bar2),pyfn(hovered.price2));
      } else if(hovered.price!==undefined){
        ctx.moveTo(0,pyfn(hovered.price)); ctx.lineTo(W,pyfn(hovered.price));
      }
      ctx.stroke();
      ctx.restore();
    }
  }

  all.forEach(d=>{
    ctx.save();
    const isSel = d===selectedDrawing;
    const isWIP = d===drawingWIP;
    const isWIP2 = d === drawingWIP;
    const baseCol = d.color || (d.type==='short'?'#f03060':d.type==='long'?'#00c9a0': C.am || '#f0a500');
    const col = isSel ? lightenColor(baseCol, 0.3) : baseCol;
    ctx.globalAlpha = isWIP ? 0.7 : 1;

    switch(d.type){

      case 'hline':{
        const y=pyfn(d.price);
        ctx.strokeStyle=col; ctx.lineWidth=isSel?(d.lw||1)+1:(d.lw||1);
        // Refinement annotations use dashed style; normal hlines use their stored style
        const hlineStyle = d._tapRefinement ? (d.dash?'dashed':'solid') : (isSel?'solid':(d.ls||'dashed'));
        _btApplyLineStyle(ctx, hlineStyle);
        ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W-R_PANEL_OFFSET-4,y); ctx.stroke();
        ctx.setLineDash([]);
        // Label pill — show custom label for refinement annotations, price for normal hlines
        const pillLabel = d._tapRefinement && d.label ? d.label : fP(d.price);
        ctx.font = d._tapRefinement ? 'bold 9px ui-monospace,monospace' : '9px monospace';
        const lw=ctx.measureText(pillLabel).width+10;
        ctx.fillStyle=col+'28'; // semi-transparent bg matching line color
        ctx.fillRect(4,y-12,lw,14);
        ctx.fillStyle=col; ctx.textAlign='left';
        ctx.fillText(pillLabel,9,y-2);
        break;
      }

      case 'hray':{
        const y=pyfn(d.price);
        ctx.strokeStyle=col; ctx.lineWidth=isSel?(d.lw||1)+1:(d.lw||1);
        _btApplyLineStyle(ctx, d.ls||'solid');
        ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W-R_PANEL_OFFSET-8,y); ctx.stroke();
        // arrowhead
        ctx.fillStyle=col;
        ctx.beginPath(); ctx.moveTo(W-R_PANEL_OFFSET-8,y-5); ctx.lineTo(W-R_PANEL_OFFSET,y); ctx.lineTo(W-R_PANEL_OFFSET-8,y+5); ctx.closePath(); ctx.fill();
        const label=fP(d.price);
        ctx.font='9px monospace'; const lw=ctx.measureText(label).width+10;
        ctx.fillStyle=ca(C.am,.18); ctx.fillRect(4,y-10,lw,13);
        ctx.fillStyle=col; ctx.textAlign='left'; ctx.fillText(label,9,y-1);
        break;
      }

      case 'vline':{
        const x=barXfn(d.bar);
        ctx.strokeStyle=col; ctx.lineWidth=isSel?(d.lw||1)+1:(d.lw||1);
        _btApplyLineStyle(ctx, d.ls||'dashed');
        ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke();
        ctx.setLineDash([]);
        // date label at top
        const bar=Math.round(d.bar); 
        const label = (curData[bar]&&curData[bar].time) ? fDate(curData[bar].time) : '';
        if(label){
          ctx.font='9px monospace'; const lw=ctx.measureText(label).width+10;
          ctx.fillStyle=ca(C.am,.18); ctx.fillRect(x-lw/2-2,4,lw,13);
          ctx.fillStyle=col; ctx.textAlign='center'; ctx.fillText(label,x,14);
        }
        break;
      }

      case 'line':{
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        ctx.strokeStyle=col; ctx.lineWidth=isSel?(d.lw||1.5)+1:(d.lw||1.5);
        _btApplyLineStyle(ctx, d.ls||'solid');
        ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
        ctx.setLineDash([]);
        if(!isSel){
          ctx.fillStyle=col;
          [[x1,y1],[x2,y2]].forEach(([x,y])=>{ ctx.beginPath(); ctx.arc(x,y,3,0,Math.PI*2); ctx.fill(); });
        }
        if(isSel){
          const diff = d.price2-d.price1;
          const pct  = (diff/d.price1*100).toFixed(2);
          const angleDeg = (Math.atan2(-(y2-y1),(x2-x1))*180/Math.PI).toFixed(1);
          const label= `${angleDeg}° · ${diff>=0?'+':''}${pct}%`;
          const mx=(x1+x2)/2, my=(y1+y2)/2;
          ctx.font='bold 9px monospace'; const lw=ctx.measureText(label).width+10;
          ctx.fillStyle='rgba(8,11,22,0.88)'; ctx.fillRect(mx-lw/2,my-13,lw,15);
          ctx.fillStyle=diff>=0?'#00c9a0':'#f03060'; ctx.textAlign='center';
          ctx.fillText(label,mx,my-2);
        }
        break;
      }

      case 'ray':{
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const angle=Math.atan2(y2-y1,x2-x1);
        const ex=x1+Math.cos(angle)*W*4, ey=y1+Math.sin(angle)*W*4;
        ctx.strokeStyle=col; ctx.lineWidth=isSel?(d.lw||1.5)+1:(d.lw||1.5);
        _btApplyLineStyle(ctx, d.ls||'solid');
        ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(ex,ey); ctx.stroke();
        ctx.setLineDash([]);
        if(!isSel){
          ctx.fillStyle=col; ctx.beginPath(); ctx.arc(x1,y1,3,0,Math.PI*2); ctx.fill();
          ctx.beginPath(); ctx.arc(x2,y2,3,0,Math.PI*2); ctx.fill();
        }
        break;
      }

      case 'rect':{
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const rx=Math.min(x1,x2),ry=Math.min(y1,y2),rw=Math.abs(x2-x1),rh=Math.abs(y2-y1);
        ctx.fillStyle=isSel?'rgba(240,165,0,.08)':'rgba(240,165,0,.04)';
        ctx.fillRect(rx,ry,rw,rh);
        ctx.strokeStyle=col; ctx.lineWidth=isSel?2:1; ctx.setLineDash([]);
        ctx.strokeRect(rx,ry,rw,rh);
        // size label when selected
        if(isSel&&rw>60&&rh>20){
          const barSpan=Math.abs(d.bar2-d.bar1).toFixed(0);
          const priceSpan=Math.abs(d.price2-d.price1);
          const pct=(priceSpan/Math.min(d.price1,d.price2)*100).toFixed(2);
          const label=`${barSpan}b  ${pct}%`;
          ctx.font='8px monospace'; ctx.textAlign='center';
          ctx.fillStyle=ca(C.bg3,.75);
          const lw=ctx.measureText(label).width+8;
          ctx.fillRect(rx+rw/2-lw/2,ry+rh/2-8,lw,13);
          ctx.fillStyle=col; ctx.fillText(label,rx+rw/2,ry+rh/2+3);
        }
        break;
      }

      case 'fib':{
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const range=d.price1-d.price2;
        const levels=[
          {v:0,    c:'rgba(240,165,0,.8)',  n:'0%'},
          {v:0.236,c:'rgba(61,127,255,.8)', n:'23.6%'},
          {v:0.382,c:'rgba(0,201,160,.8)',  n:'38.2%'},
          {v:0.5,  c:'rgba(255,255,255,.7)',n:'50%'},
          {v:0.618,c:'rgba(0,201,160,.8)',  n:'61.8%'},
          {v:0.786,c:'rgba(240,48,96,.8)',  n:'78.6%'},
          {v:1,    c:'rgba(240,165,0,.8)',  n:'100%'},
        ];
        const minX=Math.min(x1,x2), maxX=Math.max(x1,x2);
        // fill zones between levels
        const lvPrices=levels.map(lv=>pyfn(d.price2+range*lv.v));
        for(let i=0;i<lvPrices.length-1;i++){
          ctx.fillStyle=`rgba(240,165,0,${0.015+i*0.006})`;
          const top=Math.min(lvPrices[i],lvPrices[i+1]);
          const bot=Math.max(lvPrices[i],lvPrices[i+1]);
          ctx.fillRect(minX,top,maxX-minX,bot-top);
        }
        levels.forEach((lv,i)=>{
          const price=d.price2+range*lv.v;
          const y=pyfn(price);
          ctx.strokeStyle=lv.c; ctx.lineWidth=isSel&&i===0||i===levels.length-1?1.5:1;
          ctx.setLineDash([4,4]);
          ctx.beginPath(); ctx.moveTo(minX,y); ctx.lineTo(maxX,y); ctx.stroke();
          ctx.setLineDash([]);
          ctx.font='8px monospace'; ctx.textAlign='left';
          ctx.fillStyle=ca(C.bg3,.7);
          const label=`${lv.n}  ${fP(price)}`;
          const lw=ctx.measureText(label).width+6;
          ctx.fillRect(maxX+2,y-9,lw,12);
          ctx.fillStyle=lv.c; ctx.fillText(label,maxX+5,y+1);
        });
        // anchor line
        ctx.strokeStyle='rgba(240,165,0,.35)'; ctx.lineWidth=1; ctx.setLineDash([]);
        ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
        break;
      }

      case 'pitchfork':{
        if(!d.pts||d.pts.length<2) break;
        const pts=d.pts;
        const p0x=barXfn(pts[0].bar),p0y=pyfn(pts[0].price);
        const p1x=barXfn(pts[1].bar),p1y=pyfn(pts[1].price);
        ctx.strokeStyle=col; ctx.lineWidth=isSel?2:1.5; ctx.setLineDash([]);
        // Draw handle line (p0 to p1 and p0 to p2 if available)
        if(pts.length>=3){
          const p2x=barXfn(pts[2].bar),p2y=pyfn(pts[2].price);
          const midX=(p1x+p2x)/2, midY=(p1y+p2y)/2;
          const dx=midX-p0x, dy=midY-p0y;
          const len=Math.hypot(dx,dy)||1;
          const ext=3; // extension factor
          // median line
          ctx.beginPath(); ctx.moveTo(p0x,p0y); ctx.lineTo(p0x+dx*ext,p0y+dy*ext); ctx.stroke();
          // handle connecting line
          ctx.beginPath(); ctx.moveTo(p1x,p1y); ctx.lineTo(p2x,p2y); ctx.stroke();
          // tines
          [[p1x,p1y],[p2x,p2y]].forEach(([px,py])=>{
            ctx.beginPath(); ctx.moveTo(px,py); ctx.lineTo(px+dx*ext,py+dy*ext); ctx.stroke();
          });
          // mid line from p0 to midpoint (the "handle")
          ctx.strokeStyle=`${col}60`; ctx.setLineDash([3,3]);
          ctx.beginPath(); ctx.moveTo(p0x,p0y); ctx.lineTo(midX,midY); ctx.stroke();
          ctx.setLineDash([]);
        } else {
          ctx.beginPath(); ctx.moveTo(p0x,p0y); ctx.lineTo(p1x,p1y); ctx.stroke();
        }
        // guide dots on points (if not selected)
        if(!isSel){
          ctx.fillStyle=col;
          pts.forEach(p=>{ const x=barXfn(p.bar),y=pyfn(p.price); ctx.beginPath(); ctx.arc(x,y,3,0,Math.PI*2); ctx.fill(); });
        }
        break;
      }

      case 'text':{
        const x=barXfn(d.bar),y=pyfn(d.price);
        ctx.font='bold 11px monospace'; ctx.textAlign='left';
        const tw=ctx.measureText(d.text||'').width;
        ctx.fillStyle=isSel?ca(C.am,.25):ca(C.bg3,.85);
        ctx.fillRect(x-3,y-14,tw+10,17);
        if(isSel){ ctx.strokeStyle=col; ctx.lineWidth=1; ctx.strokeRect(x-3,y-14,tw+10,17); }
        ctx.fillStyle=col; ctx.fillText(d.text||'',x+2,y-1);
        break;
      }

      // ── MENTOR ANNOTATION TYPES ────────────────────────────────────────────
      // mentor_arrow: downward/upward arrow pointing at a specific candle
      // mentor_box:   highlight box around a candle range
      // mentor_label: floating callout with explanation text
      // All are selectable and deletable. Marked with isMentorAnnotation=true.

      // ── MENTOR ANNOTATIONS ─────────────────────────────────────────────────
      // Three types following visual hierarchy:
      //   mentor_arrow  → structure points (small, clean triangle marker + label)
      //   mentor_box    → zones (semi-transparent fill, subtle border, inline label)
      //   mentor_label  → explanatory notes (compact callout anchored to price)
      //
      // Priority tiers control opacity and size:
      //   d.tier = 'primary'   → full opacity, bold label
      //   d.tier = 'secondary' → 75% opacity
      //   d.tier = 'tertiary'  → 50% opacity, smaller label

      case 'mentor_arrow': {
        const ax  = barXfn(d.bar);
        const ay  = pyfn(d.price);

        if (ax < -barWidth * 2 || ax > W + barWidth * 2) break;

        const isDown    = d.pointing !== 'up';
        const tier      = d.tier || 'secondary';
        const isPrimary = tier === 'primary';
        const accentCol = d.highlight ? '#f0a500' : isPrimary ? '#00c9a0' : tier === 'secondary' ? '#7c5cbf' : '#4a6080';
        const alpha     = isPrimary ? 1.0 : tier === 'secondary' ? 0.85 : 0.65;

        if (!d.label && !d.explanation) {
          ctx.save(); ctx.fillStyle = accentCol; ctx.globalAlpha = alpha;
          ctx.beginPath(); ctx.arc(ax, ay, 3, 0, Math.PI*2); ctx.fill();
          ctx.restore(); break;
        }

        // ── Text measurement ─────────────────────────────────────────────────
        const explanation = d.explanation || '';
        const fontSize    = isPrimary ? 11 : 10;
        const padX = 10, padY = 7;
        // Bubble must stay LEFT of the price scale panel
        const chartRight  = W - R_PANEL_OFFSET - 8;
        const chartBottom = H - X_AXIS_H - 4;   // above time axis
        const chartTop    = 52;                  // below toolbar (~48px) + margin
        const chartLeft   = 52;                  // right of left nav strip (48px) + margin

        const maxBubbleW = Math.min(200, (chartRight - chartLeft) * 0.4);
        const innerW     = maxBubbleW - padX * 2 - 4;

        const titleFont  = `${isPrimary ? 'bold ' : ''}${fontSize}px sans-serif`;
        const explFont   = `${fontSize - 1}px sans-serif`;
        const titleLines = _mentorWrapText(ctx, d.label || '', titleFont, innerW);
        const explLines  = explanation ? _mentorWrapText(ctx, explanation, explFont, innerW) : [];

        let actualMaxW = 80;
        [...titleLines, ...explLines].forEach((ln, i) => {
          ctx.font = i < titleLines.length ? titleFont : explFont;
          actualMaxW = Math.max(actualMaxW, ctx.measureText(ln).width);
        });
        const lineH   = fontSize + 4;
        const bubbleW = Math.min(maxBubbleW, actualMaxW + padX * 2 + 6);
        const bubbleH = padY * 2 + lineH * titleLines.length +
                        (explLines.length ? lineH * explLines.length + 5 : 0);

        // ── Placement: bubbles in top or bottom band, never over candles ─────
        // Safe chart area: chartTop → chartBottom, chartLeft → chartRight
        // Band height is whichever is larger: bubble height + margin, or 16% of chart height
        if (!ctx._placedBubbles) ctx._placedBubbles = [];
        if (!ctx._mentorBubbleCount) ctx._mentorBubbleCount = 0;
        // Reserve 2 slots specifically for confluence factor annotations (✦ prefix).
        // Non-confluence secondary annotations are capped at 3 to leave room.
        const isConfluence = !!(d.isConfluenceFactor || d.label?.startsWith('✦'));
        const maxAllowed = isConfluence ? 6 : 4;
        if (ctx._mentorBubbleCount >= maxAllowed && !isPrimary && !d.highlight) break;
        if (explanation) ctx._mentorBubbleCount++;

        const chartH     = chartBottom - chartTop;
        const bandH      = Math.max(bubbleH + 12, chartH * 0.22);
        const topBandTop = chartTop;
        const topBandBot = chartTop + bandH;
        const botBandTop = chartBottom - bandH;
        const botBandBot = chartBottom;

        // Anchor in upper half → use bottom band; lower half → use top band
        const anchorInUpper = ay < chartTop + chartH * 0.5;
        const preferBottom  = anchorInUpper;

        // Clamp anchor Y so the dot always stays inside the visible chart area
        const aySafe = Math.max(chartTop + 4, Math.min(chartBottom - 4, ay));

        function tryBand(useBottom) {
          const bandTop2 = useBottom ? botBandTop : topBandTop;
          const bandBot2 = useBottom ? botBandBot : topBandBot;
          if (bandBot2 - bandTop2 < bubbleH) return null;
          const startY = useBottom ? bandTop2 : bandBot2 - bubbleH;
          const step   = useBottom ? bubbleH + 5 : -(bubbleH + 5);
          // Try multiple X positions so bubbles spread horizontally, not just vertically
          const xShifts = [0, -(bubbleW + 10), bubbleW + 10, -(bubbleW * 2 + 20), bubbleW * 2 + 20];
          for (const xShift of xShifts) {
            const bX = Math.max(chartLeft, Math.min(chartRight - bubbleW, ax - bubbleW / 2 + xShift));
            for (let attempt = 0; attempt < 4; attempt++) {
              const bY = startY + step * attempt;
              if (bY < bandTop2 || bY + bubbleH > bandBot2) break;
                if (!ctx._placedBubbles.some(b => _mentorBubbleOverlaps(bX, bY, bubbleW, bubbleH, b.x, b.y, b.w, b.h)))
                  return { bubbleX: bX, bubbleY: bY, useBottom };
            }
          }
          return null;
        }

        const { bubbleX, bubbleY, useBottom } = _mentorResolveBubblePlacement(ctx, d, {
          anchorX: ax,
          anchorY: aySafe,
          bubbleW,
          bubbleH,
          chartLeft,
          chartRight,
          chartTop,
          chartBottom,
          preferBottom,
          tryBandFn: tryBand
        });
        d._bubbleRect = { x: bubbleX, y: bubbleY, w: bubbleW, h: bubbleH, anchorX: ax, anchorY: aySafe };
        ctx._placedBubbles.push({ x: bubbleX, y: bubbleY, w: bubbleW, h: bubbleH });

        // ── Draw ─────────────────────────────────────────────────────────────
        ctx.save();
        ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

        // Anchor dot at actual structural price level
        ctx.fillStyle = accentCol;
        ctx.beginPath(); ctx.arc(ax, aySafe, isPrimary ? 3.5 : 2.5, 0, Math.PI*2); ctx.fill();
        ctx.fillStyle = 'rgba(255,255,255,0.55)';
        ctx.beginPath(); ctx.arc(ax, aySafe, 1.3, 0, Math.PI*2); ctx.fill();

        // Connector: straight single line from bubble edge → anchor point.
        // Straight line (no dogleg) so each annotation has its own visually
        // distinct connector — avoids the shared-vertical-segment "web" effect
        // when many bubbles anchor near the same bar.
        const bubbleEdgeY = useBottom ? bubbleY : bubbleY + bubbleH;
        // Attach to the bubble edge at the horizontal midpoint of the bubble,
        // clamped so it never overshoots the bubble width.
        const connX = Math.max(bubbleX + 10, Math.min(bubbleX + bubbleW - 10, ax));
        ctx.strokeStyle = accentCol;
        ctx.lineWidth   = isPrimary ? 1.8 : 1.4;
        ctx.setLineDash([4, 5]);
        ctx.globalAlpha = alpha * 0.7 * (isWIP ? 0.7 : 1);
        ctx.beginPath();
        ctx.moveTo(connX, bubbleEdgeY);   // start at bubble edge
        ctx.lineTo(ax, aySafe);           // go straight to anchor on chart
        ctx.stroke();
        ctx.setLineDash([]);

        // Arrowhead at the ANCHOR end, pointing away from the bubble
        const ahSz = 3.5;
        const angle = Math.atan2(aySafe - bubbleEdgeY, ax - connX);
        ctx.fillStyle = accentCol;
        ctx.globalAlpha = alpha * 0.9 * (isWIP ? 0.7 : 1);
        ctx.beginPath();
        ctx.moveTo(ax, aySafe);
        ctx.lineTo(ax - Math.cos(angle - 0.45) * ahSz * 2.2,
                   aySafe - Math.sin(angle - 0.45) * ahSz * 2.2);
        ctx.lineTo(ax - Math.cos(angle + 0.45) * ahSz * 2.2,
                   aySafe - Math.sin(angle + 0.45) * ahSz * 2.2);
        ctx.closePath(); ctx.fill();
        ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

        // Bubble background
        ctx.shadowColor = 'rgba(0,0,0,0.6)'; ctx.shadowBlur = 10; ctx.shadowOffsetY = 3;
        ctx.fillStyle   = 'rgba(8, 11, 22, 0.97)';
        roundRect(ctx, bubbleX, bubbleY, bubbleW, bubbleH, 6); ctx.fill();
        ctx.shadowColor = 'transparent'; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;
        ctx.strokeStyle = accentCol; ctx.lineWidth = isPrimary ? 1.5 : 1;
        roundRect(ctx, bubbleX, bubbleY, bubbleW, bubbleH, 6); ctx.stroke();

        // Left accent bar
        ctx.fillStyle = accentCol; ctx.globalAlpha = alpha * 0.5 * (isWIP ? 0.7 : 1);
        roundRect(ctx, bubbleX, bubbleY + 5, 2.5, bubbleH - 10, 1); ctx.fill();
        ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

        // Text
        const textX = bubbleX + padX + 5;
        let textY   = bubbleY + padY + fontSize;
        ctx.textAlign = 'left';
        titleLines.forEach(ln => {
          ctx.font = titleFont;
          ctx.fillStyle = isPrimary ? '#dff0ec' : tier === 'secondary' ? '#c8c0e8' : '#96a8b8';
          ctx.fillText(ln, textX, textY); textY += lineH;
        });
        if (explLines.length) {
          textY += 4;
          ctx.strokeStyle = accentCol; ctx.lineWidth = 0.4; ctx.globalAlpha = 0.25;
          ctx.beginPath();
          ctx.moveTo(bubbleX + 8, textY - lineH - 1);
          ctx.lineTo(bubbleX + bubbleW - 8, textY - lineH - 1);
          ctx.stroke();
          ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);
          explLines.forEach(ln => {
            ctx.font = explFont; ctx.fillStyle = '#6880a0';
            ctx.fillText(ln, textX, textY); textY += lineH;
          });
        }

        if (isSel) {
          ctx.strokeStyle = accentCol; ctx.lineWidth = 1.5; ctx.setLineDash([2,2]);
          ctx.beginPath(); ctx.arc(ax, ay, 9, 0, Math.PI*2); ctx.stroke();
          roundRect(ctx, bubbleX - 4, bubbleY - 4, bubbleW + 8, bubbleH + 8, 8); ctx.stroke();
          ctx.setLineDash([]);
        }
        ctx.restore();
        break;
      }

      case 'mentor_box': {
        const bx1   = barXfn(d.bar1);
        const bx2   = barXfn(d.bar2);
        const by1   = pyfn(d.priceHigh);
        const by2   = pyfn(d.priceLow);
        const bxL   = Math.min(bx1, bx2) - barWidth * 0.3;
        const bxR   = Math.max(bx1, bx2) + barWidth * 0.3;
        const byT   = Math.min(by1, by2);
        const byB   = Math.max(by1, by2);
        const bW    = bxR - bxL;
        const bHt   = byB - byT;
        const tier  = d.tier || 'secondary';
        const alpha = tier === 'primary' ? 1.0 : tier === 'secondary' ? 0.75 : 0.5;

        const fillCol   = tier === 'primary' ? 'rgba(0,201,160,'   : tier === 'secondary' ? 'rgba(100,60,180,' : 'rgba(60,80,140,';
        const strokeCol = tier === 'primary' ? '#00c9a0'            : tier === 'secondary' ? '#7c5cbf'          : '#4a6080';
        const fillAlpha = (isSel ? 0.18 : 0.08) * alpha;
        const strAlpha  = (isSel ? 1.0  : 0.55) * alpha;

        ctx.save();
        if (d.isLine) {
          // ── Level line (for zone-type: S&R, liquidity levels) ──────────────
          // Draw as a single dashed line at the midpoint — the callout bubble
          // carries the full information, so we don't show a filled rectangle.
          const midY = (byT + byB) / 2;
          ctx.strokeStyle = strokeCol;
          ctx.lineWidth   = tier === 'primary' ? 1.5 : 1.2;
          ctx.globalAlpha = strAlpha * 0.85 * (isWIP ? 0.7 : 1);
          ctx.setLineDash([5, 5]);
          ctx.beginPath(); ctx.moveTo(bxL, midY); ctx.lineTo(bxR, midY); ctx.stroke();
          ctx.setLineDash([]);
        } else {
          // ── Zone fill on chart (for range/consolidation boxes) ──────────────
          ctx.globalAlpha = fillAlpha * (isWIP ? 0.7 : 1);
          ctx.fillStyle = fillCol + '1)';
          ctx.fillRect(bxL, byT, bW, bHt);
          // Edge lines
          ctx.strokeStyle = strokeCol;
          ctx.globalAlpha = strAlpha * (isWIP ? 0.7 : 1);
          ctx.lineWidth   = tier === 'primary' ? 1.5 : 1;
          ctx.setLineDash([]);
          ctx.beginPath(); ctx.moveTo(bxL, byT); ctx.lineTo(bxR, byT); ctx.stroke();
          ctx.beginPath(); ctx.moveTo(bxL, byB); ctx.lineTo(bxR, byB); ctx.stroke();
          ctx.globalAlpha = strAlpha * 0.3 * (isWIP ? 0.7 : 1);
          ctx.setLineDash([2, 4]);
          ctx.beginPath(); ctx.moveTo(bxL, byT); ctx.lineTo(bxL, byB); ctx.stroke();
          ctx.beginPath(); ctx.moveTo(bxR, byT); ctx.lineTo(bxR, byB); ctx.stroke();
          ctx.setLineDash([]);
        }
        ctx.restore();

        // ── Floating callout bubble with arrow pointing to zone centre ──────
        if (d.label && bW > 20) {
          const isPrimary  = tier === 'primary';
          const explanation = d.explanation || '';
          const fontSize   = isPrimary ? 11 : 10;
          const padX = 10, padY = 7;

          // Safe chart bounds (same constants as mentor_arrow)
          const chartRight  = W - R_PANEL_OFFSET - 8;
          const chartBottom = H - X_AXIS_H - 4;
          const chartTop    = 52;
          const chartLeft   = 52; // left of left nav strip

          const maxBubbleW = Math.min(210, (chartRight - chartLeft) * 0.45);
          const innerW     = maxBubbleW - padX * 2 - 4;

          const titleFont = `${isPrimary ? 'bold ' : ''}${fontSize}px sans-serif`;
          const explFont  = `${fontSize - 1}px sans-serif`;
          const titleLines = _mentorWrapText(ctx, d.label || '', titleFont, innerW);
          const explLines  = explanation ? _mentorWrapText(ctx, explanation, explFont, innerW) : [];

          let actualMaxW = 80;
          [...titleLines, ...explLines].forEach((ln, i) => {
            ctx.font = i < titleLines.length ? titleFont : explFont;
            actualMaxW = Math.max(actualMaxW, ctx.measureText(ln).width);
          });
          const lineH   = fontSize + 4;
          const bubbleW = Math.min(maxBubbleW, actualMaxW + padX * 2 + 6);
          const bubbleH = padY * 2 + lineH * titleLines.length +
                          (explLines.length ? lineH * explLines.length + 5 : 0);

          if (!ctx._placedBubbles) ctx._placedBubbles = [];
          if (!ctx._mentorBubbleCount) ctx._mentorBubbleCount = 0;
          if (ctx._mentorBubbleCount >= 4 && !isPrimary) break;
          if (explanation) ctx._mentorBubbleCount++;

          // Anchor: horizontal centre of zone, vertical centre of zone
          const ax = Math.max(chartLeft, Math.min(chartRight, (bxL + bxR) / 2));
          const ay = (byT + byB) / 2;

          const chartH     = chartBottom - chartTop;
          const bandH      = Math.max(bubbleH + 12, chartH * 0.22);
          const topBandTop = chartTop;
          const topBandBot = chartTop + bandH;
          const botBandTop = chartBottom - bandH;
          const botBandBot = chartBottom;

          const anchorInUpper = ay < chartTop + chartH * 0.5;
          const preferBottom  = anchorInUpper;

          function tryBandBox(useBottom) {
            const bandTop2 = useBottom ? botBandTop : topBandTop;
            const bandBot2 = useBottom ? botBandBot : topBandBot;
            if (bandBot2 - bandTop2 < bubbleH) return null;
            const startY = useBottom ? bandTop2 : bandBot2 - bubbleH;
            const step   = useBottom ? bubbleH + 5 : -(bubbleH + 5);
            // Try multiple X positions so boxes spread horizontally, not just vertically
            const xShifts = [0, -(bubbleW + 10), bubbleW + 10, -(bubbleW * 2 + 20), bubbleW * 2 + 20];
            for (const xShift of xShifts) {
              const bXb = Math.max(chartLeft, Math.min(chartRight - bubbleW, ax - bubbleW / 2 + xShift));
              for (let attempt = 0; attempt < 4; attempt++) {
                const bY = startY + step * attempt;
                if (bY < bandTop2 || bY + bubbleH > bandBot2) break;
                if (!ctx._placedBubbles.some(b => _mentorBubbleOverlaps(bXb, bY, bubbleW, bubbleH, b.x, b.y, b.w, b.h)))
                  return { bubbleX: bXb, bubbleY: bY, useBottom };
              }
            }
            return null;
          }

          const { bubbleX, bubbleY, useBottom } = _mentorResolveBubblePlacement(ctx, d, {
            anchorX: ax,
            anchorY: ay,
            bubbleW,
            bubbleH,
            chartLeft,
            chartRight,
            chartTop,
            chartBottom,
            preferBottom,
            tryBandFn: tryBandBox
          });
          d._bubbleRect = { x: bubbleX, y: bubbleY, w: bubbleW, h: bubbleH, anchorX: ax, anchorY: ay };
          ctx._placedBubbles.push({ x: bubbleX, y: bubbleY, w: bubbleW, h: bubbleH });

          ctx.save();
          ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

          // Anchor dot at zone centre (clamped to chart bounds)
          const aySafeBox = Math.max(chartTop + 4, Math.min(chartBottom - 4, ay));
          ctx.fillStyle = strokeCol;
          ctx.beginPath(); ctx.arc(ax, aySafeBox, isPrimary ? 3.5 : 2.5, 0, Math.PI*2); ctx.fill();
          ctx.fillStyle = 'rgba(255,255,255,0.55)';
          ctx.beginPath(); ctx.arc(ax, aySafeBox, 1.3, 0, Math.PI*2); ctx.fill();

          // Connector line from zone centre to bubble edge
          const bubbleEdgeY = useBottom ? bubbleY : bubbleY + bubbleH;
          const connX = Math.max(bubbleX + 12, Math.min(bubbleX + bubbleW - 12, ax));
          ctx.strokeStyle = strokeCol;
          ctx.lineWidth   = isPrimary ? 1.5 : 1;
          ctx.setLineDash([3, 4]);
          ctx.globalAlpha = alpha * 0.65 * (isWIP ? 0.7 : 1);
          ctx.beginPath();
          ctx.moveTo(ax, aySafeBox);
          if (Math.abs(connX - ax) < 6) {
            ctx.lineTo(ax, bubbleEdgeY);
          } else {
            const midY = aySafeBox + (bubbleEdgeY - aySafeBox) * 0.5;
            ctx.lineTo(ax, midY);
            ctx.lineTo(connX, bubbleEdgeY);
          }
          ctx.stroke();
          ctx.setLineDash([]);

          // Arrowhead pointing TOWARD the structure
          const ahSz = 3.5;
          ctx.fillStyle = strokeCol;
          ctx.globalAlpha = alpha * 0.9 * (isWIP ? 0.7 : 1);
          ctx.beginPath();
          if (useBottom) {
            // Bubble below anchor — arrowhead points UP toward the structure
            ctx.moveTo(connX, bubbleEdgeY);
            ctx.lineTo(connX - ahSz, bubbleEdgeY - ahSz * 2);
            ctx.lineTo(connX + ahSz, bubbleEdgeY - ahSz * 2);
          } else {
            // Bubble above anchor — arrowhead points DOWN toward the structure
            ctx.moveTo(connX, bubbleEdgeY);
            ctx.lineTo(connX - ahSz, bubbleEdgeY + ahSz * 2);
            ctx.lineTo(connX + ahSz, bubbleEdgeY + ahSz * 2);
          }
          ctx.closePath(); ctx.fill();
          ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

          // Bubble background
          ctx.shadowColor = 'rgba(0,0,0,0.6)'; ctx.shadowBlur = 10; ctx.shadowOffsetY = 3;
          ctx.fillStyle   = 'rgba(8, 11, 22, 0.97)';
          roundRect(ctx, bubbleX, bubbleY, bubbleW, bubbleH, 6); ctx.fill();
          ctx.shadowColor = 'transparent'; ctx.shadowBlur = 0; ctx.shadowOffsetY = 0;
          ctx.strokeStyle = strokeCol; ctx.lineWidth = isPrimary ? 1.5 : 1;
          roundRect(ctx, bubbleX, bubbleY, bubbleW, bubbleH, 6); ctx.stroke();

          // Left accent bar
          ctx.fillStyle = strokeCol; ctx.globalAlpha = alpha * 0.5 * (isWIP ? 0.7 : 1);
          roundRect(ctx, bubbleX, bubbleY + 5, 2.5, bubbleH - 10, 1); ctx.fill();
          ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

          // Text
          const textX = bubbleX + padX + 5;
          let textY   = bubbleY + padY + fontSize;
          ctx.textAlign = 'left';
          titleLines.forEach(ln => {
            ctx.font = titleFont;
            ctx.fillStyle = isPrimary ? '#dff0ec' : tier === 'secondary' ? '#c8c0e8' : '#96a8b8';
            ctx.fillText(ln, textX, textY); textY += lineH;
          });
          if (explLines.length) {
            textY += 4;
            ctx.strokeStyle = strokeCol; ctx.lineWidth = 0.4; ctx.globalAlpha = 0.25;
            ctx.beginPath();
            ctx.moveTo(bubbleX + 8, textY - lineH - 1);
            ctx.lineTo(bubbleX + bubbleW - 8, textY - lineH - 1);
            ctx.stroke();
            ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);
            explLines.forEach(ln => {
              ctx.font = explFont; ctx.fillStyle = '#6880a0';
              ctx.fillText(ln, textX, textY); textY += lineH;
            });
          }
          if (isSel) {
            ctx.strokeStyle = strokeCol; ctx.lineWidth = 1.5; ctx.setLineDash([2,2]);
            roundRect(ctx, bubbleX - 4, bubbleY - 4, bubbleW + 8, bubbleH + 8, 8); ctx.stroke();
            ctx.setLineDash([]);
          }
          ctx.restore();
        }
        break;
      }

      case 'mentor_label': {
        const lax  = barXfn(d.bar);
        const lay  = pyfn(d.price);
        const tier = d.tier || 'tertiary';
        const txt  = d.label || '';
        // Split on pipe or em-dash — show max 2 lines
        const allLines = txt.split(/\||—/).map(s => s.trim()).filter(Boolean).slice(0, 2);
        const fontSize = tier === 'primary' ? 10 : 9;
        ctx.font       = `${fontSize}px sans-serif`;
        const maxW     = Math.max(...allLines.map(l => ctx.measureText(l).width), 50);
        const lineH    = fontSize + 4;
        const padX     = 7, padY = 5;
        const boxW     = Math.min(maxW + padX * 2, 220);
        const boxH     = allLines.length * lineH + padY * 2;
        const alpha    = tier === 'primary' ? 0.95 : tier === 'secondary' ? 0.80 : 0.65;

        // Position: prefer right of bar, flip left if too close to screen edge
        const bxOff = barWidth * 2;
        let lbx = lax + bxOff;
        if (lbx + boxW > W - 20) lbx = lax - bxOff - boxW;
        const lby = lay - boxH / 2;

        // Only draw if fully within canvas
        if (lby < 0 || lby + boxH > H || lbx < 0) break;

        const accentCol = tier === 'primary' ? 'rgba(0,201,160,0.7)' : tier === 'secondary' ? 'rgba(124,92,191,0.6)' : 'rgba(74,96,128,0.4)';

        ctx.save();
        ctx.globalAlpha = alpha * (isWIP ? 0.7 : 1);

        // Dot connector at bar
        ctx.fillStyle = accentCol;
        ctx.beginPath();
        ctx.arc(lax, lay, 2, 0, Math.PI * 2);
        ctx.fill();

        // Thin leader line
        ctx.strokeStyle = accentCol;
        ctx.lineWidth   = 0.75;
        ctx.setLineDash([2, 3]);
        ctx.beginPath();
        ctx.moveTo(lax + (lbx > lax ? 2 : -2), lay);
        ctx.lineTo(lbx + (lbx > lax ? 0 : boxW), lay);
        ctx.stroke();
        ctx.setLineDash([]);

        // Box
        ctx.fillStyle   = 'rgba(10,12,20,0.90)';
        roundRect(ctx, lbx, lby, boxW, boxH, 3);
        ctx.fill();
        ctx.strokeStyle = accentCol;
        ctx.lineWidth   = 0.75;
        roundRect(ctx, lbx, lby, boxW, boxH, 3);
        ctx.stroke();

        // Text
        ctx.textAlign = 'left';
        allLines.forEach((line, li) => {
          ctx.font      = `${li === 0 ? (tier === 'primary' ? 'bold ' : '') : ''}${fontSize}px sans-serif`;
          ctx.fillStyle = li === 0 ? (tier === 'primary' ? '#e8f4f0' : '#c8d0e4') : '#8090a8';
          // Truncate if needed
          let txt = line;
          while (ctx.measureText(txt).width > boxW - padX * 2 - 4 && txt.length > 4) txt = txt.slice(0, -1);
          ctx.fillText(txt, lbx + padX, lby + padY + lineH * (li + 1) - 2);
        });

        ctx.restore();
        break;
      }

      case 'long': case 'short':{
        const isLong=d.type==='long';
        const ex=barXfn(d.bar), ey=pyfn(d.price);
        const sly=pyfn(d.sl), tpy=pyfn(d.tp);
        const hb=effectiveHalfBars(d);
        // For mentor example trades: box starts at entry bar (right-only extent)
        // so pre-entry candles don't appear inside the trade box.
        // For user drawings: normal symmetric behaviour.
        const bx = d.isMentorExample ? ex : ex-hb*barWidth;
        const w  = d.isMentorExample ? hb*barWidth : hb*2*barWidth;
        const entryCol=isLong?'#00c9a0':'#f03060';
        const tpCol='#00c9a0', slCol='#f03060';

        // TP zone
        ctx.fillStyle=isLong?'rgba(0,201,160,.08)':'rgba(240,48,96,.08)';
        ctx.fillRect(bx,Math.min(ey,tpy),w,Math.abs(tpy-ey));
        // SL zone
        ctx.fillStyle='rgba(240,48,96,.06)';
        ctx.fillRect(bx,Math.min(ey,sly),w,Math.abs(sly-ey));
        // TP line
        ctx.strokeStyle=tpCol; ctx.lineWidth=isSel?2:1; ctx.setLineDash([4,3]);
        ctx.beginPath(); ctx.moveTo(bx,tpy); ctx.lineTo(bx+w,tpy); ctx.stroke();
        // SL line
        ctx.strokeStyle=slCol; ctx.lineWidth=isSel?2:1;
        ctx.beginPath(); ctx.moveTo(bx,sly); ctx.lineTo(bx+w,sly); ctx.stroke();
        // Entry line (solid)
        ctx.strokeStyle=entryCol; ctx.lineWidth=isSel?3:2; ctx.setLineDash([]);
        ctx.beginPath(); ctx.moveTo(bx,ey); ctx.lineTo(bx+w,ey); ctx.stroke();

        // R:R
        const rr=Math.abs(d.tp-d.price)/Math.abs(d.sl-d.price);
        const rrStr=isFinite(rr)?`R:R ${rr.toFixed(2)}`:'';

        // Labels
        ctx.font='bold 9px monospace'; ctx.textAlign='left';
        ctx.fillStyle=entryCol; ctx.fillText(`${d.type.toUpperCase()} @ ${fP(d.price)}`, bx+4, ey-4);
        ctx.fillStyle=tpCol;    ctx.fillText(`TP ${fP(d.tp)}`,  bx+4, tpy+(isLong?-3:10));
        ctx.fillStyle=slCol;    ctx.fillText(`SL ${fP(d.sl)}`,  bx+4, sly+(isLong?10:-3));
        if(rrStr){
          ctx.fillStyle=rr>=2?'#00c9a0':'#f0a500';
          ctx.fillText(rrStr, bx+4, (ey+tpy)/2+3);
        }
        // "AI Refined" badge for refinement suggestions placed via Show on Chart
        if(d._refinementLabel){
          const badge = '★ AI REFINED SETUP';
          ctx.font = 'bold 9px ui-monospace,monospace';
          const bw = ctx.measureText(badge).width + 12;
          const bh = 15;
          const bxPos = bx + 4;
          const byPos = tpy + (isLong ? -18 : 14);
          ctx.fillStyle = isLong ? 'rgba(0,201,160,.22)' : 'rgba(240,48,96,.22)';
          ctx.beginPath();
          ctx.roundRect ? ctx.roundRect(bxPos, byPos, bw, bh, 3)
            : ctx.rect(bxPos, byPos, bw, bh);
          ctx.fill();
          ctx.strokeStyle = entryCol; ctx.lineWidth = 0.8; ctx.setLineDash([]);
          ctx.strokeRect(bxPos, byPos, bw, bh);
          ctx.fillStyle = entryCol; ctx.textAlign = 'left';
          ctx.fillText(badge, bxPos + 6, byPos + 10);
        }
        break;
      }

      case 'measure':{
        if(d.bar2===undefined) break;
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const rx=Math.min(x1,x2),ry=Math.min(y1,y2),rw=Math.abs(x2-x1),rh=Math.abs(y2-y1);
        const priceDiff=d.price2-d.price1;
        const pct=(priceDiff/d.price1*100).toFixed(2);
        const bars=Math.abs(Math.round(d.bar2-d.bar1));
        const upCol='#00c9a0', dnCol='#f03060';
        const lineCol=priceDiff>=0?upCol:dnCol;
        // shaded box
        ctx.fillStyle=priceDiff>=0?'rgba(0,201,160,.07)':'rgba(240,48,96,.07)';
        ctx.fillRect(rx,ry,rw||1,rh||1);
        ctx.strokeStyle=lineCol; ctx.lineWidth=1; ctx.setLineDash([3,3]);
        ctx.strokeRect(rx,ry,rw||1,rh||1);
        ctx.setLineDash([]);
        // arrow lines
        ctx.strokeStyle=lineCol; ctx.lineWidth=1.5;
        ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y1); ctx.stroke(); // horizontal
        ctx.beginPath(); ctx.moveTo(x2,y1); ctx.lineTo(x2,y2); ctx.stroke(); // vertical
        // labels
        const midX=rx+rw/2, midY=ry+rh/2;
        ctx.font='bold 9px monospace'; ctx.textAlign='center';
        const line1=`${priceDiff>=0?'+':''}${pct}%  ${fP(Math.abs(priceDiff))}`;
        const line2=`${bars} bar${bars!==1?'s':''}`;
        const lw1=ctx.measureText(line1).width+12, lw2=ctx.measureText(line2).width+12;
        const lw=Math.max(lw1,lw2);
        ctx.fillStyle=ca(C.bg3,.9); ctx.fillRect(midX-lw/2,midY-18,lw,30);
        ctx.strokeStyle=lineCol; ctx.lineWidth=1; ctx.strokeRect(midX-lw/2,midY-18,lw,30);
        ctx.fillStyle=lineCol; ctx.fillText(line1,midX,midY-4);
        ctx.fillStyle='#8fa0bf'; ctx.fillText(line2,midX,midY+10);
        break;
      }

      case 'extline': {
        // Extended line — projects infinitely beyond both anchor points
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const dx=x2-x1, dy=y2-y1;
        const len=Math.hypot(dx,dy)||1;
        const ux=dx/len, uy=dy/len;
        const ext=W*6;
        const ex1=x1-ux*ext, ey1=y1-uy*ext;
        const ex2=x2+ux*ext, ey2=y2+uy*ext;
        const dCol = d.color||col;
        ctx.save();
        ctx.strokeStyle=dCol; ctx.lineWidth=isSel?2.5:(d.lw||1.5);
        _btApplyLineStyle(ctx, d.ls||'solid');
        ctx.beginPath(); ctx.moveTo(ex1,ey1); ctx.lineTo(ex2,ey2); ctx.stroke();
        ctx.setLineDash([]);
        // Angle label
        if(isSel){
          const angleDeg=(Math.atan2(-(y2-y1),(x2-x1))*180/Math.PI).toFixed(1);
          const pctChg=((d.price2-d.price1)/d.price1*100).toFixed(2);
          const mx=(x1+x2)/2, my=(y1+y2)/2;
          ctx.font='bold 9px monospace'; ctx.textAlign='center';
          const lbl=`${angleDeg}°  ${pctChg>=0?'+':''}${pctChg}%`;
          const lw2=ctx.measureText(lbl).width+10;
          ctx.fillStyle='rgba(8,11,22,0.85)'; ctx.fillRect(mx-lw2/2,my-13,lw2,14);
          ctx.fillStyle=dCol; ctx.fillText(lbl,mx,my-2);
        }
        if(!isSel){
          ctx.fillStyle=dCol;
          [[x1,y1],[x2,y2]].forEach(([px,py])=>{ ctx.beginPath(); ctx.arc(px,py,3,0,Math.PI*2); ctx.fill(); });
        }
        ctx.restore();
        break;
      }

      case 'channel': {
        // Parallel channel — 3 points: two define the main line, third sets parallel offset
        if(!d.bar2||!d.price3) break;
        const x1=barXfn(d.bar1),y1=pyfn(d.price1);
        const x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const y3=pyfn(d.price3);
        const offsetY=y3-y1; // vertical pixel offset of parallel line
        const dx=x2-x1, dy=y2-y1;
        const len=Math.hypot(dx,dy)||1;
        const ux=dx/len, uy=dy/len;
        const ext=W*4;
        // Extended endpoints for both lines
        const ax1=x1-ux*ext, ay1=y1-uy*ext, ax2=x2+ux*ext, ay2=y2+uy*ext;
        const bx1=ax1, by1=ay1+offsetY, bx2=ax2, by2=ay2+offsetY;
        const dCol=d.color||col;
        ctx.save();
        // Fill between lines
        ctx.beginPath();
        ctx.moveTo(ax1,ay1); ctx.lineTo(ax2,ay2);
        ctx.lineTo(bx2,by2); ctx.lineTo(bx1,by1);
        ctx.closePath();
        const fillCol = dCol.startsWith('#') ? dCol : '#f0a500';
        ctx.fillStyle = fillCol+'18';
        ctx.fill();
        // Main line
        ctx.strokeStyle=dCol; ctx.lineWidth=isSel?2:(d.lw||1.5);
        _btApplyLineStyle(ctx, d.ls||'solid');
        ctx.beginPath(); ctx.moveTo(ax1,ay1); ctx.lineTo(ax2,ay2); ctx.stroke();
        // Parallel line
        ctx.beginPath(); ctx.moveTo(bx1,by1); ctx.lineTo(bx2,by2); ctx.stroke();
        // Mid line (dashed)
        ctx.strokeStyle=dCol+'80'; ctx.lineWidth=1; ctx.setLineDash([4,5]);
        ctx.beginPath(); ctx.moveTo((ax1+bx1)/2,(ay1+by1)/2); ctx.lineTo((ax2+bx2)/2,(ay2+by2)/2); ctx.stroke();
        ctx.setLineDash([]);
        // Anchor dots
        if(!isSel){
          ctx.fillStyle=dCol;
          [[x1,y1],[x2,y2],[x1,y3]].forEach(([px,py])=>{ ctx.beginPath(); ctx.arc(px,py,3,0,Math.PI*2); ctx.fill(); });
        }
        ctx.restore();
        break;
      }

      case 'pricerange': {
        // Full-width horizontal price zone (support/resistance band)
        const y1=pyfn(d.price1), y2=pyfn(d.price2);
        const top=Math.min(y1,y2), bot=Math.max(y1,y2);
        const dCol=d.color||col;
        ctx.save();
        // Zone fill
        ctx.fillStyle=dCol+'20';
        ctx.fillRect(0,top,W,bot-top);
        // Top edge
        ctx.strokeStyle=dCol; ctx.lineWidth=isSel?2:1.2;
        _btApplyLineStyle(ctx, d.ls||'dashed');
        ctx.beginPath(); ctx.moveTo(0,y1); ctx.lineTo(W,y1); ctx.stroke();
        // Bottom edge
        ctx.beginPath(); ctx.moveTo(0,y2); ctx.lineTo(W,y2); ctx.stroke();
        ctx.setLineDash([]);
        // Labels
        ctx.font='9px monospace'; ctx.textAlign='left';
        const lbl1=fP(d.price1), lbl2=fP(d.price2);
        const pctH=((Math.abs(d.price2-d.price1)/Math.min(d.price1,d.price2))*100).toFixed(2)+'%';
        [[y1,lbl1],[y2,lbl2]].forEach(([y,lbl])=>{
          const lw2=ctx.measureText(lbl).width+10;
          ctx.fillStyle='rgba(8,11,22,0.85)'; ctx.fillRect(4,y-10,lw2,13);
          ctx.fillStyle=dCol; ctx.fillText(lbl,9,y-1);
        });
        if(Math.abs(y2-y1)>28){
          ctx.textAlign='right'; ctx.fillStyle=dCol+'99';
          ctx.font='bold 9px monospace';
          ctx.fillText(pctH, W-R_PANEL_OFFSET-12, (top+bot)/2+4);
        }
        ctx.restore();
        break;
      }

      case 'fibext': {
        // Fibonacci with extension levels (0% to 261.8%)
        const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
        const range=d.price1-d.price2;
        const levels=[
          {v:0,    c:'rgba(240,165,0,.85)',  n:'0%'},
          {v:0.236,c:'rgba(61,127,255,.85)', n:'23.6%'},
          {v:0.382,c:'rgba(0,201,160,.85)',  n:'38.2%'},
          {v:0.5,  c:'rgba(255,255,255,.75)',n:'50%'},
          {v:0.618,c:'rgba(0,201,160,.85)',  n:'61.8%'},
          {v:0.786,c:'rgba(240,48,96,.85)',  n:'78.6%'},
          {v:1,    c:'rgba(240,165,0,.85)',  n:'100%'},
          {v:1.272,c:'rgba(156,110,255,.85)',n:'127.2%'},
          {v:1.414,c:'rgba(156,110,255,.75)',n:'141.4%'},
          {v:1.618,c:'rgba(255,165,0,.85)',  n:'161.8%'},
          {v:2,    c:'rgba(255,165,0,.75)',  n:'200%'},
          {v:2.618,c:'rgba(255,165,0,.65)',  n:'261.8%'},
        ];
        const minX=Math.min(x1,x2), maxX=Math.max(x1,x2);
        levels.forEach((lv)=>{
          const price=d.price2+range*lv.v;
          const y=pyfn(price);
          if(y<-20||y>H+20) return;
          ctx.strokeStyle=lv.c; ctx.lineWidth=1; ctx.setLineDash([4,4]);
          ctx.beginPath(); ctx.moveTo(minX,y); ctx.lineTo(maxX,y); ctx.stroke();
          ctx.setLineDash([]);
          ctx.font='8px monospace'; ctx.textAlign='left';
          const label=`${lv.n}  ${fP(price)}`;
          const lw2=ctx.measureText(label).width+6;
          ctx.fillStyle='rgba(8,11,22,0.8)'; ctx.fillRect(maxX+2,y-9,lw2,12);
          ctx.fillStyle=lv.c; ctx.fillText(label,maxX+5,y+1);
        });
        ctx.strokeStyle='rgba(240,165,0,.35)'; ctx.lineWidth=1; ctx.setLineDash([]);
        ctx.beginPath(); ctx.moveTo(x1,y1); ctx.lineTo(x2,y2); ctx.stroke();
        break;
      }

      case 'arrow': {
        // Directional arrow annotation
        const ax=barXfn(d.bar), ay=pyfn(d.price);
        const dCol=d.color||col;
        const isUp=d.pointing==='up';
        const ahLen=22, ahW=8;
        ctx.save();
        ctx.strokeStyle=dCol; ctx.fillStyle=dCol; ctx.globalAlpha=isSel?1:0.85;
        // Shaft
        ctx.lineWidth=isSel?3:2.5;
        ctx.beginPath();
        ctx.moveTo(ax, ay+(isUp?ahLen:-ahLen));
        ctx.lineTo(ax, ay+(isUp?ahW:-ahW));
        ctx.stroke();
        // Head
        ctx.beginPath();
        if(isUp){
          ctx.moveTo(ax,ay); ctx.lineTo(ax-ahW,ay+ahLen/2); ctx.lineTo(ax+ahW,ay+ahLen/2);
        } else {
          ctx.moveTo(ax,ay); ctx.lineTo(ax-ahW,ay-ahLen/2); ctx.lineTo(ax+ahW,ay-ahLen/2);
        }
        ctx.closePath(); ctx.fill();
        // Label if any
        if(d.label){
          ctx.font='bold 10px sans-serif'; ctx.textAlign='center';
          const lw2=ctx.measureText(d.label).width+10;
          const ly=isUp?ay+ahLen+14:ay-ahLen-4;
          ctx.fillStyle='rgba(8,11,22,0.9)'; ctx.globalAlpha=0.9;
          ctx.fillRect(ax-lw2/2,ly-12,lw2,15);
          ctx.fillStyle=dCol; ctx.globalAlpha=1;
          ctx.fillText(d.label,ax,ly);
        }
        ctx.restore();
        break;
      }
    }
    ctx.restore();
  });

  // ── Multi-selection highlight glow ─────────────────────────────────────────
  if(selectedDrawings.length > 1){
    selectedDrawings.forEach(d=>{
      if(d===selectedDrawing) return; // already has handles
      ctx.save();
      ctx.strokeStyle='rgba(240,165,0,.5)';
      ctx.lineWidth=2; ctx.setLineDash([4,3]);
      // draw a bounding highlight based on type
      switch(d.type){
        case 'hline': case 'hray':{ const y=pyfn(d.price); ctx.beginPath(); ctx.moveTo(0,y); ctx.lineTo(W,y); ctx.stroke(); break; }
        case 'vline':{ const x=barXfn(d.bar); ctx.beginPath(); ctx.moveTo(x,0); ctx.lineTo(x,H); ctx.stroke(); break; }
        case 'line': case 'ray': case 'fib': case 'measure':{
          const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
          const rx=Math.min(x1,x2)-6,ry=Math.min(y1,y2)-6;
          ctx.strokeRect(rx,ry,Math.abs(x2-x1)+12,Math.abs(y2-y1)+12); break;
        }
        case 'rect':{
          const x1=barXfn(d.bar1),y1=pyfn(d.price1),x2=barXfn(d.bar2),y2=pyfn(d.price2);
          ctx.strokeRect(Math.min(x1,x2)-4,Math.min(y1,y2)-4,Math.abs(x2-x1)+8,Math.abs(y2-y1)+8); break;
        }
        case 'long': case 'short':{
          const ex=barXfn(d.bar),ey=pyfn(d.price);
          const hb=effectiveHalfBars(d); const bx=d.isMentorExample?ex:ex-hb*barWidth,w=d.isMentorExample?hb*barWidth:hb*2*barWidth;
          const sly=pyfn(d.sl),tpy=pyfn(d.tp);
          ctx.strokeRect(bx-4,Math.min(ey,sly,tpy)-4,w+8,Math.abs(Math.max(ey,sly,tpy)-Math.min(ey,sly,tpy))+8); break;
        }
        default:{ const x=barXfn(d.bar||d.bar1||0),y=pyfn(d.price||d.price1||0); ctx.strokeRect(x-10,y-10,20,20); }
      }
      ctx.restore();
    });
  }

  // ── Draw handles for selected drawing ──────────────────────────────────────
  if(selectedDrawing && !drawingWIP){
    const handles = getHandles(selectedDrawing);
    handles.forEach(h=>{
      ctx.save();
      ctx.fillStyle = 'rgba(240,165,0,.95)';
      ctx.strokeStyle = '#07090e'; ctx.lineWidth = 2;
      if(h.cur==='ew-resize'){
        ctx.beginPath(); ctx.roundRect(h.x-4, h.y-10, 8, 20, 3);
      } else if(h.cur==='ns-resize'){
        ctx.beginPath(); ctx.roundRect(h.x-10, h.y-4, 20, 8, 3);
      } else {
        ctx.beginPath(); ctx.arc(h.x, h.y, h.id==='mid'?5:6, 0, Math.PI*2);
        ctx.fillStyle = h.id==='mid'?'rgba(240,165,0,.6)':'rgba(240,165,0,.95)';
      }
      ctx.fill(); ctx.stroke();
      ctx.restore();
    });
  }

  // ── Marquee selection rectangle ────────────────────────────────────────────
  if(isMarquee){
    const rx=Math.min(marqueeX0,marqueeX1), ry=Math.min(marqueeY0,marqueeY1);
    const rw=Math.abs(marqueeX1-marqueeX0), rh=Math.abs(marqueeY1-marqueeY0);
    ctx.save();
    ctx.fillStyle='rgba(61,127,255,.07)';
    ctx.fillRect(rx,ry,rw,rh);
    ctx.strokeStyle='rgba(61,127,255,.8)';
    ctx.lineWidth=1; ctx.setLineDash([4,3]);
    ctx.strokeRect(rx,ry,rw,rh);
    ctx.setLineDash([]);
    // corner dots
    ctx.fillStyle='rgba(61,127,255,.9)';
    [[rx,ry],[rx+rw,ry],[rx+rw,ry+rh],[rx,ry+rh]].forEach(([x,y])=>{
      ctx.beginPath(); ctx.arc(x,y,3,0,Math.PI*2); ctx.fill();
    });
    // label
    ctx.font='9px monospace'; ctx.textAlign='left'; ctx.fillStyle='rgba(61,127,255,.9)';
    ctx.fillText(`${Math.round(rw)}×${Math.round(rh)}`, rx+4, ry-4);
    ctx.restore();
  }
}

// ── Lighten a hex color ───────────────────────────────────────────────────────
function lightenColor(hex, amt){
  // simple: just return as-is since we use alpha for selection cue instead
  return hex;
}
const Y_AXIS_W = 52;
const X_AXIS_H = 44;
// Pixels the right glass panel overlaps the canvas — y-axis drawn inside this
const R_PANEL_OFFSET = 280;

function getZone(x,y,W,H){
  if(x > W - R_PANEL_OFFSET - Y_AXIS_W) return 'yscale';
  if(y > H - X_AXIS_H) return 'xscale';
  return 'pan';
}

function getAutoRange(){
  const mc = _el('main-canvas');
  const W = mc.width;
  const data = curCT==='heikin'?calcHeikin(curData):curData;
  const first = Math.max(0, Math.ceil(rightBarIndex - W/barWidth));
  const last  = Math.min(data.length-1, Math.floor(rightBarIndex));
  let hi=-Infinity, lo=Infinity;
  data.slice(first,last+1).forEach(d=>{ hi=Math.max(hi,d.high); lo=Math.min(lo,d.low); });
  const pad=(hi-lo)*.08||hi*.01;
  return { hi:hi+pad, lo:lo-pad };
}

function setupEvents(){
  const mc = _el('main-canvas');

  // ── mousedown ─────────────────────────────────────────────────────────────
  mc.addEventListener('mousedown', e => {
    const r  = mc.getBoundingClientRect();
    const lx = uiToCanvasPx(e.clientX - r.left);
    const ly = uiToCanvasPx(e.clientY - r.top);
    const zone = getZone(lx, ly, mc.width, mc.height);

    // ── Replay: click on canvas play/pause button ────────────────────────
    if(replayMode && !replayPicking && window._replayBtnX >= 0){
      const dx = lx - window._replayBtnX;
      const dy = ly - window._replayBtnY;
      if(Math.sqrt(dx*dx+dy*dy) <= (window._replayBtnR||18)){
        replayTogglePlay();
        return;
      }
    }

    // ── Replay: drag the committed cutoff line ───────────────────────────
    if(replayMode && !replayPicking && replayCutoff >= 0 && zone === 'pan'){
      const cutoffX = mc.width - (rightBarIndex - replayCutoff) * barWidth;
      if(Math.abs(lx - cutoffX) <= 8){
        _replayLineDragging = true;
        // Pause auto-play while dragging
        if(replayTimer){ clearInterval(replayTimer); replayTimer = null; }
        mc.style.cursor = 'ew-resize';
        e.preventDefault();
        return;
      }
    }

    // ── Replay: clicking in the pan zone commits the start bar ────────────
    if(replayMode && replayPicking && zone === 'pan'){
      const W = mc.width;
      const firstBar = Math.max(0, Math.ceil(rightBarIndex - W / barWidth));
      const barIdx   = Math.max(1, Math.min(curData.length - 1,
        Math.round(firstBar + (lx - (W - (rightBarIndex - firstBar) * barWidth)) / barWidth)
      ));
      replayPickBar(barIdx);
      return;
    }

    // ── Drawing tools intercept pan zone ──────────────────────────────────
    if(zone === 'pan'){
      if(handleDrawMousedown(lx, ly, e)) return;
    }

    if(zone === 'pan'){
      isPanning    = true;
      panStartX    = uiToCanvasPx(e.clientX);
      panStartY    = uiToCanvasPx(e.clientY);
      panStartRight= rightBarIndex;
      // snapshot price range for vertical pan
      if(priceHi === null){ const a=getAutoRange(); priceHi=a.hi; priceLo=a.lo; }
      panStartHi   = priceHi;
      panStartLo   = priceLo;
      mc.style.cursor = 'grabbing';
    }
    else if(zone === 'xscale'){
      isXScaling      = true;
      xScaleStartX    = uiToCanvasPx(e.clientX);
      xScaleStartBW   = barWidth;
      // anchor: bar under mouse stays fixed — store both bar and pixel position
      xScaleAnchorX   = lx;
      xScaleAnchorBar = rightBarIndex - (mc.width - lx) / barWidth;
      mc.style.cursor = 'ew-resize';
    }
    else if(zone === 'yscale'){
      isYScaling        = true;
      yScaleStartY      = uiToCanvasPx(e.clientY);
      if(priceHi === null){ const a=getAutoRange(); priceHi=a.hi; priceLo=a.lo; }
      yScaleStartHi     = priceHi;
      yScaleStartLo     = priceLo;
      // anchor: price under mouse stays fixed
      yScaleAnchorPrice = priceLo + (mc.height - ly) / mc.height * (priceHi - priceLo);
      mc.style.cursor   = 'ns-resize';
    }
    e.preventDefault();
  });

  // ── mousemove on document so drag survives leaving canvas ─────────────────
  // Cache canvas bounding rect — only re-read on resize/scroll
  let _mcRect = mc.getBoundingClientRect();
  window.addEventListener('resize', ()=>{ _mcRect = mc.getBoundingClientRect(); });
  window.addEventListener('scroll', ()=>{ _mcRect = mc.getBoundingClientRect(); }, true);

  document.addEventListener('mousemove', e => {
    const r  = _mcRect;
    mouseX = uiToCanvasPx(e.clientX - r.left);
    mouseY = uiToCanvasPx(e.clientY - r.top);

    // Drawing WIP preview or drag/resize or marquee
    if(drawingWIP || isDraggingDrawing || isResizingDrawing || isMarquee){
      handleDrawMousemove(mouseX, mouseY); return;
    }

    // ── Replay line drag ──────────────────────────────────────────────────
    if(_replayLineDragging && replayMode && curData){
      const W = mc.width;
      const firstBar = Math.max(0, Math.ceil(rightBarIndex - W / barWidth));
      const newCutoff = Math.max(1, Math.min(curData.length - 1,
        Math.round(firstBar + (mouseX - (W - (rightBarIndex - firstBar) * barWidth)) / barWidth)
      ));
      replayCutoff = newCutoff;
      updateReplayStatus();
      draw();
      return;
    }

    // ── Show ew-resize cursor when hovering near the replay cutoff line ──────
    if(replayMode && !replayPicking && !_replayLineDragging && !isPanning && replayCutoff >= 0){
      const W2 = mc.width;
      const cx = W2 - (rightBarIndex - replayCutoff) * barWidth;
      if(Math.abs(mouseX - cx) <= 8){
        mc.style.cursor = 'ew-resize';
      } else if(mc.style.cursor === 'ew-resize'){
        mc.style.cursor = activeTool === 'eraser' ? 'cell' : 'crosshair';
      }
    }

    if(isPanning){
      // Add safety checks for replay mode
      if(!curData || curData.length <= 1 || barWidth <= 0) {
        isPanning = false;
        mc.style.cursor = 'crosshair';
        return;
      }
      
      const dx   = uiToCanvasPx(e.clientX) - panStartX;
      const dy   = uiToCanvasPx(e.clientY) - panStartY;

      // Horizontal: shift rightBarIndex by how many bars we moved
      rightBarIndex = panStartRight - dx / barWidth;
      // Symmetric half-screen limits: oldest bar ≥ x=W/2, newest bar ≤ x=W/2
      const _halfBars = (mc.width / 2) / barWidth;
      rightBarIndex = Math.max(_halfBars, Math.min(curData.length - 1 + _halfBars, rightBarIndex));

      // Vertical: shift price range by equivalent price delta
      const range    = panStartHi - panStartLo;
      const pricePx  = range / mc.height;
      priceHi = panStartHi + dy * pricePx;
      priceLo = panStartLo + dy * pricePx;

      // Auto-fetch more history when panned to left edge (but not during replay)
      if(!replayMode) {
        const firstVisible = Math.ceil(rightBarIndex - mc.width / barWidth);
        if(firstVisible <= 5 && !isFetchingMore) fetchMoreHistory();
      }

      draw(); return;
    }

    if(isXScaling){
      // Add safety checks for replay mode
      if(!curData || curData.length <= 1 || barWidth <= 0) {
        isXScaling = false;
        mc.style.cursor = 'crosshair';
        return;
      }
      
      const dx   = uiToCanvasPx(e.clientX) - xScaleStartX;
      // Exponential so small moves near centre feel natural
      const newBW = Math.max(1, Math.min(80, xScaleStartBW * Math.pow(1.005, dx)));
      // Keep anchor bar at same screen pixel — anchor bar stays at xScaleAnchorX from left
      rightBarIndex = xScaleAnchorBar + (mc.width - xScaleAnchorX) / newBW;
      barWidth = newBW;
      // Re-apply half-screen bounds after scale change
      const _halfBarsX = (mc.width / 2) / barWidth;
      rightBarIndex = Math.max(_halfBarsX, Math.min(curData.length - 1 + _halfBarsX, rightBarIndex));
      draw(); return;
    }

    if(isYScaling){
      // Add safety checks for replay mode
      if(!curData || curData.length <= 1 || !yScaleStartHi || !yScaleStartLo) {
        isYScaling = false;
        mc.style.cursor = 'crosshair';
        return;
      }
      
      const dy       = uiToCanvasPx(e.clientY) - yScaleStartY;
      const oldRange = yScaleStartHi - yScaleStartLo;
      // drag down = zoom in (tighter range), drag up = zoom out
      const newRange = Math.max(oldRange * 0.01, oldRange * Math.pow(1.005, dy));
      const anchorFrac = (yScaleAnchorPrice - yScaleStartLo) / oldRange;
      priceLo = yScaleAnchorPrice - anchorFrac * newRange;
      priceHi = priceLo + newRange;
      draw(); return;
    }

    // Hover — update cursor based on zone and drawings
    if(!isPanning && !isXScaling && !isYScaling){
      if(isMarquee){ mc.style.cursor='crosshair'; draw(); return; }
      const zone = getZone(mouseX, mouseY, mc.width, mc.height);
      if(activeTool === 'cursor' && zone === 'pan'){
        let cur = 'crosshair';
        if(selectedDrawing){
          const hid = hitTestHandle(selectedDrawing, mouseX, mouseY);
          if(hid){
            const handles = getHandles(selectedDrawing);
            const h = handles.find(h=>h.id===hid);
            cur = h?.cur || 'nwse-resize';
          } else if(hitTest(selectedDrawing, mouseX, mouseY)){
            cur = 'move';
          }
        }
        if(cur==='crosshair'){
          if(drawings.some(d=>d!==selectedDrawing&&hitTest(d,mouseX,mouseY))) cur='move';
        }
        mc.style.cursor = cur;
      } else {
        mc.style.cursor = replayPicking ? 'cell' : zone==='yscale'?'ns-resize': zone==='xscale'?'ew-resize': activeTool==='eraser'?'cell':'crosshair';
      }
      draw();
    }
  });

  // ── mouseup on document ────────────────────────────────────────────────────
  document.addEventListener('mouseup', e => {
    if(drawingWIP || isDraggingDrawing || isResizingDrawing || isMarquee){
      const r = mc.getBoundingClientRect();
      handleDrawMouseup(e.clientX-r.left, e.clientY-r.top);
      return;
    }
    // ── Replay line drag commit ────────────────────────────────────────────
    if(_replayLineDragging){
      _replayLineDragging = false;
      mc.style.cursor = 'crosshair';
      _replayScrollToBar(replayCutoff);

      if(mentorState.enabled) {
        const lc = mentorState.lifecycleState;

        if ((lc === 'setup_detected' || lc === 'preview') && mentorState.upcomingSetup) {
          // Approaching a setup — refresh annotations for new position, preserve setup
          const _sb = mentorState.upcomingSetup.bar;
          const _ba = _sb - replayCutoff;
          // If user dragged PAST the setup bar, reset to scanning
          if (replayCutoff >= _sb) {
            setMentorState('scanning', 'scrubbed past pending setup');
            mentorState.upcomingSetup  = null;
            mentorState._lastAnnotateStage = 0;
            mentorState._lastAnnotateBar   = null;
            mentorState.setupCache && mentorState.setupCache.clear();
            setTimeout(() => updateMentor(), 80);
          } else {
            // Still before the setup — refresh annotations and message
            mentorState._lastAnnotateStage = 0; // force redraw from stage 1
            mentorState._lastAnnotateBar   = null;
            if (!mentorState.earlyWarningShown && _ba > 5) {
              _mentorAnnotateSetup(mentorState.upcomingSetup.setup, replayCutoff, _sb);
            }
            _buildSetupDetectedMessage(replayCutoff);
            updateMentorUI();
          }

        } else if (lc === 'setup_wait' || lc === 'trade_monitoring' ||
                   lc === 'trade_result' || lc === 'trade_completed') {
          // Trade is active or was completed — preserve everything, just update UI
          // The trade tool, annotations, and panel all stay intact
          if (mentorState._tradeSetupData) {
            const tsd = mentorState._tradeSetupData;
            _mentorAnnotateSetup(tsd.setup, replayCutoff, tsd.setupBar);
          }
          // Re-run the monitoring step in case user scrubbed during a trade
          if (lc === 'trade_monitoring' && mentorState.exampleTradeActive) {
            monitorExampleTrade(replayCutoff);
          }
          updateMentorUI();

        } else {
          // scanning / no_setup_found / method_selection — safe to reset and re-scan
          setMentorState('scanning', 'scrub reset');
          mentorState.setupCache && mentorState.setupCache.clear();
          setTimeout(() => updateMentor(), 80);
        }
      }
      updateReplayStatus();
      draw();
      return;
    }
    if(isPanning || isXScaling || isYScaling){
      syncActiveChartTabRuntimeState(true);
    }
    isPanning = isXScaling = isYScaling = false;
    mc.style.cursor = activeTool==='eraser'?'cell':'crosshair';
  });

  // ── mouseleave — hide crosshair only if not dragging ───────────────────────
  mc.addEventListener('mouseleave', () => {
    if(!isPanning && !isXScaling && !isYScaling){
      mouseX = -1; mouseY = -1; draw();
    }
  });

  // ── double-click to reset or edit text ──────────────────────────────────────
  mc.addEventListener('dblclick', e => {
    const r  = mc.getBoundingClientRect();
    const lx = e.clientX-r.left, ly = e.clientY-r.top;
    const zone = getZone(lx, ly, mc.width, mc.height);
    // Edit text drawing on double-click
    if(activeTool==='cursor'){
      for(let i=drawings.length-1;i>=0;i--){
        if(drawings[i].type==='text' && hitTest(drawings[i],lx,ly)){
          const txt=prompt('Edit label:',drawings[i].text||'');
          if(txt!==null){ drawings[i].text=txt||drawings[i].text; draw(); }
          return;
        }
      }
    }
    if(zone === 'pan' || zone === 'yscale'){ priceHi=null; priceLo=null; }
    if(zone === 'xscale'){ barWidth=8; }
    syncActiveChartTabRuntimeState(true);
    draw();
  });

  // ── scroll wheel ──────────────────────────────────────────────────────────
  mc.addEventListener('wheel', e => {
    e.preventDefault();
    const r    = mc.getBoundingClientRect();
    const lx   = uiToCanvasPx(e.clientX - r.left);
    const ly   = uiToCanvasPx(e.clientY - r.top);
    const zone = getZone(lx, ly, mc.width, mc.height);
    const up   = e.deltaY < 0;

    if(zone === 'xscale' || zone === 'pan'){
      // Zoom candle width, anchored to bar under mouse
      const anchorBar = rightBarIndex - (mc.width - lx) / barWidth;
      const factor    = up ? 1.1 : 0.91;
      barWidth = Math.max(1, Math.min(80, barWidth * factor));
      // Restore anchor bar to same screen position
      rightBarIndex = anchorBar + (mc.width - lx) / barWidth;
    }
    else if(zone === 'yscale'){
      if(priceHi===null){ const a=getAutoRange(); priceHi=a.hi; priceLo=a.lo; }
      const anchorPrice = priceLo + (mc.height-ly)/mc.height*(priceHi-priceLo);
      const range = priceHi - priceLo;
      const newRange = range * (up ? 0.88 : 1.14);
      const frac = (anchorPrice - priceLo) / range;
      priceLo = anchorPrice - frac * newRange;
      priceHi = priceLo + newRange;
    }
    syncActiveChartTabRuntimeState(true);
    draw();
  }, { passive:false });

  window.addEventListener('resize', () => setTimeout(()=>{ sizeCanvases(); positionChartTabsBar(); draw(); }, 50));
}

// ══ LOAD SYMBOL ═══════════════════════════════════════════════════════════════
// ── Live WebSocket tick ────────────────────────────────────────────────────────
let liveWS = null;
let liveWSSym = null;

async function connectLiveTick(sym, type){
  if(liveWS){ try{ liveWS.close(); }catch(e){} liveWS=null; }
  // Only Finnhub WS supports stocks + forex; crypto uses Binance WS
  if(type==='Crypto'){
    const pair = sym.replace('/','').toLowerCase()+'t'; // BTC/USD → btcusdt
    liveWS = new WebSocket('wss://stream.binance.com:9443/ws/'+pair+'@ticker');
    liveWSSym = sym;
    liveWS.onmessage = e => {
      try{
        const d = JSON.parse(e.data);
        if(!d.c) return;
        const price = parseFloat(d.c);
        updateLiveTick(sym, price);
      }catch(err){}
    };
    liveWS.onerror = ()=>{};
  }
}

function setSrcStatus(text, color){
  const el = document.getElementById('st-src');
  if(el){ el.textContent=text; el.style.color=color||''; }
}
function updateLiveTick(sym, price){
  if(sym !== curSym.s || !curData.length) return;
  const last = curData[curData.length-1];
  const now  = Math.floor(Date.now()/1000);
  const step = {'1m':60,'5m':300,'15m':900,'1h':3600,'1d':86400,'1w':604800,'1M':2592000}[curTF]||86400;
  if(now - last.time < step){
    last.close = price;
    last.high  = Math.max(last.high, price);
    last.low   = Math.min(last.low, price);
  } else {
    curData.push({time:now, open:price, high:price, low:price, close:price, volume:0});
  }
  updateTopbar(); draw();
  const s = SYMS.find(x=>x.s===sym);
  if(s){ const prev=s.p||price; s.c=+((price-prev)/prev*100).toFixed(2); s.p=price; }
  setSrcStatus('● live','var(--tl)');
}

// ── Historical extension (pan left past oldest bar) ─────────────────────────
let isFetchingMore = false;

async function fetchMoreHistory(){
  if(isFetchingMore || !curData.length) return;
  const oldest = curData[0].time;
  const sym = curSym.s;
  const tf  = curTF;
  isFetchingMore = true;
  setSrcStatus('⟳ loading history…','var(--tx3)');
  try{
    let bars = [];
    if(curSym.t === 'Crypto'){
      bars = await fetchBinanceCandles(sym, tf, null, oldest*1000);
    }
    if(bars.length && sym===curSym.s && tf===curTF){
      // Deduplicate and prepend
      const existingTimes = new Set(curData.map(d=>d.time));
      const newBars = bars.filter(b=>!existingTimes.has(b.time)).sort((a,b)=>a.time-b.time);
      if(newBars.length){
        curData = [...newBars, ...curData];
        invalidateIndCache();
        rightBarIndex += newBars.length; // keep view stable
        dataCache[sym+'_'+tf] = curData;
        draw();
        setSrcStatus('● live · '+newBars.length+' bars added','var(--tl)');
      } else {
        setSrcStatus('● live · no older data','var(--tl)');
      }
    }
  }catch(e){
    setSrcStatus('● live','var(--tl)');
  }
  isFetchingMore = false;
}

// ── Binance candle fetcher ───────────────────────────────────────────────────
async function fetchBinanceCandles(sym, tf, startTime=null, endTime=null){
  const pair   = sym.replace('/','').toUpperCase().replace('USD','USDT');
  const btf    = BINANCE_TF[tf]||'1d';
  let url = `https://api.binance.com/api/v3/klines?symbol=${pair}&interval=${btf}&limit=1000`;
  if(endTime)   url += `&endTime=${endTime}`;
  if(startTime) url += `&startTime=${startTime}`;
  const data = await fetch(url).then(r=>r.json()).catch(()=>[]);
  if(!Array.isArray(data)) return [];
  return data.map(k=>({
    time:  Math.floor(k[0]/1000),
    open:  parseFloat(k[1]),
    high:  parseFloat(k[2]),
    low:   parseFloat(k[3]),
    close: parseFloat(k[4]),
    volume:parseFloat(k[5])
  }));
}

// ── Main symbol loader ───────────────────────────────────────────────────────
async function loadSym(sym){
  const requestTabId = activeChartTabId;
  const requestTF = curTF;
  const requestSeq = ++chartLoadSeq;
  beginChartTransition(requestTabId, requestSeq);
  const requestTab = chartTabs.find(t => t.id === requestTabId) || null;
  if(curSym && curSym.s) saveDrawings(curSym.s, requestTF);
  const prevSym = curSym?.s;
  const symbolChanged = prevSym !== sym;
  curSym = SYMS.find(x=>x.s===sym) || SYMS[0];
  if(requestTab){
    requestTab.sym = curSym.s;
    requestTab.title = _chartTabTitle(curSym.s, requestTF);
    requestTab.tf = requestTF;
    requestTab.chartType = curCT;
    requestTab.updatedAt = Date.now();
    if(activeChartTabId === requestTabId) renderChartTabs();
  }
  const requestKey = sym+'_'+requestTF;
  // Use last real close as placeholder base so all TFs start from the same price
  const placeholderBase = (prevSym === sym && curData.length)
    ? curData[curData.length-1].close
    : curSym.p;
  curData = genData(placeholderBase, 300, VOL_MAP[requestTF]||.018);
  if(!requestTab){
    barWidth = 8;
    priceHi = null;
    priceLo = null;
  }
  if(symbolChanged){
    rightBarIndex = curData.length + 5;
    priceHi = null;
    priceLo = null;
  } else {
    rightBarIndex = clampChartTabRightIndex(requestTab?.rightBarIndex, curData.length);
  }
  normalizeChartViewportForCurrentData(symbolChanged);
  // Don't load drawings yet — curData is fake placeholder.
  // Drawings will be correctly resolved once real data arrives.
  drawings=[]; drawingWIP=null; selectedDrawing=null;
  delete aiCache[requestKey];

  // Restore indicator on/off state from persisted indActive (not from topbarInds)
  applyIndActive();
  renderTopbarInds(); sizeCanvases(); updateTopbar(); draw();
  buildWL(); buildAIPanel(); buildInfo(); buildJournal(); buildAlertsPanel(); renderThesisTrackerWidget();
  tapSyncToSymbol();
  setSrcStatus('⟳ fetching…','var(--tx3)');

  // Check session cache first
  if(dataCache[requestKey]){
    if(!isCurrentChartRequest(requestTabId, requestTF, sym, requestSeq)) return;
    curData = dataCache[requestKey];
    // Keep p in sync with cached real price
    const cachedClose = curData[curData.length-1]?.close;
    if(cachedClose && curSym.p !== cachedClose) curSym.p = cachedClose;
    if(symbolChanged){
      rightBarIndex = curData.length + 5;
      priceHi = null;
      priceLo = null;
    } else {
      rightBarIndex = clampChartTabRightIndex(requestTab?.rightBarIndex, curData.length);
    }
    normalizeChartViewportForCurrentData(symbolChanged);
    // Real data — now safe to resolve drawing timestamps → bar indices
    loadDrawings(sym, requestTF);
    // force=true: overwrite any stale placeholder-data cache entry
    updateTopbar(); draw(); buildAIPanel(true);
    setSrcStatus('● live · cached','var(--tl)');
    connectLiveTick(sym, curSym.t);
    endChartTransition(requestTabId, requestSeq, true);
    return;
  }

  try{
    let bars = [];
    if(curSym.t === 'Crypto'){
      const shortTFs = ['1m', '5m', '15m', '1h'];
      if (shortTFs.includes(requestTF)) {
        // For short timeframes, chain two 1000-bar fetches to get ~2000 bars
        const recent = await fetchBinanceCandles(sym, requestTF);
        const older = recent.length > 0
          ? await fetchBinanceCandles(sym, requestTF, null, recent[0].time * 1000)
          : [];
        const combined = [...older, ...recent];
        const seen = new Set();
        bars = combined.filter(b => { if (seen.has(b.time)) return false; seen.add(b.time); return true; });
        bars.sort((a, b) => a.time - b.time);
      } else {
        bars = await fetchBinanceCandles(sym, requestTF);
      }
    }

    if(bars.length >= 2){
      if(!isCurrentChartRequest(requestTabId, requestTF, sym, requestSeq)) return;
      bars.sort((a,b)=>a.time-b.time);
      dataCache[requestKey] = bars;
      curData = bars;
      // Keep curSym.p in sync with real price so placeholder is accurate next load
      const realClose = bars[bars.length-1].close;
      if(curSym.p !== realClose) curSym.p = realClose;
      invalidateIndCache();
      if(symbolChanged){
        rightBarIndex = curData.length + 5;
        priceHi = null;
        priceLo = null;
      } else {
        rightBarIndex = clampChartTabRightIndex(requestTab?.rightBarIndex, curData.length);
      }
      normalizeChartViewportForCurrentData(symbolChanged);
      // Re-resolve drawing timestamps → bar indices now that real data is loaded
      loadDrawings(sym, requestTF);
      // force=true: overwrite any stale placeholder-data cache entry
      updateTopbar(); draw(); buildAIPanel(true); buildInfo();
      setSrcStatus('● live','var(--tl)');
      connectLiveTick(sym, curSym.t);
      setTimeout(() => tapScanCurrentChart().catch(() => {}), 2000); // incremental scan in background
      endChartTransition(requestTabId, requestSeq, true);
    } else {
      if(!isCurrentChartRequest(requestTabId, requestTF, sym, requestSeq)) return;
      setSrcStatus('⚠ simulated · no live data','var(--am)');
      endChartTransition(requestTabId, requestSeq, true);
    }
  } catch(err){
    if(!isCurrentChartRequest(requestTabId, requestTF, sym, requestSeq)) return;
    setSrcStatus('⚠ simulated · fetch error','var(--rd)');
    endChartTransition(requestTabId, requestSeq, true);
  }
}

function updateTopbar(){
  if(!curData.length)return;
  const last=curData[curData.length-1], prev=curData[curData.length-2]||last;
  const pct=((last.close-prev.close)/prev.close*100);
  document.getElementById('sym-t').textContent=curSym.s;
  document.getElementById('sym-e').textContent=curSym.e;
  // Statusbar — symbol, timeframe, bar count
  const sbSym = document.getElementById('sb-sym'); if(sbSym) sbSym.textContent = curSym.s;
  const sbTf  = document.getElementById('sb-tf');  if(sbTf)  sbTf.textContent  = curTF.toUpperCase();
  const sbBars= document.getElementById('sb-bars'); if(sbBars) sbBars.textContent = curData.length + ' bars';
  updateChartScrubber();
  document.getElementById('px-main').textContent=fP(last.close);
  const cel=document.getElementById('px-chg');
  cel.textContent=(pct>=0?'+':'')+pct.toFixed(2)+'%';
  cel.className='px-chg '+(pct>=0?'up':'dn');
  document.getElementById('ov-o').textContent=fP(last.open);
  document.getElementById('ov-h').textContent=fP(last.high);
  document.getElementById('ov-l').textContent=fP(last.low);
  document.getElementById('ov-c').textContent=fP(last.close);
  document.getElementById('ov-v').textContent=fV(last.volume);
}

// ══ CONTROLS ══════════════════════════════════════════════════════════════════
function setTF(btn,tf){
  saveDrawings(curSym.s, curTF);
  curTF=tf;
  const requestTabId = activeChartTabId;
  const activeTab = chartTabs.find(t => t.id === activeChartTabId);
  if(activeTab){
    activeTab.tf = tf;
    activeTab.title = _chartTabTitle(activeTab.sym || curSym?.s, tf);
    activeTab.updatedAt = Date.now();
    renderChartTabs();
  }
  // Clear cache for this TF so we always fetch fresh real data on TF switch
  delete dataCache[curSym.s+'_'+tf];
  document.querySelectorAll('.tf').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
  loadSym(curSym.s).then(() => {
    if(activeChartTabId !== requestTabId) return;
    // Re-anchor any AI-placed drawings to the latest bar in the new data
    const n = curData.length;
    if(!n) return;
    drawings.forEach(d => {
      if(!d._aisPlaced) return;
      const halfBars = effectiveHalfBars(d);
      d.bar = n - 1 + halfBars;
    });
    rightBarIndex = Math.max(rightBarIndex, n - 1 + 20);
    draw();
    saveChartTabs();
  });
}
function setCT(btn,type){
  // legacy — delegate to new system
  ctSelect(type, ctIconFor(type), ctLabelFor(type));
}
function ctIconFor(t){ return {candle:'▪',line:'∿',area:'◿',heikin:'⬡'}[t]||'▪'; }
function ctLabelFor(t){ return {candle:'Candles',line:'Line',area:'Area',heikin:'Heikin Ashi'}[t]||t; }
function ctSelect(type, icon, label){
  curCT = type;
  const activeTab = chartTabs.find(t => t.id === activeChartTabId);
  if(activeTab){
    activeTab.chartType = type;
    activeTab.updatedAt = Date.now();
    renderChartTabs();
    saveChartTabs();
  }
  // Update button face
  const iconEl = document.getElementById('ct-sel-icon');
  if(iconEl) iconEl.textContent = icon;
  // Mark active option
  document.querySelectorAll('.ct-opt').forEach(b => b.classList.remove('active'));
  const active = document.querySelector(`.ct-opt[onclick*="'${type}'"]`);
  if(active) active.classList.add('active');
  ctCloseMenu();
  draw();
}
function ctToggleMenu(){
  const btn  = document.getElementById('ct-sel-btn');
  const menu = document.getElementById('ct-menu');
  if(!btn || !menu) return;
  const isOpen = menu.classList.contains('open');
  if(isOpen){ ctCloseMenu(); }
  else {
    btn.classList.add('open');
    menu.classList.add('open');
    // Mark current type active
    document.querySelectorAll('.ct-opt').forEach(b => b.classList.remove('active'));
    const active = document.querySelector(`.ct-opt[onclick*="'${curCT}'"]`);
    if(active) active.classList.add('active');
  }
}
function ctCloseMenu(){
  const btn  = document.getElementById('ct-sel-btn');
  const menu = document.getElementById('ct-menu');
  if(btn)  btn.classList.remove('open');
  if(menu) menu.classList.remove('open');
}
// Close dropdown when clicking outside
document.addEventListener('click', e => {
  if(!e.target.closest('#ct-dropdown')) ctCloseMenu();
});
// Turn indicator draw on/off and update its topbar button style
function toggleInd(name){
  if(name==='sessions'){ toggleSessions(); return; }
  let needsResize = ['vol','rsi','macd','stoch'].includes(name);

  // Flip both the runtime bool and the persisted indActive state
  if(name in indActive) indActive[name] = !indActive[name];
  applyIndActive();
  saveIndActive();

  const nowOn = getIndState(name);
  // Update button active state
  const btn = document.getElementById('btn-'+name);
  if(btn) btn.classList.toggle('on', nowOn);
  renderTopbarInds();
  syncActiveChartTabRuntimeState(true);
  saveSettingsToStorage();
  invalidateIndCache();
  if(needsResize) sizeCanvases();
  draw();
  // Keep the indicator list panel in sync
  renderIndList(_indSearchQ());
}

// Add indicator button to the topbar
function addIndToTopbar(id){
  // Add to pinned list if not already there
  if(!topbarInds.includes(id)){
    topbarInds.push(id);
    saveTopbarInds();
  }
  renderTopbarInds();
  // Turn on if not already active
  if(!getIndState(id)) toggleInd(id);
  else { renderIndList(_indSearchQ()); sizeCanvases(); draw(); }
}

// Remove indicator button from topbar without changing its visibility state
function removeIndFromTopbar(id){
  topbarInds = topbarInds.filter(x=>x!==id);
  saveTopbarInds();
  renderTopbarInds();
  renderIndList(_indSearchQ());
  sizeCanvases();
  draw();
}

// Rebuild the #ind-topbar div from topbarInds array
function renderTopbarInds(){
  const container = document.getElementById('ind-topbar');
  if(!container) return;
  container.innerHTML = '';
  topbarInds.forEach(id => {
    const ind = BUILTIN_INDS.find(i=>i.id===id);
    const label = ind ? ind.name : id.toUpperCase();
    const on = getIndState(id);
    const btn = document.createElement('button');
    btn.className = 'tbtn' + (on?' on':'');
    btn.id = 'btn-'+id;
    btn.textContent = label;
    btn.title = (on ? 'Hide ' : 'Show ') + label;
    btn.onclick = ()=>{ toggleInd(id); };
    container.appendChild(btn);
  });
  // Sync special indicator button states (sessions, replay use their own state vars)
  ['sessions'].forEach(id=>{
    const b = document.getElementById('btn-'+id);
    if(b) b.classList.toggle('on', getIndState(id));
  });
  // Custom indicator buttons
  customIndicators.filter(i=>i.visible).forEach(ind=>{
    const btn = document.createElement('button');
    btn.className = 'tbtn on';
    btn.id = 'btn-ci-'+ind.id;
    btn.textContent = ind.name;
    btn.title = ind.formula;
    btn.onclick = ()=>indToggle(ind.id);
    container.appendChild(btn);
  });
  // Show/hide the separator depending on whether there are any chips
  const sep = document.getElementById('ind-topbar-sep');
  if(sep) sep.style.display = container.children.length > 0 ? 'block' : 'none';
}
function sbTab(btn,tab){
  document.querySelectorAll('.sbtab').forEach(b=>b.classList.remove('on'));
  document.querySelectorAll('.sb-body').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
  document.getElementById('sb-'+tab).classList.add('on');
}
function rpTab(btn,tab){
  document.querySelectorAll('.rp-tab').forEach(b=>b.classList.remove('on'));
  document.querySelectorAll('.rp-body').forEach(b=>{ b.classList.remove('on'); b.style.display=''; });
  if(btn) btn.classList.add('on');
  const panel = document.getElementById('rp-'+tab);
  if(panel){
    panel.classList.add('on');
    if(tab==='analytics') panel.style.display='flex';
  }
  if(tab==='analytics') buildAnalytics();
  if(tab==='analytics') checkWeeklyLock();
  if(tab==='analytics') refreshAiHistoryPanel();
}

// ══ CUSTOM INDICATOR ENGINE ═══════════════════════════════════════════════════

const IND_FUNCTIONS = [
  { name:'sma',     sig:'sma(src, len)',     desc:'Simple Moving Average' },
  { name:'ema',     sig:'ema(src, len)',     desc:'Exponential Moving Average' },
  { name:'rsi',     sig:'rsi(src, len)',     desc:'Relative Strength Index' },
  { name:'stdev',   sig:'stdev(src, len)',   desc:'Standard Deviation' },
  { name:'highest', sig:'highest(src, len)', desc:'Highest value over period' },
  { name:'lowest',  sig:'lowest(src, len)',  desc:'Lowest value over period' },
  { name:'abs',     sig:'abs(x)',            desc:'Absolute value' },
  { name:'sqrt',    sig:'sqrt(x)',           desc:'Square root' },
  { name:'log',     sig:'log(x)',            desc:'Natural logarithm' },
];
const IND_SRCS = ['close','open','high','low','volume'];
const IND_ALL  = [...IND_FUNCTIONS.map(f=>f.name), ...IND_SRCS];

let indEditId = null; // null = new, string = editing

function openIndBuilder(){
  document.getElementById('indbuild-bg').style.display='flex';
  initIndChips();
  setTimeout(()=>document.getElementById('ind-name').focus(),80);
}
function closeIndBuilder(){
  document.getElementById('indbuild-bg').style.display='none';
}
function openIndList(){ toggleOverlay('inds'); }
function closeIndList(){ if(_activeOverlay==='inds') closeOverlay(); }
let ilCurrentTab='builtin';
function ilTab(btn,tab){
  ilCurrentTab=tab;
  document.querySelectorAll('.iltab').forEach(b=>b.classList.remove('on'));
  btn.classList.add('on');
  const q = (document.getElementById('ov-ind-search')||{}).value||'';
  renderIndList(q);
}
function filterIndList(q){ renderIndList(q); }

// Helper — gets current search query regardless of where the search input lives
function _indSearchQ(){ return (document.getElementById('ov-ind-search')||{}).value||''; }

function renderIndList(q){
  const el = document.getElementById('indlist-body');
  if(!el) return;
  const lq = (q||'').toLowerCase();
  if(ilCurrentTab==='builtin'){
    const rows = BUILTIN_INDS.filter(i=>!lq||i.name.toLowerCase().includes(lq)||i.desc.toLowerCase().includes(lq));
    if(!rows.length){ el.innerHTML='<div style="padding:20px;text-align:center;color:var(--tx3);font-size:10px;">No results</div>'; return; }
    el.innerHTML = rows.map(ind=>{
      const pinned = topbarInds.includes(ind.id);
      return `<div class="il-row" style="cursor:default;">
        <div style="font-size:18px;width:28px;text-align:center;flex-shrink:0;">${ind.icon}</div>
        <div style="flex:1;min-width:0;">
          <div class="il-name">${ind.name}</div>
          <div class="il-desc">${ind.desc}</div>
        </div>
        <div style="display:flex;align-items:center;gap:6px;flex-shrink:0;">
          ${pinned
            ? `<button onclick="removeIndFromTopbar('${ind.id}')" style="padding:4px 10px;background:rgba(240,165,0,.1);border:1px solid rgba(240,165,0,.4);color:var(--am);font-size:11px;border-radius:3px;cursor:pointer;font-family:monospace;white-space:nowrap;">✓ On bar</button>`
            : `<button onclick="addIndToTopbar('${ind.id}')" style="padding:4px 10px;background:var(--bg3);border:1px solid var(--b2);color:var(--tx2);font-size:11px;border-radius:3px;cursor:pointer;font-family:monospace;white-space:nowrap;" onmouseover="this.style.borderColor='var(--am)';this.style.color='var(--am)'" onmouseout="this.style.borderColor='var(--b2)';this.style.color='var(--tx2)'">+ Add to bar</button>`
          }
        </div>
      </div>`;
    }).join('');
  } else {
    // Custom tab
    const rows = customIndicators.filter(i=>!lq||i.name.toLowerCase().includes(lq)||i.formula.toLowerCase().includes(lq));
    if(!rows.length){
      el.innerHTML=`<div style="padding:30px 20px;text-align:center;">
        <div style="font-size:24px;margin-bottom:8px;">⚗</div>
        <div style="color:var(--tx2);font-size:11px;font-weight:600;margin-bottom:4px;">No custom indicators yet</div>
        <div style="color:var(--tx3);font-size:11px;margin-bottom:14px;">Use the builder to create your own</div>
        <button onclick="openIndBuilder();closeIndList()" style="padding:6px 16px;background:rgba(240,165,0,.1);border:1px solid rgba(240,165,0,.4);color:var(--am);font-size:10px;border-radius:3px;cursor:pointer;font-family:monospace;">⚗ Build Custom</button>
      </div>`;
      return;
    }
    el.innerHTML = rows.map(ind=>{
      const onBar = ind.visible;
      return `<div class="il-row" style="cursor:default;">
        <div style="width:10px;height:10px;border-radius:50%;background:${ind.color};flex-shrink:0;margin-right:4px;"></div>
        <div style="flex:1;min-width:0;">
          <div class="il-name">${ind.name}</div>
          <div class="il-desc">${ind.type==='panel'?'Sub-panel':'Overlay'} · ${ind.formula.substring(0,36)}${ind.formula.length>36?'…':''}</div>
        </div>
        <div style="display:flex;gap:5px;align-items:center;flex-shrink:0;">
          ${onBar
            ? `<button onclick="indToggle('${ind.id}');renderIndList((document.getElementById('ov-ind-search')||{}).value||'')" style="padding:4px 10px;background:rgba(240,165,0,.1);border:1px solid rgba(240,165,0,.4);color:var(--am);font-size:11px;border-radius:3px;cursor:pointer;font-family:monospace;white-space:nowrap;">✓ On bar</button>`
            : `<button onclick="indToggle('${ind.id}');renderIndList((document.getElementById('ov-ind-search')||{}).value||'')" style="padding:4px 10px;background:var(--bg3);border:1px solid var(--b2);color:var(--tx2);font-size:11px;border-radius:3px;cursor:pointer;font-family:monospace;white-space:nowrap;" onmouseover="this.style.borderColor='var(--am)';this.style.color='var(--am)'" onmouseout="this.style.borderColor='var(--b2)';this.style.color='var(--tx2)'">+ Add to bar</button>`
          }
          <button onclick="indEdit('${ind.id}');closeIndList()" style="background:none;border:1px solid var(--b1);color:var(--tx3);font-size:11px;padding:3px 7px;border-radius:3px;cursor:pointer;" onmouseover="this.style.color='var(--am)'" onmouseout="this.style.color='var(--tx3)'">✎</button>
          <button onclick="indDelete('${ind.id}');renderIndList((document.getElementById('ov-ind-search')||{}).value||'')" style="background:none;border:none;color:var(--tx3);font-size:12px;padding:2px 5px;cursor:pointer;" onmouseover="this.style.color='var(--rd)'" onmouseout="this.style.color='var(--tx3)'">✕</button>
        </div>
      </div>`;
    }).join('');
  }
}
function getIndState(id){
  if(id==='sma')      return showSMA;
  if(id==='ema')      return showEMA;
  if(id==='bb')       return showBB;
  if(id==='vwap')     return showVWAP;
  if(id==='vol')      return showVol;
  if(id==='rsi')      return showRSI;
  if(id==='macd')     return showMACD;
  if(id==='stoch')    return showStoch;
  if(id==='sessions') return showSessions;
  return false;
}
function initIndChips(){
  const chips = document.getElementById('ind-chips');
  if(!chips || chips.children.length) return;
  IND_FUNCTIONS.forEach(fn=>{
    const b = document.createElement('button');
    b.textContent = fn.name; b.title = fn.desc;
    b.style.cssText='padding:3px 9px;background:var(--bg3);border:1px solid var(--b2);color:var(--tx2);font-size:11px;border-radius:3px;cursor:pointer;font-family:monospace;transition:all .15s;';
    b.onmouseover=()=>{b.style.borderColor='var(--am)';b.style.color='var(--am)';};
    b.onmouseout=()=>{b.style.borderColor='var(--b2)';b.style.color='var(--tx2)';};
    b.onclick=()=>indInsert(fn.sig); chips.appendChild(b);
  });
  IND_SRCS.forEach(s=>{
    const b = document.createElement('button');
    b.textContent = s;
    b.style.cssText='padding:3px 9px;background:var(--bg);border:1px solid var(--b1);color:var(--tx3);font-size:11px;border-radius:3px;cursor:pointer;font-family:monospace;transition:all .15s;';
    b.onmouseover=()=>{b.style.color='var(--tx2)';};
    b.onmouseout=()=>{b.style.color='var(--tx3)';};
    b.onclick=()=>indInsert(s); chips.appendChild(b);
  });
}
// Legacy alias so rpTab call still works
function buildIndBuilder(){ openIndBuilder(); }

function indInsert(text){
  const ta = document.getElementById('ind-formula');
  const s = ta.selectionStart, e = ta.selectionEnd;
  ta.value = ta.value.substring(0,s) + text + ta.value.substring(e);
  ta.selectionStart = ta.selectionEnd = s + text.length;
  ta.focus();
  indFormulaChanged();
}

function indNameChanged(){ document.getElementById('ind-status').innerHTML=''; }

function indFormulaChanged(){
  // Simple autocomplete
  const ta    = document.getElementById('ind-formula');
  const ac    = document.getElementById('ind-autocomplete');
  const pos   = ta.selectionStart;
  const text  = ta.value.substring(0, pos);
  const match = text.match(/([a-zA-Z_]+)$/);
  if(match && match[1].length >= 2){
    const q = match[1].toLowerCase();
    const hits = IND_ALL.filter(n=>n.startsWith(q) && n!==q);
    if(hits.length){
      ac.style.display='block';
      ac.innerHTML = hits.map(h=>`<div class="ac-item" onclick="indAutocomplete('${match[1]}','${h}')" style="padding:5px 9px;cursor:pointer;color:var(--tx2);" onmouseover="this.style.background='var(--bg4)'" onmouseout="this.style.background=''"><span style="color:var(--am)">${h}</span></div>`).join('');
      return;
    }
  }
  ac.style.display='none';
}

function indAutocomplete(partial, full){
  const ta  = document.getElementById('ind-formula');
  const pos = ta.selectionStart;
  const before = ta.value.substring(0, pos);
  const after  = ta.value.substring(pos);
  const replaced = before.replace(new RegExp(partial+'$'), full);
  // If it's a function, add parens
  const isFn = IND_FUNCTIONS.some(f=>f.name===full);
  ta.value = replaced + (isFn?'(':'' ) + after;
  const newPos = replaced.length + (isFn?1:0);
  ta.selectionStart = ta.selectionEnd = newPos;
  ta.focus();
  document.getElementById('ind-autocomplete').style.display='none';
}

// Close autocomplete on outside click
document.addEventListener('click', e=>{
  const ac = document.getElementById('ind-autocomplete');
  if(ac && !ac.contains(e.target) && e.target.id!=='ind-formula') ac.style.display='none';
});

function evalIndFormula(formula, data){
  // Build per-bar value arrays from data
  const close  = data.map(d=>d.close);
  const open   = data.map(d=>d.open);
  const high   = data.map(d=>d.high);
  const low    = data.map(d=>d.low);
  const volume = data.map(d=>d.volume);

  // Helper: rolling function over an array
  const roll = (arr, n, fn) => arr.map((_,i)=>i<n-1?null:fn(arr.slice(i-n+1,i+1)));

  // Expose functions
  function smaFn(src,len){ return roll(src,len,a=>a.reduce((s,v)=>s+v,0)/len); }
  function emaFn(src,len){
    const k=2/(len+1); let e=src[0];
    return src.map((v,i)=>{ if(i)e=v*k+e*(1-k); return e; });
  }
  function rsiFn(src,len){
    return src.map((x,i)=>{
      if(i<len)return null;
      let g=0,l=0;
      for(let j=i-len+1;j<=i;j++){const v=src[j]-src[j-1];v>0?g+=v:l-=v;}
      return 100-100/(1+(g/(l||.001)));
    });
  }
  function stdevFn(src,len){
    return roll(src,len,a=>{const m=a.reduce((s,v)=>s+v,0)/len;return Math.sqrt(a.reduce((s,v)=>s+(v-m)**2,0)/len);});
  }
  function highestFn(src,len){ return roll(src,len,a=>Math.max(...a)); }
  function lowestFn(src,len){  return roll(src,len,a=>Math.min(...a)); }

  // Replace function names to safe calls
  let expr = formula.trim();

  // We evaluate per-bar by building a result array
  // Strategy: detect if formula references array fns or is a scalar expression
  // We'll run in array-aware mode: sma/ema/rsi/stdev/highest/lowest return arrays
  // scalar ops (+,-,*,/) are applied element-wise

  // Substitute function names
  const safeExpr = expr
    .replace(/\bsma\b/g, 'smaFn')
    .replace(/\bema\b/g, 'emaFn')
    .replace(/\brsi\b/g, 'rsiFn')
    .replace(/\bstdev\b/g, 'stdevFn')
    .replace(/\bhighest\b/g, 'highestFn')
    .replace(/\blowest\b/g, 'lowestFn')
    .replace(/\babs\b/g, 'Math.abs')
    .replace(/\bsqrt\b/g, 'Math.sqrt')
    .replace(/\blog\b/g, 'Math.log');

  // Evaluate — result may be array or scalar
  // eslint-disable-next-line no-new-func
  const raw = new Function(
    'close','open','high','low','volume',
    'smaFn','emaFn','rsiFn','stdevFn','highestFn','lowestFn',
    `"use strict"; return (${safeExpr});`
  )(close,open,high,low,volume,smaFn,emaFn,rsiFn,stdevFn,highestFn,lowestFn);

  // Normalise to array
  if(Array.isArray(raw)) return raw;
  // Scalar — fill all bars with that value
  if(typeof raw === 'number') return data.map(()=>raw);
  // Array of arrays (e.g. two lines) — take first for now
  if(Array.isArray(raw[0])) return raw[0];
  return null;
}

function indTest(){
  const formula = document.getElementById('ind-formula').value.trim();
  const status  = document.getElementById('ind-status');
  if(!formula){ status.innerHTML='<span style="color:var(--rd)">⚠ Enter a formula first</span>'; return; }
  if(!curData.length){ status.innerHTML='<span style="color:var(--rd)">⚠ Load a chart first</span>'; return; }
  const data = curCT==='heikin'?calcHeikin(curData):curData;
  try{
    const result = evalIndFormula(formula, data);
    if(!result){ status.innerHTML='<span style="color:var(--rd)">⚠ Formula returned no data</span>'; return; }
    const vals   = result.filter(v=>v!=null&&isFinite(v));
    if(!vals.length){ status.innerHTML='<span style="color:var(--rd)">⚠ All values are null/invalid</span>'; return; }
    const mn = Math.min(...vals).toFixed(4), mx = Math.max(...vals).toFixed(4);
    status.innerHTML=`<span style="color:var(--tl)">✓ OK — ${vals.length} values · range [${mn}, ${mx}]</span>`;
  }catch(err){
    status.innerHTML=`<span style="color:var(--rd)">✗ ${err.message}</span>`;
  }
}

function indSave(){
  const name    = document.getElementById('ind-name').value.trim();
  const formula = document.getElementById('ind-formula').value.trim();
  const status  = document.getElementById('ind-status');
  if(!name){    status.innerHTML='<span style="color:var(--rd)">⚠ Give this indicator a name</span>'; return; }
  if(!formula){ status.innerHTML='<span style="color:var(--rd)">⚠ Enter a formula first</span>'; return; }
  if(!curData.length){ status.innerHTML='<span style="color:var(--rd)">⚠ Load a chart first</span>'; return; }
  const data = curCT==='heikin'?calcHeikin(curData):curData;
  try{
    const result = evalIndFormula(formula, data);
    const vals = (result||[]).filter(v=>v!=null&&isFinite(v));
    if(!vals.length){ status.innerHTML='<span style="color:var(--rd)">⚠ Formula produced no valid values</span>'; return; }
  }catch(err){
    status.innerHTML=`<span style="color:var(--rd)">✗ ${err.message}</span>`; return;
  }

  const color     = document.getElementById('ind-color').value;
  const type      = document.getElementById('ind-type').value;
  const linestyle = document.getElementById('ind-linestyle').value;
  const linewidth = parseFloat(document.getElementById('ind-linewidth').value);

  if(indEditId){
    const idx = customIndicators.findIndex(i=>i.id===indEditId);
    if(idx>=0) customIndicators[idx] = {...customIndicators[idx], name, formula, color, type, linestyle, linewidth};
  } else {
    customIndicators.push({ id: Date.now().toString(36)+Math.random().toString(36).slice(2,5), name, formula, color, type, linestyle, linewidth, visible: true });
  }
  saveCustomInds();
  renderTopbarInds();
  sizeCanvases();
  draw();
  const savedName = name;
  indClear();
  closeIndBuilder();
  toast(`⚗ ${savedName} added to chart`);
}

function indClear(){
  document.getElementById('ind-name').value='';
  document.getElementById('ind-formula').value='';
  document.getElementById('ind-color').value='#00e5ff';
  document.getElementById('ind-color-hex').value='#00e5ff';
  document.getElementById('ind-type').value='overlay';
  document.getElementById('ind-linestyle').value='solid';
  document.getElementById('ind-linewidth').value='1.5';
  document.getElementById('ind-status').innerHTML='';
  document.getElementById('ind-save-btn').textContent='✚ Add to Chart';
  document.getElementById('ind-autocomplete').style.display='none';
  const title = document.getElementById('indbuild-title');
  if(title) title.textContent='⚗ BUILD INDICATOR';
  indEditId=null;
}

function indEdit(id){
  const ind = customIndicators.find(i=>i.id===id);
  if(!ind) return;
  indEditId = id;
  document.getElementById('ind-name').value = ind.name;
  document.getElementById('ind-formula').value = ind.formula;
  document.getElementById('ind-color').value = ind.color;
  document.getElementById('ind-color-hex').value = ind.color;
  document.getElementById('ind-type').value = ind.type;
  document.getElementById('ind-linestyle').value = ind.linestyle||'solid';
  document.getElementById('ind-linewidth').value = ind.linewidth||1.5;
  document.getElementById('ind-save-btn').textContent='✔ Update Indicator';
  document.getElementById('ind-status').innerHTML='';
  document.getElementById('indbuild-title').textContent='✎ EDIT INDICATOR';
  initIndChips();
  document.getElementById('indbuild-bg').style.display='flex';
}

function indDelete(id){
  const ind = customIndicators.find(i=>i.id===id);
  if(!ind||!confirm(`Delete "${ind.name}"?`)) return;
  customIndicators = customIndicators.filter(i=>i.id!==id);
  saveCustomInds(); renderTopbarInds(); sizeCanvases(); draw();
}

function indToggle(id){
  const ind = customIndicators.find(i=>i.id===id);
  if(!ind) return;
  ind.visible = !ind.visible;
  saveCustomInds(); renderTopbarInds(); sizeCanvases(); draw();
}

function buildIndList(){
  const el = document.getElementById('ind-list');
  if(!el) return;
  if(!customIndicators.length){
    el.innerHTML='<div style="padding:14px 10px;text-align:center;color:var(--tx3);font-size:11px;font-family:monospace;">No custom indicators yet.<br>Build one above ↑</div>';
    return;
  }
  el.innerHTML = customIndicators.map(ind=>`
    <div style="display:flex;align-items:center;padding:6px 8px;border-bottom:1px solid var(--b1);gap:5px;${ind.visible?'':'opacity:.45'}">
      <div style="width:8px;height:8px;border-radius:50%;background:${ind.color};flex-shrink:0;"></div>
      <div style="flex:1;min-width:0;">
        <div style="font-size:10px;color:var(--tx);font-family:monospace;font-weight:600;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${ind.name}</div>
        <div style="font-size:11px;color:var(--tx2);font-family:monospace;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;">${ind.type==='panel'?'sub-panel':'overlay'} · ${ind.formula.substring(0,28)}${ind.formula.length>28?'…':''}</div>
      </div>
      <button onclick="indToggle('${ind.id}')" title="${ind.visible?'Hide':'Show'}" style="background:none;border:1px solid var(--b1);color:${ind.visible?'var(--am)':'var(--tx3)'};font-size:11px;padding:2px 6px;border-radius:3px;cursor:pointer;">${ind.visible?'●':'○'}</button>
      <button onclick="indEdit('${ind.id}')" title="Edit" style="background:none;border:1px solid var(--b1);color:var(--tx3);font-size:11px;padding:2px 6px;border-radius:3px;cursor:pointer;" onmouseover="this.style.color='var(--am)'" onmouseout="this.style.color='var(--tx3)'">✎</button>
      <button onclick="indDelete('${ind.id}')" title="Delete" style="background:none;border:none;color:var(--tx3);font-size:11px;padding:2px 4px;cursor:pointer;" onmouseover="this.style.color='var(--rd)'" onmouseout="this.style.color='var(--tx3)'">✕</button>
    </div>
  `).join('');
}


function buildWL(filter=''){
  const cats={Stock:[],ETF:[],Futures:[],Crypto:[],Forex:[]};
  SYMS.filter(s=>watchlist.has(s.s)&&(!filter||s.s.toLowerCase().includes(filter.toLowerCase())||s.n.toLowerCase().includes(filter.toLowerCase())))
    .forEach(s=>{if(cats[s.t])cats[s.t].push(s);});
  let html='';
  const hasAny = Object.values(cats).some(a=>a.length);
  if(!hasAny){
    html=`<div style="padding:24px 12px;text-align:center;line-height:1.8;">
      <div style="font-size:18px;margin-bottom:6px;">📋</div>
      <div style="color:var(--tx2);font-size:10px;font-weight:600;margin-bottom:3px;">Watchlist is empty</div>
      <div style="color:var(--tx3);font-size:11px;margin-bottom:12px;">Search and add symbols to track them here</div>
      <button onclick="openModal()" style="padding:5px 14px;background:rgba(240,165,0,.1);border:1px solid rgba(240,165,0,.4);color:var(--am);font-size:10px;border-radius:3px;cursor:pointer;font-family:monospace;">+ Add Symbol</button>
    </div>`;
  } else {
    for(const[cat,syms]of Object.entries(cats)){
      if(!syms.length)continue;
      html+=`<div class="wl-cat">${cat}</div>`;
      syms.forEach(s=>{html+=`<div class="wl-row${s.s===curSym.s?' on':''}" data-sym="${s.s}" onclick="selSym('${s.s}')">
        <div style="flex:1;min-width:0;"><div class="wl-sym">${s.s}</div><div class="wl-name">${s.n}</div></div>
        <div class="wl-r"><div class="wl-px">${fP(s.p)}</div><div class="wl-ch ${s.c>=0?'up':'dn'}">${s.c>=0?'+':''}${s.c}%</div></div>
        <button onclick="event.stopPropagation();removeFromWatchlist('${s.s}')" title="Remove from watchlist" style="background:none;border:none;color:var(--tx3);cursor:pointer;padding:0 2px 0 6px;font-size:11px;line-height:1;flex-shrink:0;transition:color .15s;" onmouseover="this.style.color='var(--rd)'" onmouseout="this.style.color='var(--tx3)'">✕</button>
      </div>`;});
    }
  }
  document.getElementById('wl-list').innerHTML=html;
}
function selSym(s){loadSym(s);closeModal();}
function selSymNewTab(s){ createChartTab(s, curTF); closeModal(); }

// ══ DRAGGABLE POPUPS ══════════════════════════════════════════════════════════
// makeDraggable(el, handle) — call once per popup on DOMContentLoaded.
// Drag by the handle (or el itself). Position resets when caller invokes resetDrag(el).
function makeDraggable(el, handle) {
  if (!el) return;
  handle = handle || el;
  let ox = 0, oy = 0, mx = 0, my = 0, dragging = false;
  handle.style.cursor = 'grab';

  handle.addEventListener('mousedown', e => {
    if (e.button !== 0) return;
    if (e.target.closest('button,input,select,textarea,a')) return;
    dragging = true;
    const rect = el.getBoundingClientRect();
    el.style.position  = 'fixed';
    el.style.margin    = '0';
    el.style.left      = rect.left + 'px';
    el.style.top       = rect.top  + 'px';
    el.style.right     = 'auto';
    el.style.bottom    = 'auto';
    el.style.transform = 'none';
    ox = rect.left; oy = rect.top;
    mx = e.clientX;  my = e.clientY;
    handle.style.cursor = 'grabbing';
    document.body.classList.add('is-dragging');
    e.preventDefault();
    e.stopPropagation(); // prevent canvas from stealing the event
  });

  const onMove = e => {
    if (!dragging) return;
    const dx = e.clientX - mx, dy = e.clientY - my;
    const nx = Math.max(0, Math.min(window.innerWidth  - el.offsetWidth,  ox + dx));
    const ny = Math.max(0, Math.min(window.innerHeight - el.offsetHeight, oy + dy));
    el.style.left = nx + 'px';
    el.style.top  = ny + 'px';
    el.dataset.dragged = '1';
  };
  const onUp = () => {
    if (!dragging) return;
    dragging = false;
    handle.style.cursor = 'grab';
    document.body.classList.remove('is-dragging');
  };

  // Attach to both document AND window to catch mouseup even if it fires on canvas
  document.addEventListener('mousemove', onMove);
  document.addEventListener('mouseup', onUp);
  window.addEventListener('mouseup', onUp);   // safety net for canvas-eaten events
  // Also reset if mouse leaves the window entirely
  document.addEventListener('mouseleave', onUp);
}
function resetDrag(el) {
  if (!el) return;
  // Force any active drag state to end by dispatching a synthetic mouseup
  document.dispatchEvent(new MouseEvent('mouseup'));
  el.style.position  = '';
  el.style.left      = '';
  el.style.top       = '';
  el.style.right     = '';
  el.style.bottom    = '';
  el.style.transform = '';
  el.style.margin    = '';
  delete el.dataset.dragged;
}
// Initialise on load
document.addEventListener('DOMContentLoaded', () => {
  // tap-anchor: drag by header
  makeDraggable(document.getElementById('tap-anchor'),        document.getElementById('tap-anchor-hdr'));
  // Symbol picker
  makeDraggable(document.querySelector('.modal'),             document.querySelector('.modal .modal-hdr, .modal h2, .modal') );
  // Journal modal
  makeDraggable(document.getElementById('jmodal'),            document.querySelector('#jmodal .jm-hdr, #jmodal'));
  // Settings
  makeDraggable(document.getElementById('settings-modal'),    document.querySelector('#settings-modal .sm-hdr, #settings-modal'));
  // Trade analysis full modal
  makeDraggable(document.getElementById('tap-modal'),         document.getElementById('tap-hdr'));
  // Premarket brief
  makeDraggable(document.getElementById('pmb-modal'),         document.querySelector('#pmb-modal .pmb-hdr, #pmb-modal'));
  // AI Setups
  makeDraggable(document.getElementById('ais-modal'),         document.querySelector('#ais-modal .ais-hdr, #ais-modal'));
  // Tutorial
  makeDraggable(document.getElementById('tut-content'),       document.querySelector('#tut-content .tut-hdr, #tut-content'));
});

