function openModal(){
  document.getElementById('modal-bg').classList.add('open');
  document.getElementById('m-input').value='';
  filterModal('');
  setTimeout(()=>document.getElementById('m-input').focus(),50);
}
function closeModal(){ document.getElementById('modal-bg').classList.remove('open'); resetDrag(document.querySelector('.modal')); }
function filterModal(q){
  const syms=q?SYMS.filter(s=>s.s.toLowerCase().includes(q.toLowerCase())||s.n.toLowerCase().includes(q.toLowerCase())):SYMS;
  document.getElementById('m-list').innerHTML=syms.map(s=>{
    const watching=watchlist.has(s.s);
    return `<div class="mr" onclick="selSym('${s.s}')">
      <div class="mr-s">${s.s}</div><div class="mr-n">${s.n}</div>
      <div class="mr-p">${fP(s.p)}</div><div class="mr-t">${s.t}</div>
      <button onclick="event.stopPropagation();selSymNewTab('${s.s}')" style="flex-shrink:0;padding:2px 8px;border-radius:999px;font-size:10px;font-family:monospace;cursor:pointer;transition:all .15s;background:rgba(61,142,255,.08);border:1px solid rgba(61,142,255,.24);color:var(--blue);" onmouseover="this.style.background='rgba(61,142,255,.14)';this.style.color='#a9c9ff'" onmouseout="this.style.background='rgba(61,142,255,.08)';this.style.color='var(--blue)'">+ Tab</button>
      <button onclick="event.stopPropagation();${watching?`removeFromWatchlist('${s.s}')`:`addToWatchlist('${s.s}')`}" style="flex-shrink:0;padding:2px 8px;border-radius:3px;font-size:11px;font-family:monospace;cursor:pointer;transition:all .15s;${watching?'background:rgba(240,165,0,.12);border:1px solid rgba(240,165,0,.4);color:var(--am);':'background:transparent;border:1px solid var(--b2);color:var(--tx3);'}" onmouseover="this.style.borderColor='var(--am)';this.style.color='var(--am)'" onmouseout="this.style.borderColor='${watching?'rgba(240,165,0,.4)':'var(--b2)'}';this.style.color='${watching?'var(--am)':'var(--tx3)'}">${watching?'✓ Watching':'+ Watch'}</button>
    </div>`;
  }).join('');
}
document.addEventListener('keydown',e=>{
  if(e.key==='Escape'){ closeModal(); closeIndBuilder(); closeIndList(); closePSC(); }
  if((e.ctrlKey||e.metaKey)&&e.key==='k'){e.preventDefault();openModal();}
  // Global shortcuts — skip if typing in an input
  if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA') return;
  // 1-7 = timeframes
  const tfMap={'1':'1m','2':'5m','3':'15m','4':'1h','5':'1d','6':'1w','7':'1M'};
  if(tfMap[e.key] && !e.ctrlKey && !e.metaKey){
    const tf=tfMap[e.key];
    const btn=document.querySelector(`.tf[onclick*="'${tf}'"]`);
    if(btn){ btn.click(); toast(`⏱ ${tf} timeframe`); }
    return;
  }
  // P = position size calculator
  if(e.key.toLowerCase()==='p' && !e.ctrlKey && !e.metaKey){
    const pscBg=document.getElementById('psc-bg');
    if(pscBg.style.display==='flex') closePSC(); else openPSC();
    return;
  }
  // / = symbol search
  if(e.key==='/'){
    e.preventDefault();
    openModal();
    return;
  }
  // F = fullscreen chart (hide panels)
  if(e.key.toLowerCase()==='f' && !e.ctrlKey && !e.metaKey){
    toggleFullscreenChart();
    return;
  }
  // R = toggle replay mode
  if(e.key.toLowerCase()==='r' && !e.ctrlKey && !e.metaKey){
    toggleReplay();
    return;
  }
  // Replay controls when active (arrows just step, chart still pannable)
  if(replayMode && !replayPicking){
    // Prevent keyboard controls when replay is complete
    if(curData && replayCutoff >= curData.length - 1) {
      if(e.key===' '){ e.preventDefault(); toast('⏹ Already at end — Esc to exit'); return; }
      if(e.key==='ArrowRight'){ e.preventDefault(); toast('⏹ Already at end'); return; }
    }
    if(e.key==='ArrowRight'){ e.preventDefault(); replayStep(1);   return; }
    if(e.key==='ArrowLeft'){  e.preventDefault(); replayStep(-1);  return; }
    if(e.key==='ArrowUp'){    e.preventDefault(); replayStep(10);  return; }
    if(e.key==='ArrowDown'){  e.preventDefault(); replayStep(-10); return; }
    if(e.key===' '){          e.preventDefault(); replayTogglePlay(); return; }
  }
  if(replayMode && e.key==='Escape'){ stopReplay(); return; }
});

let _chartFullscreen=false;
function toggleFullscreenChart(){
  _chartFullscreen=!_chartFullscreen;
  const sidebar=document.getElementById('sidebar');
  const rpanel =document.getElementById('rpanel');
  const scanner=document.getElementById('scanner-wrap');
  const lrh=document.getElementById('left-resize-handle');
  const rrh=document.getElementById('right-resize-handle');
  [sidebar,lrh].forEach(el=>{ if(el) el.style.display=_chartFullscreen?'none':''; });
  [rpanel, rrh].forEach(el=>{ if(el) el.style.display=_chartFullscreen?'none':''; });
  if(scanner) scanner.style.display=_chartFullscreen?'none':'';
  setTimeout(()=>{ sizeCanvases(); draw(); },30);
  toast(_chartFullscreen?'▶ Fullscreen — press F to exit':'◀ Normal view');
}

// ══ SCANNER / PROMPT ══════════════════════════════════════════════════════════
function runPrompt(btn, q){
  // Highlight active prompt button
  document.querySelectorAll('.sp').forEach(s=>s.classList.remove('sp-active'));
  btn.classList.add('sp-active');

  const res   = document.getElementById('scanner-results');
  const label = document.getElementById('scanner-result-label');
  res.classList.add('show');
  // Remove old chips
  res.querySelectorAll('.nl-chip').forEach(c=>c.remove());
  label.textContent = 'Scanning...';

  const scored = SYMS.map(s => {
    // Use real cached data if available, otherwise placeholder
    const d = dataCache[s.s+'_'+curTF] || (s.s===curSym.s ? curData : null) || genData(s.p, 80, VOL_MAP[curTF] || 0.018);
    const rsiArr = calcRSI(d);
    const rsi = rsiArr[rsiArr.length-1] || 50;
    const sma20arr = calcSMA(d,20); const sma20 = sma20arr[sma20arr.length-1];
    const sma50arr = calcSMA(d,50); const sma50 = sma50arr[sma50arr.length-1];
    const bbArr = calcBB(d); const bb = bbArr[bbArr.length-1];
    const last = d[d.length-1]; const prev = d[d.length-2];
    const avgVol = d.slice(-21,-1).reduce((a,x)=>a+x.volume,0)/20;
    const volRatio = last.volume/(avgVol||1);
    const bodySize = Math.abs(last.close-last.open);
    const range = last.high-last.low;
    const lowerWick = Math.min(last.open,last.close)-last.low;
    const upperWick = last.high-Math.max(last.open,last.close);
    const pats = detectPatterns(d);
    const bullPats = pats.filter(p=>p.dir==='bull').length;
    const bearPats = pats.filter(p=>p.dir==='bear').length;
    const aboveSMA  = sma20 && last.close > sma20;
    const goldenX   = sma20 && sma50 && sma20 > sma50;
    const deathX    = sma20 && sma50 && sma20 < sma50;
    const nearBBUpper = bb && last.close > bb.upper * 0.995;
    const nearBBLower = bb && last.close < bb.lower * 1.005;
    const bbSqueeze   = bb && (bb.upper-bb.lower)/last.close < 0.03;
    const doji        = bodySize < range * 0.1;
    const hammer      = lowerWick > bodySize*2 && last.close > last.open;
    const shootingStar= upperWick > bodySize*2 && last.close < last.open;
    const engulfBull  = prev.close<prev.open && last.close>last.open && last.open<prev.close && last.close>prev.open;
    const engulfBear  = prev.close>prev.open && last.close<last.open && last.open>prev.close && last.close<prev.open;
    const breakout    = volRatio > 2 && last.close > prev.high;
    const breakdown   = volRatio > 2 && last.close < prev.low;
    const momentum    = Math.abs(s.c);
    return { ...s, rsi, volRatio, sma20, sma50, bb, last, bullPats, bearPats,
      aboveSMA, goldenX, deathX, nearBBUpper, nearBBLower, bbSqueeze,
      doji, hammer, shootingStar, engulfBull, engulfBear, breakout, breakdown, momentum, pats };
  });

  const ql = q.toLowerCase();
  const intents = [
    { test: q=>q.match(/oversold|rsi.{0,8}low|rsi.{0,8}(under|below|<).{0,5}3|cheap|beaten.?down/),
      filter:s=>s.rsi<38, sort:(a,b)=>a.rsi-b.rsi, label:'RSI Oversold', fmt:s=>`${s.s} RSI:${s.rsi.toFixed(0)}` },
    { test: q=>q.match(/overbought|rsi.{0,8}high|rsi.{0,8}(over|above|>).{0,5}7|extended|stretched/),
      filter:s=>s.rsi>62, sort:(a,b)=>b.rsi-a.rsi, label:'RSI Overbought', fmt:s=>`${s.s} RSI:${s.rsi.toFixed(0)}` },
    { test: q=>q.match(/rsi.{0,10}(50|midline|mid|neutral|cross)/),
      filter:s=>Math.abs(s.rsi-50)<8, sort:(a,b)=>Math.abs(a.rsi-50)-Math.abs(b.rsi-50), label:'RSI Near 50', fmt:s=>`${s.s} RSI:${s.rsi.toFixed(0)}` },
    { test: q=>q.match(/high.{0,8}vol|vol.{0,8}spike|vol.{0,8}surge|unusual.{0,8}vol|active|hot/),
      filter:s=>s.volRatio>1.8, sort:(a,b)=>b.volRatio-a.volRatio, label:'High Volume', fmt:s=>`${s.s} ${s.volRatio.toFixed(1)}x` },
    { test: q=>q.match(/low.{0,8}vol|quiet|consolidat|flat|range.?bound|squeeze/),
      filter:s=>s.volRatio<0.6||s.bbSqueeze, sort:(a,b)=>a.volRatio-b.volRatio, label:'Low Vol / Squeeze', fmt:s=>`${s.s} ${s.volRatio.toFixed(1)}x` },
    { test: q=>q.match(/breakout|break.?out|break(ing)? (up|higher|out)|burst/),
      filter:s=>s.breakout, sort:(a,b)=>b.volRatio-a.volRatio, label:'Breakouts', fmt:s=>`${s.s} ${s.volRatio.toFixed(1)}x vol` },
    { test: q=>q.match(/breakdown|break.?down|break(ing)? (down|lower)|collapse|dump/),
      filter:s=>s.breakdown, sort:(a,b)=>b.volRatio-a.volRatio, label:'Breakdowns', fmt:s=>`${s.s} ${s.volRatio.toFixed(1)}x vol` },
    { test: q=>q.match(/uptrend|trending.{0,8}up|above.{0,8}(sma|ma)|bullish.{0,8}trend|golden.{0,8}cross/),
      filter:s=>s.goldenX||s.aboveSMA, sort:(a,b)=>b.momentum-a.momentum, label:'Uptrend', fmt:s=>`${s.s} ${s.goldenX?'GoldenX':'↑SMA'}` },
    { test: q=>q.match(/downtrend|trending.{0,8}down|below.{0,8}(sma|ma)|bearish.{0,8}trend|death.{0,8}cross/),
      filter:s=>s.deathX||!s.aboveSMA, sort:(a,b)=>b.momentum-a.momentum, label:'Downtrend', fmt:s=>`${s.s} ${s.deathX?'DeathX':'↓SMA'}` },
    { test: q=>q.match(/gain|gainer|up|green|bull|pump|rocket|best.{0,8}perf|top.{0,8}(mover|perform)/),
      filter:s=>s.c>0, sort:(a,b)=>b.c-a.c, label:'Top Gainers', fmt:s=>`${s.s} +${s.c}%` },
    { test: q=>q.match(/loser|loss|down|red|bear|drop|fall|worst|sell.?off/),
      filter:s=>s.c<0, sort:(a,b)=>a.c-b.c, label:'Top Losers', fmt:s=>`${s.s} ${s.c}%` },
    { test: q=>q.match(/momentum|strong|mov(ing|er)|volatile|big.{0,8}mov|action/),
      filter:s=>s.momentum>1, sort:(a,b)=>b.momentum-a.momentum, label:'High Momentum', fmt:s=>`${s.s} ${s.c>=0?'+':''}${s.c}%` },
    { test: q=>q.match(/hammer|reversal.{0,8}bull|bullish.{0,8}reversal/),
      filter:s=>s.hammer||s.engulfBull, sort:(a,b)=>b.bullPats-a.bullPats, label:'Bullish Reversals', fmt:s=>`${s.s} ${s.hammer?'Hammer':'Engulf'}` },
    { test: q=>q.match(/shooting.?star|reversal.{0,8}bear|bearish.{0,8}reversal/),
      filter:s=>s.shootingStar||s.engulfBear, sort:(a,b)=>b.bearPats-a.bearPats, label:'Bearish Reversals', fmt:s=>`${s.s} ${s.shootingStar?'Shoot★':'Engulf'}` },
    { test: q=>q.match(/doji|indecis|uncertain|neutral.{0,8}candle/),
      filter:s=>s.doji, sort:(a,b)=>b.momentum-a.momentum, label:'Doji', fmt:s=>`${s.s} Doji` },
    { test: q=>q.match(/engulf/),
      filter:s=>s.engulfBull||s.engulfBear, sort:(a,b)=>(b.engulfBull?1:0)-(a.engulfBull?1:0), label:'Engulfing', fmt:s=>`${s.s} ${s.engulfBull?'▲Bull':'▼Bear'}` },
    { test: q=>q.match(/pattern|setup|signal|opportunity|trade/),
      filter:s=>s.bullPats+s.bearPats>=2, sort:(a,b)=>(b.bullPats+b.bearPats)-(a.bullPats+a.bearPats), label:'Best Setups', fmt:s=>`${s.s} ${s.bullPats}↑${s.bearPats}↓` },
    { test: q=>q.match(/bollinger|bb|band.{0,8}(touch|squeeze|upper|lower)/),
      filter:s=>s.nearBBUpper||s.nearBBLower||s.bbSqueeze,
      sort:(a,b)=>(b.nearBBUpper?2:b.nearBBLower?1:0)-(a.nearBBUpper?2:a.nearBBLower?1:0),
      label:'BB Signals', fmt:s=>`${s.s} ${s.bbSqueeze?'Squeeze':s.nearBBUpper?'Upper':'Lower'}` },
    { test: q=>q.match(/crypto|bitcoin|btc|eth|sol|coin|bnb|xrp|doge|ada|avax|link|dot|matic|uni|ltc|atom|ton/),
      filter:s=>s.t==='Crypto', sort:(a,b)=>b.momentum-a.momentum, label:'Crypto', fmt:s=>`${s.s} ${s.c>=0?'+':''}${s.c}%` },

    ...SYMS.map(s=>({
      test: q=>q.includes(s.s.toLowerCase())||q.includes(s.n.toLowerCase().split(' ')[0]),
      filter:x=>x.s===s.s, sort:()=>0, label:s.s, fmt:x=>`${x.s} ${x.c>=0?'+':''}${x.c}% RSI:${x.rsi.toFixed(0)}`
    })),
    { test: q=>q.match(/all|everything|any|overview|scan|screen|market/),
      filter:s=>true, sort:(a,b)=>b.momentum-a.momentum, label:'Full Market Scan', fmt:s=>`${s.s} ${s.c>=0?'+':''}${s.c}%` },
  ];

  for(const intent of intents){
    if(!intent.test(ql)) continue;
    const results = scored.filter(intent.filter).sort(intent.sort);
    if(!results.length) continue;

    label.textContent = `${intent.label} (${results.length}):`;
    results.forEach(s=>{
      const chip = document.createElement('span');
      chip.className = 'nl-chip';
      chip.textContent = intent.fmt(s);
      chip.onclick = ()=>nlPick(s.s, chip);
      res.appendChild(chip);
    });
    return;
  }

  label.textContent = 'No results found';
}

function nlPick(sym, el){
  document.querySelectorAll('.nl-chip').forEach(c=>c.classList.remove('nl-chip-active'));
  el.classList.add('nl-chip-active');
  loadSym(sym);
  toast(`📈 Loaded ${sym}`);
}

// ══ TOAST + CLOCK ═════════════════════════════════════════════════════════════
let toastT;
function toast(msg){
  const el=document.getElementById('toast');
  el.textContent=msg; el.classList.add('show');
  clearTimeout(toastT); toastT=setTimeout(()=>el.classList.remove('show'),4000);
}
setInterval(()=>{
  const n=new Date();
  const clkEl=document.getElementById('st-clk'); if(clkEl) clkEl.textContent=n.toLocaleTimeString('en-GB',{hour12:false});
  // Crypto trades 24/7 — always LIVE. Only show CLOSED on weekends for context.
  const dayOfWeek = n.getDay(); // 0=Sun, 6=Sat
  const isCryptoWeekend = false; // crypto never closes
  const open = curSym && curSym.t === 'Crypto' ? true : !(dayOfWeek === 0 || dayOfWeek === 6);
  const liveEl=document.getElementById('st-live'); if(liveEl){ liveEl.textContent=open?'● LIVE':'● CLOSED'; liveEl.style.color=open?'var(--tl)':'var(--tx3)'; }
  updateSessionCountdown();
  updateTiltDetector();
},1000);

// ══ SCANNER HELPERS ═══════════════════════════════════════════════════════════
function scrollPrompts(dx){
  const el=document.getElementById('scanner-prompts'); if(el) el.scrollBy({top:dx, behavior:'smooth'});
}

function filterPrompts(val){
  const q = val.toLowerCase().trim();
  document.querySelectorAll('#scanner-prompts .sp').forEach(sp=>{
    const label = (sp.dataset.label||sp.textContent).toLowerCase();
    sp.classList.toggle('sp-hidden', q.length>0 && !label.includes(q));
  });
}

function initScannerDrag(){
  const el = document.getElementById('scanner-prompts');
  if(!el) return;
  let down=false, startX=0, scrollStart=0;
  el.addEventListener('mousedown', e=>{
    if(e.target.classList.contains('sp')) return;
    down=true; startX=e.pageX; scrollStart=el.scrollLeft; e.preventDefault();
  });
  document.addEventListener('mousemove', e=>{
    if(!down) return;
    el.scrollLeft = scrollStart-(e.pageX-startX);
  });
  document.addEventListener('mouseup', ()=>{ down=false; });
  el.addEventListener('touchstart', e=>{ startX=e.touches[0].pageX; scrollStart=el.scrollLeft; },{passive:true});
  el.addEventListener('touchmove',  e=>{ el.scrollLeft=scrollStart-(e.touches[0].pageX-startX); },{passive:true});
}

// ══ SIDEBAR RESIZE ════════════════════════════════════════════════════════════

// ResizeObserver: redraws chart whenever chart-area changes size
// (catches overlay-panel dock/undock, window resize, zoom changes)
(function(){
  const area = _el('chart-area');
  if(!area || !window.ResizeObserver) return;
  let _roRaf = null;
  const ro = new ResizeObserver(() => {
    if(_roRaf) cancelAnimationFrame(_roRaf);
    _roRaf = requestAnimationFrame(() => {
      try { sizeCanvases(); draw(); } catch(e){}
    });
  });
  ro.observe(area);
})();

function initSidebarResize(){
  const SIDEBAR_MIN = 0, SIDEBAR_MAX = 380, SIDEBAR_DEFAULT = 196;
  const RPANEL_MIN  = 0, RPANEL_MAX  = 420, RPANEL_DEFAULT  = 240;
  const COLLAPSE_THRESHOLD = 40; // px — snap to 0 if dragged below this

  const sidebar = document.getElementById('sidebar');
  const rpanel  = document.getElementById('rpanel');
  const lHandle = document.getElementById('left-resize-handle');
  const rHandle = document.getElementById('right-resize-handle');

  // Return early if essential elements don't exist
  if(!sidebar || !rpanel || !lHandle || !rHandle) {
    console.warn('Sidebar resize elements not found (sidebar, rpanel, or resize handles). This is normal for overlay-based layouts.');
    return;
  }

  // Track pre-collapse widths for restore on double-click
  let sidebarPrev = SIDEBAR_DEFAULT;
  let rpanelPrev  = RPANEL_DEFAULT;
  let _rafPending = false; // rAF dedupe during drag

  function setWidth(el, w, isLeft){
    const clamped = Math.max(0, Math.min(isLeft ? SIDEBAR_MAX : RPANEL_MAX, w));
    el.style.transition = 'none';
    el.style.width = clamped + 'px';
    if(clamped < COLLAPSE_THRESHOLD){
      el.style.width = '0px';
      el.style.overflow = 'hidden';
    } else {
      el.style.overflow = '';
    }
    // During drag: only resize+redraw once per animation frame to avoid jitter.
    // sizeCanvases() resets mc.width which clears the canvas — batching via rAF
    // means we only get one clear+repaint per frame instead of one per pixel.
    if(!_rafPending){
      _rafPending = true;
      requestAnimationFrame(() => {
        _rafPending = false;
        try { sizeCanvases(); draw(); } catch(e){}
      });
    }
  }

  function collapse(el, isLeft){
    if(isLeft){ sidebarPrev = parseInt(el.style.width)||SIDEBAR_DEFAULT; }
    else      { rpanelPrev  = parseInt(el.style.width)||RPANEL_DEFAULT; }
    el.style.transition = 'width .2s ease';
    el.style.width = '0px';
    el.style.overflow = 'hidden';
    setTimeout(()=>{ el.style.transition=''; sizeCanvases(); draw(); }, 210);
  }

  function expand(el, isLeft){
    const target = isLeft ? (sidebarPrev || SIDEBAR_DEFAULT) : (rpanelPrev || RPANEL_DEFAULT);
    el.style.overflow = '';
    el.style.transition = 'width .2s ease';
    el.style.width = target + 'px';
    setTimeout(()=>{ el.style.transition=''; sizeCanvases(); draw(); }, 210);
  }

  function isCollapsed(el){ return parseInt(el.style.width||'999') < COLLAPSE_THRESHOLD; }

  function makeDraggable(handle, el, isLeft){
    let dragging = false, startX = 0, startW = 0;

    handle.addEventListener('mousedown', e => {
      dragging = true;
      startX = e.clientX;
      startW = parseInt(el.style.width) || (isLeft ? SIDEBAR_DEFAULT : RPANEL_DEFAULT);
      handle.classList.add('dragging');
      document.body.style.cursor = 'col-resize';
      document.body.style.userSelect = 'none';
      e.preventDefault();
    });

    handle.addEventListener('dblclick', e => {
      e.preventDefault();
      if(isCollapsed(el)) expand(el, isLeft);
      else collapse(el, isLeft);
    });

    document.addEventListener('mousemove', e => {
      if(!dragging) return;
      const dx = isLeft ? (e.clientX - startX) : (startX - e.clientX);
      const newW = startW + dx;
      setWidth(el, newW, isLeft);
    });

    document.addEventListener('mouseup', () => {
      if(!dragging) return;
      dragging = false;
      handle.classList.remove('dragging');
      document.body.style.cursor = '';
      document.body.style.userSelect = '';
      // Snap fully closed if below threshold
      const w = parseInt(el.style.width) || 0;
      if(w < COLLAPSE_THRESHOLD && w > 0){
        el.style.transition = 'width .15s ease';
        el.style.width = '0px';
        el.style.overflow = 'hidden';
        setTimeout(()=>{ el.style.transition=''; sizeCanvases(); draw(); }, 160);
      }
    });
  }

  makeDraggable(lHandle, sidebar, true);
  makeDraggable(rHandle, rpanel, false);

  // Collapse buttons
  const lBtn = document.getElementById('left-collapse-btn');
  const rBtn = document.getElementById('right-collapse-btn');

  function updateBtnArrows(){
    if(lBtn) lBtn.textContent = isCollapsed(sidebar) ? '›' : '‹';
    if(rBtn) rBtn.textContent = isCollapsed(rpanel)  ? '‹' : '›';
    // Toggle wide hit-area class on handles
    if(lHandle) lHandle.classList.toggle('panel-collapsed', isCollapsed(sidebar));
    if(rHandle) rHandle.classList.toggle('panel-collapsed', isCollapsed(rpanel));
  }

  // Patch collapse/expand to also update arrows and prevent drag from triggering on btn click
  const _origCollapse = collapse, _origExpand = expand;
  function collapseAndSync(el, isLeft){ _origCollapse(el, isLeft); setTimeout(updateBtnArrows, 220); }
  function expandAndSync(el, isLeft) { _origExpand(el, isLeft);   setTimeout(updateBtnArrows, 220); }

  if(lBtn){
    lBtn.addEventListener('click', e => {
      e.stopPropagation();
      if(isCollapsed(sidebar)) expandAndSync(sidebar, true);
      else collapseAndSync(sidebar, true);
    });
  }
  if(rBtn){
    rBtn.addEventListener('click', e => {
      e.stopPropagation();
      if(isCollapsed(rpanel)) expandAndSync(rpanel, false);
      else collapseAndSync(rpanel, false);
    });
  }

  // Also update arrows on dblclick (already handled inline but need sync)
  if(lHandle) lHandle.addEventListener('dblclick', () => setTimeout(updateBtnArrows, 220));
  if(rHandle) rHandle.addEventListener('dblclick', () => setTimeout(updateBtnArrows, 220));

  // Keep settings toggle in sync — patch to also update widths
  const origScSidebar = document.getElementById('sc-sidebar');
  if(origScSidebar){
    origScSidebar.addEventListener('change', function(){
      if(this.checked && sidebar) expand(sidebar, true);
      else if(sidebar) collapse(sidebar, true);
    });
  }
  const origScRpanel = document.getElementById('sc-rpanel');
  if(origScRpanel){
    origScRpanel.addEventListener('change', function(){
      if(this.checked && rpanel) expand(rpanel, false);
      else if(rpanel) collapse(rpanel, false);
    });
  }
}

// ══ SETTINGS ══════════════════════════════════════════════════════════════════

function applyUIScale(val){
  const numericVal = Math.max(80, Math.min(130, parseFloat(val) || 100));
  const pct = numericVal / 100;
  const app = document.getElementById('app');
  const statusbar = document.getElementById('statusbar');
  const root = document.documentElement;
  uiScale = pct || 1;
  setSettingValue('uiScale', numericVal);
  if(app){
    const safePct = uiScale;
    app.style.zoom = '1';
    app.style.transform = `scale(${safePct})`;
    app.style.transformOrigin = 'top left';
    app.style.width = `${100 / safePct}%`;
    app.style.height = `${100 / safePct}%`;
    app.style.minHeight = `${100 / safePct}vh`;
  }
  if(root){
    const safePct = uiScale;
    root.style.setProperty('--statusbar-h', `${22 / safePct}px`);
    root.style.setProperty('--ui-scale', String(safePct));
  }
  if(statusbar){
    const safePct = uiScale;
    statusbar.style.zoom = '1';
    statusbar.style.transform = `scale(${1 / safePct})`;
    statusbar.style.transformOrigin = 'left bottom';
  }
  const lbl = document.getElementById('sc-fontsize-v');
  if(lbl) lbl.textContent = Math.round(numericVal) + '%';
  // After zoom, canvases need a redraw
  setTimeout(()=>{ try{ sizeCanvases(); draw(); }catch(e){} }, 50);
}

function applyPanelVisibility(panelId, isVisible){
  const targetIds = {
    sidebar: ['nav'],
    rpanel: ['rdrawer'],
    'scanner-wrap': ['scanner-wrap'],
    'draw-toolbar': ['nav-draw'],
    statusbar: ['statusbar'],
  };
  const ids = targetIds[panelId] || [panelId];
  ids.forEach(function(id){
    const el = document.getElementById(id);
    if(el) el.style.display = isVisible ? '' : 'none';
  });
  if(panelId === 'sidebar' || panelId === 'rpanel'){
    positionChartTabsBar();
    setTimeout(() => { try { sizeCanvases(); draw(); } catch(e){} }, 50);
  }
}

function applyToggleSetting(inputId){
  const el = document.getElementById(inputId);
  if(!el) return;
  const checked = !!el.checked;
  const stateKey = getSettingStateKey(inputId);
  setSettingValue(stateKey, checked);
  if(inputId === 'sc-scanner') applyPanelVisibility('scanner-wrap', checked);
  if(inputId === 'sc-drawtb') applyPanelVisibility('draw-toolbar', checked);
  if(inputId === 'sc-statusbar') applyPanelVisibility('statusbar', checked);
  if(inputId === 'sc-sidebar') applyPanelVisibility('sidebar', checked);
  if(inputId === 'sc-rpanel') applyPanelVisibility('rpanel', checked);
  if(inputId === 'sc-contextmenu') appPrefs.enableContextMenus = checked;
  if(inputId === 'sc-guestintro') appPrefs.guestTutorialIntro = checked;
  if(inputId === 'sc-confirmclear') appPrefs.confirmClearDrawings = checked;
  if(inputId === 'sc-animations') appPrefs.enableChartAnimations = checked;
  saveSettingsToStorage();
  draw();
}

