// Generate seeded data for a specific symbol + timeframe
// Uses a standalone seed so it's independent of the current chart TF
async function genDataForTF(sym, tf, bars) {
  const cacheKey = sym + '_' + tf + '_mtf';
  if (dataCache[cacheKey] && dataCache[cacheKey].length > 0) return dataCache[cacheKey];
  try {
    const fetched = await fetchBinanceCandles(sym, tf);
    if (fetched && fetched.length > 0) {
      dataCache[cacheKey] = fetched;
      return fetched;
    }
  } catch(e) {}
  // Fallback: generate synthetic if fetch fails
  const vol = VOL_MAP[tf] || 0.018;
  const basePrice = (SYMS.find(s => s.s === sym) || {p: 100}).p;
  const seedVal = sym.split('').reduce((a,c) => a + c.charCodeAt(0), 0) * 9301 + tf.length * 49297 + bars;
  const rng = seededRng(seedVal);
  const d = []; let p = basePrice;
  const now = Math.floor(Date.now() / 1000);
  const step = {'1m':60,'5m':300,'15m':900,'1h':3600,'4h':14400,'1d':86400,'1w':604800,'1M':2592000}[tf] || 86400;
  for (let i = bars; i >= 0; i--) {
    const t = now - i * step;
    const chg = (rng() - .479) * vol * p;
    const o = p, c = +(p + chg).toFixed(4);
    const h = +(Math.max(o, c) + rng() * vol * p * .6).toFixed(4);
    const l = +(Math.min(o, c) - rng() * vol * p * .6).toFixed(4);
    d.push({ time: t, open: +o.toFixed(4), high: h, low: l, close: c, volume: Math.floor(rng() * 60e6 + 2e6) });
    p = c;
  }
  return d;
}

// Analyse a single symbol on a single timeframe
async function analyseTF(sym, tf, realData) {
  // Use real data if provided, otherwise fall back to generated placeholder
  const bars = PMB_TF_BARS[tf] || 200;
  const data  = realData && realData.length >= 10 ? realData : await genDataForTF(sym, tf, bars);
  const n     = data.length;
  const pats  = detectPatterns(data);
  const sr    = detectSR(data);
  const rsiV  = calcRSI(data);
  const lastRSI = rsiV[n-1];
  const atrV  = calcATR(data);
  const atr   = atrV[n-1] || 0;

  const sma20 = calcSMA(data, 20);
  const sma50 = calcSMA(data, 50);
  const ema8  = calcEMA(data, 8);
  const ema21 = calcEMA(data, 21);

  const bulls = pats.filter(p => p.dir === 'bull').length;
  const bears = pats.filter(p => p.dir === 'bear').length;
  const bias  = bulls > bears ? 'bull' : bears > bulls ? 'bear' : 'neut';

  // EMA alignment
  const e8 = ema8[n-1], e21 = ema21[n-1], s20 = sma20[n-1], s50 = sma50[n-1];
  const emaAligned = e8 && e21 ? (e8 > e21 ? 'bull' : 'bear') : 'neut';
  const smaAligned = s20 && s50 ? (s20 > s50 ? 'bull' : 'bear') : 'neut';

  // Combined directional score: 0 (full bear) → 100 (full bull)
  let score = 50;
  if (bias === 'bull') score += 15; else if (bias === 'bear') score -= 15;
  if (emaAligned === 'bull') score += 10; else if (emaAligned === 'bear') score -= 10;
  if (smaAligned === 'bull') score += 10; else if (smaAligned === 'bear') score -= 10;
  if (lastRSI) {
    if (lastRSI > 55) score += 8; else if (lastRSI < 45) score -= 8;
    if (lastRSI > 70) score += 5; else if (lastRSI < 30) score -= 5;
  }
  score = Math.max(0, Math.min(100, score));

  const topPat = [...pats].sort((a,b) => b.conf - a.conf)[0] || null;
  const price = (data[n-1].high + data[n-1].low + data[n-1].close) / 3;  // typical price
  // Filter by side of price so "nearest support" is always below and "nearest resistance" above
  const nearestS = sr.support.filter(s => s < price).sort((a,b) => b-a)[0] || null;
  const nearestR = sr.resistance.filter(r => r > price).sort((a,b) => a-b)[0] || null;

  // % change vs 5 bars ago using typical price — includes wick momentum
  const tp5ago  = n >= 6 ? (data[n-6].high + data[n-6].low + data[n-6].close) / 3 : price;
  const movePct = n >= 6 ? ((price - tp5ago) / tp5ago * 100) : 0;

  return {
    tf, bias, score, emaAligned, smaAligned,
    rsi: lastRSI ? lastRSI.toFixed(1) : '—',
    atrPct: (atr / price * 100).toFixed(2),
    topPat: topPat ? { name: topPat.name, conf: topPat.conf, dir: topPat.dir } : null,
    nearestS, nearestR, price,
    movePct: +movePct.toFixed(2),
    bulls, bears, pats,
    sr
  };
}

// Compute multi-TF confluence for a symbol
function computeConfluence(tfResults) {
  const tfs = Object.values(tfResults);
  // Weight: higher TFs have more weight
  const weights = { '1h': 1, '4h': 1.5, '1d': 2.5, '1w': 3.5, '1M': 4.5 };
  let totalW = 0, weightedScore = 0;
  tfs.forEach(t => {
    const w = weights[t.tf] || 1;
    weightedScore += t.score * w;
    totalW += w;
  });
  const confScore = Math.round(weightedScore / totalW);

  const bullTFs  = tfs.filter(t => t.bias === 'bull').length;
  const bearTFs  = tfs.filter(t => t.bias === 'bear').length;
  const totalTFs = tfs.length;

  // Confluence verdict
  let verdict, verdictCol;
  if (confScore >= 68) { verdict = 'STRONG BULL'; verdictCol = 'var(--tl)'; }
  else if (confScore >= 58) { verdict = 'BULLISH'; verdictCol = '#00c9a0cc'; }
  else if (confScore <= 32) { verdict = 'STRONG BEAR'; verdictCol = 'var(--rd)'; }
  else if (confScore <= 42) { verdict = 'BEARISH'; verdictCol = '#f03060cc'; }
  else { verdict = 'NEUTRAL / MIXED'; verdictCol = 'var(--am)'; }

  // Higher TF bias (weekly + monthly)
  const htfTFs = tfs.filter(t => ['1w','1M'].includes(t.tf));
  const htfBull = htfTFs.filter(t => t.bias === 'bull').length;
  const htfBear = htfTFs.filter(t => t.bias === 'bear').length;
  const htfBias = htfBull > htfBear ? 'bull' : htfBear > htfBull ? 'bear' : 'neut';

  // Best entry context: Daily bias matching HTF bias
  const daily = tfResults['1d'];
  const dailyMatchesHTF = daily && daily.bias === htfBias;

  return { confScore, verdict, verdictCol, bullTFs, bearTFs, totalTFs, htfBias, dailyMatchesHTF };
}

async function generatePremarket() {
  if (_pmbInFlight) return; // prevent double-trigger on rapid clicks
  _pmbInFlight = true;
  const btn = document.getElementById('pmb-gen-btn');
  btn.disabled = true;
  btn.textContent = '⟳ Analysing…';

  document.getElementById('pmb-idle').style.display = 'none';
  pmbSetProgress(2, 'Gathering watchlist…');

  try {
    const wlSyms = SYMS.filter(s => watchlist.has(s.s));
    const symsToAnalyse = wlSyms.length >= 1 ? wlSyms : SYMS.slice(0, 6);
    const total = symsToAnalyse.length * PMB_TFS.length;
    let done = 0;

    pmbAnalyses = {};
    buildPMBNav(symsToAnalyse, true);

    for (const sym of symsToAnalyse) {
      const tfData = {};
      for (const tf of PMB_TFS) {
        pmbSetProgress(Math.round(done / total * 80) + 2, `Fetching ${sym.s} ${PMB_TF_LABELS[tf]} data…`);
        await new Promise(r => setTimeout(r, 0));
        let realData = null;
        if(sym.t === 'Crypto'){
          try {
            realData = await fetchBinanceCandles(sym.s, tf);
          } catch(e) {
            realData = null;
          }
        }
        tfData[tf] = await analyseTF(sym.s, tf, realData);
        done++;
      }
      const confluence = computeConfluence(tfData);
      const daily = tfData['1d'];
      const realPrice = daily?.price || (SYMS.find(s => s.s === sym.s)?.p) || 0;
      pmbAnalyses[sym.s] = {
        sym: sym.s, name: sym.n, type: sym.t, exchange: sym.e,
        tfData, confluence,
        price: realPrice,
        movePct: daily?.movePct || 0,
        dailyBias: daily?.bias || 'neut',
        dailyRSI: daily?.rsi || '—'
      };
      updatePMBNavItem(sym.s, pmbAnalyses[sym.s]);
    }

    const analyses = symsToAnalyse.map(s => pmbAnalyses[s.s]).filter(Boolean);

    pmbSetProgress(82, 'Building overview…');
    await new Promise(r => setTimeout(r, 0));
    buildPMBOverview(analyses);
    buildPMBChecklist();

    pmbSetProgress(88, 'Building per-symbol detail pages…');
    await new Promise(r => setTimeout(r, 0));
    buildAllSymbolPanes(analyses);

    pmbSetProgress(92, 'Generating AI narratives…');
    for (const sym of symsToAnalyse) {
      const a = pmbAnalyses[sym.s];
      if (!a) continue;
      pmbSetProgress(92, `AI narrative: ${sym.s}…`);
      await new Promise(r => setTimeout(r, 0));
      try {
        const text = await generateSymbolNarrative(a);
        const el = document.getElementById(`pmb-narrative-${sym.s}`);
        if (el) el.textContent = text;
      } catch(e) {
        const el = document.getElementById(`pmb-narrative-${sym.s}`);
        if (el) {
          // Generate a local narrative from the pre-computed analysis data
          const _a = pmbAnalyses[sym.s];
          if (_a && _a.daily) {
            const _bias = _a.daily.htfBias || _a.daily.bias || 'mixed';
            const _rsi  = _a.daily.rsi ? ` RSI is at ${_a.daily.rsi.toFixed(0)}.` : '';
            const _sup  = _a.daily.nearestSupport ? ` Nearest support: ${fP(_a.daily.nearestSupport)}.` : '';
            const _res  = _a.daily.nearestResistance ? ` Nearest resistance: ${fP(_a.daily.nearestResistance)}.` : '';
            el.textContent = `${sym.s} is showing a ${_bias} bias on the daily.${_rsi}${_sup}${_res} Watch for a reaction at key levels before entering.`;
          } else {
            el.textContent = 'Technical analysis complete — see timeframe breakdown above for details.';
          }
        }
      } finally {
        const loadEl = document.getElementById(`pmb-narr-load-${sym.s}`);
        if (loadEl) loadEl.style.display = 'none';
      }
    }

    pmbSetProgress(98, 'Fetching news…');
    await fetchPMBNews(symsToAnalyse.slice(0,3).map(s => s.s));

    pmbSetProgress(100, `Complete — ${symsToAnalyse.length} symbols analysed across ${PMB_TFS.length} timeframes`);
    document.getElementById('pmb-generated-at').textContent =
      `Generated ${new Date().toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'})} · ${symsToAnalyse.length} symbols · ${PMB_TFS.length} TFs each`;

    pmbShowPane('overview');
  } catch (err) {
    console.error('Premarket brief failed:', err);
    pmbSetProgress(100, 'Pre-market brief failed');
    document.getElementById('pmb-generated-at').textContent =
      `Could not finish brief: ${err.message || 'unexpected error'}`;
  } finally {
    btn.disabled = false;
    btn.textContent = '⚡ Generate Brief';
    _pmbInFlight = false;
  }
}
function buildPMBNav(syms, loading = false) {
  const navEl = document.getElementById('pnav-items');
  navEl.innerHTML = syms.map(sym => {
    const a = pmbAnalyses[sym.s];
    return `<div class="pnav-item" id="pnav-${sym.s}" onclick="pmbShowPane('${sym.s}')">
      <span class="pnav-sym">${sym.s}</span>
      ${loading ? `<div class="pnav-loading"></div>` : renderPNavBias(a)}
    </div>`;
  }).join('');
}

function renderPNavBias(a) {
  if (!a) return '';
  const c = a.confluence;
  const biasClass = c.confScore >= 58 ? 'bull' : c.confScore <= 42 ? 'bear' : 'neut';
  const biasLabel = biasClass === 'bull' ? '▲' : biasClass === 'bear' ? '▼' : '●';
  const chgCol = a.movePct >= 0 ? 'var(--tl)' : 'var(--rd)';
  return `<span class="pnav-bias ${biasClass}">${biasLabel}</span>
          <span class="pnav-chg" style="color:${chgCol}">${a.movePct >= 0 ? '+' : ''}${a.movePct}%</span>`;
}

function updatePMBNavItem(symStr, a) {
  const el = document.getElementById('pnav-' + symStr);
  if (!el) return;
  el.innerHTML = `<span class="pnav-sym">${symStr}</span>${renderPNavBias(a)}`;
}

function buildPMBOverview(analyses) {
  // Market mood
  const bulls = analyses.filter(a => a.confluence.confScore >= 58).length;
  const bears = analyses.filter(a => a.confluence.confScore <= 42).length;
  const total = analyses.length || 1;
  const bullPct = Math.round(bulls / total * 100);
  const mood = bulls >= bears * 1.5 ? 'RISK ON' : bears >= bulls * 1.5 ? 'RISK OFF' : 'MIXED';
  const moodCol = mood === 'RISK ON' ? 'var(--tl)' : mood === 'RISK OFF' ? 'var(--rd)' : 'var(--am)';

  const moodLbl = document.getElementById('pmb-mood-label');
  if (moodLbl) {
    moodLbl.textContent = mood;
    moodLbl.style.cssText = `font-size:11px;font-family:ui-monospace,'SF Mono',monospace;padding:2px 9px;border-radius:10px;margin-left:6px;background:${mood==='RISK ON'?'rgba(0,201,160,.12)':mood==='RISK OFF'?'rgba(240,48,96,.12)':'rgba(240,165,0,.1)'};color:${moodCol};border:1px solid ${moodCol}55`;
  }
  const fill = document.getElementById('pmb-sentiment-fill');
  if (fill) { fill.style.width = bullPct + '%'; fill.style.background = `linear-gradient(to right,var(--tl),var(--am) 60%,var(--rd))`; }
  const bCnt = document.getElementById('pmb-bull-count'); if(bCnt) bCnt.textContent = `${bulls} bullish`;
  const rCnt = document.getElementById('pmb-bear-count'); if(rCnt) rCnt.textContent = `${bears} bearish`;

  const gainers  = [...analyses].sort((a,b) => b.movePct - a.movePct).filter(a => a.movePct > 0).slice(0,3).map(a=>a.sym);
  const losers   = [...analyses].sort((a,b) => a.movePct - b.movePct).filter(a => a.movePct < 0).slice(0,3).map(a=>a.sym);
  const moodTxt  = document.getElementById('pmb-mood-text');
  if (moodTxt) {
    let t = `${bulls} of ${total} symbols showing bullish confluence across all timeframes · ${bears} bearish · ${total-bulls-bears} mixed.`;
    if (gainers.length) t += ` Daily gainers: ${gainers.join(', ')}.`;
    if (losers.length) t += ` Decliners: ${losers.join(', ')}.`;
    moodTxt.textContent = t;
  }

  // Symbol cards
  const cardsEl = document.getElementById('pmb-sym-cards');
  if (cardsEl) {
    cardsEl.innerHTML = analyses.map(a => {
      const c = a.confluence;
      const biasClass = c.confScore >= 58 ? 'bull' : c.confScore <= 42 ? 'bear' : 'neut';
      const chgClass  = a.movePct >= 0 ? 'up' : 'dn';
      const chgStr    = (a.movePct >= 0 ? '+' : '') + a.movePct.toFixed(2) + '%';
      // Mini TF alignment dots
      const tfDots = PMB_TFS.map(tf => {
        const t = a.tfData[tf];
        if (!t) return '';
        const col = t.bias === 'bull' ? '#00c9a0' : t.bias === 'bear' ? '#f03060' : '#f0a500';
        return `<span title="${PMB_TF_LABELS[tf]}: ${t.bias}" style="width:6px;height:6px;border-radius:50%;background:${col};display:inline-block;"></span>`;
      }).join('');
      return `<div class="pmb-sym-card" onclick="pmbShowPane('${a.sym}')">
        <div class="pmb-sym-card-top">
          <span class="pmb-sym-cname">${a.sym}</span>
          <span class="pmb-sym-cchg ${chgClass}">${chgStr}</span>
        </div>
        <div class="pmb-sym-cprice">${fP(a.price)} <span style="font-size:11px;color:var(--tx2);">${a.exchange}</span></div>
        <span class="pmb-sym-csig ${biasClass}">${c.verdict}</span>
        <div class="pmb-sym-ctf" style="margin-top:5px;display:flex;align-items:center;gap:4px;">
          ${tfDots}
          <span style="margin-left:2px;font-size:11px;color:var(--tx2);">${c.bullTFs}▲ ${c.bearTFs}▼ / ${c.totalTFs} TFs</span>
        </div>
      </div>`;
    }).join('');
  }
}

function buildPMBChecklist() {
  const el = document.getElementById('pmb-checklist-items');
  if (!el) return;
  const now = new Date(); const h = now.getHours();
  const checks = [
    { icon:'📰', text:'Check economic calendar — mark high-impact events for today', done:false },
    { icon:'🌍', text:'Review overnight moves in Asian and European markets', done:false },
    { icon:'🎯', text:'Mark key S/R from Weekly/Monthly on each pair before the open', done:false },
    { icon:'📊', text:'Review yesterday\'s journal — any patterns or mistakes to correct?', done: h >= 9 },
    { icon:'🧠', text:'Define your max daily loss and max trade count', done:false },
    { icon:'💡', text:'Only trade setups where Daily aligns with the HTF bias', done:false },
    { icon:'⚖', text:'Size every position before entry — no impulse sizing', done:false },
  ];
  el.innerHTML = checks.map(c => `
    <label class="pmb-check-item">
      <input type="checkbox" ${c.done?'checked':''} onchange="this.closest('label').style.opacity=this.checked?'.45':'1'" style="accent-color:var(--am);width:13px;height:13px;flex-shrink:0;">
      <span style="font-size:10px;color:var(--tx2);line-height:1.4;">${c.icon} ${c.text}</span>
    </label>`).join('');
}

function buildAllSymbolPanes(analyses) {
  const container = document.getElementById('pmb-sym-panes');
  container.innerHTML = analyses.map(a => {
    try {
      return buildSymbolPane(a);
    } catch (err) {
      console.error('Failed to build premarket pane for', a?.sym, err);
      return `<div class="pmb-sym-detail" data-sym="${a?.sym || 'unknown'}">
        <div class="pmb-section">
          <div style="font-size:12px;color:var(--rd);font-family:ui-monospace,'SF Mono',monospace;">
            Failed to render ${a?.sym || 'symbol'} details.
          </div>
        </div>
      </div>`;
    }
  }).join('');
}

function buildSymbolPane(a) {
  const c = a.confluence;
  const verdictCol = c.verdictCol;

  // TF grid cells
  const tfCells = PMB_TFS.map(tf => {
    const t = a.tfData[tf];
    if (!t) return '';
    const biasClass = t.bias;
    const biasArrow = t.bias === 'bull' ? '▲' : t.bias === 'bear' ? '▼' : '●';
    const rsiCol = parseFloat(t.rsi) > 70 ? 'var(--rd)' : parseFloat(t.rsi) < 30 ? 'var(--tl)' : 'var(--tx3)';
    const patName = t.topPat?.name || '';
    const patShort = patName ? patName.replace('Bullish ','').replace('Bearish ','').replace(' Cross','×').substring(0,12) : '';
    const cellBorder = t.bias === 'bull' ? 'border-color:rgba(0,201,160,.3)' : t.bias === 'bear' ? 'border-color:rgba(240,48,96,.3)' : '';
    return `<div class="pmb-tf-cell" style="${cellBorder}">
      <div class="pmb-tf-label">${PMB_TF_LABELS[tf]}</div>
      <div class="pmb-tf-bias ${biasClass}">${biasArrow} ${t.bias.toUpperCase()}</div>
      <div class="pmb-tf-rsi" style="color:${rsiCol}">RSI ${t.rsi}</div>
      ${patShort ? `<div class="pmb-tf-pat">${patShort}</div>` : ''}
    </div>`;
  }).join('');

  // Confluence score bar
  const confBarW = c.confScore;
  const confBarCol = c.confScore >= 58 ? 'var(--tl)' : c.confScore <= 42 ? 'var(--rd)' : 'var(--am)';

  // Key levels — combine S/R from Weekly and Monthly (most important), plus Daily
  const keyLevels = [];
  ['1M','1w','1d'].forEach(tf => {
    const t = a.tfData[tf];
    if (!t) return;
    const label = PMB_TF_LABELS[tf];
    if (t.nearestR) keyLevels.push({ label:`${label} Resistance`, price:t.nearestR, color:'var(--rd)', tf:label });
    if (t.nearestS) keyLevels.push({ label:`${label} Support`,    price:t.nearestS, color:'var(--tl)', tf:label });
  });
  // Deduplicate close prices
  const deduped = keyLevels.filter((item, i, arr) =>
    !arr.slice(0, i).find(x => Math.abs(x.price - item.price) / item.price < 0.005)
  ).slice(0, 8);

  const levelsHTML = deduped.map(l => `
    <div class="pmb-level-item" style="border-left-color:${l.color};">
      <div class="plbl">${l.label}</div>
      <div class="pval" style="color:${l.color};">${fP(l.price)}</div>
      <div class="ptf">${l.tf} timeframe</div>
    </div>`).join('');

  // HTF context note
  const htfLabel = c.htfBias === 'bull' ? '▲ BULLISH' : c.htfBias === 'bear' ? '▼ BEARISH' : '● MIXED';
  const htfCol   = c.htfBias === 'bull' ? 'var(--tl)' : c.htfBias === 'bear' ? 'var(--rd)' : 'var(--am)';
  const htfNote  = c.dailyMatchesHTF
    ? `Daily bias aligns with higher TF — <span style="color:var(--tl)">confluent setup</span>.`
    : `Daily bias conflicts with higher TF — <span style="color:var(--am)">wait for alignment before trading</span>.`;

  // Daily close context
  const daily = a.tfData['1d'];
  const daily1hStr = a.tfData['1h'] ? `1H: ${a.tfData['1h'].movePct >= 0 ? '+' : ''}${a.tfData['1h'].movePct}%` : '';

  return `<div class="pmb-sym-detail" data-sym="${a.sym}" id="pmb-pane-${a.sym}">

    <!-- Symbol header -->
    <div class="pmb-section" style="background:linear-gradient(to right,rgba(0,212,160,.04),transparent);padding:14px 18px 12px;">
      <div style="display:flex;align-items:flex-start;gap:14px;">
        <div style="flex:1;">
          <div style="display:flex;align-items:center;gap:10px;margin-bottom:4px;">
            <span style="font-size:18px;font-weight:600;font-family:ui-monospace,'SF Mono',monospace;color:var(--tx);">${a.sym}</span>
            <span style="font-size:10px;color:var(--tx3);font-family:ui-monospace,'SF Mono',monospace;">${a.name}</span>
            <span style="font-size:11px;font-family:ui-monospace,'SF Mono',monospace;padding:2px 7px;border-radius:3px;background:var(--bg4);color:var(--tx2);border:1px solid var(--b2);">${a.exchange} · ${a.type}</span>
          </div>
          <div style="display:flex;gap:16px;font-family:ui-monospace,'SF Mono',monospace;font-size:11px;color:var(--tx2);align-items:center;flex-wrap:wrap;">
            <span style="font-size:14px;font-weight:700;color:var(--tx);">${fP(a.price)}</span>
            <span style="color:${a.movePct >= 0 ? 'var(--tl)' : 'var(--rd)'};">${a.movePct >= 0 ? '+' : ''}${a.movePct}% (Daily)</span>
            ${daily1hStr ? `<span style="color:var(--tx3);font-size:11px;">${daily1hStr}</span>` : ''}
          </div>
        </div>
        <div style="text-align:right;">
          <button onclick="selSym('${a.sym}');closePremarket();" style="padding:6px 13px;background:rgba(0,212,160,.08);border:1px solid rgba(0,212,160,.3);color:var(--green);font-size:11px;font-family:ui-monospace,'SF Mono',monospace;border-radius:3px;cursor:pointer;font-weight:700;" onmouseover="this.style.background='rgba(0,212,160,.16)'" onmouseout="this.style.background='rgba(0,212,160,.08)'">Open Chart ›</button>
        </div>
      </div>
    </div>

    <!-- Confluence verdict -->
    <div class="pmb-section">
      <div class="pmb-sec-hdr">
        <span class="pmb-sec-icon">🔀</span>
        <span class="pmb-sec-title" style="color:${verdictCol};">MULTI-TF CONFLUENCE</span>
      </div>
      <div class="pmb-conf-bar" style="border-left-color:${verdictCol};">
        <div>
          <div class="pmb-conf-label" style="color:${verdictCol};">${c.verdict}</div>
          <div class="pmb-conf-note">${c.bullTFs} of ${c.totalTFs} timeframes bullish · ${c.bearTFs} bearish · HTF bias: <span style="color:${htfCol};font-weight:700;">${htfLabel}</span></div>
          <div class="pmb-conf-note" style="margin-top:2px;">${htfNote}</div>
        </div>
        <div style="text-align:right;">
          <div class="pmb-conf-score" style="color:${confBarCol};">${c.confScore}</div>
          <div style="font-size:11px;font-family:ui-monospace,'SF Mono',monospace;color:var(--tx3);">confluence score</div>
          <div style="margin-top:4px;height:5px;width:70px;background:var(--bg4);border-radius:3px;overflow:hidden;">
            <div style="width:${confBarW}%;height:100%;background:${confBarCol};border-radius:3px;transition:width .6s;"></div>
          </div>
        </div>
      </div>
    </div>

    <!-- TF breakdown grid -->
    <div class="pmb-section">
      <div class="pmb-sec-hdr">
        <span class="pmb-sec-icon">📊</span>
        <span class="pmb-sec-title" style="color:var(--am);">TIMEFRAME BREAKDOWN</span>
        <span style="font-size:11px;font-family:ui-monospace,'SF Mono',monospace;color:var(--tx3);margin-left:auto;">1H → Monthly</span>
      </div>
      <div class="pmb-tf-grid">${tfCells}</div>
    </div>

    <!-- Key Levels from HTF + Daily -->
    <div class="pmb-section">
      <div class="pmb-sec-hdr">
        <span class="pmb-sec-icon">🎯</span>
        <span class="pmb-sec-title" style="color:var(--tl);">KEY LEVELS — HTF + DAILY</span>
        <span style="font-size:11px;color:var(--tx2);font-family:ui-monospace,'SF Mono',monospace;margin-left:auto;">Monthly · Weekly · Daily S/R</span>
      </div>
      <div class="pmb-levels-grid">${levelsHTML || '<div style="font-size:11px;color:var(--tx2);">No significant levels detected.</div>'}</div>
    </div>

    <!-- AI Narrative for this symbol -->
    <div class="pmb-section">
      <div class="pmb-sec-hdr">
        <span class="pmb-sec-icon">🤖</span>
        <span class="pmb-sec-title" style="color:var(--tx2);">AI BRIEF — ${a.sym}</span>
        <span id="pmb-narr-load-${a.sym}" style="font-size:11px;font-family:ui-monospace,'SF Mono',monospace;color:var(--tx3);margin-left:8px;">⟳ generating…</span>
      </div>
      <div class="pmb-narrative" id="pmb-narrative-${a.sym}"></div>
    </div>

    <!-- News for this symbol -->
    <div class="pmb-section">
      <div class="pmb-sec-hdr">
        <span class="pmb-sec-icon">📡</span>
        <span class="pmb-sec-title" style="color:var(--rd);">NEWS — ${a.sym}</span>
      </div>
      <div id="pmb-news-${a.sym}" style="font-size:10px;color:var(--tx3);">⟳ fetching…</div>
    </div>

  </div>`;
}

async function generateSymbolNarrative(a) {
  const c = a.confluence;
  const htfLabel = c.htfBias === 'bull' ? 'BULLISH' : c.htfBias === 'bear' ? 'BEARISH' : 'MIXED';
  const daily = a.tfData['1d'];
  const h1    = a.tfData['1h'];
  const now   = new Date();
  const dateStr = now.toLocaleDateString([], {weekday:'long', year:'numeric', month:'long', day:'numeric'});
  const hour    = now.getUTCHours();
  const session = hour < 7 ? 'Asia' : hour < 12 ? 'Europe' : hour < 21 ? 'US' : 'Asia';

  // Build multi-TF data rows
  const tfRows = ['1h','1d','1w','1M'].map(tf => {
    const t = a.tfData[tf];
    if (!t) return null;
    return `  ${tf.padEnd(3)}: ${t.bias.toUpperCase().padEnd(7)} | RSI ${String(t.rsi).padEnd(5)} | ATR ${t.atr ? fP(t.atr) : 'n/a'} | S: ${t.nearestS ? fP(t.nearestS) : 'n/a'} | R: ${t.nearestR ? fP(t.nearestR) : 'n/a'}${t.topPat ? ' | Pattern: '+t.topPat.name : ''}`;
  }).filter(Boolean).join('\n');

  const allS = ['1w','1d','1h'].flatMap(tf => { const t = a.tfData[tf]; return t?.nearestS ? [t.nearestS] : []; });
  const allR = ['1w','1d','1h'].flatMap(tf => { const t = a.tfData[tf]; return t?.nearestR ? [t.nearestR] : []; });
  const supportLevels    = [...new Set(allS.map(p => fP(p)))].slice(0,4).join(', ') || 'None detected';
  const resistanceLevels = [...new Set(allR.map(p => fP(p)))].slice(0,4).join(', ') || 'None detected';

  const rsiDaily  = daily?.rsi ? `${daily.rsi} ${daily.rsi > 70 ? '(Overbought)' : daily.rsi < 30 ? '(Oversold)' : '(Neutral)'}` : 'N/A';
  const rsiH1     = h1?.rsi    ? `${h1.rsi} ${h1.rsi > 70 ? '(Overbought)'   : h1.rsi < 30    ? '(Oversold)'   : '(Neutral)'}` : 'N/A';
  const volStatus = a.movePct > 1 ? 'Elevated — strong bullish move' : a.movePct < -1 ? 'Elevated — strong bearish move' : 'Normal';
  const dailyMove = `${a.movePct >= 0 ? '+' : ''}${a.movePct}%`;
  const isBTC     = a.sym.includes('BTC');
  const cryptoCtx = isBTC
    ? 'BTC is the market benchmark — its structure drives overall crypto sentiment.'
    : `Monitor BTC dominance and BTC price action for correlation signals on ${a.sym}.`;

  const prompt = `You are a professional financial market analyst responsible for preparing a clear and concise pre-market briefing for traders. Your goal is to summarise the most important market developments and highlight potential trading opportunities for the upcoming session. Use objective analysis based on macroeconomic context, market sentiment, technical structure, and key levels.

INPUT DATA:
Date: ${dateStr}
Session: ${session}
Asset: ${a.sym} (${a.name})
Current Price: ${fP(a.price)}
Daily Move: ${dailyMove}
Overall Confluence: ${c.verdict} (score: ${c.confScore}/100)
Higher TF Bias (Weekly + Monthly): ${htfLabel}
Daily Aligns with HTF: ${c.dailyMatchesHTF ? 'YES — confluent' : 'NO — conflicting'}

Multi-Timeframe Technical Data:
${tfRows}

Key Support Levels: ${supportLevels}
Key Resistance Levels: ${resistanceLevels}

Indicators:
  RSI (Daily): ${rsiDaily}
  RSI (1H): ${rsiH1}
  Volume Conditions: ${volStatus}
  ATR (Daily): ${daily?.atr ? fP(daily.atr) : 'N/A'}

Crypto Market Context: ${cryptoCtx}
Patterns Detected: ${['1d','1h'].map(tf => a.tfData[tf]?.topPat?.name).filter(Boolean).join(', ') || 'None'}
--------------------------------
PRE-MARKET BRIEFING STRUCTURE

1. GLOBAL MARKET OVERVIEW
Summarise the current state of global markets and how they relate to ${a.sym}. Identify whether overall sentiment is bullish, bearish, or neutral. Use the multi-timeframe data above to support your view.

2. MACRO & NEWS DRIVERS
Highlight the most important macroeconomic events or news affecting ${a.sym} today, including:
- central bank developments
- economic data releases (CPI, NFP, FOMC etc.)
- geopolitical developments
- crypto-specific drivers (ETF flows, regulatory news, on-chain activity)
Explain how these events could influence price behaviour.

3. KEY MARKET LEVELS
Identify the most important technical levels for ${a.sym}:
- Major support zones (use exact prices from the data above)
- Major resistance zones (use exact prices from the data above)
- Breakout or breakdown areas
Explain why each level is significant.

4. VOLATILITY & SENTIMENT
Assess market sentiment using RSI, price momentum, multi-timeframe bias, and volume conditions.
Classify sentiment as: Bullish / Bearish / Mixed / Neutral
Explain the reasoning using the data provided.

5. POTENTIAL TRADING THEMES TODAY
Identify 3–5 possible themes or narratives traders may focus on for ${a.sym} today. Examples: momentum continuation, key level retest, volatility expansion, BTC correlation play, altcoin rotation.

6. WATCHLIST SETUPS
For ${a.sym}, provide:
  Asset Name: ${a.sym}
  Current Market Context: (describe current structure)
  Potential Setup: (breakout, pullback, trend continuation, or range trade — be specific)
  Key Levels to Watch: (use exact prices from the data above)

7. RISK EVENTS TO WATCH
List the most important factors during this session that could cause volatility for ${a.sym}. Include technical invalidation levels and macro sensitivity.

8. TRADER SUMMARY
A 3–4 sentence summary of the most important things a trader should watch for ${a.sym} today. Be specific, use the exact price levels provided, and remain actionable. Do not make guaranteed predictions or provide financial advice.`;

  return await groqFetch(prompt);
}

async function fetchPMBNews(symStrs) {
  for (const sym of symStrs) {
    const el = document.getElementById('pmb-news-' + sym);
    if (!el) continue;
    try {
      const symObj = SYMS.find(x=>x.s===sym); const items = await fetchNewsFromAPI(sym, symObj?.t||'Stock');
      if (!items || !items.length) {
        el.innerHTML = '<div style="font-size:11px;color:var(--tx2);">No news available.</div>';
        continue;
      }
      const bullKw = ['surge','rally','beat','strong','growth','record','upgrade','buy','bull','gain','profit','rise','soar'];
      const bearKw = ['fall','drop','miss','weak','loss','risk','cut','sell','bear','decline','plunge','warn'];
      const colMap = { bull:'var(--tl)', bear:'var(--rd)', neut:'var(--am)' };
      el.innerHTML = items.slice(0,5).map(item => {
        const t = (item.title||'').toLowerCase();
        const bs = bullKw.filter(k=>t.includes(k)).length;
        const rs = bearKw.filter(k=>t.includes(k)).length;
        const sent = bs > rs ? 'bull' : rs > bs ? 'bear' : 'neut';
        const col = colMap[sent];
        const title = (item.title||'').replace(/</g,'&lt;').replace(/>/g,'&gt;');
        const wrap  = item.link ? `<a href="${item.link}" target="_blank" rel="noopener" style="text-decoration:none;">` : '<div>';
        const wend  = item.link ? '</a>' : '</div>';
        return `${wrap}<div class="pmb-news-item">
          <div class="pmb-news-dot" style="background:${col}"></div>
          <div>
            <div class="pmb-news-title">${title}</div>
            <div class="pmb-news-src">${item.source||''} · ${timeAgo(item.date)||''}</div>
          </div>
        </div>${wend}`;
      }).join('');
    } catch(e) {
      if(el) el.innerHTML = '<div style="font-size:11px;color:var(--tx2);">News unavailable.</div>';
    }
  }
}



// ══ AI BEST SETUPS ════════════════════════════════════════════════════════════
let aisSetups   = [];
let aisSortKey  = 'score';
let aisActiveTypes = new Set(['Crypto']);
let aisActiveDirs  = new Set(['bull','bear']);
let aisTFScan    = new Set(['1m','5m','15m','1h','4h','1d','1w','1M']); // used at scan time
let aisTFFilter  = new Set(['1m','5m','15m','1h','4h','1d','1w','1M']); // used for live filtering

const AIS_TF_CFG = {
  '1m':  { bars:300, slMult:0.8,  tgtMult:1.5 },
  '5m':  { bars:300, slMult:1.0,  tgtMult:2.0 },
  '15m': { bars:250, slMult:1.1,  tgtMult:2.0 },
  '1h':  { bars:200, slMult:1.2,  tgtMult:2.0 },
  '4h':  { bars:200, slMult:1.5,  tgtMult:2.5 },
  '1d':  { bars:200, slMult:1.5,  tgtMult:2.5 },
  '1w':  { bars:150, slMult:2.0,  tgtMult:4.0 },
  '1M':  { bars:100, slMult:2.5,  tgtMult:5.0 },
};

const ALL_TFS = Object.keys(AIS_TF_CFG);

function aisToggleTF(el){
  const tf = el.dataset.tf;
  const allOn = ALL_TFS.every(t => aisTFFilter.has(t));

  if(tf === 'all'){
    if(allOn){
      // All selected → deselect all
      aisTFFilter.clear();
      document.querySelectorAll('.ais-chip.tf').forEach(b => b.classList.remove('on'));
    } else {
      // Not all → select all
      aisTFFilter = new Set(ALL_TFS);
      document.querySelectorAll('.ais-chip.tf').forEach(b => b.classList.toggle('on', b.dataset.tf === 'all'));
    }
  } else {
    if(allOn){
      // Currently showing all — first click on a specific TF = switch exclusively to that one
      aisTFFilter = new Set([tf]);
      document.querySelector('.ais-chip.tf-all').classList.remove('on');
      document.querySelectorAll('.ais-chip.tf:not(.tf-all)').forEach(b => b.classList.toggle('on', b.dataset.tf === tf));
    } else {
      // Toggle this TF in/out of the current selection
      if(aisTFFilter.has(tf)){ aisTFFilter.delete(tf); el.classList.remove('on'); }
      else                    { aisTFFilter.add(tf);   el.classList.add('on'); }
      // Nothing left → reset to all
      if(aisTFFilter.size === 0){
        aisTFFilter = new Set(ALL_TFS);
        document.querySelectorAll('.ais-chip.tf').forEach(b => b.classList.toggle('on', b.dataset.tf === 'all'));
      } else {
        document.querySelector('.ais-chip.tf-all').classList.remove('on');
      }
    }
  }
  aisApplyFilter();
}

const ALL_TYPES = ['Crypto'];

function aisTypeAll(){
  const allOn = ALL_TYPES.every(t => aisActiveTypes.has(t));
  if(allOn){
    aisActiveTypes.clear();
    document.querySelectorAll('.ais-chip.type, .ais-chip.type-all').forEach(b => b.classList.remove('on'));
  } else {
    aisActiveTypes = new Set(ALL_TYPES);
    document.querySelectorAll('.ais-chip.type').forEach(b => b.classList.add('on'));
    document.querySelector('.ais-chip.type-all').classList.add('on');
  }
  aisApplyFilter();
}

function aisToggleFilter(el){
  const f = el.dataset.filter, group = el.dataset.group;
  const set = group === 'type' ? aisActiveTypes : aisActiveDirs;
  const allTypes = ALL_TYPES;

  if(group === 'type'){
    const allOn = allTypes.every(t => aisActiveTypes.has(t));
    if(allOn){
      // All active — first click switches exclusively to this type
      aisActiveTypes = new Set([f]);
      document.querySelector('.ais-chip.type-all').classList.remove('on');
      document.querySelectorAll('.ais-chip.type').forEach(b => b.classList.toggle('on', b.dataset.filter === f));
    } else {
      if(set.has(f)){ set.delete(f); el.classList.remove('on'); }
      else           { set.add(f);   el.classList.add('on'); }
      // Nothing left → reset to all
      if(set.size === 0){
        aisActiveTypes = new Set(ALL_TYPES);
        document.querySelectorAll('.ais-chip.type').forEach(b => b.classList.add('on'));
        document.querySelector('.ais-chip.type-all').classList.add('on');
      } else {
        const allNowOn = ALL_TYPES.every(t => aisActiveTypes.has(t));
        document.querySelector('.ais-chip.type-all').classList.toggle('on', allNowOn);
      }
    }
  } else {
    // Dir filter — simple toggle
    if(set.has(f)){ set.delete(f); el.classList.remove('on'); }
    else           { set.add(f);   el.classList.add('on'); }
    if(set.size === 0){ set.add(f); el.classList.add('on'); } // keep at least one
  }
  aisApplyFilter();
}

// ── Instant filter: just show/hide cards, no re-render ───────────────────────
function aisApplyFilter(){
  const cards = document.querySelectorAll('.ais-card');
  let shown = 0;
  cards.forEach(card => {
    const typeOk = aisActiveTypes.has(card.dataset.type);
    const dirOk  = aisActiveDirs.has(card.dataset.dir);
    const tfOk   = aisTFFilter.has(card.dataset.tf);
    const visible = typeOk && dirOk && tfOk;
    card.style.display = visible ? '' : 'none';
    if(visible) shown++;
  });
  const total = aisSetups.length;
  document.getElementById('ais-showing-count').textContent =
    shown > 12 ? `${shown} of ${total} · scroll ↓` : `${shown} of ${total} setups`;
  let empty = document.getElementById('ais-empty-msg');
  if(!shown){
    if(!empty){
      empty = document.createElement('div');
      empty.id = 'ais-empty-msg';
      empty.style.cssText = 'grid-column:1/-1;padding:40px;text-align:center;font-size:11px;color:var(--tx2);';
      empty.textContent = 'No setups match current filters.';
      document.getElementById('ais-body').appendChild(empty);
    }
    empty.style.display = '';
  } else if(empty) {
    empty.style.display = 'none';
  }
}

