// ── Show refinement as a proper long/short trade tool on the main chart ───────
function tapShowRefinementOnChart(){
  if(!_tapDrawing || !curData?.length) return;
  const d      = _tapDrawing;
  const n      = curData.length;
  const atrV   = calcATR(curData);
  const atr    = atrV[n-1] || Math.abs(d.price - d.sl) * 0.8;
  const sr     = detectSR(curData);
  const isLong = d.type === 'long';
  const barNow = n - 1;

  // Remove any existing refinement tool so we don't stack up multiples
  drawings = drawings.filter(x => !x._tapRefinement);

  // ── Step 1: Try to parse AI-suggested levels from the analysis text ───────
  const _analysisText = tapAnalysisCache[curSym.s]?.aiResult || '';
  let suggestedEntry = null, suggestedSL = null, suggestedTP = null;

  if(_analysisText){
    // Extract section 8 (SUGGESTED IMPROVEMENTS) for the most relevant price hints
    const _improvSection = _analysisText.match(/8\.\s*SUGGESTED IMPROVEMENTS[\s\S]*?(?=\n9\.|\n10\.|\nSCORECARD|$)/i)?.[0] || _analysisText;
    // Price must be within 8% of the original entry to be considered valid
    const _validateP = p => { const v = parseFloat(p); return !isNaN(v) && v > d.price * 0.92 && v < d.price * 1.08 ? v : null; };
    const _entryM = _improvSection.match(/(?:entry|enter|short|long)\s+(?:at|around|near|@)\s*([0-9]+\.?[0-9]{0,5})/i);
    const _slM    = _improvSection.match(/(?:stop[- ]?loss|stop|sl)\s+(?:at|above|below|around|@)\s*([0-9]+\.?[0-9]{0,5})/i);
    const _tpM    = _improvSection.match(/(?:take[- ]?profit|target|tp)\s+(?:at|around|@)\s*([0-9]+\.?[0-9]{0,5})/i);
    if(_entryM) suggestedEntry = _validateP(_entryM[1]);
    if(_slM)    suggestedSL    = _validateP(_slM[1]);
    if(_tpM)    suggestedTP    = _validateP(_tpM[1]);
  }

  // ── Step 1b: Use RAG winning setups to compute historically-optimal entry/SL ─
  // Filter similar past setups that actually hit TP — average their offsets
  if(!suggestedEntry || !suggestedSL){
    const _ragWinners = _tapLastRagMatches.filter(m =>
      m.outcome === 'tp_hit' &&
      m.entry_price != null && m.sl_price != null &&
      m.direction === (isLong ? 'long' : 'short') &&
      m.similarity > 0.70
    );
    if(_ragWinners.length >= 2){
      // Average entry offset % relative to their own entry (normalised)
      const entryOffsets = _ragWinners.map(m => (m.entry_price - d.price) / d.price);
      const avgOffset    = entryOffsets.reduce((s, v) => s + v, 0) / entryOffsets.length;
      const ragEntry     = d.price * (1 + avgOffset);
      // Average SL distance % from entry
      const slDists = _ragWinners.map(m => Math.abs(m.sl_price - m.entry_price) / m.entry_price);
      const avgSlDist = slDists.reduce((s, v) => s + v, 0) / slDists.length;
      // Only apply if RAG suggests a meaningful (but not extreme) adjustment
      if(avgSlDist > 0.001 && avgSlDist < 0.15){
        if(!suggestedEntry) suggestedEntry = ragEntry;
        if(!suggestedSL){
          const slAmount = suggestedEntry * avgSlDist;
          suggestedSL = isLong ? suggestedEntry - slAmount : suggestedEntry + slAmount;
        }
      }
    }
  }

  // ── Step 2: Fill remaining gaps with S/R fallback ────────────────────────────
  // Entry: nearest S/R that IMPROVES price (lower for long, higher for short)
  // For LONG: want to enter LOWER (at support) — better price
  // For SHORT: want to enter HIGHER (at resistance) — better price
  if(!suggestedEntry){
    if(isLong){
      const cands = sr.support.filter(s => s < d.price && s > d.price * 0.98);
      suggestedEntry = cands.length ? cands.sort((a,b) => b-a)[0] : d.price;
    } else {
      const candsAbove = sr.resistance.filter(r => r > d.price && r < d.price * 1.02);
      if(candsAbove.length){
        suggestedEntry = candsAbove.sort((a,b) => a-b)[0];
      } else {
        suggestedEntry = d.price;
      }
    }
  }

  // SL: AI suggestion → RAG-derived → same proportional distance as original SL
  if(!suggestedSL){
    const origSlDist = Math.abs(d.price - d.sl);
    suggestedSL = isLong ? suggestedEntry - origSlDist : suggestedEntry + origSlDist;
  }

  // ── KEY FIX: TP always stays anchored to the original trade's target ───────
  // The refinement improves entry/SL precision — it never changes the trade idea.
  // Only use a parsed AI suggestion if it's in the same direction as the original TP.
  const _origTpInDirection = isLong ? d.tp > d.price : d.tp < d.price;
  if(!suggestedTP || (isLong ? suggestedTP <= suggestedEntry : suggestedTP >= suggestedEntry)){
    suggestedTP = _origTpInDirection ? d.tp : (isLong ? suggestedEntry + Math.abs(suggestedEntry - suggestedSL) * 2.5 : suggestedEntry - Math.abs(suggestedEntry - suggestedSL) * 2.5);
  }

  const riskAmt = Math.abs(suggestedEntry - suggestedSL);

  // ── Build a proper long/short drawing — same format as user-placed tools ───
  const halfBars = defaultTradeToolHalfBars(curTF);
  // Place the box centred on the current bar so it's clearly visible
  const refinementDraw = {
    type:         isLong ? 'long' : 'short',
    bar:          barNow + halfBars,           // right-anchored at current bar
    price:        suggestedEntry,
    sl:           suggestedSL,
    tp:           suggestedTP,
    halfBars,
    halfDuration: halfBarsToSecs(halfBars, curTF),
    tf:           curTF,
    id:           'tap-refine-' + Date.now(),
    _tapRefinement: true,                      // marks it as temporary
    _noSave:        true,                      // excluded from localStorage
    _refinementLabel: true,                    // tells renderer to show "AI Refined" badge
  };

  drawings.push(refinementDraw);
  draw();

  const rr = riskAmt > 0 ? (Math.abs(suggestedTP - suggestedEntry) / riskAmt).toFixed(2) : '—';
  toast(`📍 AI Refined ${isLong ? 'LONG' : 'SHORT'} placed — Entry ${fP(suggestedEntry)} · SL ${fP(suggestedSL)} · TP ${fP(suggestedTP)} · R:R 1:${rr}`);

  // Auto-remove after 90 seconds to keep chart clean
  setTimeout(() => {
    drawings = drawings.filter(x => !x._tapRefinement);
    draw();
  }, 90000);
}

// Clear refinement tool manually (e.g. if user re-clicks Show on Chart)
function tapClearRefinement(){
  drawings = drawings.filter(x => !x._tapRefinement);
  draw();
}

// ══ INCREMENTAL LIVE SCAN ══════════════════════════════════════════════════════
// Runs in the browser background after each chart load.
// Detects setups on recent bars using the same 10 methods as the historical scan,
// computes outcomes from OHLCV (no Groq needed), and stores to Supabase so the
// RAG system always has fresh data for the current symbol/timeframe.

function _scanFindSR(bars, i, lookback = 30) {
  const slice = bars.slice(Math.max(0, i - lookback), i);
  const support = [], resistance = [];
  for (let j = 1; j < slice.length - 1; j++) {
    if (slice[j].low  < slice[j-1].low  && slice[j].low  < slice[j+1].low)  support.push(slice[j].low);
    if (slice[j].high > slice[j-1].high && slice[j].high > slice[j+1].high) resistance.push(slice[j].high);
  }
  return { support, resistance };
}

function _scanCalcOutcome(bars, setupBar, entry, sl, tp, dir, maxBars = 50) {
  for (let i = setupBar + 1; i < Math.min(bars.length, setupBar + maxBars + 1); i++) {
    const b = bars[i];
    if (dir === 'long') {
      if (b.low  <= sl) return 'sl_hit';
      if (b.high >= tp) return 'tp_hit';
    } else {
      if (b.high >= sl) return 'sl_hit';
      if (b.low  <= tp) return 'tp_hit';
    }
  }
  return 'pending';
}

function _scanBuildFV(bars, i, dir, rr, slAtr, atr, patConf, patAligns, srProx) {
  const rsiV = calcRSI(bars);
  const s20  = calcSMA(bars, 20);
  const s50  = calcSMA(bars, 50);
  const mV   = calcMACD(bars);
  const rsi  = rsiV[i] ?? 50;
  const m20  = s20[i] ?? 0;
  const m50  = s50[i] ?? 0;
  const mH   = mV[i]?.hist ?? 0;
  const recent = bars.slice(Math.max(0, i - 19), i + 1);
  const avgVol = recent.reduce((s, b) => s + b.volume, 0) / recent.length;
  const volR   = avgVol > 0 ? bars[i].volume / avgVol : 1;
  return [
    rsi / 100,
    (m20 > 0 && m50 > 0) ? (m20 > m50 ? 1 : 0) : 0.5,
    dir === 'long' ? 1 : 0,
    Math.min(rr / 4, 1),
    Math.min(slAtr / 3, 1),
    Math.max(0, Math.min(1, patConf)),
    patAligns,
    Math.max(0, Math.min(1, srProx)),
    Math.min(volR / 3, 1),
    mH > 0 ? 1 : 0,
    atr > 0 ? Math.min(Math.abs(mH) / atr, 1) : 0,
    rsi > 50 ? 1 : 0,
  ];
}

function _scanICT(bars, i, atr) {
  if (i < 4) return [];
  const b0 = bars[i - 2], b2 = bars[i];
  const setups = [];
  if (b0.high < b2.low && b2.close > b2.open) {
    const entry = (b2.low + b0.high) / 2, sl = b0.high - atr * 0.3;
    const tp = entry + (entry - sl) * 2.5;
    const sr = _scanFindSR(bars, i);
    const all = [...sr.support, ...sr.resistance];
    const nsr = all.length ? Math.min(...all.map(v => Math.abs(v - entry))) / (atr * 2) : 1;
    setups.push({ dir: 'long',  entry, sl, tp, method: 'ICT', patConf: 0.72, patAligns: 1, srProx: 1 - Math.min(nsr, 1) });
  }
  if (b0.low > b2.high && b2.close < b2.open) {
    const entry = (b2.high + b0.low) / 2, sl = b0.low + atr * 0.3;
    const tp = entry - (sl - entry) * 2.5;
    const sr = _scanFindSR(bars, i);
    const all = [...sr.support, ...sr.resistance];
    const nsr = all.length ? Math.min(...all.map(v => Math.abs(v - entry))) / (atr * 2) : 1;
    setups.push({ dir: 'short', entry, sl, tp, method: 'ICT', patConf: 0.72, patAligns: 0, srProx: 1 - Math.min(nsr, 1) });
  }
  return setups;
}

function _scanSMC(bars, i, atr) {
  if (i < 20) return [];
  const slice = bars.slice(i - 20, i);
  const swingH = Math.max(...slice.map(b => b.high));
  const swingL = Math.min(...slice.map(b => b.low));
  const cur = bars[i], setups = [];
  if (cur.close > swingH && bars[i-1].close < swingH) {
    const entry = cur.close, sl = swingL > entry - atr * 3 ? swingL : entry - atr * 2;
    setups.push({ dir: 'long',  entry, sl, tp: entry + (entry - sl) * 2, method: 'SMC', patConf: 0.68, patAligns: 1, srProx: 0.8 });
  }
  if (cur.close < swingL && bars[i-1].close > swingL) {
    const entry = cur.close, sl = swingH < entry + atr * 3 ? swingH : entry + atr * 2;
    setups.push({ dir: 'short', entry, sl, tp: entry - (sl - entry) * 2, method: 'SMC', patConf: 0.68, patAligns: 0, srProx: 0.8 });
  }
  return setups;
}

function _scanSupplyDemand(bars, i, atr) {
  if (i < 5) return [];
  const base = bars[i-3], move = bars[i-2], retest = bars[i];
  const baseSize = Math.abs(base.close - base.open);
  const moveSize = Math.abs(move.close - move.open);
  const setups = [];
  if (moveSize > baseSize * 2 && moveSize > atr * 1.5) {
    if (move.close < move.open && retest.low <= base.high && retest.close >= base.low) {
      const entry = base.high, sl = base.low - atr * 0.2;
      setups.push({ dir: 'long',  entry, sl, tp: entry + (entry - sl) * 2.5, method: 'Supply & Demand', patConf: 0.75, patAligns: 1, srProx: 0.9 });
    }
    if (move.close > move.open && retest.high >= base.low && retest.close <= base.high) {
      const entry = base.low, sl = base.high + atr * 0.2;
      setups.push({ dir: 'short', entry, sl, tp: entry - (sl - entry) * 2.5, method: 'Supply & Demand', patConf: 0.75, patAligns: 0, srProx: 0.9 });
    }
  }
  return setups;
}

function _scanSR(bars, i, atr) {
  if (i < 30) return [];
  const sr = _scanFindSR(bars, i, 30), cur = bars[i], setups = [];
  for (const sup of sr.support) {
    if (Math.abs(cur.close - sup) < atr * 0.5 && cur.close > sup) {
      const sl = sup - atr * 0.5;
      setups.push({ dir: 'long',  entry: cur.close, sl, tp: cur.close + (cur.close - sl) * 2, method: 'Support & Resistance', patConf: 0.65, patAligns: 1, srProx: 0.95 });
    }
  }
  for (const res of sr.resistance) {
    if (Math.abs(cur.close - res) < atr * 0.5 && cur.close < res) {
      const sl = res + atr * 0.5;
      setups.push({ dir: 'short', entry: cur.close, sl, tp: cur.close - (sl - cur.close) * 2, method: 'Support & Resistance', patConf: 0.65, patAligns: 0, srProx: 0.95 });
    }
  }
  return setups.slice(0, 1);
}

function _scanMATrend(bars, i, atr) {
  if (i < 50) return [];
  const s20 = calcSMA(bars, 20), s50 = calcSMA(bars, 50);
  if (!s20[i] || !s50[i]) return [];
  const cur = bars[i], prev = bars[i-1], setups = [];
  if (s20[i] > s50[i] && prev.close < s20[i-1] && cur.close > s20[i]) {
    const sl = s50[i] > cur.close - atr * 2 ? s50[i] : cur.close - atr * 2;
    setups.push({ dir: 'long',  entry: cur.close, sl, tp: cur.close + (cur.close - sl) * 2, method: 'MA / Trend Following', patConf: 0.62, patAligns: 1, srProx: 0.7 });
  }
  if (s20[i] < s50[i] && prev.close > s20[i-1] && cur.close < s20[i]) {
    const sl = s50[i] < cur.close + atr * 2 ? s50[i] : cur.close + atr * 2;
    setups.push({ dir: 'short', entry: cur.close, sl, tp: cur.close - (sl - cur.close) * 2, method: 'MA / Trend Following', patConf: 0.62, patAligns: 0, srProx: 0.7 });
  }
  return setups;
}

function _scanPriceAction(bars, i, atr) {
  if (i < 3) return [];
  const b = bars[i], setups = [];
  const body = Math.abs(b.close - b.open);
  const upper = b.high - Math.max(b.close, b.open);
  const lower = Math.min(b.close, b.open) - b.low;
  if (lower > body * 2 && lower > upper * 2 && body > 0) {
    const sl = b.low - atr * 0.2;
    setups.push({ dir: 'long',  entry: b.close, sl, tp: b.close + (b.close - sl) * 2, method: 'Price Action', patConf: 0.7, patAligns: 1, srProx: 0.75 });
  }
  if (upper > body * 2 && upper > lower * 2 && body > 0) {
    const sl = b.high + atr * 0.2;
    setups.push({ dir: 'short', entry: b.close, sl, tp: b.close - (sl - b.close) * 2, method: 'Price Action', patConf: 0.7, patAligns: 0, srProx: 0.75 });
  }
  return setups;
}

function _scanBreakout(bars, i, atr) {
  if (i < 20) return [];
  const slice = bars.slice(i - 20, i);
  const boxH = Math.max(...slice.map(b => b.high));
  const boxL = Math.min(...slice.map(b => b.low));
  if (boxH - boxL > atr * 5) return []; // not a tight box
  const cur = bars[i], avgVol5 = bars.slice(i-5,i).reduce((s,b)=>s+b.volume,0)/5;
  const setups = [];
  if (cur.close > boxH && cur.volume > avgVol5 * 1.5) {
    setups.push({ dir: 'long',  entry: cur.close, sl: boxH - atr * 0.3, tp: cur.close + (boxH - boxL), method: 'Breakout', patConf: 0.7, patAligns: 1, srProx: 0.85 });
  }
  if (cur.close < boxL && cur.volume > avgVol5 * 1.5) {
    setups.push({ dir: 'short', entry: cur.close, sl: boxL + atr * 0.3, tp: cur.close - (boxH - boxL), method: 'Breakout', patConf: 0.7, patAligns: 0, srProx: 0.85 });
  }
  return setups;
}

function _scanFibonacci(bars, i, atr) {
  if (i < 30) return [];
  const slice = bars.slice(i - 30, i);
  const swingH = Math.max(...slice.map(b => b.high));
  const swingL = Math.min(...slice.map(b => b.low));
  const range = swingH - swingL;
  if (range < atr * 3) return [];
  const fib618 = swingH - range * 0.618;
  const cur = bars[i], setups = [];
  if (Math.abs(cur.close - fib618) < atr * 0.5) {
    setups.push({ dir: 'long',  entry: cur.close, sl: fib618 - atr * 0.5, tp: swingH, method: 'Fibonacci', patConf: 0.68, patAligns: 1, srProx: 0.85 });
  }
  if (Math.abs(cur.close - (swingH - range * 0.382)) < atr * 0.5 && cur.close < fib618) {
    const sl = swingH - range * 0.382 + atr * 0.5;
    setups.push({ dir: 'short', entry: cur.close, sl, tp: swingL, method: 'Fibonacci', patConf: 0.65, patAligns: 0, srProx: 0.8 });
  }
  return setups;
}

function _scanRSIMomentum(bars, i, atr) {
  if (i < 20) return [];
  const rsiV = calcRSI(bars);
  const rsi = rsiV[i];
  if (rsi == null) return [];
  const cur = bars[i], setups = [];
  if (rsi < 32 && bars[i-1].close < cur.close) {
    const sl = cur.low - atr * 0.5;
    setups.push({ dir: 'long',  entry: cur.close, sl, tp: cur.close + (cur.close - sl) * 2, method: 'RSI / Momentum', patConf: 0.65, patAligns: 1, srProx: 0.7 });
  }
  if (rsi > 68 && bars[i-1].close > cur.close) {
    const sl = cur.high + atr * 0.5;
    setups.push({ dir: 'short', entry: cur.close, sl, tp: cur.close - (sl - cur.close) * 2, method: 'RSI / Momentum', patConf: 0.65, patAligns: 0, srProx: 0.7 });
  }
  return setups;
}

function _scanWyckoff(bars, i, atr) {
  if (i < 30) return [];
  const slice = bars.slice(i - 30, i);
  const swingL = Math.min(...slice.map(b => b.low));
  const swingH = Math.max(...slice.map(b => b.high));
  const cur = bars[i], prev = bars[i-1], setups = [];
  if (prev.low < swingL && cur.close > swingL && cur.close > cur.open) {
    const sl = prev.low - atr * 0.2;
    setups.push({ dir: 'long',  entry: cur.close, sl, tp: cur.close + (cur.close - sl) * 2.5, method: 'Wyckoff', patConf: 0.72, patAligns: 1, srProx: 0.9 });
  }
  if (prev.high > swingH && cur.close < swingH && cur.close < cur.open) {
    const sl = prev.high + atr * 0.2;
    setups.push({ dir: 'short', entry: cur.close, sl, tp: cur.close - (sl - cur.close) * 2.5, method: 'Wyckoff', patConf: 0.72, patAligns: 0, srProx: 0.9 });
  }
  return setups;
}

const _SCAN_DETECTORS = [_scanICT, _scanSMC, _scanSupplyDemand, _scanSR, _scanMATrend,
                         _scanPriceAction, _scanBreakout, _scanFibonacci, _scanRSIMomentum, _scanWyckoff];

async function tapScanCurrentChart() {
  if (!_supa || !curData?.length || curData.length < 60) return;
  const sym = _tapNormSym(curSym?.s || '');
  const tf  = curTF;
  if (!sym || sym === 'unknown') return;

  // Cooldown per tf — daily chart scans once per day, intraday scans hourly
  const lsKey = `tap_iscan_${sym}_${tf}`;
  const lastScan = parseInt(localStorage.getItem(lsKey) || '0');
  const now = Date.now();
  const cooldownMs = { '1d': 86400000, '4h': 43200000, '1h': 14400000,
                       '30m': 7200000, '15m': 3600000, '5m': 1800000, '1m': 900000 }[tf] || 3600000;
  if (now - lastScan < cooldownMs) return;
  localStorage.setItem(lsKey, String(now));

  const bars = curData;
  const n    = bars.length;
  const atrV = calcATR(bars);

  // Only scan recent bars so we don't duplicate the historical scan data
  const scanBars = Math.min(150, Math.floor(n * 0.2));
  const startBar = Math.max(55, n - scanBars);
  const allSetups = [];

  for (let i = startBar; i < n - 5; i++) {
    const atr = atrV[i] || 0.001;
    for (const detect of _SCAN_DETECTORS) {
      try {
        for (const s of detect(bars, i, atr)) {
          if (!isFinite(s.entry) || !isFinite(s.sl) || !isFinite(s.tp)) continue;
          const outcome = _scanCalcOutcome(bars, i, s.entry, s.sl, s.tp, s.dir);
          const rr      = Math.abs(s.tp - s.entry) / (Math.abs(s.sl - s.entry) || 0.001);
          const slAtr   = Math.abs(s.entry - s.sl) / (atr || 0.001);
          const fv      = _scanBuildFV(bars, i, s.dir, rr, slAtr, atr, s.patConf, s.patAligns, s.srProx);
          allSetups.push({
            id: `iscan-${sym}-${tf}-${s.method.replace(/[\s/&]+/g,'-')}-${bars[i].time}-${allSetups.length}`,
            user_id: 'anonymous', symbol: sym, timeframe: tf,
            direction: s.dir, feature_vector: fv,
            analysis_text: `${s.method} ${s.dir} detected on ${sym} ${tf}`,
            method_detected: s.method, outcome,
            entry_price: +s.entry.toFixed(5),
            sl_price:    +s.sl.toFixed(5),
            tp_price:    +s.tp.toFixed(5),
            created_at: new Date(bars[i].time * 1000).toISOString(),
          });
        }
      } catch(e) { /* skip bad bar */ }
    }
  }

  if (!allSetups.length) return;

  // Upload in batches — upsert so re-runs don't duplicate
  const BATCH = 50;
  let stored = 0;
  for (let i = 0; i < allSetups.length; i += BATCH) {
    try {
      const { error } = await _supa.from('apex_analyses')
        .upsert(allSetups.slice(i, i + BATCH), { onConflict: 'id', ignoreDuplicates: true });
      if (!error) stored += Math.min(BATCH, allSetups.length - i);
    } catch(e) { /* Supabase unavailable */ }
  }
  if (stored > 0) console.log(`[ApexFX] Incremental scan: +${stored} setups for ${sym} ${tf}`);
}

// ══ TRADE ANALYSIS POPUP ══════════════════════════════════════════════════════
// ── Trade Analysis Cache — one entry per symbol ─────────────────────────────
// tapAnalysisCache[sym] = { drawing, sym, tf, aiResult }
// ONE analysis per symbol. Dismissed only when user explicitly ✕s the badge.
// Popup ✕ just collapses to badge — NEVER deletes the cache.
const tapAnalysisCache = {};

// ══ AI ANALYSIS — TTL CACHE + FIFO QUEUE + IN-FLIGHT DEDUP ═══════════════════
// Cache key: `${sym}|${tf}`  |  TTL: 30 min  |  Queue delay: 2 s (grows on 429)
const TAP_AI_TTL      = 1_800_000; // 30 minutes — locked until user clicks Re-analyse
const TAP_AI_INTERVAL = 2_000;

// tapAiTTLCache[key] = { result: string, ts: number }
const tapAiTTLCache = {};

// tapAiInflight[key] = { promise: Promise<string>, resolve, reject }
const tapAiInflight  = {};

// FIFO queue items: { key, execFn, resolve, reject }
const tapAiQueue     = [];
let   tapAiQueueBusy  = false;
let   tapAiNextDelay  = TAP_AI_INTERVAL;  // extended by 429 reset header

// One pending request per tab (per-user guard)
let   tapAiUserKey    = null;

// Live countdown interval handle (cleared on modal close / result)
let   _tapAiCountdownTimer = null;

function _tapAiCacheKey(sym, tf){ return `${sym}|${tf}`; }

function _tapAiCacheGet(sym, tf){
  const k = _tapAiCacheKey(sym, tf);
  const e = tapAiTTLCache[k];
  if(!e) return null;
  if(Date.now() - e.ts > TAP_AI_TTL){ delete tapAiTTLCache[k]; return null; }
  return e;
}

// Returns one of:
//   { cached: true,   result, ageMs }
//   { inFlight: true, promise }
//   { queued: true,   promise, position }
// Throws { _userPending: true } if this tab already has a queued/in-flight request.
function _tapAiEnqueue(sym, tf, execFn){
  const key = _tapAiCacheKey(sym, tf);

  // 1. TTL cache hit
  const hit = _tapAiCacheGet(sym, tf);
  if(hit) return { cached: true, result: hit.result, ageMs: Date.now() - hit.ts };

  // 2. In-flight dedup — attach to existing promise
  if(tapAiInflight[key]) return { inFlight: true, promise: tapAiInflight[key].promise };

  // 3. Per-user duplicate guard
  if(tapAiUserKey !== null){
    const e = new Error('Request already pending');
    e._userPending = true;
    throw e;
  }

  // 4. Enqueue
  let resolve, reject;
  const promise = new Promise((res, rej) => { resolve = res; reject = rej; });
  tapAiInflight[key] = { promise, resolve, reject };
  tapAiUserKey = key;
  tapAiQueue.push({ key, execFn, resolve, reject });

  if(!tapAiQueueBusy) _tapAiProcessQueue();
  return { queued: true, promise, position: tapAiQueue.length };
}

async function _tapAiProcessQueue(){
  if(tapAiQueueBusy || tapAiQueue.length === 0) return;
  tapAiQueueBusy = true;
  const item = tapAiQueue.shift();
  try {
    const result = await item.execFn();
    tapAiTTLCache[item.key] = { result, ts: Date.now() };
    item.resolve(result);
  } catch(e) {
    if(e._rateLimitResetMs) tapAiNextDelay = Math.max(e._rateLimitResetMs, TAP_AI_INTERVAL);
    item.reject(e);
  } finally {
    delete tapAiInflight[item.key];
    if(tapAiUserKey === item.key) tapAiUserKey = null;
    tapAiQueueBusy = false;
    if(tapAiQueue.length > 0){
      const delay = tapAiNextDelay;
      tapAiNextDelay = TAP_AI_INTERVAL;
      setTimeout(_tapAiProcessQueue, delay);
    }
  }
}

// ── Analysis lock — persisted to localStorage per symbol ──────────────────────
// Once an analysis runs for a symbol, it is locked permanently.
// Key: 'tap-lock-{sym}', Value: JSON {aiResult, ts, entry, sl, tp}
function tapSaveLock(sym, result, d){
  try{
    const payload = JSON.stringify({
      aiResult: result,
      ts: Date.now(),
      entry: d?.price, sl: d?.sl, tp: d?.tp,
      tf: d?.tf || curTF,
      setupMeta: d?._aisMeta || null
    });
    // Save per-drawing lock (primary) and symbol-level lock (fallback)
    if(d?.id) _lsSet('tap-lock-draw-'+d.id, payload);
    _lsSet('tap-lock-'+sym, payload);
    // Also cache in memory per drawing
    if(d?.id) tapAnalysisCache['tap-lock-draw-'+d.id] = { aiResult: result, setupMeta: d?._aisMeta || null };
  }catch(e){}
}
function tapLoadLock(sym){
  try{
    const raw = _lsGet('tap-lock-'+sym);
    return raw ? JSON.parse(raw) : null;
  }catch(e){ return null; }
}
function tapHasLock(sym){
  // Check per-drawing lock first (drawing ID based)
  const drawingId = _tapDrawing?.id;
  if(drawingId){
    const drawKey = 'tap-lock-draw-' + drawingId;
    if(tapAnalysisCache[drawKey]?.aiResult) return true;
    const drawLock = tapLoadLock(drawKey);
    if(drawLock?.aiResult){
      tapAnalysisCache[drawKey] = { aiResult: drawLock.aiResult, setupMeta: drawLock.setupMeta || null };
      return true;
    }
  }
  // Fallback: symbol-level lock (legacy)
  if(tapAnalysisCache[sym]?.aiResult) return true;
  const lock = tapLoadLock(sym);
  if(lock?.aiResult){
    tapAnalysisCache[sym] = tapAnalysisCache[sym] || { sym, aiResult: null, setupMeta: null };
    tapAnalysisCache[sym].aiResult = lock.aiResult;
    if(lock.setupMeta) tapAnalysisCache[sym].setupMeta = lock.setupMeta;
    return true;
  }
  return false;
}

let _tapDrawing = null;  // drawing currently in popup/modal
let _tapLastRagMatches = []; // RAG matches from last tapGenerateAI — used by refinement

// ── Blocked toast — shown when user tries to place a second trade on same symbol ──
function tapShowBlockedToast(){
  const cached = tapAnalysisCache[curSym.s];
  if(!cached) return;
  // Show a toast-style message with a Reopen button
  const existing = document.getElementById('tap-blocked-toast');
  if(existing) existing.remove();
  const t = document.createElement('div');
  t.id = 'tap-blocked-toast';
  t.style.cssText = `position:fixed;bottom:60px;left:50%;transform:translateX(-50%);
    z-index:2000;background:var(--bg2);border:1px solid var(--am);border-radius:6px;
    padding:10px 16px;display:flex;align-items:center;gap:12px;
    box-shadow:0 8px 32px rgba(0,0,0,.7);font-family:ui-monospace,'SF Mono',monospace;font-size:10px;
    animation:tap-pop .15s ease-out;white-space:nowrap;`;
  t.innerHTML = `
    <span style="color:var(--am);">⚠</span>
    <span style="color:var(--tx2);">Analysis already exists for <strong style="color:var(--tx)">${curSym.s}</strong> — dismiss it first to place a new trade.</span>
    <button onclick="tapReopenFromBadge();document.getElementById('tap-blocked-toast')?.remove();"
      style="padding:4px 11px;background:rgba(0,201,160,.1);border:1px solid rgba(0,201,160,.4);
      color:var(--tl);border-radius:3px;cursor:pointer;font-size:11px;font-weight:700;font-family:ui-monospace,'SF Mono',monospace;">
      🔬 Reopen
    </button>
    <button onclick="this.closest('#tap-blocked-toast').remove()"
      style="background:none;border:none;color:var(--tx3);cursor:pointer;font-size:14px;padding:0 2px;">✕</button>`;
  document.body.appendChild(t);
  setTimeout(() => t?.remove(), 6000);
}

// ── Real-time sync: update popup when drawing is dragged/resized ─────────────
function tapSyncDrawingToPopup(d){
  // Only sync if this is the currently active drawing
  if(d !== _tapDrawing) return;
  if(tapAnalysisCache[curSym.s]){
    tapAnalysisCache[curSym.s].drawing = d;
  }
  if(document.getElementById('tap-anchor').style.display !== 'none'){
    _tapAnchorFill(d);
  }
}

// ── Fill the popup fields from a drawing object ───────────────────────────────
function _tapAnchorFill(d){
  const isLong = d.type === 'long';
  const rr     = Math.abs(d.tp - d.price) / Math.abs(d.sl - d.price);
  const last   = curData.length ? curData[curData.length-1].close : d.price;

  // Compute trade status based on price history since the drawing's bar
  const { status, statusCol } = tapTradeStatus(d);

  document.getElementById('tap-anchor-dir').textContent  = isLong ? '▲ LONG' : '▼ SHORT';
  document.getElementById('tap-anchor-dir').dataset.sym = curSym.s;
  document.getElementById('tap-anchor-dir').style.color  = isLong ? 'var(--tl)' : 'var(--rd)';
  document.getElementById('tap-anchor-price').textContent =
    curSym.s + ' @ ' + fP(d.price) + (status ? '  · ' + status : '');
  document.getElementById('tap-anchor-price').style.color = statusCol || 'var(--tx2)';
  document.getElementById('tap-a-entry').textContent = fP(d.price);
  document.getElementById('tap-a-sl').textContent    = fP(d.sl);
  document.getElementById('tap-a-tp').textContent    = fP(d.tp);
  document.getElementById('tap-a-rr').textContent    = isFinite(rr) ? rr.toFixed(2) : '—';
  const btn = document.getElementById('tap-anchor-btn');
  btn.className = isLong ? '' : 'bear';

  // Only allow analysis for valid/relevant trade states
  const notTriggered   = status.includes('Not Triggered');
  const invalidPlace   = status.includes('Invalid Placement');
  if(notTriggered || invalidPlace){
    // Trade was placed in the past but price never reached entry — not analysable
    btn.style.display   = 'none';
    // Show an explanatory note instead
    let noteEl = document.getElementById('tap-anchor-note');
    if(!noteEl){
      noteEl = document.createElement('div');
      noteEl.id = 'tap-anchor-note';
      noteEl.style.cssText = 'padding:8px 14px 10px;font-family:var(--font-mono);font-size:10px;color:var(--tx2);text-align:center;opacity:.8;';
      btn.parentNode.insertBefore(noteEl, btn);
    }
    noteEl.style.display = 'block';
    noteEl.textContent   = invalidPlace ? '⛔ This placement is not valid — price has already moved past this level. Place the trade at a current or future price.' : '⚠ Price never reached this entry — move the trade to a valid level to analyse.';
  } else {
    btn.style.display = '';
    const noteEl = document.getElementById('tap-anchor-note');
    if(noteEl) noteEl.style.display = 'none';
    const cached = tapAnalysisCache[curSym.s];
    btn.textContent = (cached && cached.aiResult) ? '🔬 View Analysis' : 
                      status.includes('Future') ? '🔮 Predict This Trade' : '🔬 Analyse This Trade';
  }
}

// ── Determine if the trade (from its bar forward) hit SL, hit TP, or is open ──
function tapTradeStatus(d){
  if(!curData.length) return { status:'', statusCol:'' };
  const isLong   = d.type === 'long';
  const n        = curData.length;
  const halfBars = effectiveHalfBars(d);
  const entryBar = Math.round(d.bar - halfBars); // left edge = entry bar

  // ── CASE 1: Trade center or entry is in the future (beyond last bar) ────────
  // Use d.bar (center) — if center is beyond data, it's a future setup
  // Even if entryBar is within data, a future-centered box = forward-looking trade
  if(d.bar >= n || entryBar >= n){
    return { status:'🔮 Future Setup', statusCol:'var(--bl)' };
  }

  // ── CASE 2: Trade placed before chart data starts — invalid placement ─────
  if(entryBar < 0){
    return { status:'⛔ Invalid Placement', statusCol:'var(--rd)' };
  }

  // ── CASE 3: Entry price must be within the price range of the box window ──────
  // The simplest and most reliable validity check: do the bars that the box is
  // placed on actually trade at the entry price level? If the entry line sits
  // above every candle high in the box window, it was never reachable — invalid.
  // If it sits below every candle low — also never reachable — invalid.
  // This catches: box above chart, box below chart, box in empty historical space.
  const rightEdge = Math.min(n - 1, Math.round(d.bar + effectiveHalfBars(d)));
  const lastB    = curData[n-1];
  const curPrice = (lastB.high + lastB.low + lastB.close) / 3;

  // Collect the high/low range of every bar within the box window
  let boxHigh = -Infinity, boxLow = Infinity;
  for(let i = entryBar; i <= rightEdge; i++){
    if(curData[i].high > boxHigh) boxHigh = curData[i].high;
    if(curData[i].low  < boxLow)  boxLow  = curData[i].low;
  }
  // Entry must be within the range traded inside the box — if it's outside,
  // no candle in the box touched it and the placement is invalid.
  if(d.price > boxHigh || d.price < boxLow){
    return { status:'⛔ Invalid Placement', statusCol:'var(--rd)' };
  }

  // ── CASE 4: Scan for entry trigger and TP/SL from entryBar forward ───────────
  let entryTriggered = false;
  let triggerBar = entryBar;
  for(let i = entryBar; i < n; i++){
    const bar = curData[i];
    if(isLong  && bar.low  <= d.price){ entryTriggered = true; triggerBar = i; break; }
    if(!isLong && bar.high >= d.price){ entryTriggered = true; triggerBar = i; break; }
  }

  if(!entryTriggered){
    const dist = Math.abs(curPrice - d.price) / d.price * 100;
    return { status:`⏳ Not Triggered (${dist.toFixed(1)}% away)`, statusCol:'var(--am)' };
  }

  // ── CASE 5: Entry triggered — scan forward from trigger bar for TP/SL ─────
  for(let i = triggerBar; i < n; i++){
    const bar = curData[i];
    if(isLong){
      if(bar.low  <= d.sl) return { status:'✗ SL Hit', statusCol:'var(--rd)' };
      if(bar.high >= d.tp) return { status:'✓ TP Hit', statusCol:'var(--tl)' };
    } else {
      if(bar.high >= d.sl) return { status:'✗ SL Hit', statusCol:'var(--rd)' };
      if(bar.low  <= d.tp) return { status:'✓ TP Hit', statusCol:'var(--tl)' };
    }
  }

  // Still open — report floating P&L vs last bar
  // lastB and curPrice already declared above in CASE 3
  const openPnl  = isLong ? (curPrice - d.price) / d.price * 100
                           : (d.price - curPrice) / d.price * 100;
  return {
    status:    `Open ${openPnl >= 0 ? '+' : ''}${openPnl.toFixed(2)}%`,
    statusCol: openPnl >= 0 ? 'var(--tl)' : 'var(--rd)'
  };
}

// ── Show the floating popup (anchored top-right of chart-area) ────────────────
function showTradeAnalysisPopup(d, freshPlacement=false){
  _tapDrawing = d;
  
  // Check if we're in replay mode with mentor enabled
  if (replayMode && mentorState.enabled) {
    console.log('🚫 Trade analysis blocked - Replay training mode active');
    // In replay mode, let the mentor handle trade analysis, not the normal system
    return; // Don't show normal trade analysis popup
  }
  
  // Close any popup that belongs to a different symbol
  const anchor = document.getElementById('tap-anchor');
  if(anchor && anchor.style.display !== 'none'){
    const anchorSym = document.getElementById('tap-anchor-dir')?.dataset?.sym;
    if(anchorSym && anchorSym !== curSym.s){
      anchor.style.display = 'none';
      document.getElementById('tap-badge').style.display = 'none';
    }
  }
  // Always create/update symbol-level cache entry
  if(!tapAnalysisCache[curSym.s]){
    tapAnalysisCache[curSym.s] = { drawing: d, sym: curSym.s, tf: d.tf||curTF, aiResult: null, setupMeta: d._aisMeta || null };
  } else {
    tapAnalysisCache[curSym.s].drawing = d;
    tapAnalysisCache[curSym.s].tf = d.tf || curTF;
    if(d._aisMeta) tapAnalysisCache[curSym.s].setupMeta = d._aisMeta;
  }

  if(freshPlacement){
    // Fresh placement — clear symbol-level AI result so analysis runs fresh
    tapAnalysisCache[curSym.s].aiResult = null;
    // Each drawing has its own lock key — no need to clear others
  } else {
    // Re-opening: check for a per-drawing lock first, then symbol-level
    const drawKey = d.id ? 'tap-lock-draw-' + d.id : null;
    if(drawKey && !tapAnalysisCache[drawKey]?.aiResult){
      const drawLock = tapLoadLock(drawKey);
      if(drawLock?.aiResult){
        tapAnalysisCache[drawKey] = { aiResult: drawLock.aiResult, setupMeta: drawLock.setupMeta || null };
        tapAnalysisCache[curSym.s].aiResult = drawLock.aiResult;
        if(drawLock.setupMeta && !tapAnalysisCache[curSym.s].setupMeta) tapAnalysisCache[curSym.s].setupMeta = drawLock.setupMeta;
      }
    } else if(drawKey && tapAnalysisCache[drawKey]?.aiResult){
      tapAnalysisCache[curSym.s].aiResult = tapAnalysisCache[drawKey].aiResult;
      if(tapAnalysisCache[drawKey].setupMeta && !tapAnalysisCache[curSym.s].setupMeta) tapAnalysisCache[curSym.s].setupMeta = tapAnalysisCache[drawKey].setupMeta;
    } else if(!tapAnalysisCache[curSym.s].aiResult){
      const lock = tapLoadLock(curSym.s);
      if(lock?.aiResult) tapAnalysisCache[curSym.s].aiResult = lock.aiResult;
      if(lock?.setupMeta && !tapAnalysisCache[curSym.s].setupMeta) tapAnalysisCache[curSym.s].setupMeta = lock.setupMeta;
    }
  }
  const oldNotice = document.getElementById('tap-cached-notice');
  if(oldNotice) oldNotice.remove();
  // Make badge invisible and show popup
  document.getElementById('tap-badge').style.display  = 'none';
  document.getElementById('tap-anchor').style.display = 'block';
  _tapAnchorFill(d);
  // Sync toolbar button
  const rb = document.getElementById('dt-reopen-analysis');
  if(rb){ rb.style.display = 'inline-flex'; rb.style.alignItems = 'center'; }
}

// Popup ✕ — collapses to badge, NEVER deletes cache
function closeTradeAnalysisPopup(){
  document.getElementById('tap-anchor').style.display = 'none';
  resetDrag(document.getElementById('tap-anchor'));
  tapShowBadge();
}

// ── Persistent badge ──────────────────────────────────────────────────────────
function tapShowBadge(){
  const cached = tapAnalysisCache[curSym.s];
  if(!cached) return;
  const d = cached.drawing;
  const isLong = d.type === 'long';
  const { status, statusCol } = tapTradeStatus(d);
  document.getElementById('tap-badge-dir').textContent   = isLong ? '▲ LONG' : '▼ SHORT';
  document.getElementById('tap-badge-dir').style.color   = isLong ? 'var(--tl)' : 'var(--rd)';
  document.getElementById('tap-badge-sym').textContent   = cached.sym;
  document.getElementById('tap-badge-price').textContent = '@ ' + fP(d.price) + (status ? ' · ' + status : '');
  document.getElementById('tap-badge-price').style.color = statusCol || 'var(--am)';
  document.getElementById('tap-badge').style.borderColor = isLong ? 'rgba(0,201,160,.5)' : 'rgba(240,48,96,.5)';
  document.getElementById('tap-badge').style.display = 'block';
  const rb = document.getElementById('dt-reopen-analysis');
  if(rb){ rb.style.display = 'inline-flex'; rb.style.alignItems = 'center'; }
}

function tapHideBadge(){
  document.getElementById('tap-badge').style.display  = 'none';
  document.getElementById('tap-anchor').style.display = 'none';
  const rb = document.getElementById('dt-reopen-analysis');
  if(rb) rb.style.display = 'none';
}

// Badge ✕ — THIS is the only action that permanently clears the cache
function tapDismissBadge(){
  const cached = tapAnalysisCache[curSym.s];
  if(cached && cached.aiResult){
    // AI was actually used — mark dismissed so no new analysis can be triggered
    cached.dismissed = true;
  } else {
    // No analysis was ever run — fully delete the cache entry so they keep their slot
    delete tapAnalysisCache[curSym.s];
  }
  _tapDrawing = null;
  tapHideBadge();
}

// ── Dismiss confirmation ──────────────────────────────────────────────────────
function tapAskDismiss(){
  const cached = tapAnalysisCache[curSym.s];
  // Only warn if AI was actually run — otherwise just silently dismiss, slot is returned
  if(cached && cached.aiResult){
    document.getElementById('tap-dc-sym').textContent = curSym.s;
    document.getElementById('tap-dismiss-confirm').style.display = 'flex';
  } else {
    tapDismissBadge();
  }
}
function tapDismissCancel(){
  document.getElementById('tap-dismiss-confirm').style.display = 'none';
}
function tapDismissConfirm(){
  document.getElementById('tap-dismiss-confirm').style.display = 'none';
  tapDismissBadge();
}

// ── Analyse gate — warn before consuming the one-per-session slot ─────────────
function tapAnalyseGate(){
  if(!_tapDrawing) return;
  const { status } = tapTradeStatus(_tapDrawing);
  if(status.includes('Invalid Placement') || status.includes('Not Triggered')) return;
  // Check lock — once analysed, always show saved result
  if(tapHasLock(curSym.s)){ openFullTradeAnalysis(); return; }
  // No prior analysis — show one-time confirmation warning
  document.getElementById('tap-ac-sym').textContent = curSym.s;
  document.getElementById('tap-analyse-confirm').style.display = 'flex';
}
function tapAnalyseCancel(){
  document.getElementById('tap-analyse-confirm').style.display = 'none';
}
function tapAnalyseConfirm(){
  if(!_tapDrawing) return;
  const { status } = tapTradeStatus(_tapDrawing);
  if(status.includes('Invalid Placement') || status.includes('Not Triggered')){
    document.getElementById('tap-analyse-confirm').style.display = 'none';
    return;
  }
  document.getElementById('tap-analyse-confirm').style.display = 'none';
  openFullTradeAnalysis();
}

// ── Trade screenshot capture & share ─────────────────────────────────────────
let _tapScreenshotDataUrl = null;

function tapCaptureScreenshot(){
  const img   = document.getElementById('tap-sc-img');
  const ph    = document.getElementById('tap-sc-placeholder');
  const dlBtn = document.getElementById('tap-sc-dl-btn');
  const cpBtn = document.getElementById('tap-sc-copy-btn');
  if(!img) return;

  setTimeout(() => {
    // ── Temporarily zoom into the trade drawing for the screenshot ──────────
    const d = _tapDrawing;
    const savedBarWidth      = barWidth;
    const savedRightBarIndex = rightBarIndex;

    if(d){
      const halfBars = effectiveHalfBars(d);
      // Centre the drawing: right edge = drawing center + halfBars + padding
      const zoomBarWidth = Math.min(24, Math.max(14, barWidth * 2));  // 2× current, capped 14–24px
      barWidth = zoomBarWidth;
      // Show ~50 bars total centred on the drawing
      const visibleBars   = 50;
      const drawingCenter = d.bar;
      rightBarIndex = drawingCenter + visibleBars * 0.55;  // slight right bias so drawing isn't at edge
      draw();  // re-render at new zoom
    }

    const dataUrl = captureChart();

    // ── Restore original view ─────────────────────────────────────────────────
    if(d){
      barWidth      = savedBarWidth;
      rightBarIndex = savedRightBarIndex;
      draw();
    }

    if(dataUrl){
      _tapScreenshotDataUrl = dataUrl;
      img.src = dataUrl;
      img.style.display = 'block';
      if(ph) ph.style.display = 'none';
      if(dlBtn) dlBtn.style.display = 'inline-block';
      if(cpBtn) cpBtn.style.display = 'inline-block';
    } else {
      if(ph){ ph.textContent = 'Screenshot unavailable'; ph.style.color = 'var(--rd)'; }
    }
  }, 150);
}

function tapDownloadScreenshot(){
  if(!_tapScreenshotDataUrl) return;
  const a = document.createElement('a');
  const sym = curSym?.s || 'trade';
  const ts  = new Date().toISOString().slice(0,16).replace('T','-').replace(':','-');
  a.href     = _tapScreenshotDataUrl;
  a.download = `apexfx-${sym}-${ts}.jpg`;
  a.click();
  toast('📷 Screenshot downloaded');
}

async function tapCopyScreenshot(){
  if(!_tapScreenshotDataUrl){ toast('No screenshot to copy'); return; }
  try {
    const res  = await fetch(_tapScreenshotDataUrl);
    const blob = await res.blob();
    await navigator.clipboard.write([new ClipboardItem({ 'image/png': blob })]);
    toast('📋 Screenshot copied to clipboard');
  } catch(e) {
    // Fallback: open in new tab so user can save manually
    const w = window.open();
    if(w){ w.document.write(`<img src="${_tapScreenshotDataUrl}" style="max-width:100%">`); }
    toast('📷 Opened in new tab — right-click to save');
  }
}

// Reopen from badge or toolbar button
function tapReopenFromBadge(){
  const cached = tapAnalysisCache[curSym.s];
  if(!cached) return;
  _tapDrawing = cached.drawing;
  _tapAnchorFill(cached.drawing);
  document.getElementById('tap-badge').style.display  = 'none';
  document.getElementById('tap-anchor').style.display = 'block';
}

// Called by loadSym on symbol switch
function tapSyncToSymbol(){
  tapHideBadge();
  document.getElementById('tap-anchor').style.display = 'none';

  const cached = tapAnalysisCache[curSym.s];

  // If we have a cached drawing for this symbol, restore it as active
  if(cached?.drawing && (cached.drawing.type==='long'||cached.drawing.type==='short')){
    // Verify it still exists in drawings array
    const stillExists = drawings.includes(cached.drawing);
    if(stillExists){
      _tapDrawing = cached.drawing;
      if(!cached.dismissed) tapShowBadge();
      return;
    }
  }

  // Otherwise find the most recently placed long/short drawing
  const liveDrawings = drawings.filter(d => d.type==='long'||d.type==='short');
  if(liveDrawings.length > 0){
    _tapDrawing = liveDrawings[liveDrawings.length - 1]; // most recent
    if(cached) cached.drawing = _tapDrawing;
    tapShowBadge();
  } else {
    _tapDrawing = null;
  }
}

function closeTapModal(){
  clearInterval(_tapAiCountdownTimer); _tapAiCountdownTimer = null;
  const modalEl = document.getElementById('tap-modal');
  modalEl.classList.remove('open', 'expanded');
  document.getElementById('tap-modal-bg').classList.remove('open');
  resetDrag(modalEl);
  tapShowBadge();
}

function tapToggleExpand(){
  document.getElementById('tap-modal').classList.add('expanded');
  document.getElementById('tap-expand-row').style.display = 'none';
}

async function openFullTradeAnalysis(){
  if(!_tapDrawing) return;
  
  // Check if we're in replay mode with mentor enabled
  if (replayMode && mentorState.enabled) {
    console.log('🚫 Full trade analysis blocked - Replay training mode active');
    showMentorMessage('📚 In replay training mode, the AI Mentor reviews your trades instead of the normal analysis system.');
    return;
  }
  
  closeTradeAnalysisPopup();           // hides popup, shows badge
  const d      = _tapDrawing;
  const cached = tapAnalysisCache[curSym.s];
  const isLong = d.type === 'long';
  const dirLabel = isLong ? 'LONG ▲' : 'SHORT ▼';
  const dirCol   = isLong ? 'var(--tl)' : 'var(--rd)';
  const rr   = Math.abs(d.tp - d.price) / Math.abs(d.sl - d.price);
  const slPct = Math.abs((d.sl - d.price) / d.price * 100);
  const tpPct = Math.abs((d.tp - d.price) / d.price * 100);

  // Get live trade status (SL hit / TP hit / open / unrealistic)
  const { status, statusCol } = tapTradeStatus(d);

  // Open in compact mode (reset any previous expanded state)
  const _tapModalEl = document.getElementById('tap-modal');
  _tapModalEl.classList.remove('expanded');
  document.getElementById('tap-expand-btn').textContent = 'VIEW FULL ANALYSIS ↓';
  document.getElementById('tap-modal-bg').classList.add('open');

  document.getElementById('tap-expand-row').style.display = '';

  // Only reset verdict banner to loading state if we have no cached result
  const _hasCachedResult = !!(cached?.aiResult);
  const _vBanner = document.getElementById('tap-verdict-banner');
  if(_vBanner && !_hasCachedResult){
    _vBanner.style.background    = 'rgba(136,153,176,0.05)';
    _vBanner.style.borderColor   = 'rgba(136,153,176,0.18)';
    document.getElementById('tap-verdict-label').textContent = 'ANALYZING TRADE\u2026';
    document.getElementById('tap-verdict-label').style.color = 'var(--tx3)';
    document.getElementById('tap-verdict-score').textContent = '\u2014';
    document.getElementById('tap-verdict-score').style.color = 'var(--tx3)';
    document.getElementById('tap-verdict-sub').textContent   = 'AI is reviewing your setup';
    document.getElementById('tap-verdict-sub').style.color   = 'var(--tx3)';
    document.getElementById('tap-verdict-prob').textContent  = '';
    document.getElementById('tap-verdict-bar').style.width   = '0%';
    document.getElementById('tap-verdict-bar').style.background = 'rgba(136,153,176,0.4)';
  }

  // Header
  document.getElementById('tap-hdr-title').textContent  = `\uD83D\uDD2C TRADE ANALYSIS \u2014 ${curSym.s}`;
  document.getElementById('tap-sym-tf').textContent     = `${curSym.s} · ${curTF}`;
  document.getElementById('tap-journal-sym').textContent = curSym.s;

  // Trade status banner — inject below header if SL/TP hit or unrealistic
  let statusBanner = '';
  if(status){
    const bannerBg  = status.includes('SL') ? 'rgba(240,48,96,.12)'
                    : status.includes('TP') ? 'rgba(0,201,160,.12)'
                    : 'rgba(240,165,0,.12)';
    const bannerBdr = status.includes('SL') ? 'var(--rd)'
                    : status.includes('TP') ? 'var(--tl)'
                    : 'var(--am)';
    statusBanner = `<div style="margin:0 0 12px;padding:8px 12px;background:${bannerBg};
      border-left:3px solid ${bannerBdr};border-radius:3px;
      font-size:10px;font-weight:700;font-family:ui-monospace,'SF Mono',monospace;color:${statusCol};">
      ${status === '✗ SL Hit'            ? '🔴 STOP LOSS HIT — this trade has already been stopped out'
      : status === '✓ TP Hit'            ? '🟢 TAKE PROFIT HIT — this trade reached its target'
      : status.includes('Unrealistic')   ? '⚠ PLACEMENT WARNING — entry price is far from where price has traded'
      : status.includes('Future')        ? '🔮 FUTURE SETUP — price has not reached entry yet; AI will predict likelihood'
      : status.includes('Not Triggered') ? '⏳ NOT TRIGGERED — price never reached this entry level'
      : '📊 ' + status}
    </div>`;
  }

  document.getElementById('tap-l-dir').textContent      = dirLabel;
  document.getElementById('tap-l-dir').style.color      = dirCol;
  document.getElementById('tap-l-entry').textContent    = fP(d.price);
  document.getElementById('tap-l-sl').textContent       = fP(d.sl);
  document.getElementById('tap-l-sl-pct').textContent   = slPct.toFixed(2) + '% risk';
  document.getElementById('tap-l-tp').textContent       = fP(d.tp);
  document.getElementById('tap-l-tp-pct').textContent   = '+' + tpPct.toFixed(2) + '% potential';
  document.getElementById('tap-l-rr').textContent       = rr.toFixed(2) + ':1';
  document.getElementById('tap-l-rr-grade').textContent = rr >= 3 ? 'Excellent' : rr >= 2 ? 'Good' : rr >= 1.5 ? 'Acceptable' : 'Poor';
  document.getElementById('tap-l-rr-grade').style.color = rr >= 3 ? 'var(--tl)' : rr >= 2 ? 'var(--am)' : 'var(--rd)';
  // topScoreEl/topScoreSubEl kept as stubs — score lives in verdict banner now
  const topScoreEl    = document.getElementById('tap-l-ai-score');
  const topScoreSubEl = document.getElementById('tap-l-ai-score-sub');

  // Inject status banner
  document.getElementById('tap-status-banner').innerHTML = statusBanner;

  tapDrawChart(d);
  tapRenderChartStats(d);
  tapRenderRisk(d, rr);
  tapRenderHistorical(d);
  tapRenderJournalHistory();
  tapRenderSetupBridge(d);
  tapRenderDecisionContext(d);

  // Capture chart screenshot for sharing
  _tapScreenshotDataUrl = null;
  const scImg = document.getElementById('tap-sc-img');
  const scPh  = document.getElementById('tap-sc-placeholder');
  const scDl  = document.getElementById('tap-sc-dl-btn');
  const scCp  = document.getElementById('tap-sc-copy-btn');
  if(scImg){ scImg.style.display='none'; scImg.src=''; }
  if(scPh) { scPh.style.display='inline'; scPh.textContent='Capturing chart…'; scPh.style.color='var(--tx3)'; }
  if(scDl) scDl.style.display='none';
  if(scCp) scCp.style.display='none';
  tapCaptureScreenshot();

  // ── AI — session lock (30 min TTL) → in-flight dedup → FIFO queue ────────────
  const aiOutEl     = document.getElementById('tap-ai-out');
  const aiLoadingEl = document.getElementById('tap-ai-loading');
  const _aiTF       = d.tf || curTF;

  // Remove any stale age-badge from a previous open
  document.getElementById('tap-ai-age-badge')?.remove();
  document.getElementById('tap-ai-reanalyse-btn')?.remove();

  // ── SESSION LOCK: if we already have a result for this drawing, show it immediately ──
  // This prevents re-running on every open — use "Re-analyse" to force fresh analysis.
  if(_hasCachedResult){
    const sessionResult = cached.aiResult;
    aiOutEl.textContent = tapDisplayAnalysisText(sessionResult);
    tapRenderVerdictBanner(sessionResult);
    tapRenderMethodBadge(sessionResult);
    tapRenderHistoricalStatsBadge(d);
    tapRenderSetupBridge(d, sessionResult);
    tapRenderDecisionContext(d);
    aiLoadingEl.style.display = 'none';
    if(topScoreSubEl) topScoreSubEl.textContent = 'Locked analysis — click Re-analyse to refresh';
    // Pre-fetch RAG matches in background so "Show on Chart" refinement works
    const _fv = tapExtractFeatureVector(d, curData);
    if(_fv) tapSearchSimilarAnalyses(_fv, curSym.s, _aiTF).then(m => { _tapLastRagMatches = m; }).catch(() => {});
    // Inject age badge + Re-analyse button
    const ageEl = document.createElement('div');
    ageEl.id = 'tap-ai-age-badge';
    ageEl.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:8px;';
    ageEl.innerHTML = `<span style="font-family:ui-monospace,monospace;font-size:10px;color:var(--tx3);letter-spacing:.3px;">` +
      `\uD83D\uDD12 Showing saved analysis</span>` +
      `<button id="tap-ai-reanalyse-btn" onclick="tapForceReanalyse()" style="` +
      `background:rgba(61,142,255,.12);border:1px solid rgba(61,142,255,.35);border-radius:4px;` +
      `color:var(--bl);font-size:10px;font-family:ui-monospace,monospace;padding:2px 8px;cursor:pointer;` +
      `letter-spacing:.3px;white-space:nowrap;">↻ Re-analyse</button>`;
    aiOutEl.parentNode.insertBefore(ageEl, aiOutEl);
    return;
  }

  let _enq;
  try {
    _enq = _tapAiEnqueue(curSym.s, _aiTF, () => tapGenerateAI(d, rr, status));
  } catch(e) {
    if(e._userPending){
      aiOutEl.innerHTML = `<div style="font-family:ui-monospace,'SF Mono',monospace;font-size:11px;color:var(--am);padding:10px 0;">` +
        `\u23F3 Request already pending \u2014 please wait for the current analysis to finish.</div>`;
      aiLoadingEl.style.display = 'inline';
      return;
    }
    _tapAiRenderErr(e.message, aiOutEl, aiLoadingEl, topScoreEl, topScoreSubEl);
    return;
  }

  if(_enq.cached){
    // TTL cache hit — instant result, no Groq call
    const ageSec = Math.round(_enq.ageMs / 1000);
    aiOutEl.textContent = tapDisplayAnalysisText(_enq.result);
    tapRenderVerdictBanner(_enq.result);
    tapRenderMethodBadge(_enq.result);
    tapRenderHistoricalStatsBadge(d);
    tapRenderSetupBridge(d, _enq.result);
    tapRenderDecisionContext(d);
    aiLoadingEl.style.display = 'none';
    if(cached) cached.aiResult = _enq.result;
    if(topScoreSubEl) topScoreSubEl.textContent = `Last analyzed ${ageSec}s ago`;
    // Pre-fetch RAG matches so "Show on Chart" refinement works from cached path
    const _fv2 = tapExtractFeatureVector(d, curData);
    if(_fv2) tapSearchSimilarAnalyses(_fv2, curSym.s, _aiTF).then(m => { _tapLastRagMatches = m; }).catch(() => {});
    const ageEl = document.createElement('div');
    ageEl.id = 'tap-ai-age-badge';
    ageEl.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:8px;';
    ageEl.innerHTML = `<span style="font-family:ui-monospace,monospace;font-size:10px;color:var(--tx3);letter-spacing:.3px;">` +
      `\uD83D\uDD50 Last analyzed ${ageSec}s ago</span>` +
      `<button id="tap-ai-reanalyse-btn" onclick="tapForceReanalyse()" style="` +
      `background:rgba(61,142,255,.12);border:1px solid rgba(61,142,255,.35);border-radius:4px;` +
      `color:var(--bl);font-size:10px;font-family:ui-monospace,monospace;padding:2px 8px;cursor:pointer;` +
      `letter-spacing:.3px;white-space:nowrap;">↻ Re-analyse</button>`;
    aiOutEl.parentNode.insertBefore(ageEl, aiOutEl);
  } else {
    // Queued or in-flight — show skeleton + live position/countdown
    const initPos = _enq.position || 0;
    const initEta = initPos > 0 ? initPos * Math.ceil(TAP_AI_INTERVAL / 1000) : 0;
    aiOutEl.innerHTML = _tapAiQueueHtml(initPos, initEta);
    aiLoadingEl.style.display = 'inline';

    const _aiQueueKey = _tapAiCacheKey(curSym.s, _aiTF);
    const _aiStarted  = Date.now();
    clearInterval(_tapAiCountdownTimer);
    _tapAiCountdownTimer = setInterval(() => {
      const qEl = document.getElementById('tap-ai-queue-status');
      if(!qEl){ clearInterval(_tapAiCountdownTimer); _tapAiCountdownTimer = null; return; }
      const pos = tapAiQueue.findIndex(q => q.key === _aiQueueKey) + 1;
      if(pos > 0){
        const eta = pos * Math.ceil(TAP_AI_INTERVAL / 1000);
        qEl.textContent = `Position ${pos} \u2014 ready in ~${eta}s`;
      } else {
        const elapsedSec = Math.round((Date.now() - _aiStarted) / 1000);
        qEl.textContent = `Analyzing\u2026 (${elapsedSec}s)`;
      }
    }, 500);

    try {
      const text = await _enq.promise;
      clearInterval(_tapAiCountdownTimer); _tapAiCountdownTimer = null;
      aiOutEl.textContent = tapDisplayAnalysisText(text);
      if(cached) cached.aiResult = text;
      tapSaveLock(curSym.s, text, d);
      _tapAnchorFill(d);
      tapRenderVerdictBanner(text);
      tapRenderMethodBadge(text);
      tapRenderHistoricalStatsBadge(d);
      tapRenderSetupBridge(d, text);
      tapRenderDecisionContext(d);
      aiLoadingEl.style.display = 'none';
      // Show Re-analyse button after result arrives
      document.getElementById('tap-ai-age-badge')?.remove();
      document.getElementById('tap-ai-reanalyse-btn')?.remove();
      const doneEl = document.createElement('div');
      doneEl.id = 'tap-ai-age-badge';
      doneEl.style.cssText = 'display:flex;align-items:center;gap:8px;margin-bottom:8px;';
      doneEl.innerHTML = `<span style="font-family:ui-monospace,monospace;font-size:10px;color:var(--tx3);letter-spacing:.3px;">` +
        `\uD83D\uDD12 Analysis locked — will not re-run on reopen</span>` +
        `<button id="tap-ai-reanalyse-btn" onclick="tapForceReanalyse()" style="` +
        `background:rgba(61,142,255,.12);border:1px solid rgba(61,142,255,.35);border-radius:4px;` +
        `color:var(--bl);font-size:10px;font-family:ui-monospace,monospace;padding:2px 8px;cursor:pointer;` +
        `letter-spacing:.3px;white-space:nowrap;">↻ Re-analyse</button>`;
      aiOutEl.parentNode.insertBefore(doneEl, aiOutEl);
    } catch(e) {
      clearInterval(_tapAiCountdownTimer); _tapAiCountdownTimer = null;
      _tapAiRenderErr(e.message, aiOutEl, aiLoadingEl, topScoreEl, topScoreSubEl);
    }
  }
}

// Force re-analysis — clears session lock so next open triggers fresh Groq call
function tapForceReanalyse(){
  if(!curSym?.s) return;
  const cached = tapAnalysisCache[curSym.s];
  if(cached) cached.aiResult = null;
  // Clear TTL cache and localStorage lock for this drawing
  const _d = _tapDrawing;
  if(_d){
    const tf = _d.tf || curTF;
    const cacheKey = curSym.s + '|' + tf;
    delete tapAiTTLCache[cacheKey];
    if(_d.id){
      try{ localStorage.removeItem('tap-lock-draw-' + _d.id); }catch(e){}
    }
    try{ localStorage.removeItem('tap-lock-' + curSym.s); }catch(e){}
  }
  toast('\u21BB Re-analysing — fresh AI request queued\u2026');
  openFullTradeAnalysis();
}

// ── AI queue UI helpers ────────────────────────────────────────────────────────
function _tapAiQueueHtml(pos, etaSec){
  const statusText = pos > 0
    ? `Position ${pos} \u2014 ready in ~${etaSec}s`
    : 'Initializing analysis\u2026';
  return `<div id="tap-ai-queue-status" style="font-family:ui-monospace,'SF Mono',monospace;font-size:11px;` +
    `color:var(--tx3);padding:6px 0 10px;letter-spacing:.3px;">${statusText}</div>` +
    `<div class="tap-skel" style="height:13px;width:92%;margin:5px 0;"></div>` +
    `<div class="tap-skel" style="height:13px;width:78%;margin:5px 0;"></div>` +
    `<div class="tap-skel" style="height:13px;width:85%;margin:5px 0;"></div>` +
    `<div class="tap-skel" style="height:13px;width:70%;margin:5px 0;"></div>`;
}

function _tapAiRenderErr(rawMsg, aiOutEl, aiLoadingEl, topScoreEl, topScoreSubEl){
  const msg = tapCompactTradeAIError(rawMsg || 'unknown error');
  aiOutEl.innerHTML =
    `<div style="color:var(--rd);font-weight:700;margin-bottom:6px;">\u26A0 AI Analysis Failed</div>` +
    `<div style="color:var(--am);font-family:ui-monospace,'SF Mono',monospace;font-size:10px;background:var(--bg3);` +
    `padding:8px 10px;border-radius:3px;border-left:3px solid var(--rd);">${msg}</div>` +
    `<div style="color:var(--tx3);font-size:11px;margin-top:8px;">Real error from Groq \u2014 use this to diagnose.</div>`;
  if(topScoreEl){ topScoreEl.textContent = '\u2014'; topScoreEl.style.color = 'var(--rd)'; }
  if(topScoreSubEl){ topScoreSubEl.textContent = 'AI failed'; topScoreSubEl.style.color = 'var(--rd)'; }
  if(aiLoadingEl) aiLoadingEl.style.display = 'none';
}

// ── Mini chart with entry/sl/tp overlaid ──────────────────────────────────────
function tapDrawChart(d){
  const canvas = document.getElementById('tap-chart-canvas');
  if(!canvas || !curData.length) return;
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;
  const W = canvas.offsetWidth || 680;
  const H = 120;
  canvas.width  = W * dpr;
  canvas.height = H * dpr;
  ctx.scale(dpr, dpr);

  // Show last 80 bars, centred on the drawing's bar
  const end   = Math.min(curData.length - 1, d.bar + 20);
  const start = Math.max(0, end - 80);
  const data  = curData.slice(start, end + 1);
  const n     = data.length;
  if(!n) return;

  const pad = { t: 8, b: 8, l: 4, r: 40 };
  const cw  = W - pad.l - pad.r;
  const ch  = H - pad.t - pad.b;

  // Price range including sl and tp
  const allPrices = data.flatMap(x => [x.high, x.low]).concat([d.price, d.sl, d.tp]);
  const minP = Math.min(...allPrices) * 0.998;
  const maxP = Math.max(...allPrices) * 1.002;
  const range = maxP - minP || 1;

  const toY = p  => pad.t + ch - ((p - minP) / range) * ch;
  const toX = i  => pad.l + (i / n) * cw;
  const bw  = Math.max(1.5, (cw / n) - 1);

  ctx.clearRect(0, 0, W, H);

  // Candles
  data.forEach((bar, i) => {
    const bull = bar.close >= bar.open;
    const x    = toX(i);
    const yO   = toY(bar.open);
    const yC   = toY(bar.close);
    const yH   = toY(bar.high);
    const yL   = toY(bar.low);
    const col  = bull ? '#00c9a0' : '#f03060';
    const bodyH = Math.max(1, Math.abs(yC - yO));
    ctx.strokeStyle = col + '66'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(x + bw/2, yH); ctx.lineTo(x + bw/2, yL); ctx.stroke();
    ctx.fillStyle = col + 'aa';
    ctx.fillRect(x, Math.min(yO, yC), bw, bodyH);
  });

  // Entry line
  const isLong = d.type === 'long';
  const entryY = toY(d.price);
  const slY    = toY(d.sl);
  const tpY    = toY(d.tp);

  // SL zone
  ctx.fillStyle = 'rgba(240,48,96,.1)';
  ctx.fillRect(pad.l, Math.min(entryY, slY), cw, Math.abs(slY - entryY));
  // TP zone
  ctx.fillStyle = isLong ? 'rgba(0,201,160,.08)' : 'rgba(240,48,96,.08)';
  ctx.fillRect(pad.l, Math.min(entryY, tpY), cw, Math.abs(tpY - entryY));

  // Lines
  const drawHLine = (y, col, dash, lw, label, labelRight) => {
    ctx.setLineDash(dash || []);
    ctx.strokeStyle = col; ctx.lineWidth = lw || 1;
    ctx.beginPath(); ctx.moveTo(pad.l, y); ctx.lineTo(pad.l + cw, y); ctx.stroke();
    ctx.setLineDash([]);
    if(label){
      ctx.fillStyle = col;
      ctx.font = 'bold 8px monospace';
      ctx.textAlign = 'left';
      ctx.fillText(label, pad.l + cw + 3, y + 3);
    }
  };
  drawHLine(tpY,    '#00c9a0', [4,3], 1.5, `TP ${fP(d.tp)}`);
  drawHLine(entryY, isLong ? '#00c9a0' : '#f03060', [], 2, `${d.type.toUpperCase()} ${fP(d.price)}`);
  drawHLine(slY,    '#f03060', [4,3], 1.5, `SL ${fP(d.sl)}`);

  // Entry arrow marker
  const entryX = toX(Math.min(n-1, Math.max(0, d.bar - start)));
  ctx.fillStyle = isLong ? '#00c9a0' : '#f03060';
  ctx.beginPath();
  if(isLong){ ctx.moveTo(entryX, entryY+10); ctx.lineTo(entryX-5, entryY+18); ctx.lineTo(entryX+5, entryY+18); }
  else       { ctx.moveTo(entryX, entryY-10); ctx.lineTo(entryX-5, entryY-18); ctx.lineTo(entryX+5, entryY-18); }
  ctx.closePath(); ctx.fill();
}

// ── Chart stats row ───────────────────────────────────────────────────────────
function tapRenderChartStats(d){
  const el = document.getElementById('tap-chart-stats');
  if(!curData.length){ el.innerHTML=''; return; }
  const n    = curData.length;
  const last = curData[n-1];
  const rsiV = calcRSI(curData);
  const rsi  = rsiV[n-1]?.toFixed(1) || '—';
  const atrV = calcATR(curData);
  const atr  = atrV[n-1] || 0;
  const atrPct = (atr / last.close * 100).toFixed(2);
  const pats = detectPatterns(curData);
  const topPat = [...pats].sort((a,b)=>b.conf-a.conf)[0];
  const sr   = detectSR(curData);
  // Filter by side of price so nearest support is always below and resistance above
  const nearS = sr.support.filter(s => s < last.close).sort((a,b) => b-a)[0];
  const nearR = sr.resistance.filter(r => r > last.close).sort((a,b) => a-b)[0];

  const stat = (lbl, val, col) =>
    `<span style="font-size:11px;font-family:ui-monospace,'SF Mono',monospace;padding:3px 9px;background:var(--bg3);border:1px solid var(--b1);border-radius:3px;color:${col||'var(--tx2)'};white-space:nowrap;">
      <span style="color:var(--tx3);">${lbl} </span>${val}
    </span>`;

  const rsiCol = parseFloat(rsi) > 70 ? 'var(--rd)' : parseFloat(rsi) < 30 ? 'var(--tl)' : 'var(--tx2)';
  el.innerHTML = [
    stat('RSI', rsi, rsiCol),
    stat('ATR%', atrPct + '%'),
    stat('Support', nearS ? fP(nearS) : '—', 'var(--tl)'),
    stat('Resistance', nearR ? fP(nearR) : '—', 'var(--rd)'),
    topPat ? stat('Pattern', topPat.name.slice(0,18), topPat.dir==='bull'?'var(--tl)':'var(--rd)') : '',
  ].join('');
}

// ── Risk assessment ───────────────────────────────────────────────────────────
function tapRenderRisk(d, rr){
  const n = curData.length;
  const rsiV = calcRSI(curData);
  const rsi  = rsiV[n-1] || 50;
  const atrV = calcATR(curData);
  const atr  = atrV[n-1] || 0;
  const slPct = Math.abs((d.sl - d.price) / d.price * 100);
  const isLong = d.type === 'long';
  const sr = detectSR(curData);

  // Build risk factors
  let riskScore = 50; // neutral start
  const factors = [];

  // R:R quality
  if(rr >= 3)       { riskScore -= 15; factors.push({ icon:'✅', text:`R:R of ${rr.toFixed(1)} is excellent — risk justified by potential reward`, col:'var(--tl)' }); }
  else if(rr >= 2)  { riskScore -= 8;  factors.push({ icon:'✅', text:`R:R of ${rr.toFixed(1)} is acceptable`, col:'var(--tl)' }); }
  else if(rr >= 1.5){ factors.push({ icon:'⚠', text:`R:R of ${rr.toFixed(1)} is marginal — consider wider target or tighter stop`, col:'var(--am)' }); }
  else              { riskScore += 20; factors.push({ icon:'🔴', text:`R:R of ${rr.toFixed(1)} is poor — reward does not justify the risk`, col:'var(--rd)' }); }

  // RSI conditions
  if(isLong && rsi > 72)  { riskScore += 12; factors.push({ icon:'⚠', text:`RSI ${rsi.toFixed(0)} — overbought territory, longs face headwinds`, col:'var(--am)' }); }
  if(!isLong && rsi < 28) { riskScore += 12; factors.push({ icon:'⚠', text:`RSI ${rsi.toFixed(0)} — oversold territory, shorts face covering pressure`, col:'var(--am)' }); }
  if(isLong && rsi < 45)  { riskScore -= 8;  factors.push({ icon:'✅', text:`RSI ${rsi.toFixed(0)} — momentum has room to run upward`, col:'var(--tl)' }); }
  if(!isLong && rsi > 55) { riskScore -= 8;  factors.push({ icon:'✅', text:`RSI ${rsi.toFixed(0)} — momentum favours downside`, col:'var(--tl)' }); }

  // SL distance vs ATR
  if(atr > 0){
    const slVsAtr = slPct / (atr / d.price * 100);
    if(slVsAtr < 0.8){ riskScore += 10; factors.push({ icon:'⚠', text:`Stop is ${slPct.toFixed(2)}% — tighter than 1 ATR, may be hit by normal volatility`, col:'var(--am)' }); }
    if(slVsAtr > 2.5){ riskScore += 8;  factors.push({ icon:'⚠', text:`Stop is ${slPct.toFixed(2)}% — wide stop increases dollar risk per trade`, col:'var(--am)' }); }
    if(slVsAtr >= 0.8 && slVsAtr <= 2){ riskScore -= 5; factors.push({ icon:'✅', text:`Stop width ${slPct.toFixed(2)}% is well-placed relative to ATR`, col:'var(--tl)' }); }
  }

  // S/R proximity
  if(isLong && sr.support.length){
    // Nearest support is the highest level BELOW entry price
    const nearS = sr.support.filter(s => s < d.price).sort((a,b) => b-a)[0];
    if(nearS){
      const distToS = Math.abs(d.price - nearS) / d.price * 100;
      if(distToS < 1.5){ riskScore -= 10; factors.push({ icon:'✅', text:`Support at ${fP(nearS)} is ${distToS.toFixed(1)}% below — natural floor for the trade`, col:'var(--tl)' }); }
    }
  }
  if(!isLong && sr.resistance.length){
    // Nearest resistance is the lowest level ABOVE entry price
    const nearR = sr.resistance.filter(r => r > d.price).sort((a,b) => a-b)[0];
    if(nearR){
      const distToR = Math.abs(nearR - d.price) / d.price * 100;
      if(distToR < 1.5){ riskScore -= 10; factors.push({ icon:'✅', text:`Resistance at ${fP(nearR)} is ${distToR.toFixed(1)}% above — natural ceiling confirms short`, col:'var(--tl)' }); }
    }
  }

  riskScore = Math.max(10, Math.min(90, riskScore));
  const riskLabel = riskScore <= 30 ? 'LOW RISK' : riskScore <= 55 ? 'MODERATE' : 'HIGH RISK';
  const riskCol   = riskScore <= 30 ? '#00c9a0'  : riskScore <= 55 ? '#f0a500'  : '#f03060';

  document.getElementById('tap-risk-bar-fill').style.width      = riskScore + '%';
  document.getElementById('tap-risk-bar-fill').style.background = riskCol;
  document.getElementById('tap-risk-label').textContent         = riskLabel;
  document.getElementById('tap-risk-label').style.color         = riskCol;
  document.getElementById('tap-risk-factors').innerHTML         = factors.map(f =>
    `<div style="display:flex;gap:7px;align-items:flex-start;margin-bottom:4px;">
      <span>${f.icon}</span>
      <span style="color:${f.col};font-size:10px;line-height:1.5;">${f.text}</span>
    </div>`
  ).join('');
}

// ── Historical similar setups ─────────────────────────────────────────────────
function tapBuildFallbackAnalysis(d, rr, tradeStatus=''){
  const n = curData.length;
  const isLong = d.type === 'long';
  const rsiV = calcRSI(curData);
  const rsi = rsiV[n-1] || 50;
  const atrV = calcATR(curData);
  const atr = atrV[n-1] || 0;
  const slPct = Math.abs((d.sl - d.price) / d.price * 100);
  const sr = detectSR(curData);

  let entryQuality = 13;
  let stopPlacement = 13;
  let riskRewardLogic = 12;
  let technicalConfluence = 12;
  const weaknesses = [];
  const improvements = [];

  // Risk/Reward Logic (max 23) — continuous based on actual ratio
  if(rr >= 3)      riskRewardLogic = Math.round(19 + Math.min(4, (rr - 3) * 2));   // 19-23
  else if(rr >= 2) riskRewardLogic = Math.round(14 + (rr - 2) * 5);                // 14-19
  else if(rr >= 1.5) riskRewardLogic = Math.round(9 + (rr - 1.5) * 10);            // 9-14
  else {
    riskRewardLogic = Math.round(Math.max(3, rr * 6));                              // 0-9
    weaknesses.push(`Reward-to-risk is only ${rr.toFixed(2)}:1, which weakens the trade payoff.`);
    improvements.push('Improve the setup by tightening the stop behind cleaner structure or waiting for a better entry.');
  }

  // Stop Placement (max 26) — continuous based on ATR ratio
  if(atr > 0){
    const atrPct = (atr / d.price) * 100;
    const slVsAtr = slPct / Math.max(atrPct, 0.0001);
    if(slVsAtr >= 0.8 && slVsAtr <= 2.2){
      // Ideal range: score based on how close to the sweet spot (1.5x ATR)
      const ideal = 1.5;
      const deviation = Math.abs(slVsAtr - ideal) / ideal;
      stopPlacement = Math.round(22 - deviation * 10); // 16-22 within range
    } else if(slVsAtr < 0.8){
      stopPlacement = Math.round(Math.max(6, slVsAtr * 14)); // 0-11
      weaknesses.push('Stop is tighter than normal volatility and may be clipped by noise.');
      improvements.push('Place the stop slightly beyond the recent swing so normal ATR movement does not stop it out early.');
    } else {
      stopPlacement = Math.round(Math.max(7, 13 - (slVsAtr - 2.2) * 2)); // 7-13 for wide stops
      weaknesses.push('Stop is wider than needed, which makes the trade less efficient.');
      improvements.push('Reduce stop width by entering closer to structure if the setup still holds.');
    }
  }

  if(isLong){
    if(rsi < 45) technicalConfluence += 4;
    else if(rsi > 72){
      technicalConfluence -= 4;
      weaknesses.push(`RSI is ${rsi.toFixed(0)}, so the long is pushing into overbought conditions.`);
    }
  } else {
    if(rsi > 55) technicalConfluence += 4;
    else if(rsi < 28){
      technicalConfluence -= 4;
      weaknesses.push(`RSI is ${rsi.toFixed(0)}, so the short is pushing into oversold conditions.`);
    }
  }

  const nearestSupport = sr.support.filter(s => s < d.price).sort((a,b)=>b-a)[0] || null;
  const nearestResistance = sr.resistance.filter(r => r > d.price).sort((a,b)=>a-b)[0] || null;
  if(isLong && nearestSupport){
    const dist = Math.abs(d.price - nearestSupport) / d.price * 100;
    if(dist < 1.5){
      entryQuality += 4;
      technicalConfluence += 3;
    } else if(dist > 4){
      entryQuality -= 3;
      weaknesses.push('Entry is not sitting close to a clear nearby support level.');
    }
  }
  if(!isLong && nearestResistance){
    const dist = Math.abs(nearestResistance - d.price) / d.price * 100;
    if(dist < 1.5){
      entryQuality += 4;
      technicalConfluence += 3;
    } else if(dist > 4){
      entryQuality -= 3;
      weaknesses.push('Entry is not sitting close to a clear nearby resistance level.');
    }
  }

  const statusUpper = String(tradeStatus || '').toUpperCase();
  if(statusUpper.includes('UNREALISTIC')){
    entryQuality = Math.max(4, entryQuality - 8);
    technicalConfluence = Math.max(4, technicalConfluence - 6);
    weaknesses.push('The placement looks unrealistic relative to where price has actually traded.');
  }
  if(statusUpper.includes('SL HIT')){
    technicalConfluence = Math.max(3, technicalConfluence - 5);
  }
  if(statusUpper.includes('TP HIT')){
    technicalConfluence = Math.min(23, technicalConfluence + 4);
    entryQuality = Math.min(28, entryQuality + 3);
  }

  entryQuality = Math.max(3, Math.min(28, Math.round(entryQuality)));
  stopPlacement = Math.max(3, Math.min(26, Math.round(stopPlacement)));
  riskRewardLogic = Math.max(3, Math.min(23, Math.round(riskRewardLogic)));
  technicalConfluence = Math.max(3, Math.min(23, Math.round(technicalConfluence)));

  const combined = Math.max(0, Math.min(100, entryQuality + stopPlacement + riskRewardLogic + technicalConfluence));
  const probability = Math.max(5, Math.min(95, Math.round(combined * 0.9)));
  const verdict =
    combined >= 75 ? 'Strong Setup' :
    combined >= 55 ? 'Acceptable Setup' :
    combined >= 35 ? 'Risky Setup' :
    'Avoid Trade';

  const weaknessText = (weaknesses.length ? weaknesses : ['AI analysis was unavailable, so this score uses chart-based fallback logic.']).slice(0,3).join(' ');
  const improvementText = (improvements.length ? improvements : ['Use the structure, ATR, and nearest levels to refine the entry if you want a stronger score.']).slice(0,2).join(' ');

  return `AI fallback analysis used because the live AI request did not return successfully.

6. TRADE QUALITY SCORE
Entry Quality: ${entryQuality}/28
Stop Placement: ${stopPlacement}/26
Risk/Reward Logic: ${riskRewardLogic}/23
Technical Confluence: ${technicalConfluence}/23
Combined Score: ${combined}/100

7. CRITICAL WEAKNESSES
${weaknessText}

8. SUGGESTED IMPROVEMENTS
${improvementText}

9. PROBABILITY ESTIMATE
${probability}% probability based on reward-to-risk, ATR stop fit, RSI context, and nearby structure.

10. FINAL VERDICT
${verdict}

SCORECARD_JSON: {"entry_quality":${entryQuality},"stop_placement":${stopPlacement},"risk_reward_logic":${riskRewardLogic},"technical_confluence":${technicalConfluence},"combined_score":${combined},"probability":${probability},"verdict":"${verdict}"}`;
}

function tapRenderHistorical(d){
  const el = document.getElementById('tap-hist-items');
  const countEl = document.getElementById('tap-hist-count');
  if(!curData.length){ el.innerHTML = '<div style="font-size:11px;color:var(--tx2);">No chart data available.</div>'; return; }

  const isLong   = d.type === 'long';
  const n        = curData.length;
  const atrV     = calcATR(curData);   // ATR array — one value per bar
  const rsiV     = calcRSI(curData);
  const entryBar = Math.min(d.bar, n - 1);
  const currentRsi = rsiV[entryBar] || 50;
  const matches  = [];

  // Spread the scan across the full bar history, spacing matches at least 15 bars apart
  let lastMatchBar = -999;
  for(let i = 20; i < entryBar - 10; i++){
    const barRsi = rsiV[i];
    if(!barRsi) continue;
    if(i - lastMatchBar < 15) continue;   // enforce spacing so we don't cluster

    // RSI similarity window — ±20 of current RSI
    if(Math.abs(barRsi - currentRsi) >= 20) continue;

    // Use typical price (h+l+c)/3 for momentum bias — respects wick direction
    const tp   = (curData[i].high + curData[i].low + curData[i].close) / 3;
    const tp5  = curData[i-5] ? (curData[i-5].high + curData[i-5].low + curData[i-5].close) / 3 : tp;
    const localBias = tp > tp5 ? 'bull' : 'bear';
    if(isLong && localBias !== 'bull') continue;
    if(!isLong && localBias !== 'bear') continue;

    const fwdBars = Math.min(25, n - 1 - i);
    if(fwdBars < 8) continue;

    // Entry = typical price of the match bar; exit = typical price of the forward bar
    const entryP  = tp;
    const exitBar = curData[i + fwdBars];
    const futureP = (exitBar.high + exitBar.low + exitBar.close) / 3;
    const movePct = (futureP - entryP) / entryP * 100;

    // Use ATR at bar i (not current ATR) for a realistic SL distance at that time
    const atrAtI  = atrV[i] || entryP * 0.015;
    const slDist  = atrAtI * 1.5;

    const slice   = curData.slice(i, i + fwdBars);
    const hitSl   = isLong
      ? Math.min(...slice.map(b => b.low))  < entryP - slDist
      : Math.max(...slice.map(b => b.high)) > entryP + slDist;

    // Max favourable excursion — how far did price move our way before reversing?
    const mfe = isLong
      ? Math.max(...slice.map(b => b.high)) - entryP
      : entryP - Math.min(...slice.map(b => b.low));

    // A "winner" = moved at least 1.5× SL distance in our favour without hitting SL
    const success = !hitSl && mfe >= slDist * 1.5;

    matches.push({
      barIdx: i, fwdBars,
      date:     new Date(curData[i].time * 1000).toLocaleDateString([], {month:'short', day:'numeric', year:'numeric'}),
      entryP, futureP, movePct, success, hitSl,
      mfePct:   (mfe / entryP * 100).toFixed(2),
      barRsi:   barRsi.toFixed(0),
      ctxStart: Math.max(0, i - 15),
      ctxEnd:   Math.min(n - 1, i + fwdBars),
    });

    lastMatchBar = i;
    if(matches.length >= 6) break;
  }

  countEl.textContent = `${matches.length} similar setups found`;
  if(!matches.length){
    el.innerHTML = `<div style="font-size:10px;color:var(--tx3);">Not enough historical data — try a longer timeframe (Daily/Weekly) for more bar history.</div>`;
    return;
  }

  const wins    = matches.filter(m => m.success).length;
  const slHits  = matches.filter(m => m.hitSl).length;
  const winRate = Math.round(wins / matches.length * 100);
  const rrColor = winRate >= 60 ? 'var(--tl)' : winRate >= 40 ? 'var(--am)' : 'var(--rd)';

  el.innerHTML = `
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;padding:9px 12px;
      background:var(--bg3);border-radius:5px;border-left:3px solid ${rrColor};">
      <div style="font-size:18px;font-weight:600;font-family:ui-monospace,'SF Mono',monospace;color:${rrColor};">${winRate}%</div>
      <div style="font-size:11px;color:var(--tx2);line-height:1.6;">Historical win rate on similar conditions<br>
        <span style="color:var(--tx3);">${wins} winners · ${slHits} SL hits · ${matches.length - wins - slHits} inconclusive · ${matches.length} total</span>
      </div>
    </div>
    <div id="tap-hist-list"></div>`;

  const listEl = document.getElementById('tap-hist-list');
  listEl.innerHTML = matches.map((m, idx) => {
    const outcomeClass = m.hitSl ? 'loss' : m.success ? 'win' : 'open';
    const outcomeLabel = m.hitSl ? 'SL Hit' : m.success ? 'Winner' : 'Partial';
    const moveCol = m.movePct >= 0 ? 'var(--tl)' : 'var(--rd)';
    return `
    <div class="tap-hist-item" style="flex-direction:column;gap:0;padding:10px 0;">
      <div style="display:flex;align-items:center;gap:8px;width:100%;">
        <div class="tap-hist-num">${idx+1}</div>
        <div class="tap-hist-body">
          <div class="tap-hist-title">${m.date} · Entry ~${fP(m.entryP)} · RSI ${m.barRsi}</div>
          <div class="tap-hist-detail">
            ${m.fwdBars}-bar result: <span style="color:${moveCol};font-weight:700;">${m.movePct>=0?'+':''}${m.movePct.toFixed(2)}%</span>
            · MFE: +${m.mfePct}%
            · ${m.hitSl ? '<span style="color:var(--rd);">Stop hit</span>' : 'Stop intact'}
          </div>
        </div>
        <span class="tap-hist-outcome ${outcomeClass}">${outcomeLabel}</span>
        <button onclick="tapJumpToBar(${m.barIdx})" title="Jump to this bar on the chart"
          style="padding:3px 10px;font-size:11px;font-family:ui-monospace,'SF Mono',monospace;font-weight:700;
          background:rgba(61,127,255,.1);border:1px solid rgba(61,127,255,.35);color:var(--bl);
          border-radius:3px;cursor:pointer;white-space:nowrap;flex-shrink:0;transition:all .13s;"
          onmouseover="this.style.background='rgba(61,127,255,.22)'"
          onmouseout="this.style.background='rgba(61,127,255,.1)'">
          📈 View on Chart
        </button>
      </div>
      <div style="margin-top:7px;margin-left:28px;background:var(--bg);border:1px solid var(--b1);border-radius:3px;overflow:hidden;">
        <canvas id="tap-hist-spark-${idx}" height="48" style="display:block;width:100%;"></canvas>
      </div>
    </div>`;
  }).join('');

  requestAnimationFrame(() => {
    matches.forEach((m, idx) => tapDrawHistSparkline(idx, m, isLong));
  });
}

// ── Draw a mini sparkline for a historical match ──────────────────────────────
function tapDrawHistSparkline(idx, m, isLong){
  const canvas = document.getElementById(`tap-hist-spark-${idx}`);
  if(!canvas) return;
  const ctx = canvas.getContext('2d');
  const dpr = window.devicePixelRatio || 1;
  const W   = canvas.offsetWidth || 600;
  const H   = 48;
  canvas.width  = W * dpr;
  canvas.height = H * dpr;
  ctx.scale(dpr, dpr);

  const slice = curData.slice(m.ctxStart, m.ctxEnd + 1);
  if(!slice.length) return;
  const n = slice.length;

  const highs = slice.map(b=>b.high), lows = slice.map(b=>b.low);
  const minP = Math.min(...lows) * 0.999;
  const maxP = Math.max(...highs) * 1.001;
  const range = maxP - minP || 1;
  const pad = { t:4, b:4, l:2, r:2 };
  const cw = W - pad.l - pad.r, ch = H - pad.t - pad.b;
  const bw = Math.max(1, cw / n - 0.5);

  const toY = p => pad.t + ch - ((p - minP) / range) * ch;
  const toX = i => pad.l + (i / n) * cw;

  ctx.clearRect(0, 0, W, H);

  // Entry bar position within the slice
  const entryIdx = m.barIdx - m.ctxStart;
  const fwdEnd   = entryIdx + m.fwdBars;

  // Shade the forward period
  const shadeCol = m.success && !m.hitSl ? 'rgba(0,201,160,.06)' : 'rgba(240,48,96,.06)';
  if(entryIdx >= 0 && entryIdx < n){
    const x1 = toX(entryIdx), x2 = toX(Math.min(fwdEnd, n-1));
    ctx.fillStyle = shadeCol;
    ctx.fillRect(x1, pad.t, x2 - x1, ch);
  }

  // Candles
  slice.forEach((bar, i) => {
    const bull = bar.close >= bar.open;
    const x = toX(i);
    const col = bull ? '#00c9a0' : '#f03060';
    ctx.strokeStyle = col + '55'; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(x+bw/2, toY(bar.high)); ctx.lineTo(x+bw/2, toY(bar.low)); ctx.stroke();
    ctx.fillStyle = col + '99';
    ctx.fillRect(x, Math.min(toY(bar.open), toY(bar.close)), Math.max(bw,1.5), Math.max(1, Math.abs(toY(bar.close)-toY(bar.open))));
  });

  // Entry price line
  const entryY = toY(m.entryP);
  ctx.setLineDash([3,3]);
  ctx.strokeStyle = isLong ? '#00c9a0aa' : '#f03060aa';
  ctx.lineWidth = 1;
  ctx.beginPath(); ctx.moveTo(pad.l, entryY); ctx.lineTo(pad.l+cw, entryY); ctx.stroke();
  ctx.setLineDash([]);

  // Entry marker (vertical line at entry bar)
  if(entryIdx >= 0 && entryIdx < n){
    const ex = toX(entryIdx) + bw/2;
    ctx.strokeStyle = isLong ? '#00c9a0cc' : '#f03060cc';
    ctx.lineWidth = 1.5;
    ctx.beginPath(); ctx.moveTo(ex, pad.t); ctx.lineTo(ex, pad.t+ch); ctx.stroke();
  }

  // Date labels
  ctx.fillStyle = 'rgba(255,255,255,0.3)';
  ctx.font = '7px monospace';
  ctx.textAlign = 'left';
  ctx.fillText(new Date(slice[0].time*1000).toLocaleDateString([],{month:'short',day:'numeric'}), pad.l+2, H-2);
  ctx.textAlign = 'right';
  ctx.fillText(new Date(slice[slice.length-1].time*1000).toLocaleDateString([],{month:'short',day:'numeric'}), pad.l+cw-2, H-2);
}

// ── Jump to a historical bar on the main chart ────────────────────────────────
function tapJumpToBar(barIdx){
  // Close the modal and navigate the chart to that bar
  closeTapModal();
  // Scroll the chart so this bar is visible — set rightBarIndex to show it centered
  const visibleBars = Math.floor((_drawW || 800) / (barWidth + 1));
  rightBarIndex = barIdx + Math.floor(visibleBars * 0.6);
  rightBarIndex = Math.max(visibleBars, Math.min(curData.length - 1, rightBarIndex));
  draw();
  toast(`📈 Jumped to ${new Date(curData[barIdx].time*1000).toLocaleDateString([],{month:'short',day:'numeric',year:'numeric'})}`);
}

// ── Journal history for this symbol ──────────────────────────────────────────
function tapRenderJournalHistory(){
  const el  = document.getElementById('tap-journal-history');
  const sym = curSym.s;
  const trades = journal.filter(j => j.sym === sym && j.outcome).slice(-8).reverse();
  if(!trades.length){
    el.innerHTML = `<div style="font-size:10px;color:var(--tx3);">No completed trades in journal for ${sym}.</div>`;
    return;
  }
  const wins    = trades.filter(t=>t.outcome==='win').length;
  const winRate = Math.round(wins/trades.length*100);
  el.innerHTML = `
    <div style="font-size:10px;color:var(--tx2);margin-bottom:8px;">
      Your personal record on ${sym}: <strong style="color:${winRate>=60?'var(--tl)':winRate>=40?'var(--am)':'var(--rd)'};">${winRate}% win rate</strong> over ${trades.length} logged trades
    </div>
    ${trades.map(t => {
      const col = t.outcome==='win'?'var(--tl)':'var(--rd)';
      return `<div style="display:flex;align-items:center;gap:8px;padding:5px 0;border-bottom:1px solid rgba(255,255,255,.04);font-size:11px;">
        <span style="font-family:ui-monospace,'SF Mono',monospace;color:var(--tx3);width:70px;">${t.time ? new Date(t.time).toLocaleDateString([],{month:'short',day:'numeric'}) : '—'}</span>
        <span style="font-family:ui-monospace,'SF Mono',monospace;color:${t.dir==='long'?'var(--tl)':'var(--rd)'};">${t.dir?.toUpperCase()}</span>
        <span style="flex:1;color:var(--tx2);">${t.setup || '—'}</span>
        <span style="font-family:ui-monospace,'SF Mono',monospace;color:${col};">${t.pl != null ? (t.pl >= 0 ? '+' : '') + t.pl.toFixed(2) : t.outcome}</span>
      </div>`;
    }).join('')}`;
}

// ── AI narrative — dedicated fetch with higher token budget ───────────────────
function tapRenderVerdictBanner(text){
  const banner   = document.getElementById('tap-verdict-banner');
  const lbl      = document.getElementById('tap-verdict-label');
  const scoreEl  = document.getElementById('tap-verdict-score');
  const subEl    = document.getElementById('tap-verdict-sub');
  const probEl   = document.getElementById('tap-verdict-prob');
  const barEl    = document.getElementById('tap-verdict-bar');
  const topScoreEl = document.getElementById('tap-l-ai-score');
  const topScoreSubEl = document.getElementById('tap-l-ai-score-sub');
  if(!banner) return;

  const structured = tapParseStructuredAnalysis(text);

  // Only search verdict keywords in the FINAL VERDICT section at the end of the response
  // Prevents false positives from status words like "INVALID Placement" at the top
  const verdictIdx = text.toUpperCase().lastIndexOf('FINAL VERDICT');
  const searchZone = verdictIdx >= 0 ? text.slice(verdictIdx) : text.slice(-400);
  const zone = searchZone.toUpperCase();

  // Extract actual combined score from Trade Quality Scoring section
  const scoringIdx = Math.max(
    text.toUpperCase().indexOf('TRADE QUALITY SCORING'),
    text.toUpperCase().indexOf('TRADE QUALITY SCORE')
  );
  const scoringZone = scoringIdx >= 0 ? text.slice(scoringIdx, scoringIdx+600) : '';
  const scoreRaw = scoringZone.match(/combined\s*score[^0-9]{0,30}(\d{1,3})(?:\s*\/\s*100)?/i)
                || scoringZone.match(/(\d{1,3})\s*\/\s*100/);
  const parsedScore = structured?.combined_score ?? (scoreRaw ? Math.min(100, Math.max(0, parseInt(scoreRaw[1]))) : null);
  const scoreSource = structured ? 'Structured AI score' : (parsedScore !== null ? 'Parsed from AI analysis' : 'Verdict fallback');

  let verdict='', verdictColor='#8899b0', bg='rgba(136,153,176,0.08)', border='rgba(136,153,176,0.2)';
  let scoreVal = parsedScore, likelihood='', barPct=50;
  const structuredVerdict = String(structured?.verdict || '').toUpperCase();

  if(structuredVerdict.includes('STRONG SETUP') || zone.includes('STRONG SETUP')){
    verdict='STRONG SETUP'; verdictColor='#00d4a0'; bg='rgba(0,212,160,0.1)'; border='rgba(0,212,160,0.35)';
    scoreVal = scoreVal ?? 88; likelihood='High likelihood of success'; barPct=scoreVal;
  } else if(structuredVerdict.includes('ACCEPTABLE SETUP') || structuredVerdict === 'ACCEPTABLE' || zone.includes('ACCEPTABLE SETUP') || zone.includes('ACCEPTABLE')){
    verdict='ACCEPTABLE SETUP'; verdictColor='#3d8eff'; bg='rgba(61,142,255,0.1)'; border='rgba(61,142,255,0.35)';
    scoreVal = scoreVal ?? 68; likelihood='Moderate likelihood of success'; barPct=scoreVal;
  } else if(structuredVerdict.includes('RISKY SETUP') || structuredVerdict === 'RISKY' || zone.includes('RISKY SETUP') || zone.includes('RISKY')){
    verdict='RISKY SETUP'; verdictColor='#f5a623'; bg='rgba(245,166,35,0.1)'; border='rgba(245,166,35,0.35)';
    scoreVal = scoreVal ?? 42; likelihood='Lower likelihood — proceed with caution'; barPct=scoreVal;
  } else if(structuredVerdict.includes('AVOID TRADE') || structuredVerdict === 'AVOID' || zone.includes('AVOID TRADE') || zone.includes('AVOID')){
    verdict='AVOID TRADE'; verdictColor='#ff4d6a'; bg='rgba(255,77,106,0.1)'; border='rgba(255,77,106,0.35)';
    scoreVal = scoreVal ?? 18; likelihood='Do not trade this setup'; barPct=scoreVal;
  } else if(zone.includes('A+ SETUP')){
    verdict='A+ SETUP'; verdictColor='#00d4a0'; bg='rgba(0,212,160,0.1)'; border='rgba(0,212,160,0.35)';
    scoreVal = scoreVal ?? 95; likelihood='Excellent — high likelihood of success'; barPct=scoreVal;
  } else if(zone.includes('A SETUP')){
    verdict='A SETUP'; verdictColor='#00d4a0'; bg='rgba(0,212,160,0.1)'; border='rgba(0,212,160,0.35)';
    scoreVal = scoreVal ?? 80; likelihood='Strong — good likelihood of success'; barPct=scoreVal;
  } else if(zone.includes('B SETUP')){
    verdict='B SETUP'; verdictColor='#f5a623'; bg='rgba(245,166,35,0.1)'; border='rgba(245,166,35,0.35)';
    scoreVal = scoreVal ?? 60; likelihood='Moderate — proceed with caution'; barPct=scoreVal;
  } else if(zone.includes('C SETUP')){
    verdict='C SETUP'; verdictColor='#ff4d6a'; bg='rgba(255,77,106,0.1)'; border='rgba(255,77,106,0.35)';
    scoreVal = scoreVal ?? 35; likelihood='Weak — high risk of failure'; barPct=scoreVal;
  } else if(zone.includes('INVALID SETUP')){
    verdict='INVALID SETUP'; verdictColor='#ff4d6a'; bg='rgba(255,77,106,0.1)'; border='rgba(255,77,106,0.35)';
    scoreVal = scoreVal ?? 5; likelihood='Setup is invalid — do not trade'; barPct=scoreVal;
  }

  if(!verdict){
    // No verdict keyword found — show score-only state in banner
    if(parsedScore !== null){
      banner.style.background  = 'rgba(136,153,176,0.06)';
      banner.style.borderColor = 'rgba(136,153,176,0.2)';
      scoreEl.textContent      = String(parsedScore);
      scoreEl.style.color      = 'var(--tx)';
      lbl.textContent          = 'ANALYSIS COMPLETE';
      lbl.style.color          = 'var(--tx2)';
      subEl.textContent        = scoreSource;
      subEl.style.color        = 'var(--tx3)';
      barEl.style.background   = 'var(--tx3)';
      setTimeout(() => { barEl.style.width = parsedScore + '%'; }, 60);
    }
    return;
  }

  const probMatch = text.match(/(\d{1,3})\s*%\s*(?:chance|probability|likelihood)/i);
  const probPct = structured?.probability ?? (probMatch ? parseInt(probMatch[1]) : null);
  barPct = Math.min(100, Math.max(0, barPct ?? 50));

  banner.style.background  = bg;
  banner.style.borderColor = border;
  lbl.textContent          = verdict;
  lbl.style.color          = verdictColor;
  scoreEl.textContent      = scoreVal !== null ? String(scoreVal) : '—';
  scoreEl.style.color      = verdictColor;
  subEl.textContent        = likelihood;
  subEl.style.color        = verdictColor;
  probEl.textContent       = probPct ? `${probPct}% probability of success · ${scoreSource}` : `See full analysis below · ${scoreSource}`;
  probEl.style.color       = verdictColor;
  barEl.style.background   = verdictColor;
  if(topScoreEl){
    topScoreEl.textContent = scoreVal !== null ? `${scoreVal}/100` : '—';
    topScoreEl.style.color = verdictColor;
  }
  if(topScoreSubEl){
    topScoreSubEl.textContent = verdict || scoreSource;
    topScoreSubEl.style.color = verdictColor;
  }
  setTimeout(() => { barEl.style.width = barPct + '%'; }, 60);
}

// ══════════════════════════════════════════════════════════════════════════════
// ── TAP RAG (Retrieval-Augmented Generation) — Self-Learning Analysis Engine ─
// ══════════════════════════════════════════════════════════════════════════════
// How it works:
//   1. Extract a 12-dim normalised feature vector from the current trade setup
//   2. Search local history + Supabase for past analyses with similar vectors
//   3. Tier 1 (≥0.93 similarity, non-failed): return stored analysis → FREE
//   4. Tier 2 (≥0.75 similarity): inject as few-shot context → ~40% cheaper
//   5. Tier 3 (<0.75): full Groq call → standard cost
//   6. After every Groq call, store analysis + feature vector for future reuse
//   7. When SL/TP is hit, record outcome → system learns what worked

// ── Feature vector extraction ─────────────────────────────────────────────────
// Returns [rsi_norm, trend_bull, direction, rr_norm, sl_atr_norm, pat_conf,
//          pat_aligns, sr_prox, vol_ratio_norm, macd_bull, macd_str, rsi_bull]
function tapExtractFeatureVector(d, analysisData) {
  try {
    const n = analysisData.length;
    if (n < 20) return null;
    const isLong = d.type === 'long';
    const rsiV   = calcRSI(analysisData);
    const rsi    = rsiV[n-1] ?? 50;
    const sma20V = calcSMA(analysisData, 20);
    const sma50V = calcSMA(analysisData, 50);
    const atrV   = calcATR(analysisData);
    const atr    = atrV[n-1] || 0.0001;
    const macdV  = calcMACD(analysisData);
    const lastMACD = macdV[n-1];
    const pats   = detectPatterns(analysisData);
    const sr     = detectSR(analysisData);
    const lastBar = analysisData[n-1];
    const sma20val = sma20V[n-1] || 0;
    const sma50val = sma50V[n-1] || 0;
    const rr     = Math.abs(d.tp - d.price) / Math.abs(d.sl - d.price);
    const slAtr  = Math.abs(d.price - d.sl) / atr;
    const topPat = pats.sort((a,b) => b.conf - a.conf)[0];
    const patConf   = topPat ? topPat.conf : 0;
    const patDir    = topPat ? (topPat.dir === 'bullish' ? 1 : topPat.dir === 'bearish' ? -1 : 0) : 0;
    const patAligns = topPat ? (((isLong && patDir > 0) || (!isLong && patDir < 0)) ? 1 : (patDir === 0 ? 0.5 : 0)) : 0.5;
    const allSRVals = [...(sr.support || []), ...(sr.resistance || [])];
    const nearestSRDist = allSRVals.length > 0
      ? Math.min(...allSRVals.map(v => Math.abs(v - d.price)))
      : atr * 3;
    const srProx = 1 - Math.min(nearestSRDist / (atr * 2), 1);
    const recentBars = analysisData.slice(-20);
    const avgVol = recentBars.reduce((s,b) => s + (b.volume || 0), 0) / recentBars.length;
    const volRatio = avgVol > 0 ? (lastBar.volume || 0) / avgVol : 1;
    const macdHist = lastMACD?.hist || 0;
    return [
      rsi / 100,                                                             // 0: rsi_norm
      (sma20val > 0 && sma50val > 0) ? (sma20val > sma50val ? 1 : 0) : 0.5,// 1: trend_bull
      isLong ? 1 : 0,                                                        // 2: direction
      Math.min(rr / 4, 1),                                                   // 3: rr_norm
      Math.min(slAtr / 3, 1),                                                // 4: sl_atr_norm
      Math.max(0, Math.min(1, patConf)),                                     // 5: pat_conf
      patAligns,                                                             // 6: pat_aligns
      Math.max(0, Math.min(1, srProx)),                                      // 7: sr_prox
      Math.min(volRatio / 3, 1),                                             // 8: vol_ratio_norm
      macdHist > 0 ? 1 : 0,                                                 // 9: macd_bull
      atr > 0 ? Math.min(Math.abs(macdHist) / atr, 1) : 0,                  // 10: macd_str
      rsi > 50 ? 1 : 0,                                                      // 11: rsi_bull
    ];
  } catch(e) { return null; }
}

// ── Cosine similarity between two equal-length vectors ────────────────────────
function tapCosineSimilarity(v1, v2) {
  if (!v1 || !v2 || v1.length !== v2.length) return 0;
  let dot = 0, mag1 = 0, mag2 = 0;
  for (let i = 0; i < v1.length; i++) {
    dot  += v1[i] * v2[i];
    mag1 += v1[i] * v1[i];
    mag2 += v2[i] * v2[i];
  }
  const denom = Math.sqrt(mag1) * Math.sqrt(mag2);
  return denom > 0 ? dot / denom : 0;
}

// ── Local analysis history (localStorage) ────────────────────────────────────
function tapGetLocalAnalysisHistory() {
  try { return JSON.parse(_lsGet('apex-analyses') || '[]'); } catch(e) { return []; }
}
function tapSetLocalAnalysisHistory(arr) {
  try { _lsSet('apex-analyses', JSON.stringify(arr.slice(0, 120))); } catch(e) {}
}

// ── Normalise symbol to the format used in the historical scan database ───────
// App uses 'BTC/USD', scan saved 'BTC-USD' — normalise before any DB query
function _tapNormSym(sym) {
  return (sym || '').replace('/', '-');
}

// ── Cross-timeframe similarity weight ─────────────────────────────────────────
// Short TFs (1m/5m) have thin history so we cast a wider cross-TF net.
// Same-TF matches are always preferred; cross-TF matches are slightly discounted.
function _tapTFSimilarityWeight(currentTF, rowTF) {
  if (!rowTF || rowTF === currentTF) return 1.0;
  const shortTFs = ['1m', '5m'];
  const midTFs   = ['15m', '30m'];
  const longTFs  = ['1h', '4h', '1d'];
  const bucket = tf => shortTFs.includes(tf) ? 0 : midTFs.includes(tf) ? 1 : 2;
  const dist = Math.abs(bucket(currentTF) - bucket(rowTF));
  // 1 bucket away (e.g. 5m↔15m): 0.95×   2 buckets away (e.g. 1m↔1h): 0.88×
  return dist === 0 ? 1.0 : dist === 1 ? 0.95 : 0.88;
}

// ── Search for similar past analyses ─────────────────────────────────────────
// Pulls from:  1) localStorage (your own recent analyses)
//              2) Supabase — your personal analyses (cross-device)
//              3) Supabase — historical scan data (user_id = 'anonymous')
// Cross-timeframe matches are included but slightly down-weighted so same-TF
// matches are always preferred when available.
async function tapSearchSimilarAnalyses(featureVec, symbol, currentTF) {
  if (!featureVec) return [];
  const tf = currentTF || curTF;

  // 1. Local history
  const local = tapGetLocalAnalysisHistory();
  let candidates = local.filter(a =>
    Array.isArray(a.feature_vector) && a.feature_vector.length === featureVec.length
  );

  // 2 + 3. Supabase: your analyses AND historical scan data (anonymous)
  if (_supa) {
    try {
      // Fetch both in parallel — your personal data + the historical library
      const _sel = 'id,feature_vector,analysis_text,verdict,combined_score,direction,outcome,verdict_correct,created_at,timeframe,method_detected,entry_price,sl_price,tp_price';
      const [personalRes, historicalRes] = await Promise.all([
        _currentUserId
          ? _supa.from('apex_analyses')
              .select(_sel)
              .eq('user_id', _currentUserId)
              .order('created_at', { ascending: false })
              .limit(80)
          : { data: [] },
        _supa.from('apex_analyses')
          .select(_sel)
          .eq('user_id', 'anonymous')
          .eq('symbol', _tapNormSym(symbol)) // historical data filtered to same symbol
          .order('created_at', { ascending: false })
          .limit(200),
      ]);

      const localIds = new Set(candidates.map(a => a.id));
      const remoteRows = [
        ...(personalRes.data   || []),
        ...(historicalRes.data || []),
      ].filter(r =>
        !localIds.has(r.id) &&
        Array.isArray(r.feature_vector) &&
        r.feature_vector.length === featureVec.length
      );
      candidates = [...candidates, ...remoteRows];
    } catch(e) { /* Supabase unavailable — use local only */ }
  }

  // Score with cross-TF weight applied
  return candidates
    .map(a => ({
      ...a,
      similarity: tapCosineSimilarity(featureVec, a.feature_vector)
                  * _tapTFSimilarityWeight(tf, a.timeframe),
    }))
    .sort((a, b) => b.similarity - a.similarity)
    .slice(0, 5);
}

// ── Store a completed analysis for future RAG reuse ───────────────────────────
async function tapStoreAnalysis(d, featureVec, analysisText, scorecard, symbol, tf, methodDetected) {
  if (!featureVec || !analysisText) return null;
  const id = 'apex-' + Date.now() + '-' + Math.random().toString(36).slice(2, 8);
  const record = {
    id,
    user_id: _currentUserId || 'anonymous',
    symbol:  symbol  || curSym?.s || 'unknown',
    timeframe: tf    || curTF    || '1d',
    direction: d.type,
    feature_vector:  featureVec,
    analysis_text:   analysisText,
    scorecard:       scorecard || null,
    verdict:         scorecard?.verdict || null,
    combined_score:  scorecard?.combined_score ?? null,
    probability:     scorecard?.probability ?? null,
    method_detected: methodDetected || null,
    entry_price:     d.price,
    sl_price:        d.sl,
    tp_price:        d.tp,
    outcome:         'pending',
    verdict_correct: null,
    outcome_at:      null,
    created_at:      new Date().toISOString(),
  };

  // Always persist locally
  const history = tapGetLocalAnalysisHistory();
  history.unshift(record);
  tapSetLocalAnalysisHistory(history);

  // Sync to Supabase if user is logged in
  if (_supa && _currentUserId) {
    try {
      await _supa.from('apex_analyses').insert(record);
    } catch(e) { /* non-critical — local copy already saved */ }
  }

  return id;
}

// ── Record SL/TP outcome against a stored analysis ───────────────────────────
// Called when tapTradeStatus detects SL Hit or TP Hit for a drawing
async function tapUpdateAnalysisOutcome(d, outcome) {
  // outcome: 'tp_hit' | 'sl_hit' | 'breakeven'
  const history = tapGetLocalAnalysisHistory();
  const record = history.find(a =>
    Math.abs(a.entry_price - d.price) < 0.000001 &&
    Math.abs(a.sl_price   - d.sl)    < 0.000001 &&
    Math.abs(a.tp_price   - d.tp)    < 0.000001 &&
    a.outcome === 'pending'
  );
  if (!record) return;

  // Determine if the AI verdict was correct:
  // Strong/Acceptable Setup → expected TP hit; Risky/Avoid → expected SL hit
  const positiveVerdict = /strong|acceptable/i.test(record.verdict || '');
  const verdictCorrect  = outcome === 'tp_hit' ? positiveVerdict : !positiveVerdict;

  record.outcome         = outcome;
  record.verdict_correct = verdictCorrect;
  record.outcome_at      = new Date().toISOString();
  tapSetLocalAnalysisHistory(history);

  // Sync outcome to Supabase
  if (_supa && _currentUserId) {
    try {
      await _supa.from('apex_analyses')
        .update({ outcome, verdict_correct: verdictCorrect, outcome_at: record.outcome_at })
        .eq('id', record.id)
        .eq('user_id', _currentUserId);
    } catch(e) {}
  }
}

// ── RAG stats visible in the TAP panel (win-rate from stored outcomes) ─────────
function tapGetRAGStats(symbol) {
  const history = tapGetLocalAnalysisHistory();
  const resolved = history.filter(a => a.outcome && a.outcome !== 'pending' && a.symbol === symbol);
  if (!resolved.length) return null;
  const wins   = resolved.filter(a => a.outcome === 'tp_hit').length;
  const total  = resolved.length;
  const correct = resolved.filter(a => a.verdict_correct === true).length;
  return {
    total,
    wins,
    winRate: Math.round(wins / total * 100),
    aiAccuracy: Math.round(correct / total * 100),
  };
}

// ── Fetch historical win-rate stats from the scan database ───────────────────
// Queries the anonymous historical data for a specific symbol/TF/direction
// Returns { winRate, count, tpCount, slCount, topMethod, methodWinRate } or null
async function tapFetchHistoricalStats(symbol, tf, direction) {
  if (!_supa) return null;
  try {
    const { data, error } = await _supa
      .from('apex_analyses')
      .select('outcome, method_detected')
      .eq('user_id', 'anonymous')
      .eq('symbol', _tapNormSym(symbol))
      .eq('timeframe', tf)
      .eq('direction', direction)
      .neq('outcome', 'pending');
    if (error || !data?.length) return null;
    const total   = data.length;
    const tpCount = data.filter(r => r.outcome === 'tp_hit').length;
    const slCount = data.filter(r => r.outcome === 'sl_hit').length;
    const winRate = Math.round(tpCount / total * 100);
    // Find the method with the best win rate (min 5 samples)
    const methodMap = {};
    data.forEach(r => {
      if (!r.method_detected) return;
      if (!methodMap[r.method_detected]) methodMap[r.method_detected] = { tp: 0, total: 0 };
      methodMap[r.method_detected].total++;
      if (r.outcome === 'tp_hit') methodMap[r.method_detected].tp++;
    });
    let topMethod = null, topMethodWR = 0;
    Object.entries(methodMap).forEach(([m, v]) => {
      if (v.total >= 5) {
        const wr = Math.round(v.tp / v.total * 100);
        if (wr > topMethodWR) { topMethodWR = wr; topMethod = m; }
      }
    });
    return { winRate, count: total, tpCount, slCount, topMethod, methodWinRate: topMethodWR };
  } catch(e) { return null; }
}

// ── Parse METHOD_JSON line from analysis text ─────────────────────────────────
function tapParseMethodJSON(text) {
  if (!text) return null;
  try {
    const m = text.match(/METHOD_JSON:\s*(\{[^\n]+\})/);
    if (!m) return null;
    return JSON.parse(m[1]);
  } catch(e) { return null; }
}

// ── Render method badge in the TAP panel ──────────────────────────────────────
